def run_steward(state: AgentState) -> AgentState:
    print("--- [1] Steward: Analyzing Data ---")
    abort_state = _abort_if_requested(state, "steward")
    if abort_state:
        return abort_state
    # NOTE: Cleanup moved AFTER enter_run_workspace to clean workspace, not repo root
    run_id = state.get("run_id") if state else None
    if not run_id:
        run_id = uuid.uuid4().hex[:8]
    run_start_ts = state.get("run_start_ts") if state else None
    if not run_start_ts:
        run_start_ts = datetime.utcnow().isoformat()
    run_start_epoch = state.get("run_start_epoch") if state else None
    if run_start_epoch is None:
        run_start_epoch = time.time()
    orig_cwd_pre = os.getcwd()
    csv_path = state.get("csv_path") if state else ""
    if state and isinstance(state.get("business_objective"), str):
        state["business_objective"] = sanitize_text(state.get("business_objective", ""))
    if csv_path:
        resolved_csv_path = _resolve_csv_path_with_base(orig_cwd_pre, csv_path)
        if resolved_csv_path != csv_path:
            state["csv_path"] = resolved_csv_path
            csv_path = resolved_csv_path
    dataset_fingerprint = fingerprint_dataset(csv_path)
    memory_entries = load_dataset_memory()
    memory_context = summarize_memory(memory_entries, dataset_fingerprint)
    run_dir = init_run_dir(run_id, started_at=run_start_ts)
    init_run_bundle(run_id, state, run_dir=run_dir)

    # P0 FIX: Enter isolated run workspace to prevent cross-run contamination
    state = enter_run_workspace(state, run_dir)
    state["work_dir_abs"] = os.path.abspath(state.get("work_dir") or ".")

    # P0 FIX: Clean workspace AFTER entering (cleans work_dir, not repo root)
    clean_workspace_outputs()
    _cleanup_run_artifacts()

    # Initialize empty artifact index for this run (prevent stale data)
    try:
        os.makedirs("data", exist_ok=True)
        dump_json("data/produced_artifact_index.json", [])
    except Exception:
        pass

    agent_models = {
        "steward": getattr(getattr(steward, "model", None), "model_name", None),
        "strategist": getattr(getattr(strategist, "model", None), "model_name", None) or getattr(strategist, "model_name", None),
        "domain_expert": getattr(domain_expert, "model_name", None),
        "execution_planner": getattr(execution_planner, "model_name", None),
        "data_engineer": getattr(data_engineer, "model_name", None),
        "cleaning_reviewer": getattr(cleaning_reviewer, "model_name", None),
        "ml_engineer": getattr(ml_engineer, "model_name", None),
        "reviewer": getattr(reviewer, "model_name", None),
        "qa_reviewer": getattr(qa_reviewer, "model_name", None),
        "results_advisor": getattr(results_advisor, "model_name", None),
        "translator": getattr(translator, "model_name", None),
    }
    init_run_log(
        run_id,
        {
            "csv_path": csv_path,
            "business_objective": state.get("business_objective") if state else "",
            "dataset_fingerprint": dataset_fingerprint,
        },
    )
    log_run_event(run_id, "steward_start", {"csv_path": csv_path})

    # Pre-emptive cleanup
    import glob
    # Delete all potential report files including unique ones to avoid clutter
    for pdf_file in glob.glob("final_report*.pdf"):
        try:
            os.remove(pdf_file)
            print(f"🗑️ Cleaned up old report: {pdf_file}")
        except PermissionError:
            print(f"Note: '{pdf_file}' is locked. Ignoring.")
        except Exception as e:
            print(f"Debug: Cleanup failed for {pdf_file}: {e}")

    result = steward.analyze_data(state['csv_path'], state['business_objective'])

    summary = result.get('summary', 'Error')
    encoding = result.get('encoding', 'utf-8')
    sep = result.get('sep', ',')
    decimal = result.get('decimal', '.')
    if isinstance(state, dict):
        state["data_summary"] = summary
        state["csv_encoding"] = encoding
        state["csv_sep"] = sep
        state["csv_decimal"] = decimal
        _refresh_run_facts_pack(state)
    write_manifest_partial(
        run_id=run_id,
        manifest_path=os.path.join(run_dir, "run_manifest.json"),
        input_info={
            "path": csv_path,
            "sha256": _hash_file(csv_path),
            "dialect": {"encoding": encoding, "sep": sep, "decimal": decimal},
        },
        agent_models=agent_models,
    )

    try:
        os.makedirs("data", exist_ok=True)
        with open("data/steward_summary.txt", "w", encoding="utf-8") as f_summary:
            f_summary.write(summary or "")
        with open("data/steward_summary.json", "w", encoding="utf-8") as f_summary_json:
            json.dump(
                {
                    "run_id": run_id,
                    "csv_path": csv_path,
                    "encoding": encoding,
                    "sep": sep,
                    "decimal": decimal,
                    "summary": summary,
                },
                f_summary_json,
                indent=2,
                ensure_ascii=False,
            )
    except Exception as summary_err:
        print(f"Warning: failed to persist steward summary: {summary_err}")

    print(f"Steward Detected: Encoding={encoding}, Sep='{sep}', Decimal='{decimal}'")

    dataset_semantics = {}
    dataset_training_mask = {}
    dataset_semantics_summary = ""
    column_sets = {}
    column_sets_summary = ""
    column_manifest = {}
    column_manifest_summary = ""
    data_atlas = {}
    data_atlas_summary = ""
    steward_evidence_bundle = {}
    steward_context_quality = {"ready": False, "reasons": ["not_computed"], "warnings": []}
    steward_context_ready = False
    steward_context_error = ""
    header_cols = []
    try:
        dialect_payload = {"encoding": encoding, "sep": sep, "decimal": decimal}
        header_cols = read_header(csv_path, dialect_payload)
        if header_cols:
            try:
                column_inventory_payload = {
                    "n_columns": len(header_cols),
                    "columns": header_cols,
                    "generated_at": datetime.utcnow().isoformat(),
                    "source_csv": csv_path,
                }
                dump_json("data/column_inventory.json", column_inventory_payload)
            except Exception as inv_err:
                print(f"Warning: failed to persist column_inventory.json: {inv_err}")
            if isinstance(state, dict):
                state["column_inventory"] = {
                    "n_columns": len(header_cols),
                    "columns": header_cols,
                }
                state["column_inventory_columns"] = header_cols

        profile_payload = result.get("profile") if isinstance(result, dict) else {}
        if not isinstance(profile_payload, dict):
            profile_payload = {}
        data_atlas = build_data_atlas(
            dataset_profile=profile_payload,
            column_inventory=header_cols,
            column_sets=column_sets if isinstance(column_sets, dict) else {},
        )
        data_atlas_summary = summarize_data_atlas(data_atlas, max_columns=48, max_lines=90)
        try:
            os.makedirs("data", exist_ok=True)
            dump_json("data/data_atlas.json", data_atlas)
            with open("data/data_atlas_summary.txt", "w", encoding="utf-8") as f_atlas:
                f_atlas.write(data_atlas_summary or "")
        except Exception as atlas_err:
            print(f"Warning: failed to persist data_atlas artifacts: {atlas_err}")

        header_preview = summarize_long_list(header_cols, head=12, tail=6) if header_cols else {"count": 0, "head": [], "tail": []}
        column_count = len(header_cols)
        if column_count > 500:
            sample_cfg = {"head_n": 6, "tail_n": 4, "random_n": 8, "max_columns": 24}
        elif column_count > 200:
            sample_cfg = {"head_n": 10, "tail_n": 6, "random_n": 12, "max_columns": 32}
        elif column_count > 80:
            sample_cfg = {"head_n": 14, "tail_n": 8, "random_n": 16, "max_columns": 40}
        else:
            sample_cfg = {"head_n": 20, "tail_n": 10, "random_n": 20, "max_columns": 60}
        sample_payload = sample_rows(
            csv_path,
            dialect_payload,
            head_n=sample_cfg["head_n"],
            tail_n=sample_cfg["tail_n"],
            random_n=sample_cfg["random_n"],
            seed=42,
            max_columns=sample_cfg["max_columns"],
            max_value_chars=120,
        )
        steward_pass1_input = {
            "business_objective": state.get("business_objective") if isinstance(state, dict) else "",
            "column_inventory_path": "data/column_inventory.json",
            "column_inventory_preview": header_preview,
            "data_atlas_summary": data_atlas_summary,
            "sample_rows": sample_payload,
        }
        pass1_result = steward.decide_semantics_pass1(steward_pass1_input)
        if not isinstance(pass1_result, dict) or not pass1_result.get("primary_target"):
            pass1_result = steward.decide_semantics_pass1(
                {**steward_pass1_input, "retry_reason": "primary_target_missing"}
            )

        primary_target = pass1_result.get("primary_target") if isinstance(pass1_result, dict) else None
        split_candidates = pass1_result.get("split_candidates") if isinstance(pass1_result, dict) else []
        id_candidates = pass1_result.get("id_candidates") if isinstance(pass1_result, dict) else []
        if not isinstance(split_candidates, list):
            split_candidates = []
        if not isinstance(id_candidates, list):
            id_candidates = []

        evidence_requests = normalize_evidence_requests(
            pass1_result.get("evidence_requests") if isinstance(pass1_result, dict) else [],
            header_cols,
            max_items=16,
        )
        if not evidence_requests:
            evidence_requests = build_default_evidence_requests(
                primary_target=primary_target,
                split_candidates=split_candidates,
                id_candidates=id_candidates,
                header_cols=header_cols,
                max_items=16,
            )
        steward_evidence_bundle = _resolve_steward_evidence_bundle(
            csv_path=csv_path,
            dialect_payload=dialect_payload,
            header_cols=header_cols,
            requested=evidence_requests,
        )

        target_missingness = {}
        if primary_target:
            target_missingness = scan_missingness(csv_path, dialect_payload, str(primary_target))
        split_evidence = []
        for col in split_candidates[:5]:
            if not col:
                continue
            split_evidence.append(scan_uniques(csv_path, dialect_payload, str(col), max_unique=20))

        steward_pass2_input = {
            "business_objective": state.get("business_objective") if isinstance(state, dict) else "",
            "primary_target": primary_target,
            "split_candidates": split_candidates,
            "id_candidates": id_candidates,
            "target_missingness": target_missingness,
            "split_candidates_uniques": split_evidence,
            "evidence_bundle": steward_evidence_bundle,
            "column_inventory_path": "data/column_inventory.json",
            "column_inventory_preview": header_preview,
            "data_atlas_summary": data_atlas_summary,
        }
        pass2_result = steward.decide_semantics_pass2(steward_pass2_input)
        if not isinstance(pass2_result, dict):
            pass2_result = {}
        dataset_semantics = pass2_result.get("dataset_semantics") if isinstance(pass2_result, dict) else {}
        dataset_training_mask = pass2_result.get("dataset_training_mask") if isinstance(pass2_result, dict) else {}
        column_sets = pass2_result.get("column_sets") if isinstance(pass2_result, dict) else {}

        if not isinstance(dataset_semantics, dict):
            dataset_semantics = {}
        if not isinstance(dataset_training_mask, dict):
            dataset_training_mask = {}
        if not isinstance(column_sets, dict):
            column_sets = {}

        # Universal fallback: if column_sets is empty on wide datasets, build selectors from inventory.
        if not column_sets and header_cols and len(header_cols) > 200:
            try:
                from src.utils.column_sets import build_column_sets
                role_map = {}
                if primary_target:
                    role_map[str(primary_target)] = "target_candidate"
                for col in split_candidates:
                    if col:
                        role_map[str(col)] = "split_candidate"
                for col in id_candidates:
                    if col:
                        role_map[str(col)] = "id_like"
                column_sets = build_column_sets(header_cols, roles=role_map)
            except Exception as cs_err:
                print(f"Warning: failed to build column_sets fallback: {cs_err}")
                column_sets = {}

        dataset_semantics_summary = summarize_dataset_semantics(dataset_semantics, dataset_training_mask)
        column_sets_summary = summarize_column_sets(column_sets) if column_sets else ""
        try:
            role_map_for_manifest: Dict[str, str] = {}
            if primary_target:
                role_map_for_manifest[str(primary_target)] = "target_candidate"
            for col in split_candidates:
                if col:
                    role_map_for_manifest[str(col)] = "split_candidate"
            for col in id_candidates:
                if col:
                    role_map_for_manifest[str(col)] = "id_like"
            column_manifest = build_column_manifest(
                header_cols,
                column_sets=column_sets if isinstance(column_sets, dict) else {},
                roles=role_map_for_manifest,
            )
            column_manifest_summary = summarize_column_manifest(column_manifest)
        except Exception as manifest_err:
            print(f"Warning: failed to build column_manifest: {manifest_err}")
            column_manifest = {}
            column_manifest_summary = ""
        steward_context_quality = validate_steward_semantics(
            dataset_semantics=dataset_semantics,
            dataset_training_mask=dataset_training_mask,
            header_cols=header_cols,
            target_missingness=target_missingness,
            column_sets=column_sets,
        )
        steward_context_ready = bool(steward_context_quality.get("ready"))
        if not steward_context_ready:
            reasons = steward_context_quality.get("reasons") if isinstance(steward_context_quality, dict) else []
            steward_context_error = f"Steward context quality gate failed: {reasons}"
        try:
            os.makedirs("data", exist_ok=True)
            dump_json("data/dataset_semantics.json", dataset_semantics)
            dump_json("data/dataset_training_mask.json", dataset_training_mask)
            dump_json("data/column_sets.json", column_sets)
            dump_json("data/column_manifest.json", column_manifest)
            dump_json("data/steward_evidence_bundle.json", steward_evidence_bundle)
            dump_json("data/steward_semantics_quality.json", steward_context_quality)
            if column_manifest_summary:
                with open("data/column_manifest_summary.txt", "w", encoding="utf-8") as f_manifest_summary:
                    f_manifest_summary.write(column_manifest_summary)
        except Exception as sem_write_err:
            print(f"Warning: failed to persist dataset semantics artifacts: {sem_write_err}")
    except Exception as sem_err:
        print(f"Warning: dataset semantics extraction failed: {sem_err}")
        steward_context_error = str(sem_err)
        steward_context_ready = False
        steward_context_quality = {
            "ready": False,
            "reasons": [f"semantics_exception:{sem_err}"],
            "warnings": [],
        }
        if header_cols and not column_sets and len(header_cols) > 200:
            try:
                from src.utils.column_sets import build_column_sets
                column_sets = build_column_sets(header_cols)
                column_sets_summary = summarize_column_sets(column_sets) if column_sets else ""
                os.makedirs("data", exist_ok=True)
                dump_json("data/column_sets.json", column_sets)
            except Exception as cs_err:
                print(f"Warning: failed to build column_sets fallback after semantics error: {cs_err}")
        try:
            column_manifest = build_column_manifest(
                header_cols,
                column_sets=column_sets if isinstance(column_sets, dict) else {},
                roles={},
            )
            column_manifest_summary = summarize_column_manifest(column_manifest)
            if column_manifest:
                os.makedirs("data", exist_ok=True)
                dump_json("data/column_manifest.json", column_manifest)
                if column_manifest_summary:
                    with open("data/column_manifest_summary.txt", "w", encoding="utf-8") as f_manifest_summary:
                        f_manifest_summary.write(column_manifest_summary)
        except Exception as manifest_err:
            print(f"Warning: failed to build column_manifest fallback: {manifest_err}")
    if isinstance(state, dict):
        state["data_atlas"] = data_atlas
        state["data_atlas_summary"] = data_atlas_summary
        state["steward_evidence_bundle"] = steward_evidence_bundle
        state["steward_context_quality"] = steward_context_quality
        state["steward_context_ready"] = steward_context_ready
        state["steward_context_error"] = steward_context_error
        state["dataset_semantics"] = dataset_semantics
        state["dataset_training_mask"] = dataset_training_mask
        state["dataset_semantics_summary"] = dataset_semantics_summary
        state["column_sets"] = column_sets
        state["column_sets_summary"] = column_sets_summary
        state["column_manifest"] = column_manifest
        state["column_manifest_summary"] = column_manifest_summary

    log_run_event(
        run_id,
        "steward_complete",
        {
            "summary_len": len(summary or ""),
            "encoding": encoding,
            "sep": sep,
            "decimal": decimal,
            "steward_context_ready": bool(steward_context_ready),
            "steward_context_reasons": (steward_context_quality or {}).get("reasons", []),
        },
    )
    log_agent_snapshot(
        run_id,
        "steward",
        prompt=getattr(steward, "last_prompt", None),
        response=getattr(steward, "last_response", None) or result,
        context={"csv_path": csv_path, "business_objective": state.get("business_objective") if state else ""},
    )

    # Initialize loop variables
    budget_state = _ensure_budget_state(state or {})
    steward_payload = {
        "data_summary": summary,
        "csv_encoding": encoding,
        "csv_sep": sep,
        "csv_decimal": decimal,
        "dataset_semantics": dataset_semantics,
        "dataset_training_mask": dataset_training_mask,
        "dataset_semantics_summary": dataset_semantics_summary,
        "data_atlas": data_atlas,
        "data_atlas_summary": data_atlas_summary,
        "steward_evidence_bundle": steward_evidence_bundle,
        "steward_context_quality": steward_context_quality,
        "steward_context_ready": steward_context_ready,
        "steward_context_error": steward_context_error,
        "column_sets": column_sets,
        "column_sets_summary": column_sets_summary,
        "column_manifest": column_manifest,
        "column_manifest_summary": column_manifest_summary,
        "iteration_count": 0,
        "compliance_iterations": 0,
        "metric_iterations": 0,
        "compliance_passed": False,
        "last_iteration_type": None,
        "ml_journal_written_ids": [],
        "feedback_history": [],
        "has_partial_visuals": False,
        "plots_local": [],
        "last_generated_code": None,
        "last_gate_context": None,
        "iteration_handoff": None,
        "review_reject_streak": 0,
        "qa_reject_streak": 0,
        "ml_engineer_attempt": 0,
        "metric_improvement_nodes_managed": False,
        "metric_improvement_bootstrapped": False,
        "metric_improvement_finalized": False,
        "ml_improvement_round_active": False,
        "ml_improvement_continue": False,
        "ml_improvement_loop_complete": False,
        "ml_improvement_attempted": False,
        "ml_improvement_round_count": 0,
        "ml_improvement_rounds_allowed": 1,
        "ml_improvement_current_round_id": 0,
        "ml_improvement_no_improve_streak": 0,
        "ml_improvement_patience": 2,
        "ml_improvement_min_delta": 0.0005,
        "ml_improvement_higher_is_better": True,
        "ml_improvement_kept": "baseline",
        "ml_improvement_review_mode": "full",
        "ml_improvement_snapshot_dir": "",
        "ml_improvement_output_paths": [],
        "ml_improvement_primary_metric_name": "",
        "ml_improvement_primary_metric_source": "",
        "ml_improvement_critique_packet": {},
        "ml_improvement_candidate_critique_packet": {},
        "ml_improvement_hypothesis_packet": {},
        "ml_improvement_force_finalize_reason": "",
        "ml_improvement_round_baseline_metric": 0.0,
        "ml_improvement_round_baseline_metrics": {},
        "ml_improvement_round_baseline_reviewer_packet": {},
        "ml_improvement_round_baseline_qa_packet": {},
        "ml_improvement_incumbent_metric": 0.0,
        "ml_improvement_baseline_metric": 0.0,
        "ml_improvement_baseline_metrics": {},
        "ml_improvement_baseline_review_verdict": "",
        "ml_improvement_best_metric": 0.0,
        "ml_improvement_best_round": 0,
        "ml_improvement_round_history": [],
        "ml_improvement_pareto_frontier": [],
        "ml_improvement_apply_guard_report": {},
        "leakage_audit_summary": "",
        "restrategize_count": state.get("restrategize_count", 0) if state else 0,
        "strategist_context_override": state.get("strategist_context_override", "") if state else "",
        "missing_repeat_count": 0,
        "run_id": run_id,
        "run_start_ts": run_start_ts,
        "run_start_epoch": run_start_epoch,
        "dataset_fingerprint": dataset_fingerprint,
        "dataset_memory_context": memory_context,
        "run_budget": budget_state.get("run_budget", {}),
        "budget_counters": budget_state.get("budget_counters", {}),
        "agent_models": agent_models,
    }
    if isinstance(result, dict):
        if "profile" in result:
            steward_payload["profile"] = result.get("profile")
        if "dataset_profile" in result:
            steward_payload["dataset_profile"] = result.get("dataset_profile")
    if not steward_context_ready:
        steward_payload["error_message"] = steward_context_error or "Steward context quality gate failed."
        steward_payload["pipeline_aborted_reason"] = "STEWARD_CONTEXT_INVALID"
    steward_payload = _add_workspace_metadata(steward_payload, state, orig_cwd_pre, run_dir)
    _refresh_run_facts_pack(steward_payload)
    return steward_payload

def run_strategist(state: AgentState) -> AgentState:
    print("--- [2] Strategist: Formulating Strategies ---")
    abort_state = _abort_if_requested(state, "strategist")
    if abort_state:
        return abort_state

    # Strategist now returns a dict with "strategies": [list of 3]
    user_context = state.get("strategist_context_override") or state.get("business_objective", "")
    if _minimal_agent_context_enabled():
        data_summary = _build_senior_summary_context(state if isinstance(state, dict) else {})
        context_pack = ""
    else:
        context_pack = build_context_pack("strategist", state if isinstance(state, dict) else {})
        data_summary = state.get("data_summary", "")
        data_summary = _prepend_dataset_semantics_summary(data_summary, state)
        if context_pack:
            data_summary = f"{context_pack}\n\n{data_summary}" if data_summary else context_pack
    column_inventory: List[str] = []
    inventory_cols = state.get("column_inventory_columns")
    if isinstance(inventory_cols, list):
        column_inventory = [str(c) for c in inventory_cols if isinstance(c, str) and c.strip()]
    if not column_inventory:
        inv_state = state.get("column_inventory")
        if isinstance(inv_state, dict):
            inv_cols = inv_state.get("columns") or inv_state.get("column_inventory")
            if isinstance(inv_cols, list):
                column_inventory = [str(c) for c in inv_cols if isinstance(c, str) and c.strip()]
    if not column_inventory:
        inv_file = _load_json_safe("data/column_inventory.json")
        if isinstance(inv_file, dict):
            inv_cols = inv_file.get("columns") or inv_file.get("column_inventory")
            if isinstance(inv_cols, list):
                column_inventory = [str(c) for c in inv_cols if isinstance(c, str) and c.strip()]
    column_sets = state.get("column_sets")
    if not isinstance(column_sets, dict):
        column_sets = {}
    column_manifest = state.get("column_manifest")
    if not isinstance(column_manifest, dict) or not column_manifest:
        column_manifest = _load_json_safe("data/column_manifest.json") or {}
    compute_constraints = _collect_domain_expert_compute_constraints(state if isinstance(state, dict) else {})
    dataset_profile = state.get("profile") if isinstance(state.get("profile"), dict) else None
    if not dataset_profile and isinstance(state.get("dataset_profile"), dict):
        dataset_profile = state.get("dataset_profile")
    if isinstance(dataset_profile, dict):
        compute_hints = dataset_profile.get("compute_hints")
        if isinstance(compute_hints, dict):
            for key in ("estimated_memory_mb", "scale_category", "cross_validation_feasible", "deep_learning_feasible"):
                value = compute_hints.get(key)
                if value is not None:
                    compute_constraints[key] = value
    # Build structured column metadata for strategist
    from src.utils.data_profile_compact import build_column_metadata_for_strategist
    _data_profile_for_meta = state.get("data_profile") if isinstance(state.get("data_profile"), dict) else {}
    _ds_semantics_for_meta = state.get("dataset_semantics") if isinstance(state.get("dataset_semantics"), dict) else {}
    column_metadata = build_column_metadata_for_strategist(
        data_profile=_data_profile_for_meta,
        dataset_semantics=_ds_semantics_for_meta,
    )

    result = strategist.generate_strategies(
        data_summary,
        user_context,
        column_inventory=column_inventory,
        column_sets=column_sets,
        column_manifest=column_manifest if isinstance(column_manifest, dict) else {},
        compute_constraints=compute_constraints,
        column_metadata=column_metadata,
    )
    run_id = state.get("run_id")
    if run_id:
        log_agent_snapshot(
            run_id,
            "strategist",
            prompt=getattr(strategist, "last_prompt", None),
            response=getattr(strategist, "last_response", None) or result,
            context={
                "data_summary": data_summary,
                "user_context": user_context,
                "column_inventory_count": len(column_inventory),
                "column_sets_keys": sorted(list(column_sets.keys()))[:30] if isinstance(column_sets, dict) else [],
                "column_manifest_mode": (
                    str(column_manifest.get("schema_mode"))
                    if isinstance(column_manifest, dict) and column_manifest.get("schema_mode")
                    else "none"
                ),
                "column_manifest_family_count": (
                    int(column_manifest.get("family_count") or 0)
                    if isinstance(column_manifest, dict)
                    else 0
                ),
                "compute_constraints": compute_constraints,
            },
        )
    # Defensive handling of strategist result types (Fix for potential crashes)
    strategies_list = []
    strategy_spec = {}
    
    if isinstance(result, list):
         # Handle legacy list return directly
         strategies_list = result
    elif isinstance(result, dict):
         strategies_list = result.get('strategies', [])
         strategy_spec = result.get('strategy_spec', {})
    else:
         strategies_list = []

    # Ensure strategies_list is actually a list of dicts
    if not isinstance(strategies_list, list):
         if isinstance(strategies_list, dict):
             strategies_list = [strategies_list]
         else:
             strategies_list = []
    
    strategies_list = [s for s in strategies_list if isinstance(s, dict)]
    column_validation = result.get("column_validation") if isinstance(result, dict) else {}
    if not isinstance(column_validation, dict):
        column_validation = {}
    strategist_json_repair = result.get("json_repair") if isinstance(result, dict) else {}
    if not isinstance(strategist_json_repair, dict):
        strategist_json_repair = {}
    diversity_validation = result.get("diversity_validation") if isinstance(result, dict) else {}
    if not isinstance(diversity_validation, dict):
        diversity_validation = {}

    # Fallback if list is empty or malformed
    if not strategies_list:
        print("Warning: Strategist returned no strategies. Using fallback.")
        strategies_list = [{
                "title": "Fallback Analysis",
                "analysis_type": "statistical",
                "hypothesis": "Basic analysis due to generator failure.",
                "required_columns": [], # Dangerous but treated by DE
                "estimated_difficulty": "Low",
                "reasoning": "Fallback"
        }]

    if strategy_spec:
        try:
            os.makedirs("data", exist_ok=True)
            with open("data/strategy_spec.json", "w", encoding="utf-8") as f_spec:
                json.dump(strategy_spec, f_spec, indent=2)
        except Exception as spec_err:
            print(f"Warning: failed to persist strategy_spec.json: {spec_err}")

    return {
        "strategies": {"strategies": strategies_list},
        "strategy_spec": strategy_spec,
        "column_validation": column_validation,
        "strategist_json_repair": strategist_json_repair,
        "strategist_diversity_validation": diversity_validation,
    }

def run_domain_expert(state: AgentState) -> AgentState:
    print("--- [2.5] Domain Expert: Evaluating & Selecting Strategy ---")
    abort_state = _abort_if_requested(state, "domain_expert")
    if abort_state:
        return abort_state

    strategies_wrapper = state.get('strategies', {})
    strategies_list = strategies_wrapper.get('strategies', [])
    business_objective = state.get("business_objective", "")
    if _minimal_agent_context_enabled():
        data_summary = _build_senior_summary_context(state if isinstance(state, dict) else {})
        context_pack = ""
    else:
        context_pack = build_context_pack("domain_expert", state if isinstance(state, dict) else {})
        data_summary = state.get('data_summary', '')
        data_summary = _prepend_dataset_semantics_summary(data_summary, state)
        if context_pack:
            data_summary = f"{context_pack}\n\n{data_summary}" if data_summary else context_pack

    strategy_spec = state.get("strategy_spec")
    if not isinstance(strategy_spec, dict):
        strategy_spec = {}
    column_validation = state.get("column_validation")
    if not isinstance(column_validation, dict):
        column_validation = {}
    compute_constraints = {
        "runtime_mode": _get_execution_runtime_mode(),
    }
    heavy_cfg = _get_heavy_runner_config() or {}
    if isinstance(heavy_cfg, dict):
        timeout_sec = heavy_cfg.get("script_timeout_seconds")
        if isinstance(timeout_sec, int) and timeout_sec > 0:
            compute_constraints["max_runtime_seconds"] = int(timeout_sec)
    execution_profile = state.get("execution_profile_context")
    if isinstance(execution_profile, dict):
        for key in ("max_runtime_seconds", "max_memory_mb", "gpu_available", "cpu_cores"):
            value = execution_profile.get(key)
            if value is not None:
                compute_constraints[key] = value

    invalid_details_map: Dict[int, Dict[str, Any]] = {}
    for item in (column_validation.get("invalid_details") or []):
        if not isinstance(item, dict):
            continue
        try:
            idx = int(item.get("strategy_index"))
        except Exception:
            continue
        invalid_details_map[idx] = item
    over_budget_map: Dict[int, Dict[str, Any]] = {}
    for item in (column_validation.get("over_budget_details") or []):
        if not isinstance(item, dict):
            continue
        try:
            idx = int(item.get("strategy_index"))
        except Exception:
            continue
        over_budget_map[idx] = item

    enriched_strategies: List[Dict[str, Any]] = []
    for idx, strat in enumerate(strategies_list):
        if not isinstance(strat, dict):
            continue
        enriched = dict(strat)
        enriched["_strategy_index"] = idx
        enriched["_title"] = str(strat.get("title") or f"strategy_{idx}")
        enriched["_meta"] = {
            "column_validation": {
                "invalid_count": len((invalid_details_map.get(idx) or {}).get("invalid_columns", [])),
                "invalid_columns": (invalid_details_map.get(idx) or {}).get("invalid_columns", []),
                "over_budget": idx in over_budget_map,
                "max_required_columns": (over_budget_map.get(idx) or {}).get("max_required_columns"),
                "required_count": (over_budget_map.get(idx) or {}).get("required_count")
                or (invalid_details_map.get(idx) or {}).get("required_count"),
            },
            "strategy_spec": strategy_spec,
            "compute_constraints": compute_constraints,
        }
        enriched_strategies.append(enriched)

    # Deliberation Step — deterministic scoring (no LLM call)
    evaluation = domain_expert.evaluate_deterministic(
        data_summary,
        business_objective,
        enriched_strategies,
        compute_constraints=compute_constraints,
        dataset_memory_context=str(state.get("dataset_memory_context") or ""),
    )
    reviews = evaluation.get('reviews', [])
    review_validation = evaluation.get("review_validation") if isinstance(evaluation, dict) else {}
    if not isinstance(review_validation, dict):
        review_validation = {}
    run_id = state.get("run_id")
    if run_id:
        log_agent_snapshot(
            run_id,
            "domain_expert",
            prompt=getattr(domain_expert, "last_prompt", None),
            response=getattr(domain_expert, "last_response", None) or evaluation,
            context={
                "data_summary": data_summary,
                "business_objective": business_objective,
                "strategy_count": len(strategies_list) if isinstance(strategies_list, list) else 0,
                "compute_constraints": compute_constraints,
                "review_validation": review_validation,
            },
        )

    # Selection Logic
    best_strategy = None
    best_score = -1.0
    selection_reason = "Default Selection"
    selection_validation: Dict[str, Any] = {}
    candidate_ranking: List[Dict[str, Any]] = []

    print("\n🧐 EXPERT DELIBERATION:")
    normalized_reviews: List[Dict[str, Any]] = []
    if isinstance(reviews, list):
        normalized_reviews = [r for r in reviews if isinstance(r, dict)]
    title_lookup = {}
    for rev in normalized_reviews:
        title = str(rev.get("title") or "").strip().lower()
        if title:
            title_lookup[title] = rev

    for idx, strat in enumerate(strategies_list):
        match = None
        # Primary: positional index contract
        if idx < len(normalized_reviews):
            candidate = normalized_reviews[idx]
            cand_idx = candidate.get("strategy_index")
            try:
                if cand_idx is None or int(cand_idx) == idx:
                    match = candidate
            except Exception:
                pass
        # Secondary: explicit strategy_index search
        if match is None:
            for candidate in normalized_reviews:
                try:
                    if int(candidate.get("strategy_index")) == idx:
                        match = candidate
                        break
                except Exception:
                    continue
        # Tertiary: fuzzy title match
        if match is None:
            strat_title = str(strat.get("title") or "").strip().lower()
            best_ratio = 0.0
            best_candidate = None
            for rev_title, candidate in title_lookup.items():
                ratio = difflib.SequenceMatcher(None, rev_title, strat_title).ratio()
                if ratio > best_ratio:
                    best_ratio = ratio
                    best_candidate = candidate
            if best_candidate is not None and best_ratio >= 0.70:
                match = best_candidate

        score = _safe_float(match.get('score'), 0.0) if isinstance(match, dict) else 0.0
        selectable = bool(match.get("selectable", score >= 3.0)) if isinstance(match, dict) else False
        exec_validation = _validate_selected_strategy_executability(
            strat if isinstance(strat, dict) else {},
            review=match if isinstance(match, dict) else None,
            compute_constraints=compute_constraints if isinstance(compute_constraints, dict) else {},
        )
        candidate_ranking.append(
            {
                "strategy_index": idx,
                "title": str(strat.get("title") or f"strategy_{idx}"),
                "score": score,
                "selectable": selectable,
                "executable": bool(exec_validation.get("ok")),
                "blockers": exec_validation.get("blockers") or [],
                "warnings": exec_validation.get("warnings") or [],
                "reasoning": str(match.get("reasoning") or "") if isinstance(match, dict) else "",
            }
        )

        print(f"  • Strategy: {strat.get('title')} | Score: {score}/10")
        if isinstance(match, dict):
             critique = str(match.get("reasoning") or "")
             print(f"    - Critique: {critique[:120]}...")
             print(f"    - Selectable: {selectable}")
        print(f"    - Executable: {bool(exec_validation.get('ok'))} | Blockers: {exec_validation.get('blockers') or []}")

        if selectable and bool(exec_validation.get("ok")) and score > best_score:
            best_score = score
            best_strategy = strat
            selection_reason = str(match.get('reasoning') or "Highest Score") if isinstance(match, dict) else "Highest Score"
            selection_validation = exec_validation

    # Fallback: choose best selectable candidate with minimum blockers.
    if not best_strategy and strategies_list:
        best_candidate = None
        for candidate in candidate_ranking:
            if not candidate.get("selectable"):
                continue
            if best_candidate is None:
                best_candidate = candidate
                continue
            cand_blockers = len(candidate.get("blockers") or [])
            best_blockers = len(best_candidate.get("blockers") or [])
            if cand_blockers < best_blockers:
                best_candidate = candidate
                continue
            if cand_blockers == best_blockers and _safe_float(candidate.get("score"), 0.0) > _safe_float(best_candidate.get("score"), 0.0):
                best_candidate = candidate
        if best_candidate is None and candidate_ranking:
            best_candidate = max(candidate_ranking, key=lambda c: _safe_float(c.get("score"), 0.0))
        if isinstance(best_candidate, dict):
            try:
                best_idx = int(best_candidate.get("strategy_index"))
            except Exception:
                best_idx = 0
            best_idx = max(0, min(best_idx, len(strategies_list) - 1))
            best_strategy = strategies_list[best_idx]
            selection_reason = (
                "Fallback selection applied due to executability constraints. "
                f"Chosen strategy_index={best_idx} with blockers={best_candidate.get('blockers') or []}"
            )
            selection_validation = {
                "ok": len(best_candidate.get("blockers") or []) == 0,
                "blockers": best_candidate.get("blockers") or [],
                "warnings": best_candidate.get("warnings") or [],
            }
        else:
            best_strategy = strategies_list[0]
            selection_reason = "Fallback: First strategy selected (no candidate ranking available)."
            selection_validation = {"ok": False, "blockers": ["no_candidate_ranking"], "warnings": []}

    if not isinstance(best_strategy, dict):
        best_strategy = {}
    print(f"\n🏆 WINNER: {best_strategy.get('title')} (Score: {best_score})")
    print(f"   Reason: {selection_reason}\n")

    ranked_candidates_sorted = sorted(
        candidate_ranking,
        key=lambda c: (
            0 if bool(c.get("selectable")) else 1,
            len(c.get("blockers") or []),
            -_safe_float(c.get("score"), 0.0),
        ),
    )

    return {
        "selected_strategy": best_strategy,
        "selection_reason": selection_reason,
        "domain_expert_reviews": normalized_reviews,
        "domain_expert_validation": review_validation,
        "domain_expert_selection_validation": selection_validation,
        "domain_expert_ranked_candidates": ranked_candidates_sorted,
    }


def _extract_decisioning_required_names(contract_like: Dict[str, Any]) -> List[str]:
    if not isinstance(contract_like, dict):
        return []
    decisioning = contract_like.get("decisioning_requirements")
    if not isinstance(decisioning, dict):
        return []
    output = decisioning.get("output")
    if not isinstance(output, dict):
        return []
    required = output.get("required_columns")
    if not isinstance(required, list):
        return []
    names: List[str] = []
    for item in required:
        name = None
        if isinstance(item, dict):
            name = item.get("name") or item.get("column")
        elif isinstance(item, str):
            name = item
        if name:
            names.append(str(name))
    return list(dict.fromkeys(names))


def _env_flag(name: str, default: bool = False) -> bool:
    raw = os.getenv(name)
    if raw is None:
        return default
    return str(raw).strip().lower() in {"1", "true", "yes", "on"}


def _get_execution_runtime_mode() -> str:
    raw = (
        os.getenv("RUN_EXECUTION_MODE")
        or os.getenv("EXECUTION_RUNTIME_MODE")
        or os.getenv("CODE_EXECUTION_RUNTIME")
        or "cloudrun"
    )
    mode = str(raw).strip().lower()
    if mode in {"local", "cloudrun"}:
        return mode
    return "cloudrun"


def _get_heavy_runner_config() -> Dict[str, Any] | None:
    runtime_mode = _get_execution_runtime_mode()
    if runtime_mode == "local":
        timeout_raw = (
            os.getenv("LOCAL_RUNNER_SCRIPT_TIMEOUT_SECONDS")
            or os.getenv("HEAVY_RUNNER_SCRIPT_TIMEOUT_SECONDS")
        )
        script_timeout_seconds = None
        if timeout_raw is not None:
            try:
                parsed = int(str(timeout_raw).strip())
                if parsed > 0:
                    script_timeout_seconds = parsed
            except Exception:
                script_timeout_seconds = None
        return {
            "mode": "local",
            "job": "local_runner",
            "region": "local",
            "bucket": "local",
            "project": "local",
            "input_prefix": "inputs",
            "output_prefix": "outputs",
            "dataset_prefix": "datasets",
            "script_timeout_seconds": script_timeout_seconds,
        }

    if not _env_flag("HEAVY_RUNNER_ENABLED", False):
        return None
    job = os.getenv("HEAVY_RUNNER_JOB")
    region = os.getenv("HEAVY_RUNNER_REGION")
    bucket = os.getenv("HEAVY_RUNNER_BUCKET")
    if not job or not region or not bucket:
        return None
    timeout_raw = os.getenv("HEAVY_RUNNER_SCRIPT_TIMEOUT_SECONDS")
    script_timeout_seconds = None
    if timeout_raw is not None:
        try:
            parsed = int(str(timeout_raw).strip())
            if parsed > 0:
                script_timeout_seconds = parsed
        except Exception:
            script_timeout_seconds = None
    return {
        "mode": "cloudrun",
        "job": job,
        "region": region,
        "bucket": bucket,
        "project": os.getenv("HEAVY_RUNNER_PROJECT"),
        "input_prefix": os.getenv("HEAVY_RUNNER_INPUT_PREFIX", "inputs"),
        "output_prefix": os.getenv("HEAVY_RUNNER_OUTPUT_PREFIX", "outputs"),
        "dataset_prefix": os.getenv("HEAVY_RUNNER_DATASET_PREFIX", "datasets"),
        "script_timeout_seconds": script_timeout_seconds,
    }


_TECHNIQUE_PACKAGE_HINTS: Dict[str, List[str]] = {
    "xgboost": ["xgboost"],
    "lightgbm": ["lightgbm"],
    "pytorch": ["torch"],
    "torch": ["torch"],
    "tensorflow": ["tensorflow"],
    "transformer": ["transformers"],
    "bert": ["transformers"],
    "lstm": ["torch", "tensorflow"],
    "neural network": ["torch", "tensorflow"],
    "prophet": ["prophet"],
    "arima": ["statsmodels"],
    "sarima": ["statsmodels"],
    "survival": ["lifelines"],
    "shap": ["shap"],
}


def _collect_domain_expert_compute_constraints(state: Dict[str, Any]) -> Dict[str, Any]:
    compute_constraints = {
        "runtime_mode": _get_execution_runtime_mode(),
    }
    heavy_cfg = _get_heavy_runner_config() or {}
    if isinstance(heavy_cfg, dict):
        timeout_sec = heavy_cfg.get("script_timeout_seconds")
        if isinstance(timeout_sec, int) and timeout_sec > 0:
            compute_constraints["max_runtime_seconds"] = int(timeout_sec)
    execution_profile = state.get("execution_profile_context")
    if isinstance(execution_profile, dict):
        for key in ("max_runtime_seconds", "max_memory_mb", "gpu_available", "cpu_cores"):
            value = execution_profile.get(key)
            if value is not None:
                compute_constraints[key] = value
    dataset_profile = state.get("profile") if isinstance(state.get("profile"), dict) else None
    if not dataset_profile and isinstance(state.get("dataset_profile"), dict):
        dataset_profile = state.get("dataset_profile")
    if isinstance(dataset_profile, dict):
        compute_hints = dataset_profile.get("compute_hints")
        if isinstance(compute_hints, dict):
            for key in ("estimated_memory_mb", "scale_category", "cross_validation_feasible", "deep_learning_feasible"):
                value = compute_hints.get(key)
                if value is not None:
                    compute_constraints[key] = value
    return compute_constraints


def _required_packages_from_techniques(techniques: Any) -> List[str]:
    if not isinstance(techniques, list):
        return []
    packages: List[str] = []
    for item in techniques:
        text = str(item or "").strip().lower()
        if not text:
            continue
        for hint, deps in _TECHNIQUE_PACKAGE_HINTS.items():
            if hint in text:
                for dep in deps:
                    if dep not in packages:
                        packages.append(dep)
    return packages


def _validate_selected_strategy_executability(
    strategy: Dict[str, Any],
    *,
    review: Optional[Dict[str, Any]],
    compute_constraints: Dict[str, Any],
) -> Dict[str, Any]:
    blockers: List[str] = []
    warnings: List[str] = []
    if not isinstance(strategy, dict):
        return {"ok": False, "blockers": ["strategy_not_dict"], "warnings": []}

    meta = strategy.get("_meta") if isinstance(strategy.get("_meta"), dict) else {}
    col_meta = meta.get("column_validation") if isinstance(meta.get("column_validation"), dict) else {}
    invalid_count = int(col_meta.get("invalid_count") or 0)
    if invalid_count > 0:
        blockers.append("invalid_required_columns")
    if bool(col_meta.get("over_budget")):
        warnings.append("required_columns_over_budget")

    techniques = strategy.get("techniques")
    if not isinstance(techniques, list) or not techniques:
        blockers.append("missing_techniques")

    required_columns = strategy.get("required_columns")
    if isinstance(required_columns, list) and len(required_columns) == 0:
        warnings.append("empty_required_columns")

    max_runtime_seconds = int(_safe_float(compute_constraints.get("max_runtime_seconds"), 0.0))
    difficulty = str(strategy.get("estimated_difficulty") or "").strip().lower()
    if max_runtime_seconds > 0 and difficulty == "high" and max_runtime_seconds < 900:
        blockers.append("high_difficulty_under_runtime_budget")
    elif max_runtime_seconds > 0 and difficulty == "high" and max_runtime_seconds < 1800:
        warnings.append("high_difficulty_tight_runtime_budget")

    runtime_mode = str(compute_constraints.get("runtime_mode") or "").strip().lower()
    required_packages = _required_packages_from_techniques(techniques)
    if runtime_mode == "local" and required_packages:
        missing_local = [pkg for pkg in required_packages if importlib.util.find_spec(pkg) is None]
        if missing_local:
            blockers.append(f"missing_local_dependencies:{','.join(missing_local[:8])}")
    elif required_packages:
        warnings.append(f"requires_dependencies:{','.join(required_packages[:8])}")

    review_score = _safe_float(review.get("score"), 0.0) if isinstance(review, dict) else 0.0
    if review_score < 3.0:
        blockers.append("score_below_selectable_threshold")

    return {
        "ok": len(blockers) == 0,
        "blockers": blockers,
        "warnings": warnings,
        "required_packages": required_packages,
        "runtime_mode": runtime_mode,
    }


def _infer_problem_type_for_heavy(
    contract: Dict[str, Any],
    evaluation_spec: Dict[str, Any],
    data_profile: Dict[str, Any],
    target_col: str,
) -> str:
    objective_hints: List[str] = []
    if isinstance(evaluation_spec, dict):
        objective = evaluation_spec.get("objective_type")
        if objective:
            objective_hints.append(str(objective))
    if isinstance(contract, dict):
        objective = contract.get("objective_type")
        if objective:
            objective_hints.append(str(objective))
        contract_eval = contract.get("evaluation_spec")
        if isinstance(contract_eval, dict):
            objective = contract_eval.get("objective_type")
            if objective:
                objective_hints.append(str(objective))

    objective_norm = " ".join(objective_hints).lower()
    if any(token in objective_norm for token in ("classification", "classifier", "binary", "multiclass")):
        return "classification"
    if any(token in objective_norm for token in ("regression", "forecast", "timeseries")):
        return "regression"

    metrics: List[str] = []
    validation = contract.get("validation_requirements") if isinstance(contract, dict) else {}
    if isinstance(validation, dict):
        primary = validation.get("primary_metric")
        if primary:
            metrics.append(str(primary))
        metrics.extend([str(m) for m in (validation.get("metrics_to_report") or []) if m])
    if isinstance(evaluation_spec, dict):
        metrics.extend([str(m) for m in (evaluation_spec.get("metrics_to_report") or []) if m])
        if evaluation_spec.get("primary_metric"):
            metrics.append(str(evaluation_spec.get("primary_metric")))
    metrics_norm = {_normalize_metric_key(m) for m in metrics if m}
    cls_metric_tokens = (
        "accuracy",
        "rocauc",
        "auc",
        "f1",
        "precision",
        "recall",
        "balancedaccuracy",
        "logloss",
        "averageprecision",
        "prauc",
        "brierscore",
        "gini",
        "normalizedgini",
        "lift",
    )
    reg_metric_tokens = ("rmse", "mse", "mae", "r2", "rmsle", "mape", "smape")
    if any(any(tok in metric for tok in cls_metric_tokens) for metric in metrics_norm):
        return "classification"
    if any(any(tok in metric for tok in reg_metric_tokens) for metric in metrics_norm):
        return "regression"
    target_stats = (data_profile or {}).get("numeric_summary", {}).get(target_col) if target_col else None
    if isinstance(target_stats, dict):
        n_unique = target_stats.get("n_unique") or target_stats.get("unique")
        try:
            n_unique_val = int(n_unique)
            if n_unique_val <= 20:
                return "classification"
        except Exception:
            pass
    return "regression"


def _resolve_heavy_feature_columns(
    column_inventory: List[str],
    column_sets: Dict[str, Any],
    roles: Dict[str, List[str]],
    target_col: str,
) -> List[str]:
    features: List[str] = []
    if column_sets and column_inventory:
        expanded = expand_column_sets(column_inventory, column_sets)
        if isinstance(expanded, dict):
            features = [str(c) for c in (expanded.get("expanded_feature_columns") or []) if c]
    if not features and roles:
        features = [str(c) for c in (roles.get("pre_decision") or []) if c]
    if not features:
        features = [str(c) for c in column_inventory if c]
    filtered = [c for c in features if c and c != target_col and c != "__split"]
    return list(dict.fromkeys(filtered))


def _safe_float(value: Any, default: float = 0.0) -> float:
    try:
        if value is None:
            return default
        return float(value)
    except Exception:
        return default


def _safe_int(value: Any, default: int = 0) -> int:
    try:
        if value is None:
            return default
        return int(value)
    except Exception:
        return default


def _clamp_int(value: int, lower: int, upper: int) -> int:
    if value < lower:
        return lower
    if value > upper:
        return upper
    return value


def _detect_max_int_assignment(code: str, key: str) -> int:
    if not code or not key:
        return 0
    pattern = rf"{re.escape(key)}\s*=\s*(\d+)"
    matches = re.findall(pattern, code, flags=re.IGNORECASE)
    values: List[int] = []
    for item in matches:
        try:
            values.append(int(item))
        except Exception:
            continue
    return max(values) if values else 0


def _contains_any_pattern(code: str, patterns: List[str]) -> bool:
    if not code:
        return False
    lower = code.lower()
    return any(str(pattern).lower() in lower for pattern in patterns if pattern)


def _infer_cv_folds_for_timeout(code: str, ml_plan: Dict[str, Any] | None = None) -> int:
    if isinstance(ml_plan, dict):
        cv_policy = ml_plan.get("cv_policy")
        if isinstance(cv_policy, dict):
            folds = _safe_int(cv_policy.get("n_splits"), 0)
            if folds > 0:
                return _clamp_int(folds, 1, 20)
    folds_detected = _detect_max_int_assignment(code or "", "n_splits")
    if folds_detected > 0:
        return _clamp_int(folds_detected, 1, 20)
    return 1


def _estimate_heavy_script_timeout(
    *,
    stage: str,
    code: str,
    state: Dict[str, Any],
    ml_plan: Dict[str, Any] | None = None,
    configured_timeout_seconds: int | None = None,
) -> Dict[str, Any]:
    """
    Estimate script timeout with generous headroom from script + dataset context.

    The model keeps full reasoning freedom; timeout is adapted post-generation.
    """
    stage_norm = str(stage or "ml_engineer").strip().lower()
    hints = state.get("dataset_scale_hints") or {}
    dataset_scale = str(hints.get("scale") or state.get("dataset_scale") or "unknown").strip().lower()
    est_rows = _safe_int(hints.get("est_rows"), 0)
    n_cols = _safe_int(hints.get("cols") or hints.get("n_cols"), 0)
    file_mb = _safe_float(hints.get("file_mb"), 0.0)

    # Stage-aware baseline (seconds): intentionally conservative.
    if stage_norm == "data_engineer":
        base_seconds = 1500
        if dataset_scale == "medium":
            base_seconds = 2100
        elif dataset_scale == "large":
            base_seconds = 3000
    else:
        base_seconds = 1800
        if dataset_scale == "medium":
            base_seconds = 3000
        elif dataset_scale == "large":
            base_seconds = 4200

    complexity_bonus = 0
    tags: List[str] = []

    if est_rows >= 300_000:
        complexity_bonus += 600
        tags.append("rows_ge_300k")
    if est_rows >= 800_000:
        complexity_bonus += 900
        tags.append("rows_ge_800k")
    if n_cols >= 200:
        complexity_bonus += 240
        tags.append("cols_ge_200")
    if n_cols >= 500:
        complexity_bonus += 360
        tags.append("cols_ge_500")
    if file_mb >= 250:
        complexity_bonus += 420
        tags.append("file_mb_ge_250")
    if file_mb >= 700:
        complexity_bonus += 600
        tags.append("file_mb_ge_700")

    folds = _infer_cv_folds_for_timeout(code, ml_plan=ml_plan)
    if folds > 1:
        complexity_bonus += (folds - 1) * 240
        tags.append(f"cv_folds_{folds}")

    if _contains_any_pattern(code, ["gridsearchcv", "randomizedsearchcv", "optuna", "hyperopt"]):
        complexity_bonus += 1500
        tags.append("hpo_detected")
    if _contains_any_pattern(code, ["cross_val_score(", "cross_validate("]):
        complexity_bonus += 360
        tags.append("cross_validation_api_detected")
    if _contains_any_pattern(code, ["isotonicregression", "calibratedclassifiercv"]):
        complexity_bonus += 300
        tags.append("calibration_detected")
    if _contains_any_pattern(code, ["import shap", "shap."]):
        complexity_bonus += 1500
        tags.append("shap_detected")
    if _contains_any_pattern(code, ["shap_values(", "explainer.shap_values("]):
        complexity_bonus += 720
        tags.append("shap_value_compute_detected")

    max_estimators = _detect_max_int_assignment(code, "n_estimators")
    if max_estimators >= 500:
        complexity_bonus += 300
        tags.append("n_estimators_ge_500")
    if max_estimators >= 1000:
        complexity_bonus += 600
        tags.append("n_estimators_ge_1000")
    if max_estimators >= 2000:
        complexity_bonus += 900
        tags.append("n_estimators_ge_2000")

    if _contains_any_pattern(code, ["lightgbm", "xgboost"]):
        complexity_bonus += 240
        tags.append("boosting_detected")

    raw_estimate = base_seconds + complexity_bonus
    margin_multiplier = _safe_float(os.getenv("HEAVY_RUNNER_TIMEOUT_MARGIN_MULTIPLIER"), 1.45)
    margin_multiplier = max(1.0, margin_multiplier)
    margin_seconds = _safe_int(os.getenv("HEAVY_RUNNER_TIMEOUT_MARGIN_SECONDS"), 900)
    estimated = int(round(raw_estimate * margin_multiplier)) + max(0, margin_seconds)

    runtime_mode = _get_execution_runtime_mode()
    if runtime_mode == "local":
        default_min = 1800 if stage_norm == "data_engineer" else 3600
        min_timeout = _safe_int(
            os.getenv("LOCAL_RUNNER_SCRIPT_TIMEOUT_MIN_SECONDS")
            or os.getenv("HEAVY_RUNNER_SCRIPT_TIMEOUT_MIN_SECONDS"),
            default_min,
        )
        max_timeout = _safe_int(
            os.getenv("LOCAL_RUNNER_SCRIPT_TIMEOUT_MAX_SECONDS")
            or os.getenv("HEAVY_RUNNER_SCRIPT_TIMEOUT_MAX_SECONDS"),
            43200,
        )
    else:
        default_min = 1200 if stage_norm == "data_engineer" else 2400
        min_timeout = _safe_int(os.getenv("HEAVY_RUNNER_SCRIPT_TIMEOUT_MIN_SECONDS"), default_min)
        max_timeout = _safe_int(os.getenv("HEAVY_RUNNER_SCRIPT_TIMEOUT_MAX_SECONDS"), 7200)
    if max_timeout <= 0:
        max_timeout = 7200
    if min_timeout <= 0:
        min_timeout = default_min
    if max_timeout < min_timeout:
        max_timeout = min_timeout

    timeout = _clamp_int(estimated, min_timeout, max_timeout)
    configured = _safe_int(configured_timeout_seconds, 0)
    if configured > 0:
        timeout = _clamp_int(max(timeout, configured), min_timeout, max_timeout)
        tags.append("configured_timeout_floor")

    return {
        "timeout_seconds": int(timeout),
        "estimated_seconds_before_clamp": int(estimated),
        "raw_estimate_seconds": int(raw_estimate),
        "base_seconds": int(base_seconds),
        "complexity_bonus_seconds": int(complexity_bonus),
        "min_timeout_seconds": int(min_timeout),
        "max_timeout_seconds": int(max_timeout),
        "margin_multiplier": float(margin_multiplier),
        "margin_seconds": int(max(0, margin_seconds)),
        "dataset_scale": dataset_scale,
        "est_rows": int(est_rows),
        "n_cols": int(n_cols),
        "file_mb": float(file_mb),
        "cv_folds": int(folds),
        "max_detected_n_estimators": int(max_estimators),
        "stage": stage_norm,
        "tags": tags,
    }


def _dtype_bytes_estimate(dtype_name: str) -> float:
    dtype = str(dtype_name or "").strip().lower()
    if not dtype:
        return 16.0
    if "float16" in dtype:
        return 2.0
    if "float32" in dtype or "int32" in dtype or "uint32" in dtype:
        return 4.0
    if "float64" in dtype or "int64" in dtype or "uint64" in dtype:
        return 8.0
    if "int16" in dtype or "uint16" in dtype:
        return 2.0
    if "int8" in dtype or "uint8" in dtype or "bool" in dtype:
        return 1.0
    if "datetime" in dtype or "timedelta" in dtype:
        return 8.0
    if "category" in dtype:
        return 8.0
    if "string" in dtype or "object" in dtype:
        # Conservative estimate for Python objects + pointers.
        return 96.0
    return 24.0


def _downgrade_confidence(label: str) -> str:
    val = str(label or "").strip().lower()
    if val == "high":
        return "medium"
    if val == "medium":
        return "low"
    return "low"


def _infer_column_count_from_state(state: Dict[str, Any], hints: Dict[str, Any]) -> int:
    candidates: List[int] = []

    hint_cols = _safe_int((hints or {}).get("cols") or (hints or {}).get("n_cols"), 0)
    if hint_cols > 0:
        candidates.append(hint_cols)

    inventory = state.get("column_inventory")
    if isinstance(inventory, list) and inventory:
        candidates.append(len(inventory))
    else:
        inv = _load_json_safe("data/column_inventory.json")
        if isinstance(inv, dict):
            cols = inv.get("columns") or inv.get("column_inventory")
            if isinstance(cols, list) and cols:
                candidates.append(len(cols))

    contract = state.get("execution_contract")
    if isinstance(contract, dict):
        canonical = contract.get("canonical_columns")
        if isinstance(canonical, list) and canonical:
            candidates.append(len(canonical))

    csv_path = state.get("ml_data_path")
    if isinstance(csv_path, str) and csv_path and os.path.exists(csv_path):
        try:
            sep = state.get("csv_sep") or ","
            decimal = state.get("csv_decimal") or "."
            encoding = state.get("csv_encoding") or "utf-8"
            header = pd.read_csv(csv_path, nrows=0, sep=sep, decimal=decimal, encoding=encoding)
            if hasattr(header, "columns"):
                header_cols = len(list(header.columns))
                if header_cols > 0:
                    candidates.append(header_cols)
        except Exception:
            pass

    return max(candidates) if candidates else 0


def _estimate_dataframe_memory_gb(
    data_profile: Dict[str, Any],
    state: Dict[str, Any],
) -> Dict[str, Any]:
    profile = data_profile if isinstance(data_profile, dict) else {}
    hints = state.get("dataset_scale_hints") or {}
    basic = profile.get("basic_stats") if isinstance(profile.get("basic_stats"), dict) else {}
    dtypes = profile.get("dtypes") if isinstance(profile.get("dtypes"), dict) else {}

    sampling = profile.get("sampling") if isinstance(profile.get("sampling"), dict) else {}
    profile_rows = _safe_int(basic.get("n_rows"), 0)
    hint_rows = _safe_int(hints.get("est_rows"), 0)
    sampling_rows = 0
    if sampling.get("was_sampled"):
        sampling_rows = _safe_int(sampling.get("total_rows_in_file"), 0)

    row_candidates: List[tuple[str, int]] = []
    if profile_rows > 0:
        row_candidates.append(("profile_basic_stats", profile_rows))
    if sampling_rows > 0:
        row_candidates.append(("profile_sampling_total", sampling_rows))
    if hint_rows > 0:
        row_candidates.append(("dataset_scale_hint", hint_rows))

    row_source = "none"
    n_rows = 0
    if row_candidates:
        row_source, n_rows = max(row_candidates, key=lambda item: item[1])

    n_cols = _safe_int(basic.get("n_cols"), 0)
    col_source = "profile_basic_stats" if n_cols > 0 else "none"
    if n_cols <= 0:
        basic_cols = basic.get("columns")
        if isinstance(basic_cols, list) and basic_cols:
            n_cols = len(basic_cols)
            col_source = "profile_columns"
    if n_cols <= 0 and isinstance(dtypes, dict) and dtypes:
        n_cols = len(dtypes)
        col_source = "profile_dtypes"
    if n_cols <= 0:
        hint_cols = _safe_int(hints.get("cols") or hints.get("n_cols"), 0)
        if hint_cols > 0:
            n_cols = hint_cols
            col_source = "dataset_scale_hint"
    if n_cols <= 0:
        inferred_cols = _infer_column_count_from_state(state, hints)
        if inferred_cols > 0:
            n_cols = inferred_cols
            col_source = "state_inventory_or_header"

    if n_rows <= 0 and n_cols <= 0:
        return {
            "available": False,
            "n_rows": 0,
            "n_cols": 0,
            "raw_df_gb": None,
            "bytes_per_row": None,
            "dtype_confidence": "none",
            "row_source": row_source,
            "col_source": col_source,
            "profile_sampled": bool(sampling.get("was_sampled")),
        }

    object_cols = 0
    if isinstance(dtypes, dict) and dtypes:
        bytes_per_row = 0.0
        for _, dtype_name in dtypes.items():
            dtype = str(dtype_name or "").lower()
            if "object" in dtype or "string" in dtype:
                object_cols += 1
            bytes_per_row += _dtype_bytes_estimate(dtype_name)
        known_cols = len(dtypes)
        if known_cols > 0 and n_cols > known_cols:
            avg_bytes = bytes_per_row / float(max(known_cols, 1))
            bytes_per_row += float(n_cols - known_cols) * avg_bytes
            object_ratio = float(object_cols) / float(max(known_cols, 1))
            object_cols = int(round(object_ratio * n_cols))
            dtype_confidence = "medium"
        else:
            dtype_confidence = "high"
    else:
        # Unknown dtypes: assume mixed schema with overhead.
        bytes_per_row = max(n_cols, 1) * 24.0
        dtype_confidence = "low"

    if bool(sampling.get("was_sampled")):
        dtype_confidence = _downgrade_confidence(dtype_confidence)
    if row_source != "profile_basic_stats":
        dtype_confidence = _downgrade_confidence(dtype_confidence)
    if col_source not in {"profile_basic_stats", "profile_columns", "profile_dtypes"}:
        dtype_confidence = _downgrade_confidence(dtype_confidence)

    # Index overhead + object overhead adjustment.
    index_bytes = max(n_rows, 1) * 8.0
    object_extra_bytes = max(n_rows, 1) * object_cols * 24.0
    raw_bytes = (max(n_rows, 1) * bytes_per_row) + index_bytes + object_extra_bytes
    raw_df_gb = raw_bytes / float(1024 ** 3)
    return {
        "available": True,
        "n_rows": int(max(n_rows, 1)),
        "n_cols": int(max(n_cols, 1)),
        "object_cols": int(object_cols),
        "bytes_per_row": float(bytes_per_row),
        "raw_df_gb": float(raw_df_gb),
        "dtype_confidence": dtype_confidence,
        "row_source": row_source,
        "col_source": col_source,
        "profile_sampled": bool(sampling.get("was_sampled")),
    }


def _estimate_e2b_peak_memory_gb(
    state: Dict[str, Any],
    data_profile: Dict[str, Any],
    ml_plan: Dict[str, Any],
) -> Dict[str, Any]:
    df_est = _estimate_dataframe_memory_gb(data_profile, state)
    if not df_est.get("available"):
        return {
            "available": False,
            "estimated_peak_gb": None,
            "confidence": "low",
            "reason": "insufficient_profile",
        }

    raw_df_gb = _safe_float(df_est.get("raw_df_gb"), 0.0)
    n_rows = _safe_int(df_est.get("n_rows"), 0)
    n_cols = _safe_int(df_est.get("n_cols"), 0)
    object_cols = _safe_int(df_est.get("object_cols"), 0)

    cv_policy = (ml_plan or {}).get("cv_policy") if isinstance(ml_plan, dict) else {}
    folds = _safe_int(cv_policy.get("n_splits"), 0) if isinstance(cv_policy, dict) else 0

    # Conservative multipliers to protect E2B 8GB ceiling.
    prep_mult = 2.0
    if n_rows >= 1_000_000:
        prep_mult += 0.2
    if n_cols >= 250:
        prep_mult += 0.2
    if object_cols > 0:
        prep_mult += min(0.4, 0.05 * object_cols)

    cv_mult = 1.0 + min(0.45, max(0, folds - 1) * 0.09)

    # Generic modeling overhead (materialized matrices, estimator memory, serializations).
    modeling_overhead_gb = 0.65
    if n_rows >= 1_000_000:
        modeling_overhead_gb += 0.85
    if n_cols >= 400:
        modeling_overhead_gb += 0.5

    estimated_peak_gb = (raw_df_gb * prep_mult * cv_mult) + modeling_overhead_gb
    if estimated_peak_gb < raw_df_gb:
        estimated_peak_gb = raw_df_gb + 0.5

    confidence = str(df_est.get("dtype_confidence") or "low")
    return {
        "available": True,
        "estimated_peak_gb": float(estimated_peak_gb),
        "confidence": confidence,
        "folds": int(folds),
        "prep_mult": float(prep_mult),
        "cv_mult": float(cv_mult),
        "modeling_overhead_gb": float(modeling_overhead_gb),
        "raw_df_gb": float(raw_df_gb),
        "n_rows": int(n_rows),
        "n_cols": int(n_cols),
        "object_cols": int(object_cols),
        "row_source": str(df_est.get("row_source") or "none"),
        "col_source": str(df_est.get("col_source") or "none"),
        "profile_sampled": bool(df_est.get("profile_sampled")),
    }


def _build_backend_memory_decision(
    state: Dict[str, Any],
    data_profile: Dict[str, Any],
    ml_plan: Dict[str, Any],
) -> Dict[str, Any]:
    estimate = _estimate_e2b_peak_memory_gb(state, data_profile, ml_plan)
    e2b_limit_gb = _safe_float(os.getenv("E2B_MEMORY_LIMIT_GB"), 8.0)
    safe_fraction = _safe_float(os.getenv("E2B_MEMORY_SAFE_FRACTION"), 0.72)
    min_margin_gb = _safe_float(os.getenv("E2B_MEMORY_MIN_MARGIN_GB"), 1.5)
    safe_budget_gb = min(e2b_limit_gb * safe_fraction, max(0.1, e2b_limit_gb - min_margin_gb))

    hints = state.get("dataset_scale_hints") or {}
    file_mb = _safe_float(hints.get("file_mb"), 0.0)
    est_rows = _safe_int(hints.get("est_rows"), 0)
    n_cols_hint = _safe_int(hints.get("cols") or hints.get("n_cols"), 0)
    heavy_size_signal = bool(file_mb >= 200 or est_rows >= 1_000_000 or n_cols_hint >= 1000)

    if state.get("e2b_memory_failure_detected"):
        return {
            "use_heavy": True,
            "reason": "e2b_memory_failure_fallback",
            "safe_budget_gb": safe_budget_gb,
            "e2b_limit_gb": e2b_limit_gb,
            "estimate": estimate,
        }

    if estimate.get("available"):
        peak_gb = _safe_float(estimate.get("estimated_peak_gb"), 0.0)
        confidence = str(estimate.get("confidence") or "low").strip().lower()
        sampled_profile = bool(estimate.get("profile_sampled"))
        row_source = str(estimate.get("row_source") or "none").strip().lower()
        col_source = str(estimate.get("col_source") or "none").strip().lower()
        large_uncertain_estimate = bool(
            heavy_size_signal
            and (
                confidence in {"low", "medium"}
                or sampled_profile
                or row_source != "profile_basic_stats"
                or col_source not in {"profile_basic_stats", "profile_columns", "profile_dtypes"}
            )
        )
        if large_uncertain_estimate:
            return {
                "use_heavy": True,
                "reason": "large_dataset_uncertain_memory_estimate",
                "safe_budget_gb": safe_budget_gb,
                "e2b_limit_gb": e2b_limit_gb,
                "estimate": estimate,
            }
        if peak_gb <= safe_budget_gb:
            return {
                "use_heavy": False,
                "reason": "e2b_memory_safe",
                "safe_budget_gb": safe_budget_gb,
                "e2b_limit_gb": e2b_limit_gb,
                "estimate": estimate,
            }
        return {
            "use_heavy": True,
            "reason": "est_memory_exceeds_e2b_safe",
            "safe_budget_gb": safe_budget_gb,
            "e2b_limit_gb": e2b_limit_gb,
            "estimate": estimate,
        }

    if heavy_size_signal:
        return {
            "use_heavy": True,
            "reason": "memory_uncertain_guard",
            "safe_budget_gb": safe_budget_gb,
            "e2b_limit_gb": e2b_limit_gb,
            "estimate": estimate,
        }
    return {
        "use_heavy": False,
        "reason": "e2b_default",
        "safe_budget_gb": safe_budget_gb,
        "e2b_limit_gb": e2b_limit_gb,
        "estimate": estimate,
    }


def _is_memory_pressure_error(text: str) -> bool:
    if not text:
        return False
    lower = str(text).lower()
    patterns = [
        "out of memory",
        "memoryerror",
        "cannot allocate memory",
        "resource exhausted",
        "oom",
        "killed",
        "exit code 137",
        "sigkill",
        "std::bad_alloc",
    ]
    return any(pat in lower for pat in patterns)


def _should_use_heavy_runner(
    state: Dict[str, Any],
    data_profile: Dict[str, Any],
    ml_plan: Dict[str, Any],
) -> tuple[bool, str]:
    if state.get("heavy_runner_unavailable"):
        return False, "unavailable"
    if _env_flag("HEAVY_RUNNER_FORCE", False):
        return True, "forced"
    memory_decision = _build_backend_memory_decision(state, data_profile, ml_plan)
    state["backend_memory_estimate"] = memory_decision
    return bool(memory_decision.get("use_heavy")), str(memory_decision.get("reason") or "unknown")


def _resolve_ml_backend_selection(state: Dict[str, Any]) -> Dict[str, Any]:
    heavy_cfg = _get_heavy_runner_config()
    runtime_mode = _get_execution_runtime_mode()
    contract, _contract_min = _resolve_contract_pair_from_state(state if isinstance(state, dict) else {})
    required_deps = contract.get("required_dependencies", []) if isinstance(contract, dict) else []
    heavy_deps_required = requires_cloudrun_backend(required_deps)
    generated_code = str(state.get("generated_code") or "")
    heavy_imports_in_code = cloudrun_imports_from_code(generated_code)
    heavy_deps_from_code = bool(heavy_imports_in_code)
    ml_plan = state.get("ml_plan")
    if not isinstance(ml_plan, dict) or not ml_plan:
        loaded_plan = _load_json_safe("data/ml_plan.json")
        ml_plan = loaded_plan if isinstance(loaded_plan, dict) else {}
    data_profile = state.get("data_profile")
    if not isinstance(data_profile, dict):
        data_profile = {}
    use_heavy = bool(heavy_cfg)
    if runtime_mode == "local" and heavy_cfg:
        reason = "local_runner_mode"
    elif heavy_cfg:
        reason = "cloudrun_only_mode"
    elif heavy_deps_from_code:
        reason = "cloudrun_required_by_script_imports_but_unavailable"
    elif heavy_deps_required:
        reason = "cloudrun_required_by_dependencies_but_unavailable"
    else:
        reason = "cloudrun_config_missing"
    backend_profile = "local" if runtime_mode == "local" else "cloudrun"
    return {
        "heavy_cfg": heavy_cfg,
        "runtime_mode": runtime_mode,
        "use_heavy": bool(use_heavy),
        "reason": reason,
        "backend_profile": backend_profile,
        "heavy_deps_required": bool(heavy_deps_required),
        "heavy_deps_from_code": bool(heavy_deps_from_code),
        "heavy_imports_in_code": list(heavy_imports_in_code),
        "ml_plan": ml_plan,
        "data_profile": data_profile,
    }


def _parse_memory_gb_hint(raw_value: Any) -> float | None:
    if raw_value is None:
        return None
    text = str(raw_value).strip().lower()
    if not text:
        return None
    mult = 1.0
    if text.endswith("gi"):
        text = text[:-2]
    elif text.endswith("gib"):
        text = text[:-3]
    elif text.endswith("gb"):
        text = text[:-2]
    elif text.endswith("mi"):
        text = text[:-2]
        mult = 1.0 / 1024.0
    elif text.endswith("mib"):
        text = text[:-3]
        mult = 1.0 / 1024.0
    elif text.endswith("mb"):
        text = text[:-2]
        mult = 1.0 / 1024.0
    try:
        parsed = float(text)
    except Exception:
        return None
    if parsed <= 0:
        return None
    return round(parsed * mult, 3)


def _read_int_env_hint(*names: str) -> int | None:
    for name in names:
        raw = os.getenv(name)
        if raw is None:
            continue
        try:
            parsed = int(str(raw).strip())
            if parsed > 0:
                return parsed
        except Exception:
            continue
    return None


def _read_memory_env_hint(*names: str) -> float | None:
    for name in names:
        raw = os.getenv(name)
        if raw is None:
            continue
        parsed = _parse_memory_gb_hint(raw)
        if parsed and parsed > 0:
            return parsed
    return None


def _estimate_local_host_memory_gb() -> float | None:
    try:
        import psutil  # type: ignore

        total = float(psutil.virtual_memory().total)
        if total > 0:
            return round(total / float(1024 ** 3), 3)
    except Exception:
        pass
    try:
        if hasattr(os, "sysconf"):
            page_size = float(os.sysconf("SC_PAGE_SIZE"))
            phys_pages = float(os.sysconf("SC_PHYS_PAGES"))
            total = page_size * phys_pages
            if total > 0:
                return round(total / float(1024 ** 3), 3)
    except Exception:
        pass
    return None


def _build_ml_execution_profile_for_prompt(
    state: Dict[str, Any],
    *,
    code: str = "",
    ml_plan: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    """
    Build runtime-context profile for ML Engineer and reviewers.
    This profile is advisory context only and never mutates the execution contract.
    """
    state = state if isinstance(state, dict) else {}
    backend_selection = _resolve_ml_backend_selection(state)
    heavy_cfg = backend_selection.get("heavy_cfg") if isinstance(backend_selection.get("heavy_cfg"), dict) else {}
    runtime_mode = str(backend_selection.get("runtime_mode") or _get_execution_runtime_mode())
    hints = state.get("dataset_scale_hints") if isinstance(state.get("dataset_scale_hints"), dict) else {}
    timeout_decision = _estimate_heavy_script_timeout(
        stage="ml_engineer",
        code=str(code or ""),
        state=state,
        ml_plan=ml_plan if isinstance(ml_plan, dict) else None,
        configured_timeout_seconds=heavy_cfg.get("script_timeout_seconds") if isinstance(heavy_cfg, dict) else None,
    )
    # Keep backend taxonomy stable for downstream prompts/tests:
    # local runner mirrors heavy/cloudrun semantics (same artifact contract),
    # so expose backend as cloudrun and carry runtime_mode separately.
    backend = "cloudrun" if runtime_mode == "local" else ("cloudrun" if bool(backend_selection.get("use_heavy")) else "e2b")
    cpu_hint = _read_int_env_hint(
        "HEAVY_RUNNER_CPU_HINT",
        "HEAVY_RUNNER_CPU",
        "CLOUDRUN_JOB_CPU",
        "CLOUD_RUN_CPU",
    )
    memory_gb_hint = _read_memory_env_hint(
        "HEAVY_RUNNER_MEMORY_GB_HINT",
        "HEAVY_RUNNER_MEMORY_GB",
        "HEAVY_RUNNER_MEMORY",
        "CLOUDRUN_JOB_MEMORY",
        "CLOUD_RUN_MEMORY",
    )
    resource_source = "env_hints"
    if runtime_mode == "local":
        if cpu_hint is None:
            cpu_hint = os.cpu_count() or None
        if memory_gb_hint is None:
            memory_gb_hint = _estimate_local_host_memory_gb()
        resource_source = "local_host"
    elif backend == "cloudrun":
        # Keep infrastructure context actionable even when env hints are absent.
        # Defaults match heavy-runner deploy defaults and remain advisory-only.
        if cpu_hint is None:
            cpu_hint = _safe_int(os.getenv("HEAVY_RUNNER_DEFAULT_CPU"), 0)
            if cpu_hint <= 0:
                cpu_hint = 8
        if memory_gb_hint is None:
            memory_gb_hint = _parse_memory_gb_hint(
                os.getenv("HEAVY_RUNNER_DEFAULT_MEMORY_GB")
                or os.getenv("HEAVY_RUNNER_DEFAULT_MEMORY")
                or "32Gi"
            )
            if memory_gb_hint is None or memory_gb_hint <= 0:
                memory_gb_hint = 32.0
        if (
            os.getenv("HEAVY_RUNNER_CPU_HINT") is None
            and os.getenv("HEAVY_RUNNER_CPU") is None
            and os.getenv("CLOUDRUN_JOB_CPU") is None
            and os.getenv("CLOUD_RUN_CPU") is None
            and os.getenv("HEAVY_RUNNER_MEMORY_GB_HINT") is None
            and os.getenv("HEAVY_RUNNER_MEMORY_GB") is None
            and os.getenv("HEAVY_RUNNER_MEMORY") is None
            and os.getenv("CLOUDRUN_JOB_MEMORY") is None
            and os.getenv("CLOUD_RUN_MEMORY") is None
        ):
            resource_source = "cloudrun_defaults"
    else:
        resource_source = "env_hints_or_unknown"
    return {
        "backend": backend,
        "runtime_mode": runtime_mode,
        "selection_reason": str(backend_selection.get("reason") or "unknown"),
        "dataset_scale": str(hints.get("scale") or state.get("dataset_scale") or "unknown"),
        "dataset_estimate": {
            "est_rows": _safe_int(hints.get("est_rows"), 0),
            "file_mb": round(_safe_float(hints.get("file_mb"), 0.0), 3),
            "n_cols": _safe_int(hints.get("cols") or hints.get("n_cols"), 0),
        },
        "resources": {
            "cpu_hint": cpu_hint,
            "memory_gb_hint": memory_gb_hint,
            "source": resource_source,
        },
        "runtime_budget": {
            "hard_timeout_seconds": _safe_int(timeout_decision.get("timeout_seconds"), 0),
            "estimated_seconds_before_clamp": _safe_int(timeout_decision.get("estimated_seconds_before_clamp"), 0),
            "cv_folds": _safe_int(timeout_decision.get("cv_folds"), 0),
            "max_detected_n_estimators": _safe_int(timeout_decision.get("max_detected_n_estimators"), 0),
            "complexity_tags": timeout_decision.get("tags") if isinstance(timeout_decision.get("tags"), list) else [],
        },
        "objective": "optimize business KPI under runtime budget; prefer robust completion over timeout risk",
        "adaptation_order": [
            "bound_search_space",
            "bound_cv_cost",
            "bound_model_complexity",
            "bound_train_rows",
        ],
    }


def _build_de_backend_memory_decision(
    state: Dict[str, Any],
    required_cols_count: int = 0,
    total_cols_count: int = 0,
) -> Dict[str, Any]:
    hints = state.get("dataset_scale_hints") or {}
    file_mb = _safe_float(hints.get("file_mb"), 0.0)
    est_rows = _safe_int(hints.get("est_rows"), 0)
    n_cols = _safe_int(hints.get("cols") or hints.get("n_cols"), 0)
    if total_cols_count > 0:
        n_cols = max(n_cols, _safe_int(total_cols_count, 0))
    if n_cols <= 0:
        n_cols = max(0, _safe_int(required_cols_count, 0))

    e2b_limit_gb = _safe_float(os.getenv("E2B_MEMORY_LIMIT_GB"), 8.0)
    safe_fraction = _safe_float(os.getenv("E2B_MEMORY_SAFE_FRACTION"), 0.72)
    min_margin_gb = _safe_float(os.getenv("E2B_MEMORY_MIN_MARGIN_GB"), 1.5)
    safe_budget_gb = min(e2b_limit_gb * safe_fraction, max(0.1, e2b_limit_gb - min_margin_gb))

    bytes_per_cell = _safe_float(os.getenv("DE_STRING_BYTES_PER_CELL"), 48.0)
    working_mult = _safe_float(os.getenv("DE_E2B_WORKING_MULT"), 2.2)
    base_overhead_gb = _safe_float(os.getenv("DE_E2B_BASE_OVERHEAD_GB"), 0.8)

    raw_df_gb = None
    estimated_peak_gb = None
    if est_rows > 0 and n_cols > 0:
        raw_bytes = float(est_rows) * float(n_cols) * max(bytes_per_cell, 8.0)
        raw_df_gb = raw_bytes / float(1024 ** 3)
        estimated_peak_gb = (raw_df_gb * max(working_mult, 1.0)) + max(base_overhead_gb, 0.0)
        if file_mb >= 200:
            estimated_peak_gb += 0.5

    large_signal = bool(file_mb >= 200 or est_rows >= 800_000 or n_cols >= 1_000)
    medium_signal = bool(file_mb >= 50 or est_rows >= 200_000)
    if state.get("de_e2b_memory_failure_detected"):
        return {
            "use_heavy": True,
            "reason": "e2b_memory_failure_fallback",
            "safe_budget_gb": safe_budget_gb,
            "e2b_limit_gb": e2b_limit_gb,
            "estimated_peak_gb": estimated_peak_gb,
            "raw_df_gb": raw_df_gb,
            "file_mb": file_mb,
            "est_rows": est_rows,
            "n_cols": n_cols,
        }

    if estimated_peak_gb is not None:
        if estimated_peak_gb <= safe_budget_gb:
            return {
                "use_heavy": False,
                "reason": "e2b_memory_safe_de",
                "safe_budget_gb": safe_budget_gb,
                "e2b_limit_gb": e2b_limit_gb,
                "estimated_peak_gb": estimated_peak_gb,
                "raw_df_gb": raw_df_gb,
                "file_mb": file_mb,
                "est_rows": est_rows,
                "n_cols": n_cols,
            }
        return {
            "use_heavy": True,
            "reason": "de_est_memory_exceeds_e2b_safe",
            "safe_budget_gb": safe_budget_gb,
            "e2b_limit_gb": e2b_limit_gb,
            "estimated_peak_gb": estimated_peak_gb,
            "raw_df_gb": raw_df_gb,
            "file_mb": file_mb,
            "est_rows": est_rows,
            "n_cols": n_cols,
        }

    if large_signal:
        return {
            "use_heavy": True,
            "reason": "de_memory_uncertain_guard",
            "safe_budget_gb": safe_budget_gb,
            "e2b_limit_gb": e2b_limit_gb,
            "estimated_peak_gb": None,
            "raw_df_gb": raw_df_gb,
            "file_mb": file_mb,
            "est_rows": est_rows,
            "n_cols": n_cols,
        }
    if medium_signal:
        return {
            "use_heavy": False,
            "reason": "de_e2b_preferred_medium_scale",
            "safe_budget_gb": safe_budget_gb,
            "e2b_limit_gb": e2b_limit_gb,
            "estimated_peak_gb": None,
            "raw_df_gb": raw_df_gb,
            "file_mb": file_mb,
            "est_rows": est_rows,
            "n_cols": n_cols,
        }
    return {
        "use_heavy": False,
        "reason": "de_e2b_default",
        "safe_budget_gb": safe_budget_gb,
        "e2b_limit_gb": e2b_limit_gb,
        "estimated_peak_gb": None,
        "raw_df_gb": raw_df_gb,
        "file_mb": file_mb,
        "est_rows": est_rows,
        "n_cols": n_cols,
    }


def _should_use_heavy_runner_for_data_engineer(
    state: Dict[str, Any],
    required_cols_count: int = 0,
    total_cols_count: int = 0,
) -> tuple[bool, str]:
    if state.get("heavy_runner_unavailable"):
        return False, "unavailable"
    if not _env_flag("HEAVY_RUNNER_DE_ENABLED", True):
        return False, "disabled"
    if _env_flag("HEAVY_RUNNER_FORCE_DE", False) or _env_flag("HEAVY_RUNNER_FORCE", False):
        return True, "forced"
    if state.get("de_force_heavy_runner"):
        return True, "forced_retry"
    decision = _build_de_backend_memory_decision(
        state,
        required_cols_count=required_cols_count,
        total_cols_count=total_cols_count,
    )
    state["de_backend_memory_estimate"] = decision
    return bool(decision.get("use_heavy")), str(decision.get("reason") or "unknown")


def _detect_de_heavy_runner_protocol_mismatch(
    request_mode: Any,
    error_payload: Any,
    downloaded: Dict[str, Any],
    heavy_log_text: str,
    expected_outputs: Optional[List[str]] = None,
) -> bool:
    """Detect stale heavy-runner behavior: DE mode requested but ML outputs enforced."""
    mode_text = str(request_mode or "").strip().lower()
    if mode_text not in {"data_engineer_cleaning", "data_engineer"}:
        return False
    err_parts: List[str] = []
    if isinstance(error_payload, dict):
        err_parts.extend(
            [
                str(error_payload.get("error") or ""),
                str(error_payload.get("message") or ""),
                str(error_payload.get("stacktrace") or ""),
                str(error_payload.get("raw") or ""),
            ]
        )
    elif error_payload:
        err_parts.append(str(error_payload))
    err_text = " ".join(part for part in err_parts if part).lower()
    missing_ml_outputs = all(
        token in err_text
        for token in ["data/metrics.json", "data/scored_rows.csv", "data/alignment_check.json"]
    )
    if not missing_ml_outputs:
        return False
    cleaned_success_logged = "cleaned data written to" in str(heavy_log_text or "").lower()
    downloaded_keys = set(downloaded.keys()) if isinstance(downloaded, dict) else set()
    expected = {
        _normalize_output_path(path)
        for path in (expected_outputs or [])
        if isinstance(path, str) and path.strip()
    }
    expected_output_seen = any(path in downloaded_keys for path in expected)
    return bool(cleaned_success_logged or expected_output_seen)


def _resolve_de_output_artifacts(state: Dict[str, Any]) -> tuple[str, str, List[str]]:
    """
    Resolve DE output artifacts strictly from DE view (contract projection).
    Returns (cleaned_output_path, manifest_output_path, required_artifacts).
    """
    de_view = state.get("de_view") or (state.get("contract_views") or {}).get("de_view")
    if not isinstance(de_view, dict):
        de_view = {}
    output_path = _normalize_output_path(str(de_view.get("output_path") or ""))
    manifest_path = _normalize_output_path(
        str(
            de_view.get("output_manifest_path")
            or de_view.get("manifest_path")
            or ""
        )
    )
    required_artifacts: List[str] = []
    if output_path:
        required_artifacts.append(output_path)
    if manifest_path:
        required_artifacts.append(manifest_path)
    required_artifacts = list(dict.fromkeys(required_artifacts))
    return output_path, manifest_path, required_artifacts


def _resolve_de_outlier_report_path(state: Dict[str, Any]) -> str:
    """
    Resolve optional DE outlier treatment report path from de_view projection.
    Returns normalized relative path or empty string when not configured.
    """
    de_view = state.get("de_view") or (state.get("contract_views") or {}).get("de_view")
    if not isinstance(de_view, dict):
        return ""
    explicit = de_view.get("outlier_report_path")
    if isinstance(explicit, str) and explicit.strip():
        return _normalize_output_path(explicit)
    outlier_policy = de_view.get("outlier_policy")
    if not isinstance(outlier_policy, dict):
        return ""
    report_path = outlier_policy.get("report_path")
    if isinstance(report_path, str) and report_path.strip():
        return _normalize_output_path(report_path)
    enabled_raw = outlier_policy.get("enabled")
    if isinstance(enabled_raw, str):
        enabled = enabled_raw.strip().lower() in {"1", "true", "yes", "on", "enabled"}
    elif enabled_raw is None:
        enabled = bool(
            outlier_policy.get("target_columns")
            or outlier_policy.get("methods")
            or outlier_policy.get("treatment")
        )
    else:
        enabled = bool(enabled_raw)
    stage = str(outlier_policy.get("apply_stage") or "data_engineer").strip().lower()
    if enabled and stage in {"data_engineer", "both"}:
        return _normalize_output_path("data/outlier_treatment_report.json")
    return ""


def _candidate_ml_input_paths(state: Dict[str, Any]) -> List[str]:
    """
    Collect candidate local cleaned-dataset paths from state + contract views.
    Order is deterministic and favors contract-derived sources.
    """
    if not isinstance(state, dict):
        return []
    candidates: List[str] = []

    explicit = state.get("ml_data_path")
    if isinstance(explicit, str) and explicit.strip():
        candidates.append(explicit.strip())

    de_output_path, _, _ = _resolve_de_output_artifacts(state)
    if de_output_path:
        candidates.append(de_output_path)

    contract = state.get("execution_contract")
    if isinstance(contract, dict):
        artifact_reqs = contract.get("artifact_requirements")
        if isinstance(artifact_reqs, dict):
            clean_dataset = artifact_reqs.get("clean_dataset")
            if isinstance(clean_dataset, dict):
                output_path = clean_dataset.get("output_path")
                if isinstance(output_path, str) and output_path.strip():
                    candidates.append(output_path.strip())
        required_outputs = contract.get("required_outputs")
        if isinstance(required_outputs, list):
            for path in required_outputs:
                if not isinstance(path, str):
                    continue
                norm = _normalize_output_path(path)
                if norm.endswith(".csv") and "/clean" in norm.lower():
                    candidates.append(norm)

    # Canonical/project aliases (universal fallbacks)
    candidates.extend(
        [
            "data/cleaned_dataset.csv",
            "data/cleaned_data.csv",
            "data/cleaned_full.csv",
        ]
    )

    normalized: List[str] = []
    seen: set[str] = set()
    for path in candidates:
        norm = _normalize_output_path(str(path or ""))
        if not norm or norm in seen:
            continue
        seen.add(norm)
        normalized.append(norm)
    return normalized


def _resolve_ml_input_path(state: Dict[str, Any], *, require_exists: bool) -> str:
    """
    Resolve ML input data path from state/contract candidates.
    """
    for path in _candidate_ml_input_paths(state):
        if not path:
            continue
        if require_exists and not os.path.exists(path):
            continue
        return path
    return ""


def _execute_data_engineer_via_heavy_runner(
    *,
    state: Dict[str, Any],
    code: str,
    csv_path: str,
    csv_sep: str,
    csv_decimal: str,
    csv_encoding: str,
    heavy_cfg: Dict[str, Any],
    run_id: Optional[str],
    attempt_id: int,
    reason: str,
) -> Dict[str, Any]:
    runtime_mode = _get_execution_runtime_mode()
    _, _, required_artifacts = _resolve_de_output_artifacts(state)
    optional_outlier_report = _resolve_de_outlier_report_path(state)
    optional_download_artifacts: List[str] = []
    if optional_outlier_report and optional_outlier_report not in required_artifacts:
        optional_download_artifacts.append(optional_outlier_report)
    if not required_artifacts:
        return {
            "ok": False,
            "unavailable": False,
            "error_details": "DE_VIEW_OUTPUTS_MISSING: de_view.output_path and de_view.output_manifest_path are required.",
            "heavy_result": None,
        }
    download_map = {
        "error.json": os.path.join("artifacts", "heavy_error.json"),
        "status.json": os.path.join("artifacts", "heavy_status.json"),
        "artifacts/execution_log.txt": os.path.join("artifacts", "heavy_execution_log.txt"),
    }
    for rel_path in required_artifacts:
        download_map[rel_path] = rel_path
    for rel_path in optional_download_artifacts:
        download_map.setdefault(rel_path, rel_path)
    support_files: List[Dict[str, str]] = []
    for rel_path in [
        "data/required_columns.json",
        "data/column_sets.json",
        "data/column_inventory.json",
        "data/dataset_semantics.json",
        "data/dataset_training_mask.json",
        "data/execution_contract.json",
    ]:
        if os.path.exists(rel_path):
            support_files.append({"local_path": rel_path, "path": rel_path})

    request = {
        "run_id": run_id,
        "dataset_uri": None,
        "output_uri": None,
        "mode": "data_engineer_cleaning",
        "orchestrator_protocol": {
            "name": "latiax_heavy_runner_execute_code",
            "version": "de_mode_v1",
            "expected_execute_mode": "data_engineer_cleaning",
            "step": "data_engineer",
        },
        "read": {"sep": csv_sep, "decimal": csv_decimal, "encoding": csv_encoding},
        "required_outputs": required_artifacts,
    }
    timeout_decision = _estimate_heavy_script_timeout(
        stage="data_engineer",
        code=code,
        state=state,
        ml_plan=None,
        configured_timeout_seconds=heavy_cfg.get("script_timeout_seconds"),
    )
    request["script_timeout_seconds"] = int(timeout_decision["timeout_seconds"])
    if run_id:
        log_run_event(
            run_id,
            "heavy_runner_request",
            {
                "mode": request.get("mode"),
                "runtime_mode": runtime_mode,
                "reason": reason,
                "attempt_id": attempt_id,
                "download_keys": list(download_map.keys()),
                "required_artifacts": required_artifacts,
                "optional_download_artifacts": optional_download_artifacts,
                "support_files": [item.get("path") for item in support_files],
                "script_timeout_seconds": request.get("script_timeout_seconds"),
                "script_timeout_decision": timeout_decision,
            },
        )
        log_run_event(run_id, "heavy_runner_start", {"step": "data_engineer", "reason": reason})

    launch_fn = launch_local_runner_job if runtime_mode == "local" else launch_heavy_runner_job
    launch_exc = (LocalRunnerLaunchError,) if runtime_mode == "local" else (CloudRunLaunchError,)
    try:
        heavy_result = launch_fn(
            run_id=run_id or "unknown",
            request=request,
            dataset_path=csv_path,
            bucket=heavy_cfg.get("bucket", "local"),
            job=heavy_cfg.get("job", "local_runner"),
            region=heavy_cfg.get("region", "local"),
            project=heavy_cfg.get("project"),
            input_prefix=heavy_cfg.get("input_prefix", "inputs"),
            output_prefix=heavy_cfg.get("output_prefix", "outputs"),
            dataset_prefix=heavy_cfg.get("dataset_prefix", "datasets"),
            download_map=download_map,
            code_text=code,
            support_files=support_files,
            data_path="data/raw.csv",
            required_artifacts=required_artifacts,
            attempt_id=attempt_id,
            stage_namespace="data_engineer",
        )
    except launch_exc as exc:
        msg = str(exc)
        unavailable = ("Required CLI not found" in msg) if runtime_mode != "local" else False
        if run_id:
            log_run_event(
                run_id,
                "heavy_runner_failed",
                {
                    "step": "data_engineer",
                    "error": msg,
                    "unavailable": unavailable,
                    "runtime_mode": runtime_mode,
                },
            )
        return {
            "ok": False,
            "unavailable": unavailable,
            "error_details": f"{'LOCAL_RUNNER_ERROR' if runtime_mode == 'local' else 'HEAVY_RUNNER_ERROR'}: {msg}",
            "heavy_result": None,
        }

    combined_runner_logs = "\n".join(
        [
            str(heavy_result.get("job_error_raw") or ""),
            str(heavy_result.get("job_error") or ""),
            str(heavy_result.get("job_stderr") or ""),
            str(heavy_result.get("job_stdout") or ""),
        ]
    )
    combined_runner_logs_lc = combined_runner_logs.lower()
    local_input_uri_missing = bool(
        runtime_mode == "local"
        and "failed to load input json" in combined_runner_logs_lc
        and "request.json" in combined_runner_logs_lc
    )

    if run_id:
        log_run_event(
            run_id,
            "heavy_runner_complete",
            {
                "step": "data_engineer",
                "status": heavy_result.get("status"),
                "downloaded": list((heavy_result.get("downloaded") or {}).keys()),
                "missing_artifacts": heavy_result.get("missing_artifacts") or [],
                "error_present": bool(heavy_result.get("error")),
                "status_ok": bool(heavy_result.get("status_ok")),
                "attempt_id": attempt_id,
                "local_input_uri_missing": local_input_uri_missing,
            },
        )

    downloaded = heavy_result.get("downloaded") or {}
    missing = list(heavy_result.get("missing_artifacts") or [])
    status_ok = str(heavy_result.get("status") or "").lower() == "success"
    required_ok = all(path in downloaded for path in required_artifacts)
    outlier_report_downloaded = bool(optional_outlier_report and optional_outlier_report in downloaded)
    protocol_mismatch = False
    protocol_mismatch_hint = ""
    try:
        heavy_log_text = ""
        heavy_log_path = os.path.join("artifacts", "heavy_execution_log.txt")
        if os.path.exists(heavy_log_path):
            try:
                with open(heavy_log_path, "r", encoding="utf-8", errors="replace") as f_log:
                    heavy_log_text = f_log.read().lower()
            except Exception:
                heavy_log_text = ""
        if _detect_de_heavy_runner_protocol_mismatch(
            request.get("mode"),
            heavy_result.get("error"),
            downloaded,
            heavy_log_text,
            expected_outputs=required_artifacts,
        ):
            protocol_mismatch = True
            protocol_mismatch_hint = (
                "Heavy runner appears to enforce ML required outputs while DE mode was requested. "
                "This usually means Cloud Run job is running an outdated image without DE mode support. "
                "Redeploy cloudrun/heavy_runner image and retry."
            )
            if run_id:
                log_run_event(
                    run_id,
                    "heavy_runner_protocol_mismatch",
                    {
                        "step": "data_engineer",
                        "attempt_id": attempt_id,
                        "requested_mode": request.get("mode"),
                        "downloaded": list(downloaded.keys()),
                    },
                )
    except Exception:
        protocol_mismatch = False
        protocol_mismatch_hint = ""
    ok = bool(
        status_ok
        and required_ok
        and not heavy_result.get("error")
        and not heavy_result.get("job_failed")
        and not protocol_mismatch
    )

    heavy_log_path = os.path.join("artifacts", "heavy_execution_log.txt")
    try:
        os.makedirs("artifacts", exist_ok=True)
        if os.path.exists(heavy_log_path):
            with open(heavy_log_path, "r", encoding="utf-8", errors="replace") as f_src:
                heavy_log = f_src.read()
        else:
            heavy_log = str(heavy_result.get("job_error") or "")
        with open(os.path.join("artifacts", "data_engineer_sandbox_last.log"), "w", encoding="utf-8") as f_log:
            f_log.write(heavy_log or "")
    except Exception:
        pass

    error_details = ""
    error_kind_hint = ""
    if not ok:
        err_parts: List[str] = []
        if protocol_mismatch and protocol_mismatch_hint:
            err_parts.append(protocol_mismatch_hint)
        if heavy_result.get("job_error"):
            err_parts.append(str(heavy_result.get("job_error")))
        if heavy_result.get("error"):
            err_parts.append(str(heavy_result.get("error")))
        if missing:
            err_parts.append(f"missing_artifacts={missing}")
        if not err_parts:
            err_parts.append(f"status={heavy_result.get('status')}")
        if local_input_uri_missing:
            error_kind_hint = "infra_input_uri_missing"
            error_details = "LOCAL_RUNNER_INPUT_URI_MISSING: " + " | ".join(err_parts)
        elif protocol_mismatch:
            error_kind_hint = "infra_protocol_mismatch"
            error_details = "HEAVY_RUNNER_PROTOCOL_MISMATCH: " + " | ".join(err_parts)
        else:
            error_kind_hint = "code_or_infra_unknown"
            error_details = "HEAVY_RUNNER_ERROR: " + " | ".join(err_parts)
        error_payload = {
            "stage": "heavy_runner_error",
            "exception_type": (
                "LocalRunnerInputUriMissing"
                if local_input_uri_missing
                else ("HeavyRunnerProtocolMismatch" if protocol_mismatch else "HeavyRunnerError")
            ),
            "exception_msg": error_details,
            "traceback": error_details,
            "attempt": attempt_id,
        }
        try:
            os.makedirs("artifacts", exist_ok=True)
            with open(
                os.path.join("artifacts", "data_engineer_sandbox_last_error.json"),
                "w",
                encoding="utf-8",
            ) as f_err:
                json.dump(error_payload, f_err, indent=2, ensure_ascii=True)
        except Exception:
            pass

    return {
        "ok": ok,
        "unavailable": bool(protocol_mismatch),
        "protocol_mismatch": bool(protocol_mismatch),
        "error_details": error_details,
        "error_kind_hint": error_kind_hint,
        "heavy_result": heavy_result,
        "outlier_report_path": optional_outlier_report,
        "outlier_report_downloaded": outlier_report_downloaded,
    }


def _should_run_e2b_after_de_heavy_result(de_heavy_result: Dict[str, Any] | None) -> bool:
    """
    Decide whether to run E2B after a DE heavy-runner attempt.

    Policy:
    - No heavy result: run E2B.
    - Heavy runner unavailable: run E2B fallback.
    - Heavy runner attempted (ok or failed): do not run E2B in same cycle.
    """
    if not isinstance(de_heavy_result, dict):
        return True
    return bool(de_heavy_result.get("unavailable"))


def _finalize_heavy_execution(
    state: Dict[str, Any],
    output: str,
    exec_start_ts: float,
    contract: Dict[str, Any],
    eval_spec: Dict[str, Any],
    csv_sep: str,
    csv_decimal: str,
    csv_encoding: str,
    counters: Dict[str, int],
    run_id: Optional[str],
    attempt_id: int,
    visuals_missing: bool,
) -> Dict[str, Any]:
    import glob
    required_outputs = _resolve_required_outputs(contract, state)
    deliverables = _resolve_contract_deliverables(contract)
    output_contract = deliverables if isinstance(deliverables, list) and deliverables else contract.get("required_outputs", [])
    cleaned_path = _resolve_ml_input_path(state if isinstance(state, dict) else {}, require_exists=False)
    if not cleaned_path:
        cleaned_path, _, _ = _resolve_de_output_artifacts(state)

    artifact_issues = _artifact_alignment_gate(
        cleaned_path=cleaned_path,
        scored_path="data/scored_rows.csv",
        contract=contract,
        evaluation_spec=eval_spec,
        csv_sep=csv_sep,
        csv_decimal=csv_decimal,
        csv_encoding=csv_encoding,
    )
    if artifact_issues:
        issue_text = "; ".join(artifact_issues)
        output = f"{output}\nVALIDATION_WARNING: ARTIFACT_ALIGNMENT_GUARD: {issue_text}"

    stale_outputs = _find_stale_outputs(required_outputs, exec_start_ts)
    if stale_outputs:
        output = f"{output}\nVALIDATION_WARNING: STALE_OUTPUTS: {stale_outputs}"

    content_issues, content_diagnostics = _validate_artifact_content(state)
    if content_issues:
        issue_text = ", ".join(content_issues)
        output = f"{output}\nVALIDATION_WARNING: ARTIFACT_CONTENT_INVALID: {issue_text}"

    heavy_error_kind = state.get("heavy_runner_error_kind")
    heavy_error_context = state.get("heavy_runner_error_context")
    heavy_error_path = os.path.join("artifacts", "heavy_error.json")
    if os.path.exists(heavy_error_path):
        try:
            with open(heavy_error_path, "r", encoding="utf-8") as f_err:
                heavy_error_payload = json.load(f_err)
            error_summary = heavy_error_payload.get("error") if isinstance(heavy_error_payload, dict) else ""
            error_stack = heavy_error_payload.get("stacktrace") if isinstance(heavy_error_payload, dict) else ""
            parts = []
            if error_summary:
                parts.append(str(error_summary))
            if error_stack:
                parts.append(str(error_stack)[-2000:])
            if parts:
                output = f"{output}\nHEAVY_RUNNER_ERROR_CONTEXT:\n" + "\n".join(parts)
                if not heavy_error_kind:
                    heavy_error_kind = "code"
        except Exception:
            pass
    if heavy_error_context and "HEAVY_RUNNER_ERROR_CONTEXT" not in output:
        output = f"{output}\nHEAVY_RUNNER_ERROR_CONTEXT:\n{str(heavy_error_context)[:2000]}"

    # Read heavy runner execution log to extract actual Traceback
    heavy_log_path = os.path.join("artifacts", "heavy_execution_log.txt")
    heavy_log_traceback = ""
    if os.path.exists(heavy_log_path):
        try:
            with open(heavy_log_path, "r", encoding="utf-8", errors="replace") as f_log:
                heavy_log_content = f_log.read()
            # Extract Traceback from log if present
            if "Traceback (most recent call last)" in heavy_log_content:
                # Find the last Traceback in the log
                tb_idx = heavy_log_content.rfind("Traceback (most recent call last)")
                if tb_idx >= 0:
                    heavy_log_traceback = heavy_log_content[tb_idx:][-4000:]
                    output = f"{output}\n{heavy_log_traceback}"
        except Exception:
            pass

    # Check for errors in output - include HEAVY_RUNNER_ERROR detection
    heavy_runner_error = "HEAVY_RUNNER_ERROR" in output
    error_in_output = (
        "Traceback (most recent call last)" in output
        or "EXECUTION ERROR" in output
        or heavy_runner_error
    )
    if heavy_error_kind == "code":
        sandbox_failed = False
    elif heavy_error_kind == "infra":
        sandbox_failed = True
    else:
        sandbox_failed = heavy_runner_error  # Mark as sandbox failure for proper retry handling

    outputs_valid = not bool(artifact_issues or stale_outputs or content_issues or error_in_output)
    if run_id:
        update_sandbox_attempt(
            run_id,
            "ml_engineer",
            attempt_id,
            artifacts_valid=outputs_valid,
            artifact_issues=artifact_issues,
            stale_outputs=stale_outputs,
            content_issues=content_issues,
        )

    # Validate only ML engineer's outputs in post-ML finalization
    from src.utils.output_contract import check_required_outputs_for_owner
    oc_report = check_required_outputs_for_owner(output_contract, "ml_engineer")
    try:
        os.makedirs("data", exist_ok=True)
        dump_json("data/output_contract_report.json", oc_report)
    except Exception as oc_err:
        print(f"Warning: failed to persist output_contract_report.json: {oc_err}")

    artifact_paths: List[str] = []
    if isinstance(oc_report, dict):
        artifact_paths.extend(oc_report.get("present", []))
    plots_local = glob.glob("static/plots/*.png")
    if plots_local:
        artifact_paths.extend(plots_local)
    for extra_path in [
        "data/strategy_spec.json",
        "data/plan.json",
        "data/evaluation_spec.json",
        "data/plot_insights.json",
    ]:
        if os.path.exists(extra_path):
            artifact_paths.append(extra_path)

    deduped = []
    seen = set()
    for item in artifact_paths:
        if item not in seen:
            seen.add(item)
            deduped.append(item)
    artifact_paths = deduped

    artifact_index = _build_artifact_index(artifact_paths, deliverables if isinstance(deliverables, list) else None)
    try:
        os.makedirs("data", exist_ok=True)
        dump_json("data/produced_artifact_index.json", artifact_index)
    except Exception as idx_err:
        print(f"Warning: failed to persist produced_artifact_index.json: {idx_err}")

    attempt_score = _score_attempt(outputs_valid, oc_report, content_issues, artifact_paths)
    attempt_valid = bool(outputs_valid and not oc_report.get("missing") and not content_issues)

    result = {
        "execution_output": output,
        "plots_local": plots_local,
        "fallback_plots": [],
        "has_partial_visuals": bool(plots_local) and bool(error_in_output or sandbox_failed or visuals_missing),
        "execution_error": error_in_output,
        "execution_attempt": state.get("execution_attempt", 0) + 1,
        "last_runtime_error_tail": output[-4000:] if error_in_output else None,
        "ml_skipped_reason": state.get("ml_skipped_reason"),
        "output_contract_report": oc_report,
        "artifact_index": artifact_index,
        "produced_artifact_index": artifact_index,
        "artifact_paths": artifact_paths,
        "artifact_content_issues": content_issues,
        "artifact_content_diagnostics": content_diagnostics,
        "visuals_missing": visuals_missing,
        "last_attempt_score": attempt_score,
        "last_attempt_valid": attempt_valid,
        "sandbox_failed": sandbox_failed,
        "sandbox_retry_count": 0,
        "ml_call_refund_pending": False,
        "execution_call_refund_pending": False,
        "budget_counters": counters,
        "ml_data_path": cleaned_path or state.get("ml_data_path"),
    }
    if not error_in_output:
        result["runtime_fix_count"] = 0
        result["last_successful_execution_output"] = output
        result["last_successful_plots"] = plots_local
        result["last_successful_output_contract_report"] = oc_report
    best_score = state.get("best_attempt_score")
    if attempt_valid and (best_score is None or attempt_score > float(best_score)):
        dest = _snapshot_best_attempt(
            attempt_id=attempt_id,
            artifact_paths=artifact_paths,
            output_contract_report=oc_report,
            artifact_index=artifact_index,
            execution_output=output,
            plots_local=plots_local,
            diagnostics=content_diagnostics,
        )
        result["best_attempt_score"] = attempt_score
        result["best_attempt_id"] = attempt_id
        result["best_attempt_dir"] = dest
        result["best_attempt_artifact_index"] = artifact_index
        result["best_attempt_output_contract_report"] = oc_report
        result["best_attempt_execution_output"] = output
        result["best_attempt_plots"] = plots_local
    return result


def _flag_active_for_run(state: Dict[str, Any], flag: str, run_id: Optional[str]) -> bool:
    if not state.get(flag):
        return False
    if not run_id:
        return bool(state.get(flag))
    flag_run = state.get(f"{flag}_run_id")
    return flag_run == run_id


def _extract_error_snippet(code: str, error_details: str, *, context_lines: int = 10) -> str:
    if not code or not error_details:
        return ""
    try:
        matches = re.findall(r'cleaning\\.py", line (\\d+)', error_details)
        if not matches:
            matches = re.findall(r'line (\\d+), in', error_details)
        if not matches:
            return ""
        line_num = int(matches[-1])
        lines = code.splitlines()
        start = max(line_num - context_lines - 1, 0)
        end = min(line_num + context_lines, len(lines))
        snippet_lines = []
        for idx in range(start, end):
            prefix = ">>" if (idx + 1) == line_num else "  "
            snippet_lines.append(f"{prefix} {idx + 1}: {lines[idx]}")
        return "\n".join(snippet_lines)
    except Exception:
        return ""


def _extract_required_columns_from_contract(
    contract: Dict[str, Any] | None,
    contract_min: Dict[str, Any] | None,
) -> tuple[List[str], str]:
    sources = [("contract_min", contract_min), ("contract", contract)]
    for source_name, cfg in sources:
        if not isinstance(cfg, dict):
            continue
        artifact_reqs = cfg.get("artifact_requirements")
        if not isinstance(artifact_reqs, dict):
            continue
        clean_cfg = artifact_reqs.get("clean_dataset")
        if isinstance(clean_cfg, dict):
            required = clean_cfg.get("required_columns")
            if isinstance(required, list) and required:
                return [str(c) for c in required if c], source_name
        schema_binding = artifact_reqs.get("schema_binding")
        if isinstance(schema_binding, dict):
            required = schema_binding.get("required_columns")
            if isinstance(required, list) and required:
                return [str(c) for c in required if c], source_name
    # Keep DE required columns in sync with DE view semantics:
    # when clean_dataset/schema_binding are absent, canonical_columns are the
    # contract-declared input columns and must seed required_columns.json.
    for source_name, cfg in sources:
        if not isinstance(cfg, dict):
            continue
        canonical = cfg.get("canonical_columns")
        if isinstance(canonical, list) and canonical:
            return [str(c) for c in canonical if c], f"{source_name}.canonical_columns"
    return [], ""


def _update_column_inventory_required_columns(
    *,
    column_inventory: List[str],
    contract: Dict[str, Any] | None,
    contract_min: Dict[str, Any] | None,
    csv_path: str | None,
    state: Dict[str, Any],
) -> None:
    required_cols, source = _extract_required_columns_from_contract(contract, contract_min)
    if not required_cols:
        return
    inv_path = "data/column_inventory.json"
    inv_payload = _load_json_safe(inv_path)
    if not isinstance(inv_payload, dict):
        inv_payload = {}
    if not isinstance(inv_payload.get("columns"), list):
        inv_payload["columns"] = list(column_inventory or [])
    if "n_columns" not in inv_payload:
        inv_payload["n_columns"] = len(inv_payload.get("columns") or [])
    if csv_path and "source_csv" not in inv_payload:
        inv_payload["source_csv"] = csv_path
    inv_payload["required_columns"] = required_cols
    inv_payload["required_columns_source"] = source
    try:
        dump_json(inv_path, inv_payload)
    except Exception as inv_err:
        print(f"Warning: failed to persist column_inventory.json required_columns: {inv_err}")
    try:
        column_state = state.get("column_inventory")
        if isinstance(column_state, dict):
            column_state["required_columns"] = required_cols
            column_state["required_columns_source"] = source
            state["column_inventory"] = column_state
    except Exception:
        pass


def _sync_required_columns_artifacts(
    *,
    required_cols: List[str],
    contract: Dict[str, Any] | None,
    state: Dict[str, Any],
) -> None:
    if not required_cols:
        return
    try:
        dump_json("data/required_columns.json", required_cols)
        state["required_columns_path"] = "data/required_columns.json"
    except Exception as req_err:
        print(f"Warning: failed to persist required_columns.json: {req_err}")
    try:
        from src.utils.column_sets import build_column_sets, summarize_column_sets

        # Preserve steward/planner feature-family semantics when available.
        existing_column_sets = state.get("column_sets")
        if not isinstance(existing_column_sets, dict) or not existing_column_sets:
            loaded = _load_json_safe("data/column_sets.json")
            if isinstance(loaded, dict) and loaded:
                existing_column_sets = loaded

        if isinstance(existing_column_sets, dict) and existing_column_sets:
            state["column_sets"] = existing_column_sets
            if not os.path.exists("data/column_sets.json"):
                dump_json("data/column_sets.json", existing_column_sets)
            summary = summarize_column_sets(existing_column_sets)
            if summary:
                state["column_sets_summary"] = summary
            return

        # Fallback only when no prior column_sets exist.
        role_map: Dict[str, str] = {}
        if isinstance(contract, dict):
            for col in contract.get("outcome_columns", []) or []:
                if col:
                    role_map[str(col)] = "target_candidate"
            roles = get_column_roles(contract)
            if isinstance(roles, dict):
                for col in roles.get("identifiers", []) or []:
                    if col:
                        role_map[str(col)] = "id_like"
        dataset_semantics = state.get("dataset_semantics")
        if isinstance(dataset_semantics, dict):
            split_candidates = dataset_semantics.get("split_candidates") or []
            if isinstance(split_candidates, list):
                for col in split_candidates:
                    if col:
                        role_map[str(col)] = "split_candidate"

        column_sets = build_column_sets(required_cols, roles=role_map)
        if isinstance(column_sets, dict):
            dump_json("data/column_sets.json", column_sets)
            state["column_sets"] = column_sets
            state["column_sets_summary"] = summarize_column_sets(column_sets) or state.get("column_sets_summary")
    except Exception as cs_err:
        print(f"Warning: failed to rebuild column_sets from required_columns: {cs_err}")


def _resolve_explicit_columns_for_wide_dataset(state: Dict[str, Any] | None) -> List[str]:
    if not isinstance(state, dict):
        return []
    column_sets = state.get("column_sets")
    if not isinstance(column_sets, dict) or not column_sets:
        column_sets = _load_json_safe("data/column_sets.json") or {}
        if isinstance(column_sets, dict) and column_sets:
            state["column_sets"] = column_sets
            if not state.get("column_sets_summary"):
                try:
                    summary = summarize_column_sets(column_sets)
                    if summary:
                        state["column_sets_summary"] = summary
                except Exception:
                    pass
    if not isinstance(column_sets, dict):
        return []
    return [str(col) for col in (column_sets.get("explicit_columns") or []) if col]


def _apply_wide_dataset_contract_truth(
    *,
    state: Dict[str, Any] | None,
    contract: Dict[str, Any] | None,
    contract_min: Dict[str, Any] | None,
    n_columns: int | None,
) -> None:
    if not n_columns or n_columns <= 200:
        return
    dataset_truth_ref = {
        "column_inventory_path": "data/column_inventory.json",
        "column_sets_path": "data/column_sets.json",
        "n_columns": int(n_columns),
    }
    if isinstance(contract, dict):
        contract["dataset_truth_ref"] = dataset_truth_ref
    if not isinstance(contract_min, dict):
        return
    contract_min["dataset_truth_ref"] = dataset_truth_ref

    canonical_existing = [str(col) for col in (contract_min.get("canonical_columns") or []) if col]
    if not canonical_existing and isinstance(contract, dict):
        canonical_existing = [str(col) for col in (contract.get("canonical_columns") or []) if col]
        if canonical_existing:
            contract_min["canonical_columns"] = canonical_existing

    explicit_columns = _resolve_explicit_columns_for_wide_dataset(state)
    if explicit_columns:
        contract_min["available_columns"] = explicit_columns
        return

    # Never blank canonical columns in wide datasets; keep planner truth.
    if canonical_existing and not (isinstance(contract_min.get("available_columns"), list) and contract_min.get("available_columns")):
        contract_min["available_columns"] = list(canonical_existing)


def run_execution_planner(state: AgentState) -> AgentState:
    print("--- [2.7] Execution Planner: Building Contract ---")
    abort_state = _abort_if_requested(state, "execution_planner")
    if abort_state:
        return abort_state
    strategy = state.get("selected_strategy", {})
    data_summary = _build_senior_summary_context(state if isinstance(state, dict) else {})
    memory_context = state.get("dataset_memory_context")
    if memory_context:
        data_summary = f"{data_summary}\n\n{memory_context}"
    context_pack = ""
    if not _minimal_agent_context_enabled():
        context_pack = build_context_pack("execution_planner", state if isinstance(state, dict) else {})
        if context_pack:
            data_summary = f"{context_pack}\n\n{data_summary}" if data_summary else context_pack
    # Provide compact data_profile context for the planner without mutating state["data_summary"].
    data_summary_for_planner = data_summary
    planner_data_profile = None
    try:
        from src.utils.data_profile_compact import (
            convert_dataset_profile_to_data_profile,
            compact_data_profile_for_llm,
        )
        work_dir_abs = _resolve_work_dir_abs(state if isinstance(state, dict) else None)
        dataset_profile_path = _abs_in_work(work_dir_abs, "data/dataset_profile.json")
        dataset_profile = _load_json_safe(dataset_profile_path)
        if isinstance(dataset_profile, dict) and dataset_profile:
            analysis_type = (strategy or {}).get("analysis_type") if isinstance(strategy, dict) else None
            planner_data_profile = convert_dataset_profile_to_data_profile(
                dataset_profile, {}, analysis_type
            )
            compact_profile = compact_data_profile_for_llm(planner_data_profile)
            if compact_profile:
                planner_semantic_context = {
                    "strategy_techniques_role": "advisory_hypotheses",
                    "conflict_resolution_priority": [
                        "DATA_PROFILE_COMPACT_JSON.numeric_ranges_digest",
                        "dataset_semantics",
                        "strategy_text",
                    ],
                    "dtype_conflict_policy": (
                        "If strategy wording conflicts with observed profile ranges/dtypes, prioritize "
                        "observed profile evidence and encode safer dtype constraints."
                    ),
                }
                compact_payload = json.dumps(compact_profile, indent=2, ensure_ascii=False)
                semantic_payload = json.dumps(planner_semantic_context, indent=2, ensure_ascii=False)
                data_summary_for_planner = (
                    f"{data_summary}\n\nDATA_PROFILE_COMPACT_JSON:\n{compact_payload}"
                    f"\n\nPLANNER_SEMANTIC_CONTEXT_JSON:\n{semantic_payload}"
                )
    except Exception:
        planner_data_profile = None
    business_objective = state.get("business_objective", "")
    run_id = state.get("run_id")
    if run_id:
        log_run_event(run_id, "execution_planner_start", {"strategy": strategy.get("title", "")})
    csv_path = state.get("csv_path", "")
    orig_cwd = state.get("orig_cwd")
    if csv_path and not os.path.isabs(csv_path) and orig_cwd:
        resolved_csv_path = _resolve_csv_path_with_base(orig_cwd, csv_path)
        if resolved_csv_path != csv_path:
            state["csv_path"] = resolved_csv_path
            csv_path = resolved_csv_path
    if not csv_path or not os.path.exists(csv_path):
        error_message = f"Warning: input CSV not found: {csv_path}"
        print(error_message)
        if run_id:
            log_run_event(
                run_id,
                "pipeline_aborted_reason",
                {"reason": "input_csv_missing", "csv_path": csv_path},
            )
        oc_report = _persist_output_contract_report(state, reason="input_csv_missing")
        return {
            "error_message": error_message,
            "pipeline_aborted_reason": "input_csv_missing",
            "execution_planner_failed": True,
            "output_contract_report": oc_report,
        }
    csv_sep = state.get("csv_sep", ",")
    csv_decimal = state.get("csv_decimal", ".")
    csv_encoding = state.get("csv_encoding", "utf-8")
    column_inventory = []
    try:
        import pandas as pd
        header_df = pd.read_csv(csv_path, nrows=0, sep=csv_sep, decimal=csv_decimal, encoding=csv_encoding)
        column_inventory = header_df.columns.tolist()
    except Exception as inv_err:
        print(f"Warning: failed to read column inventory: {inv_err}")
    column_sets = state.get("column_sets")
    if not isinstance(column_sets, dict) or not column_sets:
        column_sets = _load_json_safe("data/column_sets.json") or {}
    column_manifest = state.get("column_manifest")
    if not isinstance(column_manifest, dict) or not column_manifest:
        column_manifest = _load_json_safe("data/column_manifest.json") or {}
    try:
        # Prepare output_dialect from state (csv dialect detected by steward)
        output_dialect = {
            "sep": csv_sep,
            "decimal": csv_decimal,
            "encoding": csv_encoding
        }

        # Prepare env_constraints (conservative default)
        env_constraints = {"forbid_inplace_column_creation": True}

        domain_expert_critique = state.get("selection_reason", "")
        try:
            execution_planner.last_contract_diagnostics = None
        except Exception:
            pass

        contract = execution_planner.generate_contract(
            strategy=strategy,
            data_summary=data_summary_for_planner,
            business_objective=business_objective,
            column_inventory=column_inventory,
            column_sets=column_sets if isinstance(column_sets, dict) else {},
            column_manifest=column_manifest if isinstance(column_manifest, dict) else {},
            output_dialect=output_dialect,
            env_constraints=env_constraints,
            domain_expert_critique=domain_expert_critique,
            data_profile=planner_data_profile,
            run_id=run_id,
        )
    except Exception as e:
        print(f"Warning: execution planner failed ({e}); fail-closed contract path.")
        contract = {}
    if not isinstance(contract, dict):
        contract = {}
    planner_contract_diagnostics = getattr(execution_planner, "last_contract_diagnostics", None)
    if not isinstance(planner_contract_diagnostics, dict):
        planner_contract_diagnostics = {}
    if not planner_contract_diagnostics:
        planner_contract_diagnostics = {
            "schema_version": 1,
            "where": "execution_planner:graph_fallback",
            "llm_success": False,
            "validation": {
                "status": "error",
                "accepted": False,
                "issues": [
                    {
                        "severity": "error",
                        "rule": "planner_no_contract",
                        "message": "Planner did not produce diagnostics/contract payload.",
                    }
                ],
                "summary": {"error_count": 1, "warning_count": 0},
            },
            "summary": {"status": "error", "issue_count": 1, "accepted": False},
        }
    validation_payload = planner_contract_diagnostics.get("validation")
    planner_contract_accepted = False
    if isinstance(validation_payload, dict):
        accepted_flag = validation_payload.get("accepted")
        validation_status = str(validation_payload.get("status") or "").lower()
        if isinstance(accepted_flag, bool):
            planner_contract_accepted = bool(accepted_flag and validation_status != "error")
    summary_payload = planner_contract_diagnostics.get("summary")
    if isinstance(summary_payload, dict):
        summary_accepted = summary_payload.get("accepted")
        if isinstance(summary_accepted, bool):
            if isinstance(validation_payload, dict):
                planner_contract_accepted = planner_contract_accepted and summary_accepted
            else:
                planner_contract_accepted = summary_accepted
    strategy_spec = state.get("strategy_spec") or _load_json_safe("data/strategy_spec.json")
    objective_type = None
    if isinstance(strategy_spec, dict):
        objective_type = strategy_spec.get("objective_type")
    if not objective_type:
        eval_spec = contract.get("evaluation_spec") if isinstance(contract, dict) else {}
        if isinstance(eval_spec, dict):
            objective_type = eval_spec.get("objective_type")
    dataset_profile = build_dataset_profile(data_summary, column_inventory)
    execution_plan = build_execution_plan(str(objective_type or "unknown"), dataset_profile)
    # V4.1: Do NOT write execution_plan to contract (legacy key)
    evaluation_spec = contract.get("evaluation_spec") if isinstance(contract, dict) else {}
    if not isinstance(evaluation_spec, dict):
        evaluation_spec = {}
    if not isinstance(contract, dict):
        contract = {}
    contract_scope = normalize_contract_scope(contract.get("scope")) if isinstance(contract, dict) else ""
    if not evaluation_spec and contract_scope in {"ml_only", "full_pipeline"}:
        print("Warning: execution_contract has no evaluation_spec; reviewers will use contract-level gates only.")
    work_dir_abs = _resolve_work_dir_abs(state if isinstance(state, dict) else None)
    try:
        data_dir = _abs_in_work(work_dir_abs, "data")
        os.makedirs(data_dir, exist_ok=True)
        dump_json(_abs_in_work(work_dir_abs, "data/execution_contract.json"), contract)
        if planner_contract_diagnostics:
            dump_json(
                _abs_in_work(work_dir_abs, "data/execution_contract_diagnostics.json"),
                planner_contract_diagnostics,
            )
        dump_json(_abs_in_work(work_dir_abs, "data/plan.json"), execution_plan)
        if evaluation_spec:
            dump_json(_abs_in_work(work_dir_abs, "data/evaluation_spec.json"), evaluation_spec)
    except Exception as save_err:
        print(f"Warning: failed to persist execution_contract.json: {save_err}")

    if not planner_contract_accepted:
        error_message = "Execution planner produced a contract that failed validation (fail-closed)."
        if run_id:
            log_run_event(
                run_id,
                "pipeline_aborted_reason",
                {"reason": "execution_contract_invalid"},
            )
            copy_run_contracts(
                run_id,
                [
                    _abs_in_work(work_dir_abs, "data/execution_contract.json"),
                    _abs_in_work(work_dir_abs, "data/execution_contract_diagnostics.json"),
                ],
            )
            log_agent_snapshot(
                run_id,
                "execution_planner",
                prompt=getattr(execution_planner, "last_prompt", None),
                response=getattr(execution_planner, "last_response", None) or planner_contract_diagnostics,
                context={
                    "strategy": strategy,
                    "business_objective": business_objective,
                    "planner_diag": getattr(execution_planner, "last_planner_diag", None),
                    "contract_diagnostics": planner_contract_diagnostics,
                    "fail_closed": True,
                },
                verdicts={"status": "REJECTED", "reason": "execution_contract_invalid"},
            )
        return {
            "error_message": error_message,
            "pipeline_aborted_reason": "execution_contract_invalid",
            "execution_planner_failed": True,
            "execution_contract": contract,
            "execution_contract_diagnostics": planner_contract_diagnostics,
            "execution_contract_diagnostics_path": "data/execution_contract_diagnostics.json",
        }
    try:
        _update_column_inventory_required_columns(
            column_inventory=column_inventory,
            contract=contract if isinstance(contract, dict) else {},
            contract_min={},
            csv_path=csv_path,
            state=state if isinstance(state, dict) else {},
        )
        required_cols_synced, _ = _extract_required_columns_from_contract(
            contract if isinstance(contract, dict) else {},
            {},
        )
        _sync_required_columns_artifacts(
            required_cols=required_cols_synced,
            contract=contract if isinstance(contract, dict) else {},
            state=state if isinstance(state, dict) else {},
        )
    except Exception as inv_err:
        print(f"Warning: column_inventory required_columns sync failed: {inv_err}")
    if run_id:
        copy_run_contracts(
            run_id,
            [
                _abs_in_work(work_dir_abs, "data/execution_contract.json"),
                _abs_in_work(work_dir_abs, "data/execution_contract_diagnostics.json"),
                _abs_in_work(work_dir_abs, "data/evaluation_spec.json"),
                _abs_in_work(work_dir_abs, "data/plan.json"),
            ],
        )
        _verify_run_bundle_contracts(run_id, contract, work_dir_abs)

    contract_snapshot_payload: Dict[str, Any] = {}
    try:
        contract_snapshot_payload = _persist_execution_contract_snapshot(
            state if isinstance(state, dict) else {},
            contract if isinstance(contract, dict) else {},
            {},
        )
    except Exception as snapshot_err:
        print(f"Warning: failed to persist contract snapshot: {snapshot_err}")
        contract_snapshot_payload = {}

    # DATA_PROFILE PREFLIGHT: Create data_profile.json early so it's available
    # even if DE/ML abort. This is the first opportunity after contract is persisted.
    try:
        from src.utils.data_profile_preflight import ensure_data_profile_artifact
        analysis_type = (strategy or {}).get("analysis_type")
        _dp, _dp_source = ensure_data_profile_artifact(
            state=state,
            contract=contract,
            analysis_type=analysis_type,
            work_dir_abs=work_dir_abs,
            run_id=run_id,
        )
        if _dp:
            _refresh_run_facts_pack(state)
    except Exception as dp_err:
        print(f"Warning: data_profile preflight failed: {dp_err}")

    view_payload = _build_contract_views(state if isinstance(state, dict) else {}, contract, {})
    view_projection_ok = bool(view_payload.get("contract_views_projection_ok", True))
    view_projection_errors = [
        str(err) for err in (view_payload.get("contract_views_projection_errors") or []) if err
    ]
    if not view_projection_ok:
        error_message = (
            "Execution planner produced a contract that cannot generate executable agent views "
            f"(fail-closed): {view_projection_errors}"
        )
        if run_id:
            log_run_event(
                run_id,
                "pipeline_aborted_reason",
                {
                    "reason": "execution_contract_views_invalid",
                    "view_projection_errors": view_projection_errors,
                },
            )
            log_agent_snapshot(
                run_id,
                "execution_planner",
                prompt=getattr(execution_planner, "last_prompt", None),
                response=getattr(execution_planner, "last_response", None) or planner_contract_diagnostics,
                context={
                    "strategy": strategy,
                    "business_objective": business_objective,
                    "contract_diagnostics": planner_contract_diagnostics,
                    "view_projection_errors": view_projection_errors,
                    "fail_closed": True,
                },
                verdicts={"status": "REJECTED", "reason": "execution_contract_views_invalid"},
            )
        return {
            "error_message": error_message,
            "pipeline_aborted_reason": "execution_contract_views_invalid",
            "execution_planner_failed": True,
            "execution_contract": contract,
            "execution_contract_diagnostics": planner_contract_diagnostics,
            "execution_contract_diagnostics_path": "data/execution_contract_diagnostics.json",
            "contract_views_projection_ok": False,
            "contract_views_projection_errors": view_projection_errors,
        }
    if view_payload.get("contract_views"):
        try:
            de_len = len(json.dumps(view_payload["contract_views"].get("de_view", {}), ensure_ascii=True))
            ml_len = len(json.dumps(view_payload["contract_views"].get("ml_view", {}), ensure_ascii=True))
            cleaning_len = len(json.dumps(view_payload["contract_views"].get("cleaning_view", {}), ensure_ascii=True))
            qa_len = len(json.dumps(view_payload["contract_views"].get("qa_view", {}), ensure_ascii=True))
            reviewer_len = len(json.dumps(view_payload["contract_views"].get("reviewer_view", {}), ensure_ascii=True))
            print(f"Using DE_VIEW_CONTEXT length={de_len}")
            print(f"Using ML_VIEW_CONTEXT length={ml_len}")
            print(f"Using CLEANING_VIEW_CONTEXT length={cleaning_len}")
            print(f"Using QA_VIEW_CONTEXT length={qa_len}")
            print(f"Using REVIEWER_VIEW_CONTEXT length={reviewer_len}")
            if run_id:
                log_run_event(run_id, "de_view_context", {"length": de_len})
                log_run_event(run_id, "ml_view_context", {"length": ml_len})
                log_run_event(run_id, "cleaning_view_context", {"length": cleaning_len})
                log_run_event(run_id, "qa_view_context", {"length": qa_len})
                log_run_event(run_id, "reviewer_view_context", {"length": reviewer_len})
        except Exception:
            pass
    if run_id:
        log_run_event(
            run_id,
            "execution_planner_complete",
            {"required_outputs": contract.get("required_outputs", [])},
        )
    policy = contract.get("iteration_policy") if isinstance(contract, dict) else {}
    result = {
        "execution_contract": contract,
        "execution_planner_failed": False,
    }
    if planner_contract_diagnostics:
        result["execution_contract_diagnostics"] = planner_contract_diagnostics
        result["execution_contract_diagnostics_path"] = "data/execution_contract_diagnostics.json"
    # V4.1: Do NOT add execution_plan to result (legacy key)
    if evaluation_spec:
        result["evaluation_spec"] = evaluation_spec
    if isinstance(contract_snapshot_payload, dict) and contract_snapshot_payload:
        result["execution_contract_snapshot"] = contract_snapshot_payload.get("snapshot")
        result["execution_contract_snapshot_path"] = contract_snapshot_payload.get("snapshot_path")
        result["execution_contract_signature"] = contract_snapshot_payload.get("execution_contract_signature")
        result["execution_contract_min_signature"] = contract_snapshot_payload.get("execution_contract_min_signature")
        result["execution_contract_source"] = contract_snapshot_payload.get("execution_contract_source")
    if view_payload:
        result.update(view_payload)
    if isinstance(policy, dict) and policy:
        result["iteration_policy"] = policy
        runtime_fix_max = policy.get("runtime_fix_max")
        if runtime_fix_max is not None:
            try:
                result["max_runtime_fix_attempts"] = max(1, int(runtime_fix_max))
            except Exception:
                pass
    if isinstance(state.get("column_inventory"), dict):
        result["column_inventory"] = state.get("column_inventory")
    else:
        result["column_inventory"] = {
            "n_columns": len(column_inventory),
            "columns": column_inventory,
        }
    merged_state = dict(state or {})
    merged_state.update(result)
    _refresh_run_facts_pack(merged_state)
    if run_id:
        log_agent_snapshot(
            run_id,
            "execution_planner",
            prompt=getattr(execution_planner, "last_prompt", None),
            response=getattr(execution_planner, "last_response", None) or result,
            context={
                "strategy": strategy,
                "business_objective": business_objective,
                "planner_diag": getattr(execution_planner, "last_planner_diag", None),
                "contract_diagnostics": planner_contract_diagnostics,
            },
        )
    return result




def _planner_contract_invalid_for_execution(state: Dict[str, Any]) -> bool:
    """Conservative fail-closed check before Data Engineer execution."""
    if not isinstance(state, dict):
        return True
    if bool(state.get("execution_planner_failed")):
        return True
    if state.get("pipeline_aborted_reason") in {
        "execution_contract_invalid",
        "execution_contract_views_invalid",
    }:
        return True
    if state.get("contract_views_projection_ok") is False:
        return True

    diagnostics = state.get("execution_contract_diagnostics")
    if isinstance(diagnostics, dict):
        validation = diagnostics.get("validation")
        summary = diagnostics.get("summary")
        if isinstance(validation, dict):
            accepted_flag = validation.get("accepted")
            if isinstance(accepted_flag, bool) and not accepted_flag:
                return True
            if str(validation.get("status") or "").lower() == "error":
                return True
        if isinstance(summary, dict):
            accepted_summary = summary.get("accepted")
            if isinstance(accepted_summary, bool) and not accepted_summary:
                return True

    contract = state.get("execution_contract")
    if not isinstance(contract, dict) or not contract:
        return True

    return False


def run_data_engineer(state: AgentState) -> AgentState:
    print("--- [3] Data Engineer: Cleaning Data (Sandbox Execution) ---")
    abort_state = _abort_if_requested(state, "data_engineer")
    if abort_state:
        return abort_state
    if _planner_contract_invalid_for_execution(state if isinstance(state, dict) else {}):
        reason = str(state.get("pipeline_aborted_reason") or "execution_contract_invalid")
        if reason not in {"execution_contract_invalid", "execution_contract_views_invalid"}:
            reason = "execution_contract_invalid"
        msg = "Execution contract is invalid; Data Engineer halted by fail-closed planner policy."
        run_id = state.get("run_id")
        if run_id:
            log_run_event(run_id, "pipeline_aborted_reason", {"reason": reason})
        return {
            "cleaning_code": "",
            "cleaned_data_preview": "Error: invalid execution contract",
            "error_message": msg,
            "pipeline_aborted_reason": reason,
            "data_engineer_failed": True,
            "budget_counters": state.get("budget_counters"),
        }
    run_id = state.get("run_id")
    ok, counters, err_msg = _consume_budget(state, "de_calls", "max_de_calls", "Data Engineer")
    state["budget_counters"] = counters
    if not ok:
        if run_id:
            log_run_event(run_id, "budget_exceeded", {"label": "data_engineer", "error": err_msg})
        if run_id:
            log_run_event(run_id, "pipeline_aborted_reason", {"reason": "data_engineer_budget_exceeded"})
        oc_report = _persist_output_contract_report(state, reason="data_engineer_budget_exceeded")
        return {
            "cleaning_code": "",
            "cleaned_data_preview": "Error: Budget Exceeded",
            "error_message": err_msg,
            "output_contract_report": oc_report,
            "pipeline_aborted_reason": "data_engineer_budget_exceeded",
            "data_engineer_failed": True,
            "budget_counters": counters,
        }
    attempt_id = int(state.get("data_engineer_attempt", 0)) + 1
    state["data_engineer_attempt"] = attempt_id
    if run_id:
        log_run_event(run_id, "data_engineer_start", {})

    # DATA_PROFILE PREFLIGHT (belt & suspenders): Ensure data_profile exists
    # This catches cases where execution_planner preflight didn't run or failed
    if not state.get("data_profile"):
        try:
            from src.utils.data_profile_preflight import ensure_data_profile_artifact
            contract = state.get("execution_contract", {})
            strategy = state.get("selected_strategy", {})
            analysis_type = strategy.get("analysis_type") if strategy else None
            work_dir_abs = _resolve_work_dir_abs(state)
            ensure_data_profile_artifact(
                state=state,
                contract=contract,
                analysis_type=analysis_type,
                work_dir_abs=work_dir_abs,
                run_id=run_id,
            )
        except Exception as dp_err:
            print(f"Warning: data_profile preflight (DE) failed: {dp_err}")


    selected = state.get('selected_strategy')
    if not selected:
        raise ValueError("No strategy selected for data cleaning.")

    business_objective = state.get('business_objective', '')
    csv_path = state['csv_path']
    print(f"DE_INPUT_CSV: {csv_path}")
    if csv_path and not os.path.isabs(csv_path):
        print(f"DE_INPUT_RELATIVE_WARNING: {csv_path}")
    csv_encoding = state.get('csv_encoding', 'utf-8')
    csv_decimal = state.get('csv_decimal', '.')
    csv_sep = state.get('csv_sep', ',')
    input_dialect = {"encoding": csv_encoding, "sep": csv_sep, "decimal": csv_decimal}
    leakage_audit_summary = state.get("leakage_audit_summary", "")
    minimal_context_mode = _minimal_agent_context_enabled()
    latest_de_feedback_record = state.get("data_engineer_feedback_record")
    latest_de_feedback_block = _build_latest_feedback_record_block(latest_de_feedback_record)
    if minimal_context_mode:
        feedback_context = _build_agent_feedback_context(state if isinstance(state, dict) else {}, "data_engineer")
        persisted_override = state.get("data_summary", "")
        data_engineer_audit_override = _merge_de_audit_override(feedback_context, persisted_override)
        if latest_de_feedback_block:
            data_engineer_audit_override = _merge_de_audit_override(data_engineer_audit_override, latest_de_feedback_block)
    else:
        data_engineer_audit_override = state.get("data_summary", "")
        if latest_de_feedback_block:
            data_engineer_audit_override = _merge_de_audit_override(data_engineer_audit_override, latest_de_feedback_block)
    dataset_scale_hints = state.get("dataset_scale_hints")
    if not isinstance(dataset_scale_hints, dict) or not dataset_scale_hints:
        dataset_scale_hints = {}
    if csv_path and os.path.exists(csv_path):
        if dataset_scale_hints.get("scale") in (None, "", "unknown"):
            try:
                size_mb = file_size_mb(csv_path)
                est_rows = estimate_rows_fast(csv_path, encoding=csv_encoding)
                dataset_scale_hints = classify_dataset_scale(size_mb, est_rows)
                state["dataset_scale_hints"] = dataset_scale_hints
            except Exception:
                pass
    context_pack = ""
    dataset_semantics_summary = state.get("dataset_semantics_summary")
    if not minimal_context_mode:
        context_pack = build_context_pack("data_engineer", state if isinstance(state, dict) else {})
        if context_pack:
            data_engineer_audit_override = _merge_de_audit_override(context_pack, data_engineer_audit_override)
        if dataset_semantics_summary:
            data_engineer_audit_override = _merge_de_audit_override(
                data_engineer_audit_override,
                dataset_semantics_summary,
            )

    # Add numeric ranges summary for Data Engineer to understand actual data scales
    if not minimal_context_mode:
        try:
            from src.utils.data_profile_compact import build_numeric_ranges_summary
            dataset_profile = state.get("dataset_profile") or _load_json_safe("data/dataset_profile.json")
            if isinstance(dataset_profile, dict) and dataset_profile.get("numeric_summary"):
                numeric_ranges_summary = build_numeric_ranges_summary(dataset_profile)
                if numeric_ranges_summary:
                    data_engineer_audit_override = _merge_de_audit_override(
                        data_engineer_audit_override,
                        numeric_ranges_summary,
                    )
        except Exception as nr_err:
            print(f"Warning: failed to build numeric_ranges_summary: {nr_err}")

    required_cols = []
    required_raw_map = {}
    sample_context = ""
    hints = ""
    context_payload = {}
    header_cols = []
    if csv_path and not os.path.exists(csv_path):
        candidate = None
        if not os.path.isabs(csv_path):
            orig_cwd = state.get("orig_cwd") or ""
            if orig_cwd:
                candidate = os.path.normpath(os.path.abspath(os.path.join(orig_cwd, csv_path)))
        if candidate and os.path.exists(candidate):
            csv_path = candidate
            state["csv_path"] = csv_path
        if not os.path.exists(csv_path):
            error_message = f"Input CSV not found: {csv_path}"
            print(error_message)
            if run_id:
                log_run_event(
                    run_id,
                    "pipeline_aborted_reason",
                    {"reason": "input_csv_missing", "csv_path": csv_path},
                )
            oc_report = _persist_output_contract_report(state, reason="input_csv_missing")
            return {
                "cleaning_code": "",
                "cleaned_data_preview": "Error: Input CSV Missing",
                "error_message": error_message,
                "output_contract_report": oc_report,
                "pipeline_aborted_reason": "input_csv_missing",
                "data_engineer_failed": True,
                "budget_counters": counters,
            }
    if csv_path:
        csv_path = os.path.normpath(csv_path)
        state["csv_path"] = csv_path
    required_cols = _resolve_required_input_columns(state.get("execution_contract", {}), selected)
    header_cols = _read_csv_header(csv_path, csv_encoding, csv_sep) or []
    n_cols = len(header_cols)
    memory_guard_active = False
    if isinstance(dataset_scale_hints, dict):
        scale_flag = dataset_scale_hints.get("scale")
        file_mb = dataset_scale_hints.get("file_mb") or 0.0
        est_rows = dataset_scale_hints.get("est_rows") or 0
        if scale_flag in {"medium", "large"} or file_mb >= 50 or est_rows >= 200_000 or n_cols >= 500:
            memory_guard_active = True
    state["de_memory_guard_active"] = memory_guard_active
    runtime_mode = _get_execution_runtime_mode()
    de_heavy_cfg = _get_heavy_runner_config()
    de_use_heavy_runner = bool(de_heavy_cfg)
    if runtime_mode == "local" and de_heavy_cfg:
        de_heavy_reason = "local_runner_mode"
    else:
        de_heavy_reason = "cloudrun_only_mode" if de_heavy_cfg else "cloudrun_config_missing"
    if run_id:
        try:
            log_run_event(
                run_id,
                "data_engineer_backend_selection",
                {
                    "backend": "local_runner" if runtime_mode == "local" else "heavy_runner",
                    "reason": de_heavy_reason,
                    "runtime_mode": runtime_mode,
                    "cloudrun_available": bool(de_heavy_cfg),
                    "dataset_scale": {
                        "scale": dataset_scale_hints.get("scale") if isinstance(dataset_scale_hints, dict) else None,
                        "file_mb": dataset_scale_hints.get("file_mb") if isinstance(dataset_scale_hints, dict) else None,
                        "est_rows": dataset_scale_hints.get("est_rows") if isinstance(dataset_scale_hints, dict) else None,
                        "cols": n_cols,
                    },
                    "memory_decision": state.get("de_backend_memory_estimate")
                    if isinstance(state.get("de_backend_memory_estimate"), dict)
                    else None,
                },
            )
        except Exception:
            pass
    norm_map: Dict[str, str] = {}
    if header_cols and not minimal_context_mode:
        for col in header_cols:
            normed = _norm_name(col)
            if normed and normed not in norm_map:
                norm_map[normed] = col
        inventory_payload: Dict[str, Any] = {"column_inventory_raw": header_cols}
        if len(header_cols) > 80:
            norm_items = [f"{k}->{v}" for k, v in norm_map.items()]
            norm_summary = summarize_long_list(norm_items)
            norm_summary["note"] = COLUMN_LIST_POINTER
            inventory_payload["normalized_header_map"] = norm_summary
        else:
            inventory_payload["normalized_header_map"] = norm_map
        inventory_payload, _ = compress_long_lists(inventory_payload)
        header_context = "COLUMN_INVENTORY_CONTEXT: " + json.dumps(inventory_payload, ensure_ascii=False)
        data_engineer_audit_override = _merge_de_audit_override(data_engineer_audit_override, header_context)
        required_raw_map = _build_required_raw_map(required_cols, norm_map)
        if required_raw_map:
            raw_map_payload = "REQUIRED_RAW_HEADER_MAP:\n" + json.dumps(required_raw_map, ensure_ascii=True)
            data_engineer_audit_override = _merge_de_audit_override(data_engineer_audit_override, raw_map_payload)
        sample_context = _build_required_sample_context(csv_path, input_dialect, required_cols, norm_map)
        if sample_context:
            data_engineer_audit_override = _merge_de_audit_override(data_engineer_audit_override, sample_context)
            hints = _infer_parsing_hints_from_sample_context(sample_context)
            if hints:
                data_engineer_audit_override = _merge_de_audit_override(data_engineer_audit_override, hints)
    if memory_guard_active and not minimal_context_mode:
        scale_text = dataset_scale_hints.get("scale") if isinstance(dataset_scale_hints, dict) else "unknown"
        file_mb = dataset_scale_hints.get("file_mb") if isinstance(dataset_scale_hints, dict) else None
        est_rows = dataset_scale_hints.get("est_rows") if isinstance(dataset_scale_hints, dict) else None
        chunk_size = dataset_scale_hints.get("chunk_size") if isinstance(dataset_scale_hints, dict) else None
        mem_guidance = (
            "MEMORY_SAFETY_GUIDANCE:\n"
            f"- Dataset appears {scale_text} (file_mb={file_mb}, est_rows={est_rows}, cols={n_cols}).\n"
            "- To avoid sandbox OOM, you MAY use chunked processing:\n"
            f"  * pd.read_csv(..., chunksize={chunk_size or 'N'}) with dtype=str, low_memory=False\n"
            "  * write cleaned_data.csv incrementally (header only for first chunk)\n"
            "  * avoid full-column nunique or per-column stats over entire dataset; compute on sample or per-chunk aggregates\n"
            "  * keep column order stable across chunks\n"
        )
        data_engineer_audit_override = _merge_de_audit_override(data_engineer_audit_override, mem_guidance)
    # Inject Raw Snippet for Dialect Grounding (DISABLED: Causing GLM-4.7 Empty Response / Safety Trigger)
    # try:
    #     raw_lines = []
    #     with open(csv_path, "r", encoding=csv_encoding, errors="replace") as f:
    #         for _ in range(5):
    #             line = f.readline()
    #             if not line: break
    #             # Sanitize: keeps only printable characters to avoid breaking LLM JSON prompts
    #             clean_line = "".join(c for c in line.rstrip() if c.isprintable())
    #             raw_lines.append(clean_line)
    #     raw_snippet = "\n".join(raw_lines)
    #     raw_context = f"\n*** RAW FILE SNIPPET (First 5 lines) ***\n{raw_snippet}\n"
    #     data_engineer_audit_override = _merge_de_audit_override(data_engineer_audit_override, raw_context)
    # except Exception as e:
    #     print(f"Warning: could not read raw snippet for DE: {e}")

    state["data_engineer_audit_override"] = data_engineer_audit_override
    execution_contract = state.get("execution_contract") or _load_json_safe("data/execution_contract.json") or {}
    de_view = state.get("de_view") or (state.get("contract_views") or {}).get("de_view")
    if not isinstance(de_view, dict) or not de_view:
        projected_views = build_contract_views_projection(execution_contract or {}, state.get("artifact_index") or [])
        de_view = projected_views.get("de_view") or {}
    de_output_path = str(de_view.get("output_path") or "").strip()
    de_manifest_path = str(
        de_view.get("output_manifest_path")
        or de_view.get("manifest_path")
        or ""
    ).strip()
    de_outlier_report_path = _resolve_de_outlier_report_path(
        {"de_view": de_view, "contract_views": state.get("contract_views") or {}}
    )
    if not de_output_path or not de_manifest_path:
        msg = (
            "DE_VIEW_OUTPUTS_MISSING: contract-derived de_view must define "
            "output_path and output_manifest_path."
        )
        if run_id:
            log_run_event(run_id, "pipeline_aborted_reason", {"reason": "de_view_outputs_missing"})
        oc_report = _persist_output_contract_report(state, reason="de_view_outputs_missing")
        return {
            "cleaning_code": "",
            "cleaned_data_preview": "Error: Missing DE View Outputs",
            "error_message": msg,
            "output_contract_report": oc_report,
            "pipeline_aborted_reason": "de_view_outputs_missing",
            "data_engineer_failed": True,
            "budget_counters": counters,
        }
    de_objective = build_de_objective(execution_contract or {})
    try:
        de_view_len = len(json.dumps(de_view, ensure_ascii=True))
        print(f"Using DE_VIEW_CONTEXT length={de_view_len}")
        if run_id:
            log_run_event(run_id, "de_view_context", {"length": de_view_len})
    except Exception:
        pass
    required_all_columns = _resolve_contract_columns_for_cleaning(state.get("execution_contract", {}))
    if minimal_context_mode:
        context_payload = {
            "csv_path": csv_path,
            "csv_encoding": csv_encoding,
            "csv_sep": csv_sep,
            "csv_decimal": csv_decimal,
            "de_view": de_view,
            "feedback_context": data_engineer_audit_override,
            "last_gate_context": state.get("last_gate_context"),
        }
    else:
        context_payload = {
            "csv_path": csv_path,
            "csv_encoding": csv_encoding,
            "csv_sep": csv_sep,
            "csv_decimal": csv_decimal,
            "header_cols": header_cols,
            "required_input_columns": required_cols,
            "required_all_columns": required_all_columns,
            "required_raw_header_map": required_raw_map,
            "raw_required_sample_context": sample_context,
            "data_engineer_audit_override": data_engineer_audit_override,
            "dataset_semantics_summary": dataset_semantics_summary,
            "dataset_training_mask": state.get("dataset_training_mask"),
            "de_view": de_view,
            "execution_contract": execution_contract,
            "context_pack": context_pack,
        }
    try:
        os.makedirs("artifacts", exist_ok=True)
        with open(os.path.join("artifacts", "data_engineer_context.json"), "w", encoding="utf-8") as f_ctx:
            json.dump(context_payload, f_ctx, indent=2, ensure_ascii=False)
    except Exception as ctx_err:
        print(f"Warning: failed to persist data_engineer_context.json: {ctx_err}")

    # Generate cleaning script (targeting REMOTE path)
    import inspect

    kwargs = {
        "data_audit": data_engineer_audit_override,
        "strategy": selected,
        "input_path": "data/raw.csv",  # Remote Sandbox Path
        "business_objective": de_objective,
        "csv_encoding": csv_encoding,
        "csv_sep": csv_sep,
        "csv_decimal": csv_decimal,
    }
    sig = inspect.signature(data_engineer.generate_cleaning_script)
    if "execution_contract" in sig.parameters and not minimal_context_mode:
        kwargs["execution_contract"] = execution_contract
    if "de_view" in sig.parameters:
        kwargs["de_view"] = de_view
    if "repair_mode" in sig.parameters:
        kwargs["repair_mode"] = bool(attempt_id > 1)
    code = data_engineer.generate_cleaning_script(**kwargs)
    try:
        os.makedirs("artifacts", exist_ok=True)
        with open(os.path.join("artifacts", "data_engineer_last.py"), "w", encoding="utf-8") as f_art:
            f_art.write(code)
    except Exception as art_err:
        print(f"Warning: failed to persist data_engineer_last.py: {art_err}")
    if run_id:
        log_agent_snapshot(
            run_id,
            "data_engineer",
            prompt=getattr(data_engineer, "last_prompt", None),
            response=getattr(data_engineer, "last_response", None) or code,
            context=context_payload,
            script=code,
            attempt=attempt_id,
        )

    raw_response = getattr(data_engineer, "last_response", "") or ""
    if "```" in raw_response:
        if run_id:
            log_run_event(run_id, "data_engineer_code_fence_detected", {"attempt": attempt_id})
        stripped = extract_code_block(raw_response)
        if (not stripped or not stripped.strip()) and not code.strip():
            msg = "CRITICAL: Data Engineer returned only fenced/empty code."
            print(msg)
            if run_id:
                log_run_event(run_id, "pipeline_aborted_reason", {"reason": "data_engineer_code_fence_empty"})
            oc_report = _persist_output_contract_report(state, reason="data_engineer_code_fence_empty")
            return {
                "cleaning_code": "",
                "cleaned_data_preview": "Error: Empty Code After Fence Strip",
                "error_message": msg,
                "output_contract_report": oc_report,
                "pipeline_aborted_reason": "data_engineer_code_fence_empty",
                "data_engineer_failed": True,
                "budget_counters": counters,
            }
        print("Warning: code fences detected in raw response; continuing without retry.")

    plan_payload = None
    is_plan = False
    plan_issues: List[str] = []
    force_code_mode = state.get("force_code_mode", True)
    plan, _ = parse_cleaning_plan(code)
    if plan:
        if force_code_mode:
            msg = "CLEANING_PLAN_NOT_ALLOWED: expected Python cleaning code."
            if run_id:
                log_run_event(run_id, "pipeline_aborted_reason", {"reason": "data_engineer_plan_not_allowed"})
            oc_report = _persist_output_contract_report(state, reason="data_engineer_plan_not_allowed")
            return {
                "cleaning_code": code,
                "cleaned_data_preview": "Error: Plan Output",
                "error_message": msg,
                "output_contract_report": oc_report,
                "pipeline_aborted_reason": "data_engineer_plan_not_allowed",
                "data_engineer_failed": True,
                "budget_counters": counters,
            }
        is_plan = True
        plan_payload = plan
        plan_issues = validate_cleaning_plan(plan)
        try:
            os.makedirs("artifacts", exist_ok=True)
            with open(os.path.join("artifacts", "data_engineer_last_plan.json"), "w", encoding="utf-8") as f_plan:
                json.dump(plan_payload, f_plan, indent=2, ensure_ascii=False)
        except Exception as art_err:
            print(f"Warning: failed to persist data_engineer_last_plan.json: {art_err}")
        if plan_issues:
            msg = "CLEANING_PLAN_INVALID: " + "; ".join(plan_issues)
            if run_id:
                log_run_event(run_id, "pipeline_aborted_reason", {"reason": "data_engineer_plan_invalid"})
            oc_report = _persist_output_contract_report(state, reason="data_engineer_plan_invalid")
            return {
                "cleaning_code": code,
                "cleaned_data_preview": "Error: Invalid Plan",
                "error_message": msg,
                "output_contract_report": oc_report,
                "pipeline_aborted_reason": "data_engineer_plan_invalid",
                "data_engineer_failed": True,
                "budget_counters": counters,
            }

    # Check if generation failed
    if code.strip().startswith("# Error"):
        print(f"Correction: Data Engineer failed to generate code. Error: {code}")
        can_retry_generation = not _flag_active_for_run(state, "de_generation_retry_done", run_id)
        if can_retry_generation:
            new_state = dict(state)
            new_state["de_generation_retry_done"] = True
            if run_id:
                new_state["de_generation_retry_done_run_id"] = run_id
            base_override = state.get("data_engineer_audit_override") or state.get("data_summary", "")
            generation_context = {
                "attempt": attempt_id,
                "error_message": str(code).strip()[:4000],
            }
            raw_excerpt = str(raw_response or "").strip()[:4000]
            if raw_excerpt:
                generation_context["raw_response_excerpt"] = raw_excerpt
            payload = (
                "GENERATION_FAILURE_CONTEXT:\n"
                "ENVIRONMENT_FEEDBACK (Please Repair Code Generation):\n"
                + json.dumps(generation_context, indent=2, ensure_ascii=False)
            )
            _merge_de_override_with_feedback_record(
                new_state,
                base_override=base_override,
                payload=payload,
                source="generation",
                status="REJECTED",
                iteration=int(attempt_id),
                feedback="Data Engineer failed to generate runnable cleaning code.",
                failed_gates=["generation_failed"],
                required_fixes=["Regenerate valid Python cleaning script using contract context."],
                runtime_error_tail=str(code or "")[:1200],
                evidence=[{"claim": "Code generation returned error-prefixed output.", "source": "data_engineer_response"}],
            )
            if run_id:
                log_run_event(
                    run_id,
                    "data_engineer_generation_retry",
                    {"attempt": attempt_id, "reason": "generation_failed"},
                )
            print("Generation guard: retrying Data Engineer with generation failure context.")
            return run_data_engineer(new_state)
        if run_id:
            log_run_event(run_id, "pipeline_aborted_reason", {"reason": "data_engineer_generation_failed"})
        oc_report = _persist_output_contract_report(state, reason="data_engineer_generation_failed")
        return {
            "cleaning_code": code,
            "cleaned_data_preview": "Error: Generation Failed",
            "error_message": code,
            "output_contract_report": oc_report,
            "pipeline_aborted_reason": "data_engineer_generation_failed",
            "data_engineer_failed": True,
            "budget_counters": counters,
        }

    original_code = code
    code, auto_fixes = _apply_static_autofixes(code)
    if auto_fixes and run_id:
        log_run_event(run_id, "auto_fix_applied", {"attempt": attempt_id, "fixes": auto_fixes})
        run_dir = get_run_dir(run_id)
        if run_dir:
            try:
                base = os.path.join(run_dir, "agents", "data_engineer", f"iteration_{attempt_id}")
                os.makedirs(base, exist_ok=True)
                with open(os.path.join(base, "script.py"), "w", encoding="utf-8") as f_script:
                    f_script.write(code)
            except Exception:
                pass
    is_safe, violations = scan_code_safety(code)
    if not is_safe:
        snippets = _collect_violation_snippets(original_code, violations)
        if run_id:
            log_run_event(
                run_id,
                "static_scan_failed",
                {"attempt": attempt_id, "violations": violations, "snippets": snippets},
            )
        run_dir = get_run_dir(run_id) if run_id else None
        if run_dir:
            try:
                base = os.path.join(run_dir, "agents", "data_engineer", f"iteration_{attempt_id}")
                os.makedirs(base, exist_ok=True)
                with open(os.path.join(base, "script_blocked.py"), "w", encoding="utf-8") as f_blocked:
                    f_blocked.write(original_code)
                blocked_reason = {
                    "violations": violations,
                    "snippets": snippets,
                    "auto_fixes_applied": auto_fixes,
                }
                with open(os.path.join(base, "blocked_reason.json"), "w", encoding="utf-8") as f_reason:
                    json.dump(blocked_reason, f_reason, indent=2)
                guard_code = f"raise ValueError('GENERATED CODE BLOCKED BY STATIC SCAN: {violations}')"
                with open(os.path.join(base, "script.py"), "w", encoding="utf-8") as f_guard:
                    f_guard.write(guard_code)
            except Exception:
                pass
        if not state.get("de_static_guard_retry_done"):
            new_state = dict(state)
            new_state["de_static_guard_retry_done"] = True
            base_override = state.get("data_engineer_audit_override") or state.get("data_summary", "")
            context_payload = {
                "violations": violations,
                "snippets": snippets,
                "auto_fixes_applied": auto_fixes,
            }
            payload = (
                "STATIC_SCAN_VIOLATIONS:\n"
                "ENVIRONMENT_FEEDBACK (Please Adjust Code):\n"
                + json.dumps(context_payload, indent=2, ensure_ascii=False)
            )
            _merge_de_override_with_feedback_record(
                new_state,
                base_override=base_override,
                payload=payload,
                source="static_scan",
                status="REJECTED",
                iteration=int(attempt_id),
                feedback="Static safety scan blocked generated cleaning code.",
                failed_gates=["static_scan_failed"],
                required_fixes=["Remove forbidden operations/imports and regenerate safe cleaning code."],
                hard_failures=["static_scan_failed"],
                runtime_error_tail=str(violations)[:1200],
                evidence=[{"claim": f"Static scan violations: {violations}", "source": "static_scan"}],
            )
            if run_id:
                log_run_event(run_id, "static_scan_retry", {"attempt": attempt_id, "violations": violations})
            print("Static scan guard: retrying Data Engineer with violation context.")
            return run_data_engineer(new_state)
        if run_id:
            log_run_event(run_id, "pipeline_aborted_reason", {"reason": "data_engineer_static_scan_failed"})
        oc_report = _persist_output_contract_report(state, reason="data_engineer_static_scan_failed")
        guard_code = f"raise ValueError('GENERATED CODE BLOCKED BY STATIC SCAN: {violations}')"
        return {
            "cleaning_code": guard_code,
            "cleaned_data_preview": "Error: Security Blocked",
            "error_message": "CRITICAL: cleaning code blocked by static scan.",
            "output_contract_report": oc_report,
            "pipeline_aborted_reason": "data_engineer_static_scan_failed",
            "data_engineer_failed": True,
            "budget_counters": counters,
        }

    if not is_plan:
        preflight_issues = data_engineer_preflight(code)
        if preflight_issues:
            msg = "DATA_ENGINEER_PREFLIGHT: " + "; ".join(preflight_issues)
            fh = list(state.get("feedback_history", []))
            fh.append(msg)
            lgc = {
                "source": "data_engineer_preflight",
                "status": "REJECTED",
                "feedback": msg,
                "required_fixes": preflight_issues,
                "failed_gates": preflight_issues,
            }
            try:
                print(msg)
            except Exception:
                pass
            if not state.get("de_preflight_retry_done"):
                new_state = dict(state)
                new_state["de_preflight_retry_done"] = True
                payload = "PREFLIGHT_ERROR_CONTEXT:\n" + msg
                try:
                    explainer_text = ""
                    try:
                        required_input = _resolve_required_input_columns(state.get("execution_contract", {}), selected)
                        header_cols = _read_csv_header(csv_path, csv_encoding, csv_sep)
                        norm_map = {}
                        for col in header_cols:
                            normed = _norm_name(col)
                            if normed and normed not in norm_map:
                                norm_map[normed] = col
                        required_raw_map = _build_required_raw_map(required_input, norm_map)
                        explainer_ctx = {
                            "strategy_title": selected.get("title", "") if selected else "",
                            "csv_dialect": input_dialect,
                            "required_input_columns": required_input,
                            "required_raw_header_map": required_raw_map,
                            "preflight_issues": preflight_issues,
                        }
                        explainer_text = failure_explainer.explain_data_engineer_failure(
                            code=code,
                            error_details=msg,
                            context=explainer_ctx,
                        )
                    except Exception as explainer_err:
                        print(f"Warning: failure explainer failed: {explainer_err}")
                        explainer_text = ""
                    if explainer_text:
                        payload += "\nLLM_FAILURE_EXPLANATION:\n" + explainer_text.strip()
                        try:
                            os.makedirs("artifacts", exist_ok=True)
                            with open(
                                os.path.join("artifacts", "data_engineer_preflight_explainer.txt"),
                                "w",
                                encoding="utf-8",
                            ) as f_exp:
                                f_exp.write(explainer_text.strip())
                        except Exception as exp_err:
                            print(f"Warning: failed to persist data_engineer_preflight_explainer.txt: {exp_err}")
                except Exception:
                    pass
                _merge_de_override_with_feedback_record(
                    new_state,
                    base_override=state.get("data_engineer_audit_override") or state.get("data_summary", ""),
                    payload=payload,
                    source="preflight",
                    status="REJECTED",
                    iteration=int(attempt_id),
                    feedback=str(msg),
                    failed_gates=["data_engineer_preflight"],
                    required_fixes=[str(item) for item in preflight_issues if str(item).strip()],
                    runtime_error_tail=str(msg),
                    evidence=[{"claim": "Data engineer preflight checks failed.", "source": "data_engineer_preflight"}],
                )
                print("Preflight guard: retrying Data Engineer with explainer context.")
                return run_data_engineer(new_state)
            if run_id:
                log_run_event(run_id, "pipeline_aborted_reason", {"reason": "data_engineer_preflight_failed"})
            oc_report = _persist_output_contract_report(state, reason="data_engineer_preflight_failed")
            return {
                "cleaning_code": code,
                "cleaned_data_preview": "Preflight Failed",
                "error_message": msg,
                "feedback_history": fh,
                "last_gate_context": lgc,
                "output_contract_report": oc_report,
                "pipeline_aborted_reason": "data_engineer_preflight_failed",
                "data_engineer_failed": True,
                "budget_counters": counters,
            }

    # 0a. Undefined name preflight for Data Engineer code
    if not is_plan:
        undefined = detect_undefined_names(code)
        if undefined:
            msg = f"STATIC_PRECHECK_UNDEFINED: Undefined names detected preflight: {', '.join(undefined)}"
            if not state.get("de_undefined_retry_done"):
                new_state = dict(state)
                new_state["de_undefined_retry_done"] = True
                payload = (
                    "UNDEFINED_NAME_GUARD:\n"
                    "Ensure every referenced name is defined in the same scope. "
                    "Avoid using variables created inside helper functions in outer scopes. "
                    "Do not inline JSON literals (null/true/false) into Python code."
                )
                try:
                    if undefined:
                        payload += "\nUNDEFINED_NAMES:\n- " + "\n- ".join(str(item) for item in undefined if str(item).strip())
                except Exception:
                    pass
                _merge_de_override_with_feedback_record(
                    new_state,
                    base_override=state.get("data_engineer_audit_override") or state.get("data_summary", ""),
                    payload=payload,
                    source="static_precheck_undefined",
                    status="REJECTED",
                    iteration=int(attempt_id),
                    feedback=str(msg),
                    failed_gates=["static_precheck_undefined"],
                    required_fixes=[
                        "Define every referenced variable in scope before use.",
                        "Avoid JSON literals in Python script bodies.",
                    ],
                    hard_failures=["static_precheck_undefined"],
                    runtime_error_tail=str(msg),
                    evidence=[{"claim": "Undefined names detected by static precheck.", "source": "static_precheck"}],
                )
                print("Undefined name guard triggered: retrying Data Engineer with safety instructions.")
                return run_data_engineer(new_state)
            fh = list(state.get("feedback_history", []))
            fh.append(msg)
            if run_id:
                log_run_event(run_id, "pipeline_aborted_reason", {"reason": "data_engineer_undefined_names"})
            oc_report = _persist_output_contract_report(state, reason="data_engineer_undefined_names")
            return {
                "cleaning_code": code,
                "cleaned_data_preview": "Preflight Failed",
                "error_message": msg,
                "feedback_history": fh,
                "output_contract_report": oc_report,
                "pipeline_aborted_reason": "data_engineer_undefined_names",
                "data_engineer_failed": True,
                "budget_counters": counters,
            }

    if not is_plan and contains_json_null_literal(code):
        if not state.get("de_json_literal_retry_done"):
            new_state = dict(state)
            new_state["de_json_literal_retry_done"] = True
            payload = (
                "CONTRACT_LITERAL_GUARD:\n"
                "Do not inline raw JSON into Python code. "
                "JSON literals like null/true/false are invalid identifiers in Python. "
                "If you need the execution contract, read it from data/execution_contract.json "
                "or use Python-native values."
            )
            _merge_de_override_with_feedback_record(
                new_state,
                base_override=state.get("data_engineer_audit_override") or state.get("data_summary", ""),
                payload=payload,
                source="json_literal_guard",
                status="REJECTED",
                iteration=int(attempt_id),
                feedback="JSON literals detected in generated Python script.",
                failed_gates=["json_literals_in_python"],
                required_fixes=[
                    "Remove JSON literals null/true/false from Python code.",
                    "Load contract data from files and convert to Python-native values.",
                ],
                hard_failures=["json_literals_in_python"],
                runtime_error_tail="JSON literal guard triggered.",
                evidence=[{"claim": "Raw JSON literals found in script.", "source": "data_engineer_script"}],
            )
            print("Contract literal guard triggered: retrying Data Engineer with safety instructions.")
            return run_data_engineer(new_state)
        if run_id:
            log_run_event(run_id, "pipeline_aborted_reason", {"reason": "data_engineer_json_literals"})
        oc_report = _persist_output_contract_report(state, reason="data_engineer_json_literals")
        return {
            "cleaning_code": code,
            "cleaned_data_preview": "Error: Contract Literal Guard",
            "error_message": "CRITICAL: JSON literals (null/true/false) found in Python code.",
            "output_contract_report": oc_report,
            "pipeline_aborted_reason": "data_engineer_json_literals",
            "data_engineer_failed": True,
            "budget_counters": counters,
        }

    # Manifest serialization guard: ensure json.dump uses default=
    if not is_plan and manifest_dump_missing_default(code):
        if not state.get("de_manifest_retry_done"):
            new_state = dict(state)
            new_state["de_manifest_retry_done"] = True
            payload = (
                "MANIFEST_JSON_SAFETY:\n"
                "Ensure json.dump(manifest, ..., default=_json_default) "
                "to handle numpy/pandas scalar types safely."
            )
            _merge_de_override_with_feedback_record(
                new_state,
                base_override=state.get("data_engineer_audit_override") or state.get("data_summary", ""),
                payload=payload,
                source="manifest_json_guard",
                status="REJECTED",
                iteration=int(attempt_id),
                feedback="Manifest serialization guard failed.",
                failed_gates=["manifest_json_default_missing"],
                required_fixes=[
                    "Serialize manifest using json.dump(..., default=_json_default).",
                    "Avoid raw numpy/pandas scalars in manifest payload.",
                ],
                hard_failures=["manifest_json_default_missing"],
                runtime_error_tail="Manifest JSON guard triggered.",
                evidence=[{"claim": "Manifest dump missing default serializer.", "source": "data_engineer_script"}],
            )
            print("Manifest JSON guard triggered: retrying Data Engineer with safety instructions.")
            return run_data_engineer(new_state)
        else:
            if run_id:
                log_run_event(run_id, "pipeline_aborted_reason", {"reason": "data_engineer_manifest_guard"})
            oc_report = _persist_output_contract_report(state, reason="data_engineer_manifest_guard")
            return {
                "cleaning_code": code,
                "cleaned_data_preview": "Error: Manifest JSON Guard",
                "error_message": "CRITICAL: Manifest serialization must use json.dump(..., default=_json_default).",
                "output_contract_report": oc_report,
                "pipeline_aborted_reason": "data_engineer_manifest_guard",
                "data_engineer_failed": True,
                "budget_counters": counters,
            }

    # Dialect enforcement guard: ensure pd.read_csv uses provided dialect
    # With AUTOPATCH: try to fix missing/wrong dialect params before consuming LLM retry
    dialect_issues = []
    if not is_plan:
        dialect_issues = dialect_guard_violations(code, csv_sep, csv_decimal, csv_encoding, expected_path="data/raw.csv")

        # AUTOPATCH: Try to fix dialect issues automatically before retry/abort
        if dialect_issues and not state.get("de_dialect_autopatched"):
            try:
                from src.utils.dialect_code_patch import patch_read_csv_dialect
                patched_code, patch_notes, changed = patch_read_csv_dialect(
                    code, csv_sep, csv_decimal, csv_encoding, expected_path="data/raw.csv"
                )
                if changed:
                    # Re-validate after patching
                    recheck = dialect_guard_violations(patched_code, csv_sep, csv_decimal, csv_encoding, expected_path="data/raw.csv")
                    if not recheck:
                        # Autopatch succeeded - use patched code
                        code = patched_code
                        dialect_issues = []
                        print(f"✅ DIALECT_AUTOPATCH: Fixed dialect issues: {patch_notes}")
                        if run_id:
                            log_run_event(run_id, "data_engineer_dialect_autopatched", {
                                "notes": patch_notes,
                                "sep": csv_sep,
                                "decimal": csv_decimal,
                                "encoding": csv_encoding,
                            })
                        # Persist autopatched script for audit
                        try:
                            os.makedirs("artifacts", exist_ok=True)
                            with open("artifacts/data_engineer_last_autopatched.py", "w", encoding="utf-8") as f_ap:
                                f_ap.write(patched_code)
                        except Exception:
                            pass
                    else:
                        # Autopatch didn't fully resolve - update issues for retry/abort
                        dialect_issues = recheck
                        print(f"⚠️ DIALECT_AUTOPATCH: Partial fix applied but issues remain: {recheck}")
            except Exception as patch_err:
                print(f"⚠️ DIALECT_AUTOPATCH: Failed to apply autopatch: {patch_err}")

    if dialect_issues:
        if not state.get("de_dialect_retry_done"):
            new_state = dict(state)
            new_state["de_dialect_retry_done"] = True
            new_state["de_dialect_autopatched"] = True  # Mark that autopatch was attempted
            payload = "DIALECT_GUARD:\n" + "\n".join(str(item) for item in dialect_issues if str(item).strip())
            _merge_de_override_with_feedback_record(
                new_state,
                base_override=state.get("data_engineer_audit_override") or state.get("data_summary", ""),
                payload=payload,
                source="dialect_guard",
                status="REJECTED",
                iteration=int(attempt_id),
                feedback="CSV dialect compliance failed in generated cleaning code.",
                failed_gates=["dialect_loading_missing"],
                required_fixes=list(dialect_issues),
                hard_failures=["dialect_loading_missing"],
                runtime_error_tail="\n".join(dialect_issues)[:1400],
                evidence=[{"claim": "Dialect guard found missing/wrong read_csv dialect parameters.", "source": "dialect_guard"}],
            )
            print("⚠️ DIALECT_GUARD: retrying Data Engineer with enforced dialect instructions.")
            return run_data_engineer(new_state)
        else:
            if run_id:
                log_run_event(run_id, "pipeline_aborted_reason", {"reason": "data_engineer_dialect_guard"})
            oc_report = _persist_output_contract_report(state, reason="data_engineer_dialect_guard")
            return {
                "cleaning_code": code,
                "cleaned_data_preview": "Error: Dialect Guard",
                "error_message": "CRITICAL: pd.read_csv must use provided dialect parameters.",
                "output_contract_report": oc_report,
                "pipeline_aborted_reason": "data_engineer_dialect_guard",
                "data_engineer_failed": True,
                "budget_counters": counters,
            }

    # Execute in E2B Sandbox
    de_output_path, de_manifest_path, _ = _resolve_de_output_artifacts(state if isinstance(state, dict) else {})
    if not de_output_path or not de_manifest_path:
        msg = (
            "DE_VIEW_OUTPUTS_MISSING: de_view.output_path and de_view.output_manifest_path "
            "must be present in contract-derived views."
        )
        if run_id:
            log_run_event(run_id, "pipeline_aborted_reason", {"reason": "de_view_outputs_missing"})
        oc_report = _persist_output_contract_report(state, reason="de_view_outputs_missing")
        return {
            "cleaning_code": code,
            "cleaned_data_preview": "Error: Missing DE View Outputs",
            "error_message": msg,
            "output_contract_report": oc_report,
            "pipeline_aborted_reason": "de_view_outputs_missing",
            "data_engineer_failed": True,
            "budget_counters": counters,
        }
    try:
        local_cleaned_path = de_output_path
        local_manifest_path = de_manifest_path
        output_log = ""
        downloaded_cleaned_content = None
        downloaded_paths: List[str] = []
        if is_plan:
            try:
                plan_exec = dict(plan_payload or {})
                input_cfg = plan_exec.get("input")
                if not isinstance(input_cfg, dict):
                    input_cfg = {}
                input_cfg["path"] = csv_path
                plan_exec["input"] = input_cfg
                dialect_cfg = plan_exec.get("dialect")
                if not isinstance(dialect_cfg, dict):
                    dialect_cfg = {}
                dialect_cfg.setdefault("sep", csv_sep)
                dialect_cfg.setdefault("decimal", csv_decimal)
                dialect_cfg.setdefault("encoding", csv_encoding)
                plan_exec["dialect"] = dialect_cfg
                result = execute_cleaning_plan(plan_exec, state.get("execution_contract", {}) or {})
                local_cleaned_path = result.get("cleaned_path", local_cleaned_path)
                local_manifest_path = result.get("manifest_path", local_manifest_path)
                csv_sep, csv_decimal, csv_encoding, dialect_updated = get_output_dialect_from_manifest(
                    local_manifest_path, csv_sep, csv_decimal, csv_encoding
                )
                if dialect_updated:
                    print(f"Downstream dialect updated from output_dialect: sep={csv_sep}, decimal={csv_decimal}, encoding={csv_encoding}")
            except Exception as plan_err:
                msg = f"Host Cleaning Plan Failed: {plan_err}"
                return {"cleaning_code": code, "cleaned_data_preview": "Error: Plan Failed", "error_message": msg, "budget_counters": counters}
        else:
            if not de_heavy_cfg:
                if runtime_mode == "local":
                    msg = "LOCAL_RUNNER_REQUIRED: local execution mode enabled but local runner configuration is unavailable."
                    abort_reason = "data_engineer_local_runner_config_missing"
                    preview_text = "Error: Local Runner Required"
                else:
                    msg = (
                        "CLOUDRUN_REQUIRED: Data Engineer execution is configured for Cloud Run only, "
                        "but heavy runner configuration is missing."
                    )
                    abort_reason = "data_engineer_cloudrun_config_missing"
                    preview_text = "Error: Cloud Run Required"
                if run_id:
                    log_run_event(
                        run_id,
                        "pipeline_aborted_reason",
                        {"reason": abort_reason},
                    )
                return {
                    "cleaning_code": code,
                    "cleaned_data_preview": preview_text,
                    "error_message": msg,
                    "pipeline_aborted_reason": abort_reason,
                    "data_engineer_failed": True,
                    "budget_counters": counters,
                }

            if runtime_mode == "local":
                print(f"    Backend: Local Runner (DE, reason={de_heavy_reason})")
            else:
                print(f"    Backend: Cloud Run Heavy Runner (DE, reason={de_heavy_reason})")
            de_heavy_result = _execute_data_engineer_via_heavy_runner(
                state=state,
                code=code,
                csv_path=csv_path,
                csv_sep=csv_sep,
                csv_decimal=csv_decimal,
                csv_encoding=csv_encoding,
                heavy_cfg=de_heavy_cfg,
                run_id=run_id,
                attempt_id=attempt_id,
                reason=de_heavy_reason,
            )
            if de_heavy_result.get("unavailable"):
                heavy_error = str(
                    de_heavy_result.get("error_details")
                    or "HEAVY_RUNNER_UNAVAILABLE: cloudrun execution unavailable."
                )
                if run_id:
                    log_run_event(
                        run_id,
                        "pipeline_aborted_reason",
                        {"reason": "data_engineer_cloudrun_unavailable"},
                    )
                return {
                    "cleaning_code": code,
                    "cleaned_data_preview": "Error: Cloud Run Unavailable",
                    "error_message": heavy_error,
                    "pipeline_aborted_reason": "data_engineer_cloudrun_unavailable",
                    "data_engineer_failed": True,
                    "budget_counters": counters,
                }
            if not de_heavy_result.get("ok"):
                heavy_error = str(
                    de_heavy_result.get("error_details")
                    or "HEAVY_RUNNER_ERROR: data engineer execution failed."
                )
                heavy_payload = de_heavy_result.get("heavy_result") if isinstance(de_heavy_result, dict) else {}
                heavy_script_error = heavy_payload.get("error") if isinstance(heavy_payload, dict) else None
                error_kind_hint = str(de_heavy_result.get("error_kind_hint") or "").strip().lower()
                if error_kind_hint.startswith("infra"):
                    heavy_error_kind = "infra"
                elif isinstance(heavy_script_error, dict):
                    script_error_name = str(heavy_script_error.get("error") or "").strip().lower()
                    has_trace = bool(
                        str(heavy_script_error.get("stacktrace") or "").strip()
                        or str(heavy_script_error.get("traceback") or "").strip()
                    )
                    heavy_error_kind = "code" if (has_trace or script_error_name in {"script_execution_failed", "runtime_error"}) else "infra"
                else:
                    heavy_error_kind = "code" if heavy_script_error else "infra"
                runtime_error_text = ""
                if isinstance(heavy_script_error, dict):
                    runtime_error_text = "\n".join(
                        item
                        for item in [
                            str(heavy_script_error.get("error") or "").strip(),
                            str(heavy_script_error.get("stacktrace") or "").strip(),
                        ]
                        if item
                    )
                elif heavy_script_error:
                    runtime_error_text = str(heavy_script_error)
                if not runtime_error_text:
                    runtime_error_text = heavy_error

                if heavy_error_kind == "code":
                    repaired_code, repair_notes = _attempt_de_local_syntax_repair(code, runtime_error_text)
                    if repaired_code and repaired_code != code:
                        if run_id:
                            log_run_event(
                                run_id,
                                "data_engineer_local_syntax_repair_retry",
                                {
                                    "attempt": attempt_id,
                                    "notes": repair_notes[:12],
                                },
                            )
                        try:
                            os.makedirs("artifacts", exist_ok=True)
                            with open(
                                os.path.join("artifacts", "data_engineer_last_syntax_repaired.py"),
                                "w",
                                encoding="utf-8",
                            ) as f_rep:
                                f_rep.write(repaired_code)
                        except Exception as rep_err:
                            print(f"Warning: failed to persist syntax repaired DE script: {rep_err}")
                        print("DE syntax recovery: retrying same script after local deterministic repair.")
                        retry_reason = (
                            f"{de_heavy_reason}|local_syntax_repair"
                            if de_heavy_reason
                            else "local_syntax_repair"
                        )
                        retry_result = _execute_data_engineer_via_heavy_runner(
                            state=state,
                            code=repaired_code,
                            csv_path=csv_path,
                            csv_sep=csv_sep,
                            csv_decimal=csv_decimal,
                            csv_encoding=csv_encoding,
                            heavy_cfg=de_heavy_cfg,
                            run_id=run_id,
                            attempt_id=attempt_id,
                            reason=retry_reason,
                        )
                        if retry_result.get("ok"):
                            code = repaired_code
                            de_heavy_result = retry_result
                            if run_id:
                                log_run_event(
                                    run_id,
                                    "data_engineer_local_syntax_repair_success",
                                    {"attempt": attempt_id},
                                )
                        else:
                            de_heavy_result = retry_result
                            heavy_error = str(
                                de_heavy_result.get("error_details")
                                or "HEAVY_RUNNER_ERROR: data engineer execution failed."
                            )
                            heavy_payload = (
                                de_heavy_result.get("heavy_result")
                                if isinstance(de_heavy_result, dict)
                                else {}
                            )
                            heavy_script_error = (
                                heavy_payload.get("error") if isinstance(heavy_payload, dict) else None
                            )
                            error_kind_hint = str(de_heavy_result.get("error_kind_hint") or "").strip().lower()
                            if error_kind_hint.startswith("infra"):
                                heavy_error_kind = "infra"
                            elif isinstance(heavy_script_error, dict):
                                script_error_name = str(heavy_script_error.get("error") or "").strip().lower()
                                has_trace = bool(
                                    str(heavy_script_error.get("stacktrace") or "").strip()
                                    or str(heavy_script_error.get("traceback") or "").strip()
                                )
                                heavy_error_kind = "code" if (has_trace or script_error_name in {"script_execution_failed", "runtime_error"}) else "infra"
                            else:
                                heavy_error_kind = "code" if heavy_script_error else "infra"
                            runtime_error_text = ""
                            if isinstance(heavy_script_error, dict):
                                runtime_error_text = "\n".join(
                                    item
                                    for item in [
                                        str(heavy_script_error.get("error") or "").strip(),
                                        str(heavy_script_error.get("stacktrace") or "").strip(),
                                    ]
                                    if item
                                )
                            elif heavy_script_error:
                                runtime_error_text = str(heavy_script_error)
                            if not runtime_error_text:
                                runtime_error_text = heavy_error

                if (
                    not de_heavy_result.get("ok")
                    and heavy_error_kind == "code"
                    and not _flag_active_for_run(state, "de_runtime_retry_done", run_id)
                ):
                    new_state = dict(state)
                    new_state["de_runtime_retry_done"] = True
                    if run_id:
                        new_state["de_runtime_retry_done_run_id"] = run_id
                    new_state["execution_error_message"] = runtime_error_text[-4000:]
                    base_override = state.get("data_engineer_audit_override") or state.get("data_summary", "")
                    error_snippet = _extract_error_snippet(code, runtime_error_text)
                    traceback_tail = _tail_lines(runtime_error_text, 20)
                    payload = "RUNTIME_ERROR_CONTEXT:\n" + runtime_error_text[-3000:]
                    if traceback_tail:
                        payload += "\n\nTRACEBACK_TAIL_20:\n" + traceback_tail
                    if error_snippet:
                        payload += "\n\nERROR_SNIPPET:\n" + error_snippet
                    failure_cause = _infer_de_failure_cause(runtime_error_text)
                    if failure_cause:
                        payload += "\nWHY_IT_HAPPENED: " + failure_cause
                    diagnosis_lines = _build_de_runtime_diagnosis(runtime_error_text)
                    if diagnosis_lines:
                        payload += "\nERROR_DIAGNOSIS:\n- " + "\n- ".join(diagnosis_lines)
                    de_view_for_hints = state.get("de_view") if isinstance(state.get("de_view"), dict) else {}
                    gate_hints = _build_de_gate_implementation_hints(de_view_for_hints.get("cleaning_gates"))
                    if gate_hints:
                        payload += "\nGATE_IMPLEMENTATION_HINTS:\n- " + "\n- ".join(gate_hints)
                    try:
                        runtime_record = {
                            "agent": "data_engineer",
                            "status": "RUNTIME_ERROR",
                            "source": "heavy_runner_code",
                            "error_tail": runtime_error_text[-1200:],
                            "root_cause": failure_cause if 'failure_cause' in locals() else "",
                            "diagnosis": diagnosis_lines if 'diagnosis_lines' in locals() else [],
                            "required_fixes": gate_hints if gate_hints else [],
                        }
                        payload += "\n\nITERATION_FEEDBACK_RECORD_JSON:\n" + json.dumps(runtime_record, ensure_ascii=True)
                    except Exception:
                        pass
                    try:
                        required_input = _resolve_required_input_columns(
                            state.get("execution_contract", {}), selected
                        )
                        header_cols = _read_csv_header(csv_path, csv_encoding, csv_sep)
                        norm_map = {}
                        for col in header_cols:
                            normed = _norm_name(col)
                            if normed and normed not in norm_map:
                                norm_map[normed] = col
                        required_raw_map = _build_required_raw_map(required_input, norm_map)
                        explainer_ctx = {
                            "strategy_title": selected.get("title", "") if selected else "",
                            "csv_dialect": input_dialect,
                            "required_input_columns": required_input,
                            "required_raw_header_map": required_raw_map,
                            "error_snippet": error_snippet,
                            "runtime_backend": "local_runner" if runtime_mode == "local" else "cloudrun_heavy_runner",
                            "runtime_mode": "data_engineer_cleaning",
                        }
                        explainer_text = failure_explainer.explain_data_engineer_failure(
                            code=code,
                            error_details=runtime_error_text,
                            context=explainer_ctx,
                        )
                        if explainer_text:
                            payload += "\nLLM_FAILURE_EXPLANATION:\n" + explainer_text.strip()
                            try:
                                os.makedirs("artifacts", exist_ok=True)
                                with open(
                                    os.path.join("artifacts", "data_engineer_failure_explainer.txt"),
                                    "w",
                                    encoding="utf-8",
                                ) as f_exp:
                                    f_exp.write(explainer_text.strip())
                            except Exception as exp_err:
                                print(
                                    f"Warning: failed to persist data_engineer_failure_explainer.txt: {exp_err}"
                                )
                    except Exception as explainer_err:
                        print(f"Warning: heavy-runner DE failure explainer failed: {explainer_err}")
                    _merge_de_override_with_feedback_record(
                        new_state,
                        base_override=base_override,
                        payload=payload,
                        source="runtime_heavy_runner_code",
                        status="REJECTED",
                        iteration=int(attempt_id),
                        feedback="Data Engineer runtime failure detected in heavy runner execution.",
                        failed_gates=["runtime_failure"],
                        required_fixes=[str(item) for item in (gate_hints or []) if str(item).strip()],
                        hard_failures=["runtime_failure"],
                        runtime_error_tail=str(runtime_error_text or "")[-1400:],
                        evidence=[
                            {
                                "claim": "Heavy runner reported runtime code error.",
                                "source": "heavy_runner_error",
                            }
                        ],
                    )
                    print("Runtime error guard (heavy runner code): retrying Data Engineer with error context.")
                    if run_id:
                        log_run_event(
                            run_id,
                            "data_engineer_runtime_retry",
                            {
                                "attempt": attempt_id,
                                "source": "heavy_runner_code",
                                "error_kind": heavy_error_kind,
                            },
                        )
                    return run_data_engineer(new_state)

                if not de_heavy_result.get("ok"):
                    return {
                        "cleaning_code": code,
                        "cleaned_data_preview": "Error: Cleaning Failed",
                        "error_message": heavy_error,
                        "budget_counters": counters,
                    }

            if os.path.exists(local_cleaned_path):
                try:
                    with open(local_cleaned_path, "rb") as f_local:
                        downloaded_cleaned_content = f_local.read()
                except Exception:
                    downloaded_cleaned_content = None
                downloaded_paths.append(local_cleaned_path)
            if os.path.exists(local_manifest_path):
                downloaded_paths.append(local_manifest_path)
            heavy_outlier_path = str(de_heavy_result.get("outlier_report_path") or de_outlier_report_path or "").strip()
            if heavy_outlier_path and os.path.exists(heavy_outlier_path):
                downloaded_paths.append(heavy_outlier_path)
                de_outlier_report_path = heavy_outlier_path
            csv_sep, csv_decimal, csv_encoding, dialect_updated = get_output_dialect_from_manifest(
                local_manifest_path, csv_sep, csv_decimal, csv_encoding
            )
            if dialect_updated:
                print(
                    f"Downstream dialect updated from output_dialect: sep={csv_sep}, decimal={csv_decimal}, encoding={csv_encoding}"
                )
            run_e2b_after_heavy = False
            if not run_e2b_after_heavy and isinstance(de_heavy_result, dict) and not de_heavy_result.get("ok"):
                heavy_error = str(
                    de_heavy_result.get("error_details")
                    or "HEAVY_RUNNER_ERROR: data engineer execution failed."
                )
                print("HEAVY_RUNNER_DE_FAILED: skipping E2B fallback for this iteration.")
                return {
                    "cleaning_code": code,
                    "cleaned_data_preview": "Error: Cleaning Failed",
                    "error_message": heavy_error,
                    "budget_counters": counters,
                }

            if run_e2b_after_heavy and not (isinstance(de_heavy_result, dict) and de_heavy_result.get("ok")):
                # load_dotenv() is called at module level or main
                api_key = os.getenv("E2B_API_KEY")
                if not api_key:
                    msg = "CRITICAL: E2B_API_KEY missing in .env file."
                    return {"error_message": msg, "cleaned_data_preview": "Error: Missing E2B Key", "budget_counters": counters}

                os.environ["E2B_API_KEY"] = api_key

            step_name = "data_engineer"
            for sb_attempt in range(2):
              if isinstance(de_heavy_result, dict) and de_heavy_result.get("ok"):
                break
              try:
                with create_sandbox_with_retry(Sandbox, max_attempts=2, run_id=run_id, step="data_engineer") as sandbox:
                    if not hasattr(sandbox, "commands"):
                        raise RuntimeError(
                            "E2B Sandbox missing commands runner. Ensure sandbox supports commands.run."
                        )
                    run_root = f"/home/user/run/{run_id}/{step_name}/attempt_{attempt_id}"
                    # 1. Setup Environment
                    print("Installing dependencies in Sandbox...")
                    run_cmd_with_retry(sandbox, "pip install pandas numpy", retries=2)
                    run_cmd_with_retry(sandbox, f"rm -rf {run_root}", retries=2)
                    run_cmd_with_retry(sandbox, f"mkdir -p {run_root}/data", retries=2)

                    # 2. Upload Raw Data (P2.1: Use canonical path + aliases)
                    remote_raw_abs = canonical_abs(run_root, CANONICAL_RAW_REL)
                    print(f"Uploading {csv_path} to sandbox at {CANONICAL_RAW_REL}...")
                    with open(csv_path, "rb") as f:
                        sandbox.files.write(remote_raw_abs, f)

                    # 2.5 Create aliases for raw data (P2.1)
                    alias_commands = build_symlink_or_copy_commands(
                        run_root,
                        canonical_rel=CANONICAL_RAW_REL,
                        aliases=COMMON_RAW_ALIASES
                    )
                    if alias_commands:
                        print(f"Creating {len(alias_commands)} raw data aliases...")
                        full_cmd = " && ".join(alias_commands)
                        run_cmd_with_retry(sandbox, f"sh -c 'cd {run_root} && {full_cmd}'")
                        print(f"SANDBOX_INPUT_CANONICAL: {CANONICAL_RAW_REL}")
                        print(f"SANDBOX_INPUT_ALIASES: {COMMON_RAW_ALIASES}")

                    # 2.5 Upload Execution Contract (best-effort)
                    local_contract_path = "data/execution_contract.json"
                    if os.path.exists(local_contract_path):
                        try:
                            with open(local_contract_path, "rb") as f:
                                sandbox.files.write(f"{run_root}/data/execution_contract.json", f)
                        except Exception as contract_err:
                            print(f"Warning: failed to upload execution_contract.json: {contract_err}")
                    # 2.6 Upload context artifacts used by DE logic (best-effort)
                    context_artifacts = [
                        "data/column_inventory.json",
                        "data/column_sets.json",
                        "data/required_columns.json",
                        "data/dataset_semantics.json",
                        "data/dataset_training_mask.json",
                        "data/execution_contract.json",
                    ]
                    for local_path in context_artifacts:
                        if not os.path.exists(local_path):
                            continue
                        remote_path = (
                            f"{run_root}/{local_path}"
                            if local_path.startswith("data/")
                            else f"{run_root}/data/{os.path.basename(local_path)}"
                        )
                        try:
                            with open(local_path, "rb") as f:
                                sandbox.files.write(remote_path, f)
                        except Exception as ctx_err:
                            print(f"Warning: failed to upload {local_path}: {ctx_err}")

                    # 3. Execute Cleaning (P2.1: Patch placeholders + minimal backward compat)
                    code = patch_placeholders(code, data_rel=CANONICAL_RAW_REL)
                    working_dir_injection = (
                        "import os\n"
                        f"os.makedirs(r\"{run_root}\", exist_ok=True)\n"
                        f"os.chdir(r\"{run_root}\")\n"
                    )
                    code = working_dir_injection + code
                    print("Executing Cleaning Script in Sandbox...")
                    script_path = f"{run_root}/cleaning.py"
                    sandbox.files.write(script_path, code)
                    execution = run_python_file_with_optional_timeout(
                        sandbox,
                        script_path,
                        timeout_s=DE_TIMEOUT_S,
                        workdir=run_root,
                    )

                    # Capture Output
                    stdout_text = "\n".join(execution.logs.stdout or [])
                    stderr_text = "\n".join(execution.logs.stderr or [])
                    output_log = ""
                    if stdout_text:
                        output_log += stdout_text
                    if stderr_text:
                        output_log += stderr_text
                    try:
                        os.makedirs("artifacts", exist_ok=True)
                        with open(os.path.join("artifacts", "data_engineer_sandbox_last.log"), "w", encoding="utf-8") as f_log:
                            f_log.write(output_log or "")
                    except Exception as log_err:
                        print(f"Warning: failed to persist data_engineer_sandbox_last.log: {log_err}")

                    remote_cleaned_rel = local_cleaned_path.lstrip("/").replace("\\", "/")
                    remote_manifest_rel = local_manifest_path.lstrip("/").replace("\\", "/")

                    if execution.error:
                        error_details = f"{execution.error.name}: {execution.error.value}\n{execution.error.traceback}"
                        print(f"Cleaning Failed in Sandbox: {error_details}")
                        error_payload = {
                            "stage": "execution_error",
                            "exception_type": execution.error.name,
                            "exception_msg": execution.error.value,
                            "traceback": execution.error.traceback,
                            "attempt": attempt_id,
                        }
                        try:
                            os.makedirs("artifacts", exist_ok=True)
                            with open(
                                os.path.join("artifacts", "data_engineer_sandbox_last_error.json"),
                                "w",
                                encoding="utf-8",
                            ) as f_err:
                                json.dump(error_payload, f_err, indent=2, ensure_ascii=True)
                        except Exception as err:
                            print(f"Warning: failed to persist data_engineer_sandbox_last_error.json: {err}")
                        outputs_listing = []
                        try:
                            listing_proc = sandbox.commands.run(
                                f"sh -c 'cd {run_root} && find . -maxdepth 4 -type f -printf \"%p\\t%s\\n\" 2>/dev/null'"
                            )
                            if listing_proc.exit_code == 0:
                                outputs_listing = [line for line in listing_proc.stdout.splitlines() if line.strip()]
                        except Exception:
                            outputs_listing = []
                        if run_id:
                            log_sandbox_attempt(
                                run_id,
                                step_name,
                                attempt_id,
                                code=code,
                                stdout=stdout_text,
                                stderr=stderr_text,
                                outputs_listing=outputs_listing,
                                downloaded_paths=[],
                                exit_code=getattr(execution, "exit_code", None),
                                error_tail=execution.error.traceback if execution.error else None,
                                success=False,
                                stage="execution_error",
                                exception_type=execution.error.name,
                                exception_msg=str(execution.error.value),
                            )
                        memory_error_detected = _is_memory_pressure_error(error_details)
                        can_try_heavy_after_memory_error = bool(
                            de_heavy_cfg
                            and _env_flag("HEAVY_RUNNER_DE_ENABLED", True)
                            and not state.get("heavy_runner_unavailable")
                        )
                        if memory_error_detected and can_try_heavy_after_memory_error and not _flag_active_for_run(
                            state,
                            "de_memory_backend_retry_done",
                            run_id,
                        ):
                                new_state = dict(state)
                                new_state["de_memory_backend_retry_done"] = True
                                if run_id:
                                    new_state["de_memory_backend_retry_done_run_id"] = run_id
                                new_state["de_e2b_memory_failure_detected"] = True
                                new_state["de_force_heavy_runner"] = True
                                new_state["execution_error_message"] = error_details[-4000:]
                                if run_id:
                                    log_run_event(
                                        run_id,
                                        "data_engineer_backend_escalation",
                                        {
                                            "source_backend": "e2b",
                                            "target_backend": "heavy_runner",
                                            "reason": "memory_pressure",
                                            "attempt": attempt_id,
                                        },
                                    )
                                print("Memory fallback: retrying Data Engineer on Cloud Run heavy runner.")
                                return run_data_engineer(new_state)
                        contract = state.get("execution_contract", {}) or {}
                        derived_cols = _resolve_contract_columns(contract, sources={"derived", "output"})
                        if "Missing required columns" in error_details and derived_cols and not state.get("de_missing_derived_retry_done"):
                                new_state = dict(state)
                                new_state["de_missing_derived_retry_done"] = True
                                payload = (
                                    "DERIVED_COLUMN_MISSING_GUARD:\n"
                                    f"{derived_cols} are derived. Do not treat them as required input columns. "
                                    "Only enforce source='input' columns after canonicalization; derive the rest."
                                )
                                _merge_de_override_with_feedback_record(
                                    new_state,
                                    base_override=state.get("data_engineer_audit_override") or state.get("data_summary", ""),
                                    payload=payload,
                                    source="derived_column_missing_guard",
                                    status="REJECTED",
                                    iteration=int(attempt_id),
                                    feedback="Derived columns were treated as mandatory raw input columns.",
                                    failed_gates=["derived_columns_as_required_input"],
                                    required_fixes=[
                                        "Treat derived columns as computed outputs, not mandatory raw input columns.",
                                        "Validate required input columns only from source='input' scope.",
                                    ],
                                    runtime_error_tail=str(error_details or "")[-1400:],
                                    evidence=[{"claim": "Missing required columns error referenced derived columns.", "source": "runtime_error"}],
                                )
                                print("Derived column missing guard: retrying Data Engineer with derived-column guidance.")
                                return run_data_engineer(new_state)
                        if "actual_column" in error_details and "NoneType" in error_details and not state.get("de_actual_column_guard_retry_done"):
                                new_state = dict(state)
                                new_state["de_actual_column_guard_retry_done"] = True
                                payload = (
                                    "VALIDATION_PRINT_GUARD:\n"
                                    "Use actual = str(result.get('actual_column') or 'MISSING') "
                                    "before slicing; do not subscript None."
                                )
                                _merge_de_override_with_feedback_record(
                                    new_state,
                                    base_override=state.get("data_engineer_audit_override") or state.get("data_summary", ""),
                                    payload=payload,
                                    source="validation_print_guard",
                                    status="REJECTED",
                                    iteration=int(attempt_id),
                                    feedback="Validation formatting attempted to subscript None actual_column.",
                                    failed_gates=["none_safe_validation_formatting"],
                                    required_fixes=[
                                        "Guard actual_column extraction with None-safe conversion before slicing.",
                                    ],
                                    runtime_error_tail=str(error_details or "")[-1400:],
                                    evidence=[{"claim": "NoneType actual_column formatting issue detected.", "source": "runtime_error"}],
                                )
                                print("Validation print guard: retrying Data Engineer with None-safe formatting.")
                                return run_data_engineer(new_state)
                        if "AttributeError" in error_details and "DataFrame" in error_details and "dtype" in error_details:
                                if not state.get("de_dtype_guard_retry_done"):
                                    new_state = dict(state)
                                    new_state["de_dtype_guard_retry_done"] = True
                                    payload = (
                                        "DUPLICATE_COLUMN_GUARD:\n"
                                        "When reading dtype, handle duplicate column labels. "
                                        "Use series = df[actual_col]; if isinstance(series, pd.DataFrame), "
                                        "use series = series.iloc[:, 0] and log a warning."
                                    )
                                    _merge_de_override_with_feedback_record(
                                        new_state,
                                        base_override=state.get("data_engineer_audit_override") or state.get("data_summary", ""),
                                        payload=payload,
                                        source="duplicate_column_dtype_guard",
                                        status="REJECTED",
                                        iteration=int(attempt_id),
                                        feedback="Duplicate-column dtype handling guard triggered.",
                                        failed_gates=["duplicate_column_dtype_handling"],
                                        required_fixes=[
                                            "Handle duplicate-label DataFrame returns before dtype checks.",
                                        ],
                                        runtime_error_tail=str(error_details or "")[-1400:],
                                        evidence=[{"claim": "AttributeError DataFrame has no dtype in validation path.", "source": "runtime_error"}],
                                    )
                                    print("Duplicate column dtype guard: retrying Data Engineer.")
                                    return run_data_engineer(new_state)
                        error_snippet = _extract_error_snippet(code, error_details)
                        reviewer_payload = ""
                        reviewer_result = None
                        review_context_payload = None
                        reviewer_done = False
                        runtime_reviewer_done = _flag_active_for_run(state, "de_runtime_reviewer_done", run_id)
                        if cleaning_reviewer and not runtime_reviewer_done:
                                try:
                                    failure_context = {
                                        "error_details": error_details,
                                        "code": code,
                                        "code_snippet": error_snippet,
                                        "stdout": stdout_text,
                                        "stderr": stderr_text,
                                        "attempt": attempt_id,
                                    }
                                    if run_id:
                                        log_run_event(
                                            run_id,
                                            "cleaning_reviewer_runtime_start",
                                            {"attempt": attempt_id, "has_snippet": bool(error_snippet)},
                                        )
                                    cleaning_view = state.get("cleaning_view") or (state.get("contract_views") or {}).get("cleaning_view")
                                    # Load cleaning code for intent verification by reviewer
                                    cleaning_code_for_reviewer = None
                                    try:
                                        de_code_path = os.path.join("artifacts", "data_engineer_last.py")
                                        if os.path.exists(de_code_path):
                                            with open(de_code_path, "r", encoding="utf-8") as f_code:
                                                cleaning_code_for_reviewer = f_code.read()
                                    except Exception:
                                        cleaning_code_for_reviewer = None
                                    if cleaning_view:
                                        cleaning_view_copy = dict(cleaning_view)
                                        if isinstance(input_dialect, dict):
                                            cleaning_view_copy["input_dialect"] = input_dialect
                                        if cleaning_code_for_reviewer:
                                            cleaning_view_copy["cleaning_code"] = cleaning_code_for_reviewer
                                        cleaning_view_copy = compress_long_lists(cleaning_view_copy)[0]
                                        reviewer_result = cleaning_reviewer.review_cleaning(
                                            cleaning_view_copy,
                                            cleaned_csv_path=local_cleaned_path,
                                            cleaning_manifest_path=local_manifest_path,
                                            raw_csv_path=csv_path,
                                            failure_context=failure_context,
                                        )
                                        review_context_payload = cleaning_view_copy
                                    else:
                                        contract = state.get("execution_contract", {}) or {}
                                        review_context = {
                                            "cleaning_view": {},
                                            "cleaning_gates": contract.get("cleaning_gates")
                                            or [],
                                            "required_columns": _resolve_required_input_columns(contract, selected),
                                            "dialect": input_dialect,
                                            "column_roles": contract.get("column_roles") if isinstance(contract, dict) else {},
                                        }
                                        if cleaning_code_for_reviewer:
                                            review_context["cleaning_code"] = cleaning_code_for_reviewer
                                        review_context = compress_long_lists(review_context)[0]
                                        reviewer_result = cleaning_reviewer.review_cleaning(
                                            review_context,
                                            failure_context=failure_context,
                                        )
                                        review_context_payload = review_context
                                    if run_id:
                                        log_run_event(
                                            run_id,
                                            "cleaning_reviewer_runtime_complete",
                                            {"status": reviewer_result.get("status") if isinstance(reviewer_result, dict) else None},
                                        )
                                    try:
                                        os.makedirs("artifacts", exist_ok=True)
                                        with open(
                                            os.path.join("artifacts", "cleaning_reviewer_failure_report.json"),
                                            "w",
                                            encoding="utf-8",
                                        ) as f_rep:
                                            json.dump(reviewer_result, f_rep, indent=2, ensure_ascii=False)
                                    except Exception:
                                        pass
                                    if run_id:
                                        log_agent_snapshot(
                                            run_id,
                                            "cleaning_reviewer",
                                            prompt=getattr(cleaning_reviewer, "last_prompt", None),
                                            response=getattr(cleaning_reviewer, "last_response", None) or reviewer_result,
                                            context=review_context_payload,
                                            verdicts=reviewer_result,
                                        )
                                except Exception as review_err:
                                    print(f"Warning: cleaning reviewer runtime audit failed: {review_err}")
                                    if run_id:
                                        log_run_event(
                                            run_id,
                                            "cleaning_reviewer_runtime_failed",
                                            {"error": str(review_err)},
                                        )
                        if isinstance(reviewer_result, dict):
                                reviewer_done = True
                                fixes = reviewer_result.get("required_fixes", [])
                                fixes_text = ""
                                if isinstance(fixes, list) and fixes:
                                    fixes_text = "\nREQUIRED_FIXES:\n- " + "\n- ".join(str(item) for item in fixes)
                                reviewer_payload = (
                                    "CLEANING_REVIEWER_FAILURE_CONTEXT:\n"
                                    + str(reviewer_result.get("feedback", "")).strip()
                                    + fixes_text
                                )
                        if not _flag_active_for_run(state, "de_runtime_retry_done", run_id):
                                new_state = dict(state)
                                new_state["de_runtime_retry_done"] = True
                                if run_id:
                                    new_state["de_runtime_retry_done_run_id"] = run_id
                                new_state["execution_error_message"] = error_details[-4000:]
                                if reviewer_done:
                                    new_state["de_runtime_reviewer_done"] = True
                                if run_id:
                                    new_state["de_runtime_reviewer_done_run_id"] = run_id
                                error_snippet = _extract_error_snippet(code, error_details)
                                payload = "RUNTIME_ERROR_CONTEXT:\n" + error_details[-2000:]
                                traceback_tail = _tail_lines(error_details, 20)
                                if traceback_tail:
                                    payload += "\n\nTRACEBACK_TAIL_20:\n" + traceback_tail
                                if error_snippet:
                                    payload += "\n\nERROR_SNIPPET:\n" + error_snippet
                                try:
                                    if reviewer_payload:
                                        payload += "\n\n" + reviewer_payload
                                    failure_cause = _infer_de_failure_cause(error_details)
                                    if failure_cause:
                                        payload += "\nWHY_IT_HAPPENED: " + failure_cause
                                    diagnosis_lines = _build_de_runtime_diagnosis(error_details)
                                    if diagnosis_lines:
                                        payload += "\nERROR_DIAGNOSIS:\n- " + "\n- ".join(diagnosis_lines)
                                    de_view_for_hints = state.get("de_view") if isinstance(state.get("de_view"), dict) else {}
                                    gate_hints = _build_de_gate_implementation_hints(de_view_for_hints.get("cleaning_gates"))
                                    if gate_hints:
                                        payload += "\nGATE_IMPLEMENTATION_HINTS:\n- " + "\n- ".join(gate_hints)
                                    try:
                                        runtime_record = {
                                            "agent": "data_engineer",
                                            "status": "RUNTIME_ERROR",
                                            "source": "sandbox_execute",
                                            "error_tail": error_details[-1200:],
                                            "root_cause": failure_cause if 'failure_cause' in locals() else "",
                                            "diagnosis": diagnosis_lines if 'diagnosis_lines' in locals() else [],
                                            "required_fixes": gate_hints if gate_hints else [],
                                        }
                                        payload += (
                                            "\n\nITERATION_FEEDBACK_RECORD_JSON:\n"
                                            + json.dumps(runtime_record, ensure_ascii=True)
                                        )
                                    except Exception:
                                        pass
                                    explainer_text = ""
                                    try:
                                        required_input = _resolve_required_input_columns(state.get("execution_contract", {}), selected)
                                        header_cols = _read_csv_header(csv_path, csv_encoding, csv_sep)
                                        norm_map = {}
                                        for col in header_cols:
                                            normed = _norm_name(col)
                                            if normed and normed not in norm_map:
                                                norm_map[normed] = col
                                        required_raw_map = _build_required_raw_map(required_input, norm_map)
                                        explainer_ctx = {
                                            "strategy_title": selected.get("title", "") if selected else "",
                                            "csv_dialect": input_dialect,
                                            "required_input_columns": required_input,
                                            "required_raw_header_map": required_raw_map,
                                            "error_snippet": error_snippet,
                                        }
                                        explainer_text = failure_explainer.explain_data_engineer_failure(
                                            code=code,
                                            error_details=error_details,
                                            context=explainer_ctx,
                                        )
                                    except Exception as explainer_err:
                                        print(f"Warning: failure explainer failed: {explainer_err}")
                                        explainer_text = ""
                                    if explainer_text:
                                        payload += "\nLLM_FAILURE_EXPLANATION:\n" + explainer_text.strip()
                                        try:
                                            os.makedirs("artifacts", exist_ok=True)
                                            with open(
                                                os.path.join("artifacts", "data_engineer_failure_explainer.txt"),
                                                "w",
                                                encoding="utf-8",
                                            ) as f_exp:
                                                f_exp.write(explainer_text.strip())
                                        except Exception as exp_err:
                                            print(f"Warning: failed to persist data_engineer_failure_explainer.txt: {exp_err}")
                                except Exception:
                                    pass
                                _merge_de_override_with_feedback_record(
                                    new_state,
                                    base_override=state.get("data_engineer_audit_override") or state.get("data_summary", ""),
                                    payload=payload,
                                    source="runtime_sandbox_execute",
                                    status="REJECTED",
                                    iteration=int(attempt_id),
                                    feedback="Data Engineer runtime failure detected in sandbox execution.",
                                    failed_gates=["runtime_failure"],
                                    required_fixes=[str(item) for item in (gate_hints or []) if str(item).strip()],
                                    hard_failures=["runtime_failure"],
                                    runtime_error_tail=str(error_details or "")[-1400:],
                                    evidence=[
                                        {
                                            "claim": "Sandbox execution returned traceback/runtime error.",
                                            "source": "sandbox_error",
                                        }
                                    ],
                                )
                                print("Runtime error guard: retrying Data Engineer with error context.")
                                if run_id:
                                    log_run_event(run_id, "data_engineer_runtime_retry", {"attempt": attempt_id})
                                return run_data_engineer(new_state)
                        return {
                            "cleaning_code": code,
                            "cleaned_data_preview": "Error: Cleaning Failed",
                            "error_message": f"Sandbox Cleaning Failed: {error_details}",
                            "budget_counters": counters,
                        }

                    # 4. Verification & Download
                    # Check if cleaned file exists
                    ls_check = run_cmd_with_retry(sandbox, f"ls {run_root}/{remote_cleaned_rel}", retries=2)
                    ls_failed = bool(getattr(ls_check, "exit_code", 1) != 0)
                    if ls_failed:
                        print(f"Warning: cleaned artifact not confirmed by ls ({remote_cleaned_rel}); attempting download anyway.")

                    # Persist DE artifact
                    try:
                        os.makedirs("artifacts", exist_ok=True)
                        with open(os.path.join("artifacts", "data_engineer_last.py"), "w", encoding="utf-8") as f_art:
                            f_art.write(code)
                    except Exception as art_err:
                        print(f"Warning: failed to persist data_engineer_last.py: {art_err}")

                    downloaded_paths = []

                    # Download Result (CSV) using centralized helper
                    print("Downloading cleaned data...")
                    os.makedirs(os.path.dirname(local_cleaned_path) or ".", exist_ok=True)

                    csv_content = safe_download_bytes(sandbox, f"{run_root}/{remote_cleaned_rel}")
                    if csv_content is None:
                        return {
                            "cleaning_code": code,
                            "cleaned_data_preview": "Error: Download Failed",
                            "error_message": f"Failed to download cleaned data artifact from sandbox: {remote_cleaned_rel}",
                            "budget_counters": counters,
                        }
                    downloaded_cleaned_content = csv_content
                    with open(local_cleaned_path, "wb") as f_local:
                        f_local.write(csv_content)
                    if os.path.exists(local_cleaned_path):
                        downloaded_paths.append(local_cleaned_path)

                    # Download Manifest (JSON) - Roundtrip Support using centralized helper
                    print("Downloading cleaning manifest...")
                    manifest_content = safe_download_bytes(sandbox, f"{run_root}/{remote_manifest_rel}")
                    if manifest_content is not None:
                        with open(local_manifest_path, "wb") as f_local:
                            f_local.write(manifest_content)
                    else:
                        print(f"Warning: Manifest download failed (not found?): {remote_manifest_rel}")
                    if os.path.exists(local_manifest_path):
                        downloaded_paths.append(local_manifest_path)
                    if de_outlier_report_path:
                        remote_outlier_rel = _normalize_output_path(de_outlier_report_path)
                        outlier_content = safe_download_bytes(sandbox, f"{run_root}/{remote_outlier_rel}")
                        if outlier_content is not None:
                            os.makedirs(os.path.dirname(remote_outlier_rel) or ".", exist_ok=True)
                            with open(remote_outlier_rel, "wb") as f_local:
                                f_local.write(outlier_content)
                            if os.path.exists(remote_outlier_rel):
                                downloaded_paths.append(remote_outlier_rel)
                    try:
                        os.makedirs("artifacts", exist_ok=True)
                        with open(os.path.join("artifacts", "cleaning_manifest_last.json"), "wb") as f_copy:
                            with open(local_manifest_path, "rb") as f_src:
                                f_copy.write(f_src.read())
                    except Exception as copy_err:
                        print(f"Warning: failed to persist cleaning_manifest_last.json: {copy_err}")

                    manifest_data = {}
                    try:
                        with open(local_manifest_path, "r", encoding="utf-8") as f_manifest:
                            manifest_data = json.load(f_manifest)
                    except Exception:
                        manifest_data = {}
                    manifest_alerts = _extract_manifest_alerts(
                        manifest_data,
                        _resolve_contract_columns(state.get("execution_contract", {}), sources={"derived", "output"})
                    )
                    if manifest_alerts and not state.get("de_manifest_guard_retry_done"):
                        new_state = dict(state)
                        new_state["de_manifest_guard_retry_done"] = True
                        base_override = state.get("data_engineer_audit_override") or state.get("data_summary", "")
                        payload = "MANIFEST_ALERTS:\n" + "\n".join(f"- {alert}" for alert in manifest_alerts)
                        _merge_de_override_with_feedback_record(
                            new_state,
                            base_override=base_override,
                            payload=payload,
                            source="manifest_alerts",
                            status="REJECTED",
                            iteration=int(attempt_id),
                            feedback="Manifest consistency alerts require a cleaning-script retry.",
                            failed_gates=["manifest_alerts_detected"],
                            required_fixes=[str(item) for item in manifest_alerts if str(item).strip()],
                            runtime_error_tail="\n".join(str(item) for item in manifest_alerts)[:1400],
                            evidence=[{"claim": "Manifest alert(s) detected after DE execution.", "source": "cleaning_manifest.json"}],
                        )
                        print("MANIFEST_GUARD: retrying Data Engineer once with manifest alerts.")
                        return run_data_engineer(new_state)

                    outputs_listing = []
                    try:
                        listing_proc = sandbox.commands.run(
                            f"sh -c 'cd {run_root} && find . -maxdepth 4 -type f -printf \"%p\\t%s\\n\" 2>/dev/null'"
                        )
                        if listing_proc.exit_code == 0:
                            outputs_listing = [line for line in listing_proc.stdout.splitlines() if line.strip()]
                    except Exception:
                        outputs_listing = []
                    if run_id:
                        log_sandbox_attempt(
                            run_id,
                            step_name,
                            attempt_id,
                            code=code,
                            stdout=stdout_text,
                            stderr=stderr_text,
                            outputs_listing=outputs_listing,
                            downloaded_paths=downloaded_paths,
                            exit_code=getattr(execution, "exit_code", None),
                            error_tail=(execution.error.traceback if execution.error else None),
                            success=True,
                            stage="completed",
                        )

                    required_input = _resolve_required_input_columns(state.get("execution_contract", {}), selected)
                    raw_rows = _count_raw_rows(csv_path, csv_encoding, csv_sep, csv_decimal)
                    cleaned_encoding = None
                    try:
                        cleaned_encoding = (
                            manifest_data.get("output_dialect", {}).get("encoding")
                            if isinstance(manifest_data.get("output_dialect"), dict)
                            else None
                        )
                    except Exception:
                        cleaned_encoding = None
                    cleaned_encoding = cleaned_encoding or "utf-8"
                    cleaned_sep = None
                    cleaned_decimal = None
                    try:
                        if isinstance(manifest_data.get("output_dialect"), dict):
                            cleaned_sep = manifest_data["output_dialect"].get("sep")
                            cleaned_decimal = manifest_data["output_dialect"].get("decimal")
                    except Exception:
                        cleaned_sep = None
                        cleaned_decimal = None
                    cleaned_rows = _count_raw_rows(local_cleaned_path, cleaned_encoding, cleaned_sep, cleaned_decimal)
                    row_drop_summary = _summarize_row_drop(
                        manifest_data,
                        required_input,
                        initial_override=raw_rows,
                        after_override=cleaned_rows,
                    )
                    if row_drop_summary and not state.get("de_row_drop_retry_done"):
                        new_state = dict(state)
                        new_state["de_row_drop_retry_done"] = True
                        base_override = state.get("data_engineer_audit_override") or state.get("data_summary", "")
                        payload = (
                            "CLEANING_RECOVERY_ALERT:\n"
                            f"- rows_initial={row_drop_summary.get('initial')}\n"
                            f"- rows_after={row_drop_summary.get('after')}\n"
                            f"- drop_frac={row_drop_summary.get('drop_frac')}\n"
                        )
                        suspects = row_drop_summary.get("suspects") or []
                        if suspects:
                            payload += "SUSPECT_CONVERSIONS:\n" + json.dumps(suspects, ensure_ascii=True)
                            try:
                                header_cols = _read_csv_header(csv_path, csv_encoding, csv_sep)
                                norm_map = {}
                                for col in header_cols:
                                    normed = _norm_name(col)
                                    if normed and normed not in norm_map:
                                        norm_map[normed] = col
                                suspect_cols = [item.get("column") for item in suspects if item.get("column")]
                                sample_context = _build_required_sample_context(
                                    csv_path, input_dialect, suspect_cols, norm_map, max_rows=200
                                )
                                if sample_context:
                                    payload = f"{payload}\n\n{sample_context}"
                            except Exception:
                                pass
                        try:
                            explainer_text = failure_explainer.explain_data_engineer_failure(
                                code=code,
                                error_details=payload,
                                context={
                                    "strategy_title": selected.get("title", "") if selected else "",
                                    "csv_dialect": input_dialect,
                                    "required_input_columns": required_input,
                                    "row_drop_summary": row_drop_summary,
                                },
                            )
                        except Exception as explainer_err:
                            print(f"Warning: failure explainer failed: {explainer_err}")
                            explainer_text = ""
                        if explainer_text:
                            payload = payload + "\nLLM_FAILURE_EXPLANATION:\n" + explainer_text.strip()
                            try:
                                os.makedirs("artifacts", exist_ok=True)
                                with open(
                                    os.path.join("artifacts", "data_engineer_failure_explainer.txt"),
                                    "w",
                                    encoding="utf-8",
                                ) as f_exp:
                                    f_exp.write(explainer_text.strip())
                            except Exception as exp_err:
                                print(f"Warning: failed to persist data_engineer_failure_explainer.txt: {exp_err}")
                        _merge_de_override_with_feedback_record(
                            new_state,
                            base_override=base_override,
                            payload=payload,
                            source="row_drop_guard",
                            status="REJECTED",
                            iteration=int(attempt_id),
                            feedback="Detected excessive row loss likely caused by destructive conversions.",
                            failed_gates=["row_drop_sanity_failed"],
                            required_fixes=[
                                "Avoid destructive conversions that remove too many rows.",
                                "Use contract-aligned null/typing handling and preserve row integrity.",
                            ],
                            runtime_error_tail=json.dumps(row_drop_summary, ensure_ascii=True)[:1400],
                            evidence=[{"claim": "Row drop summary exceeded guard threshold.", "source": "cleaning_manifest.json#row_counts"}],
                        )
                        print("ROW_DROP_GUARD: retrying Data Engineer with recovery context.")
                        return run_data_engineer(new_state)

                    print("Cleaning Success (Artifacts Downloaded).")

                    # Apply output_dialect for downstream reads
                    csv_sep, csv_decimal, csv_encoding, dialect_updated = get_output_dialect_from_manifest(
                        local_manifest_path, csv_sep, csv_decimal, csv_encoding
                    )
                    if dialect_updated:
                        print(f"Downstream dialect updated from output_dialect: sep={csv_sep}, decimal={csv_decimal}, encoding={csv_encoding}")

                    break  # Sandbox execution successful, exit retry loop
              except Exception as e:
                error_payload = {
                    "stage": "exception",
                    "exception_type": type(e).__name__,
                    "exception_msg": str(e),
                    "traceback": traceback.format_exc(),
                    "attempt": attempt_id,
                }
                try:
                    os.makedirs("artifacts", exist_ok=True)
                    with open(
                        os.path.join("artifacts", "data_engineer_sandbox_last.log"),
                        "w",
                        encoding="utf-8",
                    ) as f_log:
                        f_log.write(str(e))
                except Exception as log_err:
                    print(f"Warning: failed to persist data_engineer_sandbox_last.log: {log_err}")
                try:
                    os.makedirs("artifacts", exist_ok=True)
                    with open(
                        os.path.join("artifacts", "data_engineer_sandbox_last_error.json"),
                        "w",
                        encoding="utf-8",
                    ) as f_err:
                        json.dump(error_payload, f_err, indent=2, ensure_ascii=True)
                except Exception as err:
                    print(f"Warning: failed to persist data_engineer_sandbox_last_error.json: {err}")
                if run_id:
                    log_sandbox_attempt(
                        run_id,
                        step_name,
                        attempt_id,
                        code=code,
                        stdout="",
                        stderr="",
                        outputs_listing=[],
                        downloaded_paths=[],
                        exit_code=None,
                        error_tail=str(e),
                        success=False,
                        stage="exception",
                        exception_type=type(e).__name__,
                        exception_msg=str(e),
                    )
                err_msg = str(e)
                err_trace = traceback.format_exc()
                err_details = f"{type(e).__name__}: {err_msg}\n{err_trace}"
                is_oom_like = _is_memory_pressure_error(err_details)
                can_try_heavy_after_memory_error = bool(
                    de_heavy_cfg
                    and _env_flag("HEAVY_RUNNER_DE_ENABLED", True)
                    and not state.get("heavy_runner_unavailable")
                )
                if is_oom_like and can_try_heavy_after_memory_error and not _flag_active_for_run(
                    state,
                    "de_memory_backend_retry_done",
                    run_id,
                ):
                    new_state = dict(state)
                    new_state["de_memory_backend_retry_done"] = True
                    if run_id:
                        new_state["de_memory_backend_retry_done_run_id"] = run_id
                    new_state["de_e2b_memory_failure_detected"] = True
                    new_state["de_force_heavy_runner"] = True
                    new_state["execution_error_message"] = err_details[-4000:]
                    if run_id:
                        log_run_event(
                            run_id,
                            "data_engineer_backend_escalation",
                            {
                                "source_backend": "e2b",
                                "target_backend": "heavy_runner",
                                "reason": "memory_pressure_exception",
                                "attempt": attempt_id,
                            },
                        )
                    print("Memory fallback (exception): retrying Data Engineer on Cloud Run heavy runner.")
                    return run_data_engineer(new_state)
                if is_oom_like and not state.get("de_oom_retry_done") and state.get("de_memory_guard_active"):
                    new_state = dict(state)
                    new_state["de_oom_retry_done"] = True
                    new_state["execution_error_message"] = err_details[-4000:]
                    base_override = state.get("data_engineer_audit_override") or state.get("data_summary", "")
                    payload = (
                        "RUNTIME_ERROR_CONTEXT: Sandbox process was killed (likely OOM / exit code 137). "
                        "Switch to chunked processing and avoid full-column stats over the entire dataset."
                    )
                    _merge_de_override_with_feedback_record(
                        new_state,
                        base_override=base_override,
                        payload=payload,
                        source="oom_guard",
                        status="REJECTED",
                        iteration=int(attempt_id),
                        feedback="OOM-like runtime failure detected during DE execution.",
                        failed_gates=["oom_runtime_failure"],
                        required_fixes=[
                            "Use chunked/streaming processing for large datasets.",
                            "Avoid full-table expensive operations that exceed memory budget.",
                        ],
                        hard_failures=["oom_runtime_failure"],
                        runtime_error_tail=str(err_details or "")[-1400:],
                        evidence=[{"claim": "Exception pattern indicates memory pressure/OOM.", "source": "runtime_exception"}],
                    )
                    print("OOM guard: retrying Data Engineer with chunked processing guidance.")
                    return run_data_engineer(new_state)
                if not _flag_active_for_run(state, "de_runtime_retry_done", run_id):
                    new_state = dict(state)
                    new_state["de_runtime_retry_done"] = True
                    if run_id:
                        new_state["de_runtime_retry_done_run_id"] = run_id
                    new_state["execution_error_message"] = err_details[-4000:]
                    base_override = state.get("data_engineer_audit_override") or state.get("data_summary", "")
                    payload = (
                        "RUNTIME_ERROR_CONTEXT:\n"
                        + err_msg[-3000:]
                        + "\n\nUNIVERSAL_PANDAS_DTYPE_GUARD:\n"
                        + "- Before using .str accessor, enforce string dtype on the working Series "
                        + "(astype(str) or astype('string')).\n"
                        + "- After replace(..., np.nan), do not assume the dtype is still string; re-cast before .str.*.\n"
                        + "- Apply this rule universally for any CSV/objective (no hardcoded columns)."
                    )
                    _merge_de_override_with_feedback_record(
                        new_state,
                        base_override=base_override,
                        payload=payload,
                        source="runtime_exception",
                        status="REJECTED",
                        iteration=int(attempt_id),
                        feedback="Unhandled runtime exception detected during DE execution.",
                        failed_gates=["runtime_exception"],
                        required_fixes=[
                            "Fix runtime exception and keep data typing robust before string operations.",
                            "Preserve contract-required outputs after patch.",
                        ],
                        hard_failures=["runtime_exception"],
                        runtime_error_tail=str(err_details or "")[-1400:],
                        evidence=[{"claim": "Runtime exception captured in sandbox exception handler.", "source": "runtime_exception"}],
                    )
                    print("Runtime exception guard: retrying Data Engineer with exception context.")
                    if run_id:
                        log_run_event(run_id, "data_engineer_runtime_retry", {"attempt": attempt_id, "source": "exception"})
                    return run_data_engineer(new_state)
                if sb_attempt == 0 and is_transient_sandbox_error(e):
                    print(f"SANDBOX_RETRY step=data_engineer attempt={sb_attempt+1} err={e}")
                    continue
                raise


        if not os.path.exists(local_cleaned_path) and downloaded_cleaned_content:
            try:
                os.makedirs(os.path.dirname(local_cleaned_path) or ".", exist_ok=True)
                with open(local_cleaned_path, "wb") as f_local:
                    f_local.write(downloaded_cleaned_content)
            except Exception as write_err:
                print(f"Warning: failed to restore cleaned data: {write_err}")
        if not os.path.exists(local_cleaned_path):
            print(f"Warning: cleaned data missing at {local_cleaned_path}; proceeding to reviewer checks.")
        if not os.path.exists(local_manifest_path):
            msg = f"DE_REQUIRED_ARTIFACT_MISSING: manifest artifact not produced at '{local_manifest_path}'"
            if run_id:
                log_run_event(run_id, "pipeline_aborted_reason", {"reason": "de_manifest_missing"})
            return {
                "cleaning_code": code,
                "cleaned_data_preview": "Error: Missing Manifest Artifact",
                "error_message": msg,
                "pipeline_aborted_reason": "de_manifest_missing",
                "data_engineer_failed": True,
                "budget_counters": counters,
            }
        try:
            os.makedirs("artifacts", exist_ok=True)
            with open(os.path.join("artifacts", "cleaning_manifest_last.json"), "wb") as f_copy:
                with open(local_manifest_path, "rb") as f_src:
                    f_copy.write(f_src.read())
        except Exception as copy_err:
            print(f"Warning: failed to persist cleaning_manifest_last.json: {copy_err}")
        # --- HOST-SIDE COLUMN MAPPING PROTOCOL v2 ---
        import pandas as pd
        from src.utils.column_mapping import build_mapping
        from src.utils.cleaning_validation import (
            normalize_manifest,
            load_json,
            detect_destructive_drop,
            format_patch_instructions,
            sample_raw_columns,
        )

        try:
            df = pd.read_csv(
                local_cleaned_path,
                sep=csv_sep,
                decimal=csv_decimal,
                encoding=csv_encoding
            )
            assert_not_single_column_delimiter_mismatch(df, csv_sep, csv_decimal, csv_encoding)
            if df.empty:
                raise ValueError(
                    f"Delimiter/Dialect mismatch: cleaned dataset loaded empty with sep='{csv_sep}', decimal='{csv_decimal}', encoding='{csv_encoding}'."
                )
            contract = state.get("execution_contract", {}) or {}
            required_cols = _resolve_required_input_columns(contract, selected)
            contract_all_cols = _resolve_contract_columns(contract)
            try:
                from src.utils.contract_accessors import get_derived_column_names
                contract_derived_cols = get_derived_column_names(contract)
            except Exception:
                contract_derived_cols = []
            constant_cols = _load_constant_columns_from_profile()
            cleaned_columns_set = set(df.columns.str.lower())
            host_mapping_enabled = False  # context-only: do not modify DE output

            print(f"Applying Column Mapping v2 for strategy: {selected.get('title')}")
            print(f"Required: {required_cols}")

            mapping_result = build_mapping(
                required_cols,
                df.columns.tolist(),
                allow_synthetic_margin=False,
                enable_fuzzy=False,
            )

            # Check for Missing Critical Columns (input only)
            if mapping_result['missing']:
                missing_cols = mapping_result['missing']
                missing_input = [m for m in missing_cols]
                missing_input, ignored_constants = _filter_missing_required_constants(
                    missing_input,
                    contract,
                    constant_cols,
                )
                if ignored_constants:
                    info_msg = (
                        "IGNORED_MISSING_CONSTANT_COLUMNS: "
                        f"{ignored_constants[:10]} (total={len(ignored_constants)})"
                    )
                    warnings = state.get("data_engineer_guard_warnings")
                    if not isinstance(warnings, list):
                        warnings = []
                    warnings.append(info_msg)
                    state["data_engineer_guard_warnings"] = warnings
                    state["data_engineer_constant_columns_ignored"] = ignored_constants
                if missing_input:
                    alias_conflicts = [req for req, meta in mapping_result.get("summary", {}).items() if meta.get("method") == "alias_conflict"]
                    manifest_raw = normalize_manifest(load_json(local_manifest_path))
                    issues = detect_destructive_drop(
                        manifest_raw,
                        missing_input,
                        csv_path,
                        input_dialect
                    )
                    if issues:
                        patch = format_patch_instructions(issues)
                        warnings = state.get("data_engineer_guard_warnings")
                        if not isinstance(warnings, list):
                            warnings = []
                        warnings.append("DESTRUCTIVE_CONVERSION_GUARD:\n" + patch)
                        state["data_engineer_guard_warnings"] = warnings
                    conflict_msg = f" Alias conflicts: {alias_conflicts}" if alias_conflicts else ""
                    warning_msg = f"MISSING_REQUIRED_COLUMNS_AFTER_MAPPING: {missing_input}.{conflict_msg}"
                    warnings = state.get("data_engineer_guard_warnings")
                    if not isinstance(warnings, list):
                        warnings = []
                    warnings.append(warning_msg)
                    state["data_engineer_guard_warnings"] = warnings
                    state["data_engineer_missing_required_columns"] = missing_input
                    state["data_engineer_alias_conflicts"] = alias_conflicts
                    print("Missing required columns after mapping: recorded warning for reviewer context.")

            # Do not apply deterministic renaming to DE output; mapping is context-only.
            df_mapped = df.copy()

            # Skip deterministic renames for derived columns (context-only).

            # --- ID/SCALE GUARDS (Deterministic) ---
            id_issues = []
            scale_issues = []
            identifier_cols = []
            roles = get_column_roles(contract) if isinstance(contract, dict) else {}
            role_ids = roles.get("identifiers") if isinstance(roles, dict) else None
            if isinstance(role_ids, list):
                identifier_cols = [c for c in role_ids if c in df_mapped.columns]
            if not identifier_cols:
                identifier_cols = [c for c in df_mapped.columns if is_identifier_like(c)]

            guard_columns = list(dict.fromkeys(identifier_cols + required_cols))
            raw_map = _build_required_raw_map(guard_columns, norm_map)
            raw_usecols = list(dict.fromkeys(raw_map.values()))
            raw_sample_df = (
                sample_raw_columns(csv_path, input_dialect, raw_usecols, nrows=200, dtype=str)
                if raw_usecols
                else pd.DataFrame()
            )

            if identifier_cols and not state.get("de_id_guard_retry_done"):
                for col in identifier_cols:
                    if col not in df_mapped.columns:
                        continue
                    series = df_mapped[col]
                    detection = detect_identifier_scientific_notation(series)
                    if not detection.get("flag"):
                        continue
                    raw_col = raw_map.get(col)
                    raw_examples = []
                    if raw_col and raw_col in raw_sample_df.columns:
                        raw_examples = raw_sample_df[raw_col].dropna().astype(str).head(6).tolist()
                    cleaned_examples = series.dropna().astype(str).head(6).tolist()
                    id_issues.append(
                        {
                            "column": col,
                            "raw_column": raw_col,
                            "raw_examples": raw_examples,
                            "cleaned_examples": cleaned_examples,
                            "details": detection,
                        }
                    )

            if required_cols and not state.get("de_scale_guard_retry_done"):
                for col in required_cols:
                    if col not in df_mapped.columns:
                        continue
                    if col in identifier_cols:
                        continue
                    series = df_mapped[col]
                    if not pd.api.types.is_numeric_dtype(series):
                        continue
                    raw_col = raw_map.get(col)
                    if not raw_col or raw_col not in raw_sample_df.columns:
                        continue
                    raw_strings = raw_sample_df[raw_col].dropna().astype(str).head(200).tolist()
                    if not raw_strings:
                        continue
                    if _is_percent_like(col, raw_strings):
                        continue
                    raw_values = [v for v in (_coerce_raw_numeric(v) for v in raw_strings) if v is not None]
                    if len(raw_values) < 5:
                        continue
                    try:
                        cleaned_max = float(series.max())
                    except Exception:
                        continue
                    if cleaned_max > 1.5:
                        continue
                    raw_median = _median(raw_values)
                    raw_max = max(raw_values) if raw_values else None
                    raw_high_ratio = (
                        sum(val > 5 for val in raw_values) / len(raw_values) if raw_values else 0.0
                    )
                    if raw_median is None:
                        continue
                    if raw_median > 5 or (raw_high_ratio >= 0.6 and raw_max and raw_max > 5):
                        cleaned_examples = series.dropna().astype(str).head(6).tolist()
                        scale_issues.append(
                            {
                                "column": col,
                                "raw_column": raw_col,
                                "raw_examples": raw_strings[:6],
                                "cleaned_examples": cleaned_examples,
                                "cleaned_max": cleaned_max,
                                "raw_median": raw_median,
                                "raw_max": raw_max,
                                "raw_high_ratio": raw_high_ratio,
                            }
                        )

            if id_issues or scale_issues:
                payload_lines = []
                if id_issues:
                    payload_lines.append("ID_SCI_NOTATION_GUARD:")
                    payload_lines.append(
                        "- Identifier-like columns must remain string-like; avoid scientific notation or .0 suffixes."
                    )
                    for issue in id_issues:
                        payload_lines.append(
                            f"* col={issue.get('column')} raw={issue.get('raw_column')} "
                            f"raw_examples={issue.get('raw_examples')} cleaned_examples={issue.get('cleaned_examples')} "
                            f"details={issue.get('details')}"
                        )
                if scale_issues:
                    payload_lines.append("SCALE_SHIFT_GUARD:")
                    payload_lines.append(
                        "- Do NOT rescale numeric columns unless percent-like evidence exists (name or raw '%')."
                    )
                    for issue in scale_issues:
                        payload_lines.append(
                            f"* col={issue.get('column')} raw={issue.get('raw_column')} "
                            f"raw_examples={issue.get('raw_examples')} cleaned_examples={issue.get('cleaned_examples')} "
                            f"cleaned_max={issue.get('cleaned_max')} raw_median={issue.get('raw_median')} "
                            f"raw_max={issue.get('raw_max')} raw_high_ratio={issue.get('raw_high_ratio')}"
                        )
                if payload_lines:
                    warnings = state.get("data_engineer_guard_warnings")
                    if not isinstance(warnings, list):
                        warnings = []
                    warnings.append("ID/SCALE_GUARD:\n" + "\n".join(payload_lines))
                    state["data_engineer_guard_warnings"] = warnings
                    print("ID/SCALE guard: recorded warning for reviewer context.")

            empty_required = _find_empty_required_columns(df_mapped, required_cols)
            if empty_required:
                required_issues = []
                optional_issues = []
                for item in empty_required:
                    req_meta = _resolve_requirement_meta(contract, item.get("column", ""))
                    is_optional = _is_optional_requirement(req_meta)
                    item["required"] = not is_optional
                    if is_optional:
                        optional_issues.append(item)
                    else:
                        required_issues.append(item)
                if optional_issues and not required_issues:
                    warn_cols = [item.get("column") for item in optional_issues if item.get("column")]
                    warnings = state.get("data_engineer_guard_warnings")
                    if not isinstance(warnings, list):
                        warnings = []
                    warnings.append(f"OPTIONAL_COLUMNS_EMPTY: {warn_cols}")
                    state["data_engineer_guard_warnings"] = warnings
                    print(f"Warning: optional columns empty after cleaning: {warn_cols}")
                else:
                    required_cols_only = [item.get("column") for item in required_issues if item.get("column")]
                    raw_map = _build_required_raw_map(required_cols_only, norm_map)
                    raw_stats = _sample_raw_null_stats(csv_path, input_dialect, list(raw_map.values()))
                    parse_lines = []
                    for item in required_issues:
                        col = item.get("column")
                        raw_col = raw_map.get(col) if col else None
                        stats = raw_stats.get(raw_col, {}) if raw_col else {}
                        non_null_frac = stats.get("non_null_frac")
                        parse_lines.append(
                            f"- {col}: null_frac={item.get('null_frac'):.2%}, non_null_count={item.get('non_null_count')}, "
                            f"raw_col={raw_col}, raw_non_null_frac={non_null_frac}"
                        )
                    payload = "EMPTY_REQUIRED_COLUMNS:\n" + "\n".join(parse_lines)
                    try:
                        sample_context = _build_required_sample_context(
                            csv_path, input_dialect, required_cols_only, norm_map, max_rows=200
                        )
                        if sample_context:
                            payload = f"{payload}\n\n{sample_context}"
                            hints = _infer_parsing_hints_from_sample_context(sample_context)
                            if hints:
                                payload = f"{payload}\n\n{hints}"
                    except Exception:
                        pass
                    warnings = state.get("data_engineer_guard_warnings")
                    if not isinstance(warnings, list):
                        warnings = []
                    warnings.append(payload)
                    state["data_engineer_guard_warnings"] = warnings
                    print("Empty required columns guard: recorded warning for reviewer context.")

            # --- CLEANING REVIEWER (contract-driven) ---
            if cleaning_reviewer:
                try:
                    manifest_for_review = _load_json_safe(local_manifest_path)
                    output_dialect = None
                    output_payload = manifest_for_review.get("output_dialect")
                    if isinstance(output_payload, dict):
                        output_dialect = {
                            "sep": output_payload.get("sep") or csv_sep,
                            "decimal": output_payload.get("decimal") or csv_decimal,
                            "encoding": output_payload.get("encoding") or csv_encoding,
                        }
                    cleaning_view = state.get("cleaning_view") or (state.get("contract_views") or {}).get("cleaning_view")
                    # Load cleaning code for intent verification by reviewer
                    cleaning_code_for_normal_review = None
                    try:
                        de_code_path = os.path.join("artifacts", "data_engineer_last.py")
                        if os.path.exists(de_code_path):
                            with open(de_code_path, "r", encoding="utf-8") as f_code:
                                cleaning_code_for_normal_review = f_code.read()
                    except Exception:
                        cleaning_code_for_normal_review = None
                    if cleaning_view:
                        cleaning_view_copy = dict(cleaning_view)
                        if output_dialect:
                            cleaning_view_copy["output_dialect"] = output_dialect
                        if isinstance(input_dialect, dict):
                            cleaning_view_copy["input_dialect"] = input_dialect
                        if cleaning_code_for_normal_review:
                            cleaning_view_copy["cleaning_code"] = cleaning_code_for_normal_review
                        if os.path.exists("data/required_columns.json"):
                            cleaning_view_copy["required_columns_path"] = "data/required_columns.json"
                        cleaning_view_copy = compress_long_lists(cleaning_view_copy)[0]
                        review_result = cleaning_reviewer.review_cleaning(
                            cleaning_view_copy,
                            cleaned_csv_path=local_cleaned_path,
                            cleaning_manifest_path=local_manifest_path,
                            raw_csv_path=csv_path,
                        )
                        review_context_payload = cleaning_view_copy
                    else:
                        contract = state.get("execution_contract", {}) or {}
                        review_context = {
                            "cleaning_view": {},
                            "cleaning_gates": contract.get("cleaning_gates")
                            or [],
                            "required_columns": _resolve_required_input_columns(contract, selected),
                            "dialect": input_dialect,
                            "column_roles": contract.get("column_roles") if isinstance(contract, dict) else {},
                            "cleaned_csv_path": local_cleaned_path,
                            "cleaning_manifest_path": local_manifest_path,
                            "raw_csv_path": csv_path,
                        }
                        if os.path.exists("data/required_columns.json"):
                            review_context["required_columns_path"] = "data/required_columns.json"
                        if output_dialect:
                            review_context["output_dialect"] = output_dialect
                        if isinstance(input_dialect, dict):
                            review_context["input_dialect"] = input_dialect
                        if cleaning_code_for_normal_review:
                            review_context["cleaning_code"] = cleaning_code_for_normal_review
                        review_context = compress_long_lists(review_context)[0]
                        review_result = cleaning_reviewer.review_cleaning(review_context)
                        review_context_payload = review_context
                    try:
                        os.makedirs("artifacts", exist_ok=True)
                        with open(os.path.join("artifacts", "cleaning_reviewer_report.json"), "w", encoding="utf-8") as f_rep:
                            json.dump(review_result, f_rep, indent=2, ensure_ascii=False)
                    except Exception:
                        pass
                    if run_id:
                        log_agent_snapshot(
                            run_id,
                            "cleaning_reviewer",
                            prompt=getattr(cleaning_reviewer, "last_prompt", None),
                            response=getattr(cleaning_reviewer, "last_response", None) or review_result,
                            context=review_context_payload,
                            verdicts=review_result,
                        )

                    if isinstance(review_result, dict):
                        status = review_result.get("status")
                        if status == "REJECTED":
                            if not state.get("cleaning_reviewer_retry_done"):
                                base_override = state.get("data_engineer_audit_override") or state.get("data_summary", "")
                                fixes = review_result.get("required_fixes", [])
                                fixes_text = ""
                                if isinstance(fixes, list) and fixes:
                                    fixes_text = "\nREQUIRED_FIXES:\n- " + "\n- ".join(str(item) for item in fixes)
                                evidence_text = _format_gate_failure_evidence(review_result.get("gate_results"))
                                payload = "CLEANING_REVIEWER_ALERT:\n" + str(review_result.get("feedback", "")).strip() + fixes_text
                                if evidence_text:
                                    payload += "\n\n" + evidence_text
                                try:
                                    feedback_record = {
                                        "agent": "cleaning_reviewer",
                                        "status": "REJECTED",
                                        "failed_gates": [
                                            str(item) for item in (review_result.get("failed_checks") or []) if item
                                        ],
                                        "required_fixes": [str(item) for item in (fixes or []) if item],
                                        "hard_failures": [
                                            str(item) for item in (review_result.get("hard_failures") or []) if item
                                        ],
                                    }
                                    payload += (
                                        "\n\nITERATION_FEEDBACK_RECORD_JSON:\n"
                                        + json.dumps(feedback_record, ensure_ascii=True)
                                    )
                                except Exception:
                                    pass
                                new_state = dict(state)
                                new_state["cleaning_reviewer_retry_done"] = True
                                failed_checks = [str(item) for item in (review_result.get("failed_checks") or []) if item]
                                hard_failures = [str(item) for item in (review_result.get("hard_failures") or []) if item]
                                required_fix_items = [str(item) for item in (fixes or []) if item]
                                gate_evidence_items: List[Dict[str, str]] = []
                                gate_results = review_result.get("gate_results")
                                if isinstance(gate_results, list):
                                    for gate in gate_results:
                                        if not isinstance(gate, dict):
                                            continue
                                        if gate.get("passed") is True:
                                            continue
                                        gate_name = str(gate.get("name") or "unknown_gate")
                                        issues = gate.get("issues") if isinstance(gate.get("issues"), list) else []
                                        issue_text = "; ".join(str(x) for x in issues[:2]) if issues else "Gate failed."
                                        gate_evidence_items.append(
                                            {
                                                "claim": f"Gate {gate_name} failed: {issue_text}",
                                                "source": "cleaning_reviewer_report.json#gate_results",
                                            }
                                        )
                                        if len(gate_evidence_items) >= 8:
                                            break
                                _merge_de_override_with_feedback_record(
                                    new_state,
                                    base_override=base_override,
                                    payload=payload,
                                    source="cleaning_reviewer_reject",
                                    status="REJECTED",
                                    iteration=int(attempt_id),
                                    feedback=str(review_result.get("feedback") or "Cleaning reviewer rejected cleaned output."),
                                    failed_gates=failed_checks,
                                    required_fixes=required_fix_items,
                                    hard_failures=hard_failures,
                                    runtime_error_tail=str(review_result.get("feedback") or "")[-1400:],
                                    evidence=gate_evidence_items
                                    or [{"claim": "Cleaning reviewer rejected DE output.", "source": "cleaning_reviewer_report.json"}],
                                )
                                print("Cleaning reviewer rejected output: retrying Data Engineer with guidance.")
                                return run_data_engineer(new_state)
                            if run_id:
                                log_run_event(run_id, "pipeline_aborted_reason", {"reason": "cleaning_reviewer_rejected"})
                            return {
                                "cleaning_code": code,
                                "cleaned_data_preview": "Error: Cleaning Reviewer Rejected",
                                "error_message": "CRITICAL: Cleaning reviewer rejected cleaned data.",
                                "pipeline_aborted_reason": "cleaning_reviewer_rejected",
                                "data_engineer_failed": True,
                                "budget_counters": counters,
                            }
                        if status == "APPROVE_WITH_WARNINGS":
                            warnings = review_result.get("warnings") or []
                            if not isinstance(warnings, list):
                                warnings = [str(warnings)]
                            state["cleaning_reviewer_warnings"] = warnings
                except Exception as review_err:
                    msg = f"CRITICAL: Cleaning reviewer failed: {review_err}"
                    print(msg)
                    if run_id:
                        log_run_event(run_id, "pipeline_aborted_reason", {"reason": "cleaning_reviewer_failed"})
                    return {
                        "cleaning_code": code,
                        "cleaned_data_preview": "Error: Cleaning Reviewer Failed",
                        "error_message": msg,
                        "pipeline_aborted_reason": "cleaning_reviewer_failed",
                        "data_engineer_failed": True,
                        "budget_counters": counters,
                    }
            # Guard: derived columns should not be constant if present (context-only; do not block runs)
            derived_issues = []
            derived_evidence = {}
            if contract_derived_cols:
                col_by_norm = {_norm_name(c): c for c in df_mapped.columns}
                # V4.1: Use derived_columns from contract root or feature_engineering_plan
                v41_derived = contract.get("derived_columns", []) if isinstance(contract, dict) else []
                if not v41_derived:
                    fep = contract.get("feature_engineering_plan", {}) if isinstance(contract, dict) else {}
                    v41_derived = fep.get("derived_columns", []) if isinstance(fep, dict) else []
                spec_derived = v41_derived if isinstance(v41_derived, list) else []
                for derived_name in contract_derived_cols:
                    norm_name = _norm_name(derived_name)
                    actual_name = col_by_norm.get(norm_name)
                    if not actual_name:
                        continue
                    nunique = df_mapped[actual_name].nunique(dropna=False)
                    if nunique <= 1:
                        derived_issues.append(f"{derived_name} has no variance (nunique={nunique})")
                    deps = []
                    for entry in spec_derived:
                        if not isinstance(entry, dict):
                            continue
                        entry_name = entry.get("name")
                        if entry_name and _norm_name(entry_name) == norm_name:
                            deps = entry.get("depends_on", []) or []
                            break
                    if deps:
                        dep_stats = {}
                        for dep in deps:
                            dep_norm = _norm_name(dep)
                            dep_actual = col_by_norm.get(dep_norm)
                            if not dep_actual:
                                dep_stats[dep] = {"status": "missing"}
                                continue
                            series = df_mapped[dep_actual]
                            non_null = int(series.notna().sum())
                            sample_vals = []
                            try:
                                for val in series.dropna().astype(str).head(3).tolist():
                                    if val not in sample_vals:
                                        sample_vals.append(val)
                            except Exception:
                                sample_vals = []
                            dep_stats[dep] = {
                                "actual": dep_actual,
                                "non_null": non_null,
                                "sample": sample_vals,
                            }
                        derived_evidence[derived_name] = dep_stats
            if derived_issues:
                warning_payload = "DERIVED_COLUMN_GUARD: " + "; ".join(derived_issues)
                try:
                    if derived_evidence:
                        warning_payload += "\nDERIVED_SOURCE_EVIDENCE:\n" + json.dumps(
                            derived_evidence,
                            ensure_ascii=True,
                        )
                except Exception:
                    pass
                warnings = state.get("data_engineer_guard_warnings")
                if not isinstance(warnings, list):
                    warnings = []
                warnings.append(warning_payload)
                state["data_engineer_guard_warnings"] = warnings
                print("Derived column guard warning recorded for reviewer context.")

            # Create Synthetic Columns if needed
            for synth in mapping_result['synthetic']:
                print(f"Creating Synthetic Column: {synth} (0.0)")
                df_mapped[synth] = 0.0

            # Integrity audit only (no auto-fix)
            feature_flags = {}
            feature_stats = {}
            contract = state.get("execution_contract", {})
            try:
                contract_for_audit = _filter_input_contract(contract)
                issues, stats = run_integrity_audit(df_mapped, contract_for_audit)
                feature_stats = stats
                os.makedirs("data", exist_ok=True)
                with open("data/integrity_audit_report.json", "w", encoding="utf-8") as f:
                    json.dump({"issues": issues, "stats": stats}, f, indent=2)
                critical = [i for i in issues if i.get("severity") == "critical"]
                if critical and not state.get("integrity_retry_done"):
                    new_state = dict(state)
                    new_state["integrity_retry_done"] = True
                    try:
                        issue_text = json.dumps(issues, indent=2)
                    except Exception:
                        issue_text = str(issues)
                    base_override = state.get("data_engineer_audit_override") or state.get("data_summary", "")
                    payload = "INTEGRITY_AUDIT_ISSUES:\n" + issue_text
                    integrity_failed = [str(item.get("issue") or item.get("name") or "integrity_issue") for item in critical if isinstance(item, dict)]
                    _merge_de_override_with_feedback_record(
                        new_state,
                        base_override=base_override,
                        payload=payload,
                        source="integrity_audit",
                        status="REJECTED",
                        iteration=int(attempt_id),
                        feedback="Integrity audit detected critical post-cleaning issues.",
                        failed_gates=list(dict.fromkeys(integrity_failed))[:12],
                        required_fixes=[
                            "Resolve integrity audit critical issues without violating contract-required columns/gates.",
                        ],
                        hard_failures=list(dict.fromkeys(integrity_failed))[:12],
                        runtime_error_tail=issue_text[:1400],
                        evidence=[{"claim": "Critical integrity audit findings detected.", "source": "data/integrity_audit_report.json"}],
                    )
                    print("⚠️ INTEGRITY_AUDIT: triggering Data Engineer retry with issues context.")
                    return run_data_engineer(new_state)
            except Exception as audit_err:
                print(f"Warning: integrity audit failed: {audit_err}")
                try:
                    os.makedirs("data", exist_ok=True)
                    with open("data/integrity_audit_report.json", "w", encoding="utf-8") as f:
                        json.dump({"error": str(audit_err)}, f, indent=2)
                except Exception:
                    pass

            try:
                os.makedirs("data", exist_ok=True)
                df_mapped.to_csv(
                    "data/cleaned_full.csv",
                    index=False,
                    sep=csv_sep,
                    decimal=csv_decimal,
                    encoding=csv_encoding
                )
            except Exception as full_save_err:
                print(f"Warning: failed to save cleaned_full.csv: {full_save_err}")

            try:
                audit = run_unsupervised_numeric_relation_audit(df_mapped)
                with open("data/leakage_audit.json", "w", encoding="utf-8") as f:
                    json.dump(audit, f, indent=2)
                findings = audit.get("relations", [])
                if findings:
                    top = findings[:3]
                    leakage_audit_summary = "; ".join(
                        [
                            f"{rel.get('type')}:{','.join(rel.get('columns', []))} (support={rel.get('support_frac', 0):.3f})"
                            for rel in top
                        ]
                    )
                else:
                    leakage_audit_summary = "No deterministic numeric relations found."
            except Exception as audit_err:
                print(f"Warning: leakage audit failed: {audit_err}")
                leakage_audit_summary = "Leakage audit failed; proceed with caution."

            # Do not rewrite cleaned_data.csv; keep DE output as the source of truth.
            if host_mapping_enabled:
                # Filter to only required columns (Strict output)
                final_cols = [c for c in required_cols if c in df_mapped.columns]
                if contract_derived_cols:
                    for col in contract_derived_cols:
                        if col in df_mapped.columns and col not in final_cols:
                            final_cols.append(col)
                if not final_cols:
                    final_cols = df_mapped.columns.tolist()
                df_final = df_mapped[final_cols]
                df_final.to_csv(
                    local_cleaned_path,
                    index=False,
                    sep=csv_sep,
                    decimal=csv_decimal,
                    encoding=csv_encoding
                )
                print(f"Mapped data saved to '{local_cleaned_path}'")
            else:
                df_final = df_mapped
                print(f"Host mapping disabled; using DE cleaned artifact as-is: {local_cleaned_path}")

            cleaned_data_summary_min = {}
            cleaned_data_summary_min_path = "data/cleaned_data_summary_min.json"
            try:
                cleaning_manifest_payload = _load_json_safe(local_manifest_path)
                if not isinstance(cleaning_manifest_payload, dict):
                    cleaning_manifest_payload = {}
                outlier_report_payload = (
                    _load_json_safe(de_outlier_report_path) if de_outlier_report_path else {}
                )
                if not isinstance(outlier_report_payload, dict):
                    outlier_report_payload = {}
                outlier_policy_payload = de_view.get("outlier_policy")
                if not isinstance(outlier_policy_payload, dict):
                    outlier_policy_payload = {}
                cleaned_data_summary_min = _build_cleaned_data_summary_min(
                    df_clean=df_final,
                    contract=contract,
                    required_columns=required_cols,
                    data_path=local_cleaned_path,
                    outlier_policy=outlier_policy_payload,
                    outlier_report=outlier_report_payload,
                    cleaning_manifest=cleaning_manifest_payload,
                )
                dump_json(cleaned_data_summary_min_path, cleaned_data_summary_min)
                if run_id:
                    log_run_event(
                        run_id,
                        "cleaned_data_summary_min_built",
                        {
                            "path": cleaned_data_summary_min_path,
                            "row_count": cleaned_data_summary_min.get("row_count"),
                            "column_count": cleaned_data_summary_min.get("column_count"),
                            "missing_required_columns": cleaned_data_summary_min.get("missing_required_columns", []),
                            "role_dtype_warnings": len(cleaned_data_summary_min.get("role_dtype_warnings", [])),
                            "outlier_policy_enabled": bool(
                                ((cleaned_data_summary_min.get("outlier_treatment") or {}).get("enabled"))
                            ),
                            "outlier_report_present": bool(
                                ((cleaned_data_summary_min.get("outlier_treatment") or {}).get("report_present"))
                            ),
                        },
                    )
            except Exception as summary_err:
                print(f"Warning: failed to build cleaned_data_summary_min: {summary_err}")
                cleaned_data_summary_min = {}
                cleaned_data_summary_min_path = ""

            # Save Summary
            with open("data/column_mapping_summary.json", "w", encoding="utf-8") as f:
                json.dump(mapping_result, f, indent=2)

            preview = df_final.head(5).to_json(orient='split')

        except Exception as e:
            print(f"Column Mapping Failed: {e}")
            return {
                "cleaning_code": code,
                "cleaned_data_preview": f"Error: Mapping Failed {e}",
                "error_message": f"Host-side Column Mapping Failed: {str(e)}",
                "csv_sep": csv_sep,
                "csv_decimal": csv_decimal,
                "csv_encoding": csv_encoding,
                "leakage_audit_summary": leakage_audit_summary,
                "budget_counters": counters,
            }

        # P2.3: Calculate dataset scale hints after Data Engineer
        work_dir = state.get("work_dir", ".")
        dataset_scale_hints = get_dataset_scale_hints(work_dir, local_cleaned_path)

        if run_id:
            log_run_event(
                run_id,
                "data_engineer_complete",
                {
                    "rows": len(df_final),
                    "columns": len(df_final.columns),
                    "dataset_scale": dataset_scale_hints.get("scale"),
                    "dataset_file_mb": dataset_scale_hints.get("file_mb"),
                },
            )

        result = {
            "cleaning_code": code,
            "cleaned_data_preview": preview,
            "csv_sep": csv_sep,
            "csv_decimal": csv_decimal,
            "csv_encoding": csv_encoding,
            "leakage_audit_summary": leakage_audit_summary,
            "budget_counters": counters,
            "dataset_scale_hints": dataset_scale_hints,
            "dataset_scale": dataset_scale_hints.get("scale") if isinstance(dataset_scale_hints, dict) else None,
            "ml_data_path": local_cleaned_path,
            "cleaning_manifest_path": local_manifest_path,
            "outlier_report_path": de_outlier_report_path,
            "cleaned_data_summary_min": cleaned_data_summary_min,
            "cleaned_data_summary_min_path": cleaned_data_summary_min_path,
            "error_message": None,
        }
        merged_state = dict(state or {})
        merged_state.update(result)
        _refresh_run_facts_pack(merged_state)
        return result

    except Exception as e:
        print(f"Cleaning Execution Error (System): {e}")
        return {
            "cleaning_code": code,
            "cleaned_data_preview": f"Error: {e}",
            "error_message": f"System Error during Data Cleaning: {str(e)}",
            "budget_counters": counters,
        }

def check_data_success(state: AgentState):
    err = state.get("error_message")
    if err:
        print(f"❌ Data Engineer Failed: {err}")
        return "failed"

    cleaned_path, _, _ = _resolve_de_output_artifacts(state if isinstance(state, dict) else {})
    if not cleaned_path:
        cleaned_path = str(state.get("ml_data_path") or "").strip()
    if not cleaned_path or not os.path.exists(cleaned_path):
        print(f"❌ Critical: cleaned dataset missing locally ({cleaned_path or '<unset>'}).")
        return "failed"

    run_start_epoch = state.get("run_start_epoch")
    if run_start_epoch is not None:
        try:
            cleaned_mtime = os.path.getmtime(cleaned_path)
            if cleaned_mtime < float(run_start_epoch) - 1.0:
                print(f"Data Engineer Failed: stale cleaned dataset detected at {cleaned_path}.")
                return "failed"
        except Exception:
            pass

    preview = state.get("cleaned_data_preview", "")
    if str(preview).startswith("Error") or "Error reading preview" in str(preview):
        print(f"❌ Data Engineer Failed (Preview Error): {preview}")
        return "failed"

    contract = state.get("execution_contract") if isinstance(state, dict) else {}
    if not isinstance(contract, dict):
        contract = {}
    scope = normalize_contract_scope(contract.get("scope"))
    if scope == "cleaning_only":
        return "success_cleaning_only"

    return "success"


def check_steward_context_success(state: AgentState):
    if bool(state.get("steward_context_ready")):
        return "success"
    reason = str(state.get("steward_context_error") or state.get("error_message") or "").strip()
    if reason:
        print(f"❌ Steward Context Invalid: {reason}")
    else:
        print("❌ Steward Context Invalid: unknown reason")
    return "failed"


def check_execution_planner_success(state: AgentState):
    if _planner_contract_invalid_for_execution(state if isinstance(state, dict) else {}):
        return "failed"
    return "success"

def run_engineer(state: AgentState) -> AgentState:
    next_ml_attempt = int(state.get("ml_engineer_attempt", 0) or 0) + 1
    print(
        f"--- [4] ML Engineer: Generating Code "
        f"(Iteration {state.get('iteration_count', 0) + 1}, Attempt {next_ml_attempt}) ---"
    )
    abort_state = _abort_if_requested(state, "ml_engineer")
    if abort_state:
        return abort_state
    run_id = state.get("run_id")
    ok, counters, err_msg = _consume_budget(state, "ml_calls", "max_ml_calls", "ML Engineer")
    state["budget_counters"] = counters
    if not ok:
        if run_id:
            log_run_event(run_id, "budget_exceeded", {"label": "ml_engineer", "error": err_msg})
        last_code = state.get("last_generated_code")
        last_success_output = state.get("last_successful_execution_output")
        result = {
            "error_message": err_msg,
            "generated_code": last_code or "# Generation Failed",
            "last_generated_code": last_code,
            "execution_output": last_success_output or err_msg,
            "execution_output_stale": bool(last_success_output),
            "budget_counters": counters,
            "ml_engineer_attempt": next_ml_attempt,
        }
        if bool(state.get("ml_improvement_round_active")):
            # Ensure metric-improvement rounds close deterministically on budget exhaustion.
            result["ml_improvement_force_finalize_reason"] = "budget_exceeded"
            result["ml_improvement_continue"] = False
        return result

    # Strategy Lock: Capture snapshot on first iteration, validate on subsequent iterations
    strategy_lock_snapshot = state.get("strategy_lock_snapshot")
    if not strategy_lock_snapshot:
        strategy_lock_snapshot = _capture_strategy_snapshot(state)
        state["strategy_lock_snapshot"] = strategy_lock_snapshot
        print(f"STRATEGY_LOCK: Captured initial snapshot: {strategy_lock_snapshot.get('strategy_title')}")
    else:
        lock_ok, lock_details = _validate_strategy_lock(state)
        if not lock_ok:
            drifts = lock_details.get("drifts", [])
            print(f"STRATEGY_LOCK_FAILED: Drift detected: {drifts}")
            if run_id:
                log_run_event(run_id, "strategy_lock_failed", {"drifts": drifts})
            error_msg = f"STRATEGY_LOCK_FAILED: Strategy drift detected: {drifts}"
            placeholder_code = f"# {error_msg}\n# Pipeline halted due to strategy/contract drift."
            return {
                "hard_fail_reason": "STRATEGY_LOCK_FAILED",
                "review_verdict": "NEEDS_IMPROVEMENT",
                "review_retry_worth_it": False,
                "stop_reason": "STRATEGY_LOCK",
                "error_message": error_msg,
                "strategy_lock_failed": True,
                "strategy_lock_details": lock_details,
                "budget_counters": counters,
                # Terminal flags to halt pipeline before execution
                "generated_code": placeholder_code,
                "last_generated_code": placeholder_code,
                "review_abort_reason": "strategy_lock_failed",
            }

    ml_attempt = next_ml_attempt
    if run_id:
        log_run_event(
            run_id,
            "ml_engineer_start",
            {
                "iteration": state.get("iteration_count", 0) + 1,
                "ml_engineer_attempt": ml_attempt,
                "runtime_fix_count": int(state.get("runtime_fix_count", 0) or 0),
            },
        )

    strategy = state.get('selected_strategy')

    # SENIOR REASONING: Ensure data_profile.json exists (final fallback)
    # Uses unified helper - should be a no-op if preflight already ran
    iteration_count = state.get("iteration_count", 0)
    if not state.get("data_profile") and iteration_count == 0:
        try:
            from src.utils.data_profile_preflight import ensure_data_profile_artifact
            contract = state.get("execution_contract") or _load_json_safe("data/execution_contract.json")
            analysis_type = (strategy or {}).get("analysis_type")
            work_dir_abs = _resolve_work_dir_abs(state)
            ensure_data_profile_artifact(
                state=state,
                contract=contract,
                analysis_type=analysis_type,
                work_dir_abs=work_dir_abs,
                run_id=run_id,
            )
        except Exception as profile_err:
            print(f"Warning: failed to build data_profile: {profile_err}")
            if run_id:
                log_run_event(run_id, "data_profile_failed", {"error": str(profile_err)})


    # Pass input context
    data_path = _resolve_ml_input_path(state if isinstance(state, dict) else {}, require_exists=False)
    minimal_context_mode = _minimal_agent_context_enabled()
    data_audit_context = _build_agent_feedback_context(state if isinstance(state, dict) else {}, "ml_engineer")
    if not data_path:
        data_audit_context = _merge_de_audit_override(
            data_audit_context,
            "WARNING: ml_data_path missing from contract-derived context.",
        )
    feedback_history = state.get('feedback_history', [])
    leakage_summary = state.get("leakage_audit_summary", "")
    dataset_semantics_summary = state.get("dataset_semantics_summary")
    ml_audit_override = state.get("ml_engineer_audit_override", "")
    latest_ml_feedback_record = state.get("ml_feedback_record")
    latest_ml_feedback_block = _build_latest_feedback_record_block(latest_ml_feedback_record)
    context_pack = ""
    if not minimal_context_mode:
        data_audit_context = _strip_run_facts_blocks(str(state.get('data_summary', '') or ""))
        if leakage_summary:
            data_audit_context = f"{data_audit_context}\nLEAKAGE_AUDIT: {leakage_summary}"
        if dataset_semantics_summary:
            data_audit_context = _merge_de_audit_override(
                data_audit_context,
                dataset_semantics_summary,
            )
        if ml_audit_override:
            data_audit_context = _merge_de_audit_override(data_audit_context, ml_audit_override)
        if latest_ml_feedback_block:
            data_audit_context = _merge_de_audit_override(data_audit_context, latest_ml_feedback_block)
        context_pack = build_context_pack("ml_engineer", state if isinstance(state, dict) else {})
        if context_pack:
            data_audit_context = _merge_de_audit_override(context_pack, data_audit_context)
    elif latest_ml_feedback_block:
        data_audit_context = _merge_de_audit_override(data_audit_context, latest_ml_feedback_block)
    business_objective = state.get('business_objective', '')
    csv_encoding = state.get('csv_encoding', 'utf-8') # Pass real encoding
    csv_sep = state.get('csv_sep', ',')
    csv_decimal = state.get('csv_decimal', '.')
    execution_contract, _ = _resolve_contract_pair_from_state(state if isinstance(state, dict) else {})
    evaluation_spec = state.get("evaluation_spec") or (execution_contract or {}).get("evaluation_spec") or {}
    if not execution_contract:
        data_audit_context = _merge_de_audit_override(
            data_audit_context,
            "WARNING: execution_contract missing; using minimal contract context only.",
        )
    manifest_path = "data/cleaning_manifest.json"
    if os.path.exists(manifest_path):
        use_manifest = bool(state.get("use_output_dialect") or state.get("dialect_from_manifest"))
        if not use_manifest and csv_sep == "," and csv_decimal == "." and str(csv_encoding).lower() in {"utf-8", "utf8"}:
            use_manifest = True
        if use_manifest:
            try:
                csv_sep, csv_decimal, csv_encoding, dialect_updated = get_output_dialect_from_manifest(
                    manifest_path, csv_sep, csv_decimal, csv_encoding
                )
                if dialect_updated:
                    print(f"ML dialect updated from output_dialect: sep={csv_sep}, decimal={csv_decimal}, encoding={csv_encoding}")
            except Exception:
                pass
    if not data_path or not os.path.exists(data_path):
        data_audit_context = _merge_de_audit_override(
            data_audit_context,
            f"WARNING: ML input data missing at '{data_path or '<unset>'}'. ML execution cannot proceed.",
        )
    required_input_cols = _resolve_required_input_columns(execution_contract, strategy)
    header_cols = _read_csv_header(data_path, csv_encoding, csv_sep) if os.path.exists(data_path) else []
    cleaned_data_summary_min = state.get("cleaned_data_summary_min")
    if not isinstance(cleaned_data_summary_min, dict) or not cleaned_data_summary_min:
        cleaned_data_summary_min = _load_json_safe("data/cleaned_data_summary_min.json")
    if not isinstance(cleaned_data_summary_min, dict):
        cleaned_data_summary_min = {}
    if required_input_cols and header_cols and not minimal_context_mode:
        header_norm = {_norm_name(c) for c in header_cols}
        missing_required = [c for c in required_input_cols if _norm_name(c) not in header_norm]
        constant_cols = _load_constant_columns_from_profile()
        missing_required, ignored_constants = _filter_missing_required_constants(
            missing_required,
            execution_contract or {},
            constant_cols,
        )
        if ignored_constants:
            note = (
                "ML_REQUIRED_COLUMNS_IGNORED_CONSTANTS: "
                f"{ignored_constants[:10]} (total={len(ignored_constants)})"
            )
            data_audit_context = _merge_de_audit_override(data_audit_context, note)
        if missing_required:
            note = (
                "ML_REQUIRED_COLUMNS_MISSING: "
                f"{missing_required[:10]} (total={len(missing_required)})"
            )
            data_audit_context = _merge_de_audit_override(data_audit_context, note)
    # V4.1: Removed legacy feature_availability and availability_summary
    iteration_memory = list(state.get("ml_iteration_memory", []) or [])
    iteration_memory_block = state.get("ml_iteration_memory_block", "")
    last_run_memory = load_recent_memory(run_id, k=5) if run_id else []
    iter_id = int(state.get("iteration_count", 0)) + 1
    if run_id and iter_id >= 2:
        journal_entries = _load_ml_iteration_journal(run_id)
        journal_block = _build_ml_iteration_memory_block(journal_entries)
        if journal_block:
            iteration_memory_block = journal_block
    compliance_checklist = (execution_contract or {}).get("compliance_checklist", [])
    if compliance_checklist and not state.get("compliance_passed", False) and not minimal_context_mode:
        checklist_payload = "COMPLIANCE_BOOTSTRAP_CHECKLIST:\n" + json.dumps(compliance_checklist, ensure_ascii=True)
        data_audit_context = _merge_de_audit_override(data_audit_context, checklist_payload)

    # Patch Mode Inputs
    previous_code = state.get('generated_code') or state.get('last_generated_code')
    gate_context = state.get('last_gate_context')
    metric_round_active = bool(state.get("ml_improvement_round_active"))
    editor_mode_active = _should_use_ml_editor_mode(
        previous_code,
        gate_context,
        iteration_count=int(state.get("iteration_count", 0) or 0),
    ) or (metric_round_active and _is_editable_ml_code(previous_code))
    iteration_handoff = state.get("iteration_handoff")
    if previous_code and gate_context and not isinstance(iteration_handoff, dict):
        iteration_handoff = _build_iteration_handoff(
            state=state if isinstance(state, dict) else {},
            status=state.get("review_verdict"),
            gate_context=gate_context,
            oc_report=state.get("output_contract_report") if isinstance(state.get("output_contract_report"), dict) else {},
            review_result=state.get("reviewer_last_result") if isinstance(state.get("reviewer_last_result"), dict) else {},
            qa_result=state.get("qa_last_result") if isinstance(state.get("qa_last_result"), dict) else {},
            evaluation_spec=evaluation_spec if isinstance(evaluation_spec, dict) else {},
        )
    if state.get("reset_ml_patch_context"):
        previous_code = None
        gate_context = None
        iteration_handoff = None
        editor_mode_active = False

    if editor_mode_active:
        if metric_round_active:
            print("ML_EDITOR_MODE_OPTIMIZATION: reusing previous code for metric improvement round.")
        else:
            print("ML_EDITOR_MODE: reusing previous code with iterative feedback.")
        if run_id:
            payload = {"attempt": ml_attempt, "iteration": iter_id, "metric_round_active": bool(metric_round_active)}
            log_run_event(run_id, "ml_editor_mode", payload)

    print(f"DEBUG: Generating code for strategy: {strategy['title']}")

    try:
        import inspect
        kwargs = dict(
            strategy=strategy,
            data_path=data_path,
            feedback_history=feedback_history,
            previous_code=previous_code,
            gate_context=gate_context,
            iteration_handoff=iteration_handoff,
            csv_encoding=csv_encoding,
            csv_sep=csv_sep,
            csv_decimal=csv_decimal,
            data_audit_context=data_audit_context,
            business_objective=business_objective,
            # V4.1: Removed feature_availability and availability_summary from kwargs
            signal_summary={},
            iteration_memory=iteration_memory,
            iteration_memory_block=iteration_memory_block,
            last_run_memory=last_run_memory,
            strategy_lock=strategy_lock_snapshot,
            editor_mode=editor_mode_active,
        )
        sig = inspect.signature(ml_engineer.generate_code)
        if "execution_contract" in sig.parameters:
            kwargs["execution_contract"] = execution_contract
        if "dataset_scale" in sig.parameters:
            dataset_scale_hints = state.get("dataset_scale_hints") or {}
            kwargs["dataset_scale"] = dataset_scale_hints
        if "dataset_scale_str" in sig.parameters:
            dataset_scale_hints = state.get("dataset_scale_hints") or {}
            kwargs["dataset_scale_str"] = dataset_scale_hints.get("scale") if isinstance(dataset_scale_hints, dict) else None
        if "ml_view" in sig.parameters:
            ml_view = state.get("ml_view") or (state.get("contract_views") or {}).get("ml_view")
            if not isinstance(ml_view, dict) or not ml_view:
                projected_views = build_contract_views_projection(execution_contract or {}, state.get("artifact_index") or [])
                ml_view = projected_views.get("ml_view") or {}
            kwargs["ml_view"] = ml_view
            try:
                ml_view_len = len(json.dumps(ml_view, ensure_ascii=True))
                print(f"Using ML_VIEW_CONTEXT length={ml_view_len}")
                if run_id:
                    log_run_event(run_id, "ml_view_context", {"length": ml_view_len})
            except Exception:
                pass
        ml_plan_for_gen = state.get("ml_plan")
        if not ml_plan_for_gen:
            ml_plan_for_gen = _load_json_safe("data/ml_plan.json")
        if "ml_plan" in sig.parameters:
            kwargs["ml_plan"] = ml_plan_for_gen or {}
        if "cleaned_data_summary_min" in sig.parameters:
            kwargs["cleaned_data_summary_min"] = cleaned_data_summary_min or {}
        if "last_run_memory" not in sig.parameters:
            kwargs.pop("last_run_memory", None)
        if "strategy_lock" not in sig.parameters:
            kwargs.pop("strategy_lock", None)
        if "editor_mode" not in sig.parameters:
            kwargs.pop("editor_mode", None)
        aliasing = {}
        derived_present = []
        sample_context = ""
        context_ops_blocks = []
        execution_profile: Dict[str, Any] = {}
        dataset_scale_hints = state.get("dataset_scale_hints") or {}
        code_hint = previous_code if isinstance(previous_code, str) else str(state.get("generated_code") or "")
        execution_profile = _build_ml_execution_profile_for_prompt(
            state if isinstance(state, dict) else {},
            code=code_hint,
            ml_plan=ml_plan_for_gen if isinstance(ml_plan_for_gen, dict) else None,
        )
        if execution_profile:
            execution_profile_payload = compress_long_lists(execution_profile)[0]
            execution_profile_block = (
                "EXECUTION_PROFILE_CONTEXT (INFRASTRUCTURE BUDGET; ADVISORY, NEVER OVERRIDE CONTRACT):\n"
                + json.dumps(execution_profile_payload, ensure_ascii=True)
            )
            data_audit_context = _merge_de_audit_override(data_audit_context, execution_profile_block)
            kwargs["data_audit_context"] = data_audit_context
            if "execution_profile" in sig.parameters:
                kwargs["execution_profile"] = execution_profile
        if not minimal_context_mode:
            scale_line = (
                "POST-CLEAN DATASET SCALE: "
                f"scale={dataset_scale_hints.get('scale') or 'unknown'} "
                f"file_mb={dataset_scale_hints.get('file_mb') or 'unknown'} "
                f"est_rows={dataset_scale_hints.get('est_rows') or 'unknown'} "
                f"max_train_rows={dataset_scale_hints.get('max_train_rows') or 'unknown'} "
                f"chunk_size={dataset_scale_hints.get('chunk_size') or 'unknown'}"
            )
            context_ops_blocks.append(scale_line)
            if execution_profile:
                context_ops_blocks.append(
                    "EXECUTION_PROFILE_CONTEXT:\n"
                    + json.dumps(compress_long_lists(execution_profile)[0], ensure_ascii=True)
                )
            # V4.1: Removed feature_availability and availability_summary blocks
            if iteration_memory:
                memory_slice = iteration_memory[-2:]
                context_ops_blocks.append(
                    "ITERATION_MEMORY_CONTEXT:\n" + json.dumps(memory_slice, ensure_ascii=True)
                )
            ml_view = state.get("ml_view") or (state.get("contract_views") or {}).get("ml_view")
            if isinstance(ml_view, dict) and ml_view:
                context_ops_blocks.append(
                    "ML_VIEW_CONTEXT:\n" + json.dumps(compress_long_lists(ml_view)[0], ensure_ascii=True)
                )
            if cleaned_data_summary_min:
                compact_cleaned_summary = compress_long_lists(cleaned_data_summary_min)[0]
                context_ops_blocks.append(
                    "CLEANED_DATA_SUMMARY_MIN (ADVISORY_ONLY; NEVER_OVERRIDE_ML_VIEW_OR_EXECUTION_CONTRACT):\n"
                    + json.dumps(compact_cleaned_summary, ensure_ascii=True)
                )
            if header_cols:
                norm_map = {}
                norm_buckets = {}
                for col in header_cols:
                    normed = _norm_name(col)
                    if normed and normed not in norm_map:
                        norm_map[normed] = col
                    if normed:
                        norm_buckets.setdefault(normed, []).append(col)
                aliasing = {k: v for k, v in norm_buckets.items() if len(v) > 1}
                try:
                    derived_cols = _resolve_contract_columns(execution_contract, sources={"derived"})
                    if derived_cols:
                        derived_present = [c for c in derived_cols if c in set(header_cols)]
                except Exception:
                    derived_present = []
                cleaned_payload: Dict[str, Any] = {
                    "cleaned_column_inventory_raw": header_cols,
                    "cleaned_aliasing_collisions": aliasing,
                    "derived_columns_present": derived_present,
                }
                if len(header_cols) > 80:
                    norm_items = [f"{k}->{v}" for k, v in norm_map.items()]
                    norm_summary = summarize_long_list(norm_items)
                    norm_summary["note"] = COLUMN_LIST_POINTER
                    cleaned_payload["normalized_cleaned_header_map"] = norm_summary
                else:
                    cleaned_payload["normalized_cleaned_header_map"] = norm_map
                cleaned_payload, _ = compress_long_lists(cleaned_payload)
                header_context = "CLEANED_COLUMN_INVENTORY_CONTEXT: " + json.dumps(
                    cleaned_payload, ensure_ascii=False
                )
                data_audit_context = _merge_de_audit_override(data_audit_context, header_context)
                kwargs["data_audit_context"] = data_audit_context
                required_input_cols = _resolve_required_input_columns(execution_contract, strategy)
                sample_context = _build_required_sample_context(
                    data_path,
                    {"sep": csv_sep, "encoding": csv_encoding, "decimal": csv_decimal},
                    required_input_cols,
                    norm_map,
                    max_rows=80,
                )
                if sample_context:
                    data_audit_context = _merge_de_audit_override(data_audit_context, sample_context)
                    kwargs["data_audit_context"] = data_audit_context
                signal_summary = _build_signal_summary_context(
                    data_path,
                    {"sep": csv_sep, "encoding": csv_encoding, "decimal": csv_decimal},
                    required_input_cols,
                    norm_map,
                    header_cols,
                    state.get("dataset_semantics") if isinstance(state, dict) else None,
                )
                if signal_summary:
                    context_ops_blocks.append(
                        "SIGNAL_SUMMARY_CONTEXT:\n" + json.dumps(signal_summary, ensure_ascii=True)
                    )
                    kwargs["signal_summary"] = signal_summary
                try:
                    derived_cols = _resolve_contract_columns(execution_contract, sources={"derived"}) or []
                    output_cols = _resolve_contract_columns(execution_contract, sources={"output"}) or []
                    target_cols = [c for c in derived_cols + output_cols if c]
                    if target_cols:
                        summary = {}
                        for tgt in target_cols:
                            norm = _norm_name(tgt)
                            actual = norm_map.get(norm, tgt if tgt in header_cols else None)
                            if not actual:
                                continue
                            series_stats = {"present": True}
                            try:
                                import pandas as pd
                                df_preview = pd.read_csv(
                                    data_path,
                                    sep=csv_sep,
                                    decimal=csv_decimal,
                                    encoding=csv_encoding,
                                    usecols=[actual],
                                    nrows=200,
                                    low_memory=False,
                                )
                                series = df_preview[actual]
                                series_stats["non_null"] = int(series.notna().sum())
                                series_stats["nunique"] = int(series.nunique(dropna=False))
                                series_stats["sample"] = [str(v) for v in series.dropna().head(3).tolist()]
                            except Exception:
                                pass
                            summary[tgt] = series_stats
                        if summary:
                            context_ops_blocks.append(
                                "DERIVED_OUTPUT_OBSERVATIONS:\n" + json.dumps(summary, ensure_ascii=True)
                            )
                except Exception:
                    pass
                try:
                    business_alignment = (execution_contract or {}).get("business_alignment", {})
                    if business_alignment:
                        context_ops_blocks.append(
                            "BUSINESS_ALIGNMENT_OPERATIVE:\n" + json.dumps(business_alignment, ensure_ascii=True)
                        )
                except Exception:
                    pass
        try:
            os.makedirs("artifacts", exist_ok=True)
            if minimal_context_mode:
                ctx_payload = {
                    "data_path": data_path,
                    "csv_encoding": csv_encoding,
                    "csv_sep": csv_sep,
                    "csv_decimal": csv_decimal,
                    "ml_view": kwargs.get("ml_view"),
                    "execution_profile": execution_profile,
                    "cleaned_data_summary_min": cleaned_data_summary_min,
                    "data_audit_context": data_audit_context,
                    "last_gate_context": gate_context,
                    "iteration_handoff": iteration_handoff,
                    "iteration_memory_block": iteration_memory_block,
                }
            else:
                ctx_payload = {
                    "data_path": data_path,
                    "csv_encoding": csv_encoding,
                    "csv_sep": csv_sep,
                    "csv_decimal": csv_decimal,
                    "header_cols": header_cols,
                    "cleaned_aliasing_collisions": aliasing if header_cols else {},
                    "derived_columns_present": derived_present if header_cols else [],
                    "raw_required_sample_context": sample_context,
                    "context_ops_blocks": context_ops_blocks,
                    "required_features": strategy.get("required_columns", []),
                    "execution_contract": execution_contract,
                    "ml_view": state.get("ml_view") or (state.get("contract_views") or {}).get("ml_view"),
                    "execution_profile": execution_profile,
                    "cleaned_data_summary_min": cleaned_data_summary_min,
                    "data_audit_context": data_audit_context,
                    "iteration_handoff": iteration_handoff,
                    "ml_engineer_audit_override": ml_audit_override,
                    "dataset_semantics_summary": dataset_semantics_summary,
                    "dataset_training_mask": state.get("dataset_training_mask"),
                    "context_pack": context_pack,
                    # V4.1: Removed feature_availability and availability_summary
                    "dataset_scale_hints": dataset_scale_hints,
                    "signal_summary": kwargs.get("signal_summary", {}),
                    "iteration_memory": iteration_memory,
                    "iteration_memory_block": iteration_memory_block,
                }
            with open(os.path.join("artifacts", "ml_engineer_context.json"), "w", encoding="utf-8") as f_ctx:
                json.dump(ctx_payload, f_ctx, indent=2, ensure_ascii=False)
        except Exception as ctx_err:
            print(f"Warning: failed to persist ml_engineer_context.json: {ctx_err}")
        if context_ops_blocks and not minimal_context_mode:
            ops_payload = "\n\n".join(context_ops_blocks)
            data_audit_context = _merge_de_audit_override(data_audit_context, ops_payload)
            kwargs["data_audit_context"] = data_audit_context
            try:
                ops_preview = ops_payload
                if len(ops_preview) > 1200:
                    ops_preview = ops_preview[:1200] + "...(truncated)"
                print("ML_CONTEXT_OPERATIVE_PREVIEW:\n" + ops_preview)
                os.makedirs("artifacts", exist_ok=True)
                with open(os.path.join("artifacts", "ml_engineer_context_ops.txt"), "w", encoding="utf-8") as f_ops:
                    f_ops.write(ops_payload)
                if run_id:
                    log_run_event(run_id, "ml_context_ops_preview", {"preview": ops_preview})
            except Exception as ops_err:
                print(f"Warning: failed to persist ml_engineer_context_ops.txt: {ops_err}")
        data_audit_context = _truncate_text(data_audit_context)
        iteration_memory_block = _truncate_text(iteration_memory_block, max_len=6000, head_len=3500, tail_len=2000)
        kwargs["data_audit_context"] = data_audit_context
        kwargs["iteration_memory_block"] = iteration_memory_block

        # SENIOR REASONING: Generate ml_plan.json on first iteration
        ml_plan = state.get("ml_plan")
        iter_count = int(state.get("iteration_count", 0))
        if not ml_plan and iter_count == 0 and not editor_mode_active:
            try:
                from src.utils.data_profile_compact import compact_data_profile_for_llm
                data_profile = state.get("data_profile")
                analysis_type = (strategy or {}).get("analysis_type")

                # Compact profile for LLM (supports auto-conversion from dataset_profile schema)
                compact_profile = compact_data_profile_for_llm(
                    data_profile or {},
                    contract=execution_contract,
                    analysis_type=analysis_type,
                )

                ml_plan = ml_engineer.generate_ml_plan(
                    data_profile=compact_profile,
                    execution_contract=execution_contract,
                    strategy=strategy,
                    business_objective=business_objective,
                )

                # Save ml_plan to canonical location (relative to workspace root)
                os.makedirs("data", exist_ok=True)
                dump_json("data/ml_plan.json", ml_plan)

                state["ml_plan"] = ml_plan
                state["ml_plan_path"] = "data/ml_plan.json"

                print(f"ML_PLAN: Generated plan with training_rows_policy='{ml_plan.get('training_rows_policy')}', "
                      f"metric='{ml_plan.get('metric_policy', {}).get('primary_metric')}', "
                      f"source='{ml_plan.get('plan_source', 'unknown')}'")

                if run_id:
                    log_run_event(run_id, "ml_plan_generated", {
                        "training_rows_policy": ml_plan.get("training_rows_policy"),
                        "train_filter": ml_plan.get("train_filter"),
                        "metric_policy": ml_plan.get("metric_policy"),
                        "cv_policy": ml_plan.get("cv_policy"),
                        "plan_source": ml_plan.get("plan_source"),
                        "evidence_used": ml_plan.get("evidence_used"),
                    })
            except Exception as plan_err:
                print(f"Warning: failed to generate ml_plan: {plan_err}")
                ml_plan = {}
                if run_id:
                    log_run_event(run_id, "ml_plan_failed", {"error": str(plan_err)})

        # Inject ml_plan into data_audit_context for the LLM
        if ml_plan:
            plan_context = "ML_PLAN_CONTEXT (DECISION PLAN - implement this exactly):\n" + json.dumps(ml_plan, indent=2)
            data_audit_context = _merge_de_audit_override(data_audit_context, plan_context)
            kwargs["data_audit_context"] = data_audit_context

        # Build/refresh runtime execution profile after plan resolution.
        execution_profile = _build_ml_execution_profile_for_prompt(
            state if isinstance(state, dict) else {},
            code=code_hint,
            ml_plan=ml_plan if isinstance(ml_plan, dict) else None,
        )
        if execution_profile:
            if "execution_profile" in sig.parameters:
                kwargs["execution_profile"] = execution_profile
            exec_profile_ctx = (
                "EXECUTION_PROFILE_CONTEXT (INFRASTRUCTURE BUDGET; ADVISORY, NEVER OVERRIDE CONTRACT):\n"
                + json.dumps(compress_long_lists(execution_profile)[0], ensure_ascii=True)
            )
            data_audit_context = _merge_de_audit_override(data_audit_context, exec_profile_ctx)
            kwargs["data_audit_context"] = data_audit_context
            if run_id:
                try:
                    log_run_event(
                        run_id,
                        "ml_execution_profile",
                        {
                            "backend": execution_profile.get("backend"),
                            "selection_reason": execution_profile.get("selection_reason"),
                            "runtime_budget": execution_profile.get("runtime_budget"),
                            "resources": execution_profile.get("resources"),
                        },
                    )
                except Exception:
                    pass

        code = ml_engineer.generate_code(**kwargs)
        apply_guard_report: Dict[str, Any] = {}
        if bool(state.get("ml_improvement_round_active")):
            apply_guard_report = _evaluate_metric_round_hypothesis_application(
                state if isinstance(state, dict) else {},
                previous_code=previous_code,
                candidate_code=code,
                iteration_handoff=iteration_handoff if isinstance(iteration_handoff, dict) else {},
            )
            if bool(apply_guard_report.get("enforced")) and not bool(apply_guard_report.get("applied")):
                hypothesis_packet = _resolve_metric_round_hypothesis_packet(
                    state if isinstance(state, dict) else {},
                    iteration_handoff=iteration_handoff if isinstance(iteration_handoff, dict) else {},
                )
                technique = str(_extract_hypothesis_technique(hypothesis_packet) or "active_hypothesis")
                enforcement_fix = (
                    "Metric improvement round is active: apply hypothesis '"
                    + technique
                    + "' with material edits. NO_OP is not allowed."
                )
                enforcement_note = (
                    "METRIC_IMPROVEMENT_ENFORCEMENT: first editor output did not materially apply hypothesis '"
                    + technique
                    + "'. Regenerate as a targeted edit over previous code with real feature-engineering changes."
                )
                print(enforcement_note)
                if run_id:
                    try:
                        log_run_event(
                            run_id,
                            "metric_improvement_hypothesis_repair_prompt",
                            {
                                "iteration": int(state.get("iteration_count", 0) or 0) + 1,
                                "reason": apply_guard_report.get("reason"),
                                "technique": technique,
                                "changed_lines": apply_guard_report.get("changed_lines"),
                                "similarity": apply_guard_report.get("similarity"),
                            },
                        )
                    except Exception:
                        pass
                forced_feedback_history = list(feedback_history if isinstance(feedback_history, list) else [])
                forced_feedback_history.append(enforcement_note)

                forced_gate_context = dict(gate_context) if isinstance(gate_context, dict) else {}
                existing_feedback = str(forced_gate_context.get("feedback") or "").strip()
                forced_gate_context["feedback"] = (
                    f"{existing_feedback}\n\n{enforcement_note}".strip()
                    if existing_feedback
                    else enforcement_note
                )
                forced_required_fixes = [
                    str(item)
                    for item in (forced_gate_context.get("required_fixes") or [])
                    if str(item or "").strip()
                ]
                if enforcement_fix not in forced_required_fixes:
                    forced_required_fixes.insert(0, enforcement_fix)
                forced_gate_context["required_fixes"] = forced_required_fixes[:12]
                forced_gate_context["source"] = str(forced_gate_context.get("source") or "metric_improvement_round")

                forced_handoff = dict(iteration_handoff) if isinstance(iteration_handoff, dict) else {}
                forced_quality = (
                    dict(forced_handoff.get("quality_focus"))
                    if isinstance(forced_handoff.get("quality_focus"), dict)
                    else {}
                )
                forced_quality_fixes = [
                    str(item)
                    for item in (forced_quality.get("required_fixes") or [])
                    if str(item or "").strip()
                ]
                if enforcement_fix not in forced_quality_fixes:
                    forced_quality_fixes.insert(0, enforcement_fix)
                forced_quality["required_fixes"] = forced_quality_fixes[:12]
                forced_quality["status"] = "NEEDS_IMPROVEMENT"
                forced_handoff["quality_focus"] = forced_quality
                forced_patch_objectives = [
                    str(item)
                    for item in (forced_handoff.get("patch_objectives") or [])
                    if str(item or "").strip()
                ]
                if enforcement_fix not in forced_patch_objectives:
                    forced_patch_objectives.insert(0, enforcement_fix)
                forced_handoff["patch_objectives"] = forced_patch_objectives[:8]
                editor_constraints = (
                    dict(forced_handoff.get("editor_constraints"))
                    if isinstance(forced_handoff.get("editor_constraints"), dict)
                    else {}
                )
                editor_constraints["must_apply_hypothesis"] = True
                editor_constraints["forbid_noop"] = True
                editor_constraints["patch_intensity"] = "aggressive"
                forced_handoff["editor_constraints"] = editor_constraints
                forced_handoff["must_apply_hypothesis"] = True
                forced_handoff["forbid_noop"] = True
                forced_handoff["patch_intensity"] = "aggressive"

                forced_kwargs = dict(kwargs)
                forced_kwargs["feedback_history"] = forced_feedback_history
                forced_kwargs["gate_context"] = forced_gate_context
                forced_kwargs["iteration_handoff"] = forced_handoff
                forced_kwargs["previous_code"] = previous_code
                forced_kwargs["editor_mode"] = True
                code = ml_engineer.generate_code(**forced_kwargs)
                retry_report = _evaluate_metric_round_hypothesis_application(
                    state if isinstance(state, dict) else {},
                    previous_code=previous_code,
                    candidate_code=code,
                    iteration_handoff=forced_handoff,
                )
                retry_report["repair_attempted"] = True
                retry_report["first_pass_reason"] = apply_guard_report.get("reason")
                apply_guard_report = retry_report
                if run_id:
                    try:
                        log_run_event(
                            run_id,
                            "metric_improvement_hypothesis_repair_result",
                            {
                                "iteration": int(state.get("iteration_count", 0) or 0) + 1,
                                "applied": bool(apply_guard_report.get("applied")),
                                "reason": apply_guard_report.get("reason"),
                                "technique": apply_guard_report.get("technique"),
                                "changed_lines": apply_guard_report.get("changed_lines"),
                                "similarity": apply_guard_report.get("similarity"),
                            },
                        )
                    except Exception:
                        pass
        try:
            os.makedirs("artifacts", exist_ok=True)
            with open(os.path.join("artifacts", "ml_engineer_last.py"), "w", encoding="utf-8") as f_art:
                f_art.write(code)
        except Exception as artifact_err:
            print(f"Warning: failed to persist ml_engineer_last.py: {artifact_err}")
        if run_id:
            log_agent_snapshot(
                run_id,
                "ml_engineer",
                prompt=getattr(ml_engineer, "last_prompt", None),
                response=getattr(ml_engineer, "last_response", None) or code,
                context=ctx_payload,
                script=code,
                attempt=ml_attempt,
                iteration=iter_id,
            )
        try:
            iter_id = ml_attempt
            os.makedirs(os.path.join("artifacts", "iterations"), exist_ok=True)
            iter_path = os.path.join("artifacts", "iterations", f"ml_code_attempt_{iter_id}.py")
            with open(iter_path, "w", encoding="utf-8") as f_iter:
                f_iter.write(code)
        except Exception as iter_err:
            print(f"Warning: failed to persist ml_code_attempt_{iter_id}.py: {iter_err}")

        policy_warnings = getattr(ml_engineer, "last_training_policy_warnings", None)
        if policy_warnings and run_id:
            log_run_event(run_id, "ml_training_policy_warning", policy_warnings)

        if run_id:
            log_run_event(run_id, "ml_engineer_complete", {"code_len": len(code or "")})
        if str(code).strip().startswith("{") or str(code).strip().startswith("["):
            msg = "ML_CODE_REQUIRED: model returned JSON plan; expected Python code."
            if not state.get("ml_code_retry_done"):
                new_state = dict(state)
                new_state["ml_code_retry_done"] = True
                override = new_state.get("ml_engineer_audit_override") or state.get("data_summary", "")
                override += "\n\nML_CODE_REQUIRED: Return executable Python code only. Do not output JSON plans."
                new_state["ml_engineer_audit_override"] = override
                print("ML code-only guard triggered: retrying ML Engineer with code-only instructions.")
                return run_engineer(new_state)
            return {
                "error_message": msg,
                "generated_code": code,
                "execution_output": msg,
                "budget_counters": counters,
                "ml_engineer_attempt": ml_attempt,
            }
        if str(code).strip().startswith("# Error:"):
            return {
                "error_message": code,
                "generated_code": code,
                "execution_output": code,
                "budget_counters": counters,
                "ml_engineer_attempt": ml_attempt,
            }
        result = {
            "selected_strategy": strategy,
            "generated_code": code,
            "last_generated_code": code, # Update for next patch
            "ml_training_policy_warnings": policy_warnings,
            # Reset sandbox retry counters on every new code generation.
            # Retries are scoped to an execution attempt, not carried across iterations.
            "sandbox_retry_count": 0,
            "sandbox_failed": False,
            "ml_data_path": data_path,
            "csv_sep": csv_sep,
            "csv_decimal": csv_decimal,
            "csv_encoding": csv_encoding,
            "error_message": "",
            "ml_engineer_host_crash": False,
            "ml_engineer_host_crash_count": 0,
            "max_ml_engineer_host_retries": int(state.get("max_ml_engineer_host_retries", 1)),
            "ml_call_refund_pending": False,
            "execution_call_refund_pending": False,
            "ml_context_snapshot": {
                "cleaned_column_inventory": header_cols,
                "cleaned_aliasing_collisions": aliasing if header_cols else {},
                "derived_columns_present": derived_present if header_cols else [],
                "raw_required_sample_context": sample_context,
                "feature_semantics": (execution_contract or {}).get("feature_semantics", []),
                "business_sanity_checks": (execution_contract or {}).get("business_sanity_checks", []),
                "execution_contract": execution_contract,
                "execution_profile": execution_profile,
            },
            "budget_counters": counters,
            "strategy_lock_snapshot": strategy_lock_snapshot,
            # SENIOR REASONING: Include data_profile and ml_plan
            "data_profile": state.get("data_profile"),
            "data_profile_path": state.get("data_profile_path"),
            "ml_plan": ml_plan if 'ml_plan' in dir() else state.get("ml_plan"),
            "ml_plan_path": state.get("ml_plan_path"),
            "ml_engineer_attempt": ml_attempt,
            "ml_execution_profile": execution_profile,
            "ml_improvement_apply_guard_report": apply_guard_report,
        }
        merged_state = dict(state or {})
        merged_state.update(result)
        _refresh_run_facts_pack(merged_state)
        return result
    except Exception as e:
        msg = f"CRITICAL: ML Engineer crashed in host: {str(e)}"
        print(msg)
        trace_text = traceback.format_exc()
        iter_id = ml_attempt
        if run_id:
            log_run_event(
                run_id,
                "ml_engineer_host_crash",
                {
                    "error": str(e),
                    "exc_type": type(e).__name__,
                    "traceback": trace_text[:5000],
                    "iteration": iter_id,
                    "ml_engineer_attempt": ml_attempt,
                },
            )
        try:
            os.makedirs("artifacts", exist_ok=True)
            crash_path = os.path.join("artifacts", "ml_engineer_host_crash.txt")
            with open(crash_path, "w", encoding="utf-8") as f_crash:
                f_crash.write(trace_text)
        except Exception as artifact_err:
            print(f"Warning: failed to persist ml_engineer_host_crash.txt: {artifact_err}")
        host_crash_count = int(state.get("ml_engineer_host_crash_count", 0) or 0) + 1
        max_host_retries = int(state.get("max_ml_engineer_host_retries", 1) or 1)
        return {
            "error_message": msg,
            "generated_code": "# Generation Failed",
            "execution_output": msg,
            "budget_counters": counters,
            "ml_engineer_attempt": ml_attempt,
            "ml_engineer_host_crash": True,
            "ml_engineer_host_crash_count": host_crash_count,
            "max_ml_engineer_host_retries": max_host_retries,
        }

def _is_budget_exceeded_error(message: Any) -> bool:
    return "BUDGET_EXCEEDED" in str(message or "").upper()


def check_engineer_success(state: AgentState):
    if state.get("error_message"):
        if bool(state.get("ml_improvement_round_active")) and _is_budget_exceeded_error(state.get("error_message")):
            return "finalize_metric_round"
        if bool(state.get("ml_engineer_host_crash")):
            crash_count = int(state.get("ml_engineer_host_crash_count", 0) or 0)
            max_retries = int(state.get("max_ml_engineer_host_retries", 1) or 1)
            if crash_count <= max_retries:
                print(
                    "ML Engineer host crash detected. "
                    f"Retrying code generation ({crash_count}/{max_retries})."
                )
                return "retry_host_crash"
        return "failed"
    return "success"


def run_reviewer(state: AgentState) -> AgentState:
    print("--- REVIEWER AGENT ---")
    abort_state = _abort_if_requested(state, "reviewer")
    if abort_state:
        return abort_state
    run_id = state.get("run_id")
    ok, counters, err_msg = _consume_budget(state, "reviewer_calls", "max_reviewer_calls", "Reviewer")
    state["budget_counters"] = counters
    if not ok:
        if run_id:
            log_run_event(run_id, "budget_exceeded", {"label": "reviewer", "error": err_msg})
        return {
            "review_verdict": "REJECTED",
            "review_feedback": err_msg,
            "error_message": err_msg,
            "budget_counters": counters,
        }
    if run_id:
        log_run_event(run_id, "reviewer_start", {})

    code = state['generated_code']
    current_iter = state.get('reviewer_iteration', 0)
    new_history = list(state.get('feedback_history', []))
    # Context Construction
    strategy = state.get('selected_strategy', {})
    evaluation_spec = state.get("evaluation_spec") or (state.get("execution_contract", {}) or {}).get("evaluation_spec")
    reviewer_view = state.get("reviewer_view") or (state.get("contract_views") or {}).get("reviewer_view")
    if not isinstance(reviewer_view, dict) or not reviewer_view:
        projected_views = build_contract_views_projection(
            state.get("execution_contract", {}) or {},
            state.get("artifact_index") or [],
        )
        reviewer_view = projected_views.get("reviewer_view") or {}
    reviewer_contract = state.get("execution_contract", {}) if isinstance(state.get("execution_contract"), dict) else {}
    reviewer_view, evaluation_spec = _apply_ml_reviewer_output_scope(
        reviewer_contract,
        state if isinstance(state, dict) else {},
        reviewer_view if isinstance(reviewer_view, dict) else {},
        evaluation_spec if isinstance(evaluation_spec, dict) else None,
    )
    dataset_semantics_summary = state.get("dataset_semantics_summary")
    execution_profile = state.get("ml_execution_profile")
    if not isinstance(execution_profile, dict) or not execution_profile:
        execution_profile = _build_ml_execution_profile_for_prompt(
            state if isinstance(state, dict) else {},
            code=str(code or ""),
            ml_plan=state.get("ml_plan") if isinstance(state.get("ml_plan"), dict) else None,
        )
    if dataset_semantics_summary and isinstance(reviewer_view, dict):
        reviewer_view = dict(reviewer_view)
        reviewer_view["dataset_semantics_summary"] = dataset_semantics_summary
    if isinstance(reviewer_view, dict) and execution_profile:
        reviewer_view = dict(reviewer_view)
        reviewer_view["execution_profile"] = execution_profile
    if isinstance(reviewer_view, dict):
        reviewer_view = compress_long_lists(reviewer_view)[0]
    analysis_type = reviewer_view.get("objective_type") or strategy.get('analysis_type', 'predictive')
    strategy_context = reviewer_view.get("strategy_summary") or ""
    business_objective = ""
    try:
        reviewer_view_len = len(json.dumps(reviewer_view, ensure_ascii=True))
        print(f"Using REVIEWER_VIEW_CONTEXT length={reviewer_view_len}")
        if run_id:
            log_run_event(run_id, "reviewer_view_context", {"length": reviewer_view_len})
    except Exception:
        pass

    try:
        review = reviewer.review_code(
            code,
            analysis_type,
            business_objective,
            strategy_context,
            evaluation_spec,
            reviewer_view=reviewer_view,
        )
        print(f"Verdict: {review['status']}")

        # Update Streak
        streak = state.get('review_reject_streak', 0)
        if review['status'] == "REJECTED":
            streak += 1
            print(f"Feedback: {review['feedback']}")
        else:
            streak = 0

        # Pass Structured Context for Patching
        gate_context = {
            "source": "reviewer",
            "status": review['status'],
            "feedback": review['feedback'],
            "failed_gates": review.get('failed_gates', []),
            "required_fixes": _expand_required_fixes(review.get('required_fixes', []), review.get('failed_gates', []))
        }
        # Include hard_failures in gate_context if present
        if review.get('hard_failures'):
            gate_context["hard_failures"] = review.get('hard_failures', [])
        gate_context["feedback_json"] = _build_ml_feedback_json(
            source="reviewer",
            status=review.get("status"),
            feedback=review.get("feedback"),
            failed_gates=review.get("failed_gates"),
            required_fixes=review.get("required_fixes"),
            hard_failures=review.get("hard_failures"),
            review_result=review,
            qa_result={},
            evidence=review.get("evidence") if isinstance(review.get("evidence"), list) else [],
        )
        fix_block = _build_fix_instructions(gate_context["required_fixes"])
        if fix_block:
            gate_context["edit_instructions"] = fix_block

        if review['status'] == "REJECTED":
            new_history.append(f"REVIEWER FEEDBACK (Attempt {current_iter+1}): {review['feedback']}")

            # Check Fail-Safe Condition (Streak Based)
            # 1. Critical API Error
            if "Reviewer unavailable" in review['feedback']:
                msg = f"CRITICAL SYSTEM FAILURE: {review['feedback']}"
                return {
                    "review_verdict": "REJECTED",
                    "review_feedback": review['feedback'],
                    "feedback_history": new_history,
                    "reviewer_iteration": current_iter + 1,
                    "review_abort_reason": msg,
                    "budget_counters": counters,
                }

            # 2. Reject Streak Exceeded (Avoid infinite loop on bad code)
            if streak >= 3:
                msg = f"CRITICAL: Code review failed {streak} times in a row. Aborting to avoid loops."
                print(msg)
                return {
                    "review_verdict": "REJECTED",
                    "review_feedback": review['feedback'],
                    "feedback_history": new_history,
                    "reviewer_iteration": current_iter + 1,
                    "review_abort_reason": msg,
                    "budget_counters": counters,
                }

        if run_id:
            log_run_event(run_id, "reviewer_complete", {"status": review.get("status")})
        if run_id:
            log_agent_snapshot(
                run_id,
            "reviewer",
            prompt=getattr(reviewer, "last_prompt", None),
            response=getattr(reviewer, "last_response", None) or review,
            context={
                "analysis_type": analysis_type,
                "business_objective": business_objective,
                "execution_profile": execution_profile,
            },
            verdicts=review,
        )
        return {
            "review_verdict": review['status'],
            "review_feedback": review['feedback'],
            "feedback_history": new_history,
            "reviewer_iteration": current_iter + 1,
            "last_gate_context": gate_context,
            "review_reject_streak": streak,
            "budget_counters": counters,
        }

    except Exception as e:
        msg = f"CRITICAL: Reviewer Agent crashed: {str(e)}"
        print(msg)
        return {
            "review_verdict": "REJECTED",
            "review_feedback": msg,
            "feedback_history": new_history,
            "reviewer_iteration": current_iter + 1,
            "error_message": msg,
            "budget_counters": counters,
        }

def run_qa_reviewer(state: AgentState) -> AgentState:
    print("--- QA REVIEWER AGENT ---")
    abort_state = _abort_if_requested(state, "qa_reviewer")
    if abort_state:
        return abort_state
    run_id = state.get("run_id")
    ok, counters, err_msg = _consume_budget(state, "qa_calls", "max_qa_calls", "QA Reviewer")
    state["budget_counters"] = counters
    if not ok:
        if run_id:
            log_run_event(run_id, "budget_exceeded", {"label": "qa_reviewer", "error": err_msg})
        return {
            "review_verdict": "REJECTED",
            "review_feedback": err_msg,
            "error_message": err_msg,
            "qa_budget_exceeded": True,
            "budget_counters": counters,
        }
    if run_id:
        log_run_event(run_id, "qa_reviewer_start", {})
    code = state['generated_code']
    strategy = state.get('selected_strategy', {})
    business_objective = state.get('business_objective', '')

    current_history = list(state.get('feedback_history', []))
    try:
        # Run QA Audit
        contract, _ = _resolve_contract_pair_from_state(state if isinstance(state, dict) else {})
        qa_view = state.get("qa_view") or (state.get("contract_views") or {}).get("qa_view")
        if isinstance(qa_view, dict) and qa_view:
            qa_context = dict(qa_view)
            contract_source = "qa_view"
        elif isinstance(contract, dict) and contract:
            qa_context = dict(contract)
            contract_source = "execution_contract"
        else:
            qa_context = {}
            contract_source = "fallback"
        qa_context["_contract_source"] = contract_source
        execution_profile = state.get("ml_execution_profile")
        if not isinstance(execution_profile, dict) or not execution_profile:
            execution_profile = _build_ml_execution_profile_for_prompt(
                state if isinstance(state, dict) else {},
                code=str(code or ""),
                ml_plan=state.get("ml_plan") if isinstance(state.get("ml_plan"), dict) else None,
            )
        if execution_profile:
            qa_context["execution_profile"] = execution_profile

        # Wire ML Plan for QA coherence check (Senior Reasoning)
        qa_context.setdefault("evaluation_spec", {})
        if isinstance(qa_context["evaluation_spec"], dict):
             ml_plan_for_qa = state.get("ml_plan")
             if not ml_plan_for_qa:
                 ml_plan_for_qa = _load_json_safe("data/ml_plan.json")
             qa_context["evaluation_spec"]["ml_plan"] = ml_plan_for_qa or {}
             qa_context["evaluation_spec"]["data_profile"] = state.get("data_profile") or {}
             qa_context["evaluation_spec"]["ml_training_policy_warnings"] = state.get("ml_training_policy_warnings") or {}
        dataset_semantics_summary = state.get("dataset_semantics_summary")
        if dataset_semantics_summary:
            qa_context["dataset_semantics_summary"] = dataset_semantics_summary
        iteration_handoff_ctx = state.get("iteration_handoff")
        if isinstance(iteration_handoff_ctx, dict) and iteration_handoff_ctx:
            qa_context["iteration_handoff"] = iteration_handoff_ctx
        hypothesis_packet_ctx = state.get("ml_improvement_hypothesis_packet")
        if isinstance(hypothesis_packet_ctx, dict) and hypothesis_packet_ctx:
            qa_context["ml_improvement_hypothesis_packet"] = hypothesis_packet_ctx
        metric_round_active_ctx = bool(state.get("ml_improvement_round_active"))
        qa_context["metric_improvement_round_active"] = metric_round_active_ctx
        qa_context["augmentation_requested"] = bool(
            metric_round_active_ctx
            and _resolve_metric_round_augmentation_requested(
                state if isinstance(state, dict) else {},
                contract if isinstance(contract, dict) else {},
            )
        )
        ml_data_path = state.get("ml_data_path")
        if not ml_data_path and isinstance(qa_context, dict):
            artifact_reqs = qa_context.get("artifact_requirements")
            if isinstance(artifact_reqs, dict):
                outputs = artifact_reqs.get("required_outputs") or artifact_reqs.get("required_files") or []
                if isinstance(outputs, list):
                    for path in outputs:
                        if isinstance(path, str) and path.endswith(".csv") and "clean" in path.lower():
                            ml_data_path = path
                            break
        if ml_data_path:
            qa_context["ml_data_path"] = ml_data_path
        qa_context_prompt = compress_long_lists(qa_context)[0] if isinstance(qa_context, dict) else qa_context
        if contract_source == "qa_view":
            try:
                qa_len = len(json.dumps(qa_context_prompt, ensure_ascii=True))
                print(f"Using QA_VIEW_CONTEXT length={qa_len}")
                if run_id:
                    log_run_event(run_id, "qa_view_context", {"length": qa_len})
            except Exception:
                pass
        allowed_columns = _resolve_allowed_columns_for_gate(state, contract, qa_context)
        allowed_patterns = _resolve_allowed_patterns_for_gate(contract)
        static_facts = collect_static_qa_facts(code)
        static_result = run_static_qa_checks(code, qa_context, static_facts)
        if static_result and static_result.get("status") == "REJECTED":
            status = "REJECTED"
            feedback = static_result.get("feedback") or "Static QA gate failures detected."
            failed_gates = static_result.get("failed_gates", [])
            required_fixes = static_result.get("required_fixes", [])
            current_history.append(f"QA_STATIC_REJECTED: {feedback}")
            print(f"QA Verdict: {status}")
            streak = int(state.get("qa_reject_streak", 0) or 0) + 1
            gate_context = {
                "source": "qa_reviewer",
                "status": status,
                "feedback": feedback,
                "failed_gates": failed_gates,
                "required_fixes": _expand_required_fixes(required_fixes, failed_gates),
            }
            # Include hard_failures from static QA in gate_context
            static_hard_failures = static_result.get("hard_failures", [])
            if static_hard_failures:
                gate_context["hard_failures"] = static_hard_failures
            gate_context["feedback_json"] = _build_ml_feedback_json(
                source="qa_reviewer",
                status=status,
                feedback=feedback,
                failed_gates=failed_gates,
                required_fixes=required_fixes,
                hard_failures=static_hard_failures,
                review_result={},
                qa_result=static_result if isinstance(static_result, dict) else {},
                evidence=static_result.get("evidence") if isinstance(static_result.get("evidence"), list) else [],
            )
            fix_block = _build_fix_instructions(gate_context["required_fixes"])
            if fix_block:
                gate_context["edit_instructions"] = fix_block
            if streak >= 5:
                msg = f"CRITICAL: QA Rejected code {streak} times consecutively. Quality Standard not met."
                return {
                    "review_verdict": "REJECTED",
                    "review_feedback": feedback,
                    "feedback_history": current_history,
                    "error_message": msg,
                    "last_gate_context": gate_context,
                    "qa_reject_streak": streak,
                    "budget_counters": counters,
                }
            return {
                "review_verdict": "REJECTED",
                "review_feedback": feedback,
                "feedback_history": current_history,
                "last_gate_context": gate_context,
                "qa_reject_streak": streak,
                "budget_counters": counters,
            }

        try:
            qa_result = qa_reviewer.review_code(code, strategy, business_objective, qa_context_prompt)
        except TypeError:
            qa_result = qa_reviewer.review_code(code, strategy, business_objective)

        status = qa_result['status']
        feedback = qa_result['feedback']
        failed_gates = qa_result.get('failed_gates', [])
        required_fixes = qa_result.get('required_fixes', [])

        hard_failures = qa_result.get("hard_failures") or []
        if status == "REJECTED" and not hard_failures:
            feedback = f"QA_LLM_NONBLOCKING_WARNING: {feedback}"
            current_history.append(feedback)
            status = "APPROVE_WITH_WARNINGS"
            failed_gates = []
            required_fixes = []

        print(f"QA Verdict: {status}")

        # Update QA Streak (only deterministic rejects)
        streak = state.get('qa_reject_streak', 0)
        if status in {"APPROVED", "APPROVE_WITH_WARNINGS"}:
            streak = 0

        # Structured context for Patching
        gate_context = {
            "source": "qa_reviewer",
            "status": status,
            "feedback": feedback,
            "failed_gates": failed_gates,
            "required_fixes": _expand_required_fixes(required_fixes, failed_gates)
        }
        # Include hard_failures in gate_context if present
        hard_failures = qa_result.get("hard_failures") or []
        if hard_failures:
            gate_context["hard_failures"] = hard_failures
        gate_context["feedback_json"] = _build_ml_feedback_json(
            source="qa_reviewer",
            status=status,
            feedback=feedback,
            failed_gates=failed_gates,
            required_fixes=required_fixes,
            hard_failures=hard_failures,
            review_result={},
            qa_result=qa_result if isinstance(qa_result, dict) else {},
            evidence=qa_result.get("evidence") if isinstance(qa_result.get("evidence"), list) else [],
        )
        fix_block = _build_fix_instructions(gate_context["required_fixes"])
        if fix_block:
            gate_context["edit_instructions"] = fix_block

        review_verdict = status if status in {"APPROVED", "APPROVE_WITH_WARNINGS"} else "APPROVED"
        if run_id:
            log_run_event(run_id, "qa_reviewer_complete", {"status": status})
        if run_id:
            log_agent_snapshot(
                run_id,
                "qa_reviewer",
                prompt=getattr(qa_reviewer, "last_prompt", None),
                response=getattr(qa_reviewer, "last_response", None) or qa_result,
                context={
                    "business_objective": business_objective,
                    "execution_profile": qa_context.get("execution_profile") if isinstance(qa_context, dict) else {},
                },
                verdicts=qa_result,
            )
        return {
            "review_verdict": review_verdict,
            "feedback_history": current_history,
            "last_gate_context": gate_context,
            "qa_reject_streak": streak,
            "budget_counters": counters,
        }

    except Exception as e:
        msg = f"CRITICAL: QA Reviewer crashed: {str(e)}"
        print(msg)
        return {
            "review_verdict": "REJECTED",
            "review_feedback": msg,
            "feedback_history": current_history,
            "error_message": msg,
            "budget_counters": counters,
        }

def run_ml_preflight(state: AgentState) -> AgentState:
    print("--- ML PREFLIGHT ---")
    abort_state = _abort_if_requested(state, "ml_preflight")
    if abort_state:
        return abort_state
    run_id = state.get("run_id")
    code = state.get("generated_code", "")
    evaluation_spec = state.get("evaluation_spec") or (state.get("execution_contract", {}) or {}).get("evaluation_spec") or {}
    if code and not is_syntax_valid(code):
        feedback = "ML_PREFLIGHT_SYNTAX_ERROR: Generated code is not valid Python syntax."
        history = list(state.get("feedback_history", []))
        history.append(feedback)
        gate_context = {
            "source": "ml_preflight",
            "status": "REJECTED",
            "feedback": feedback,
            "failed_gates": ["AST_PARSE_FAILED"],
            "required_fixes": ["AST_PARSE_FAILED"],
        }
        return {
            "ml_preflight_failed": True,
            "feedback_history": history,
            "last_gate_context": gate_context,
            "review_verdict": "REJECTED",
            "review_feedback": feedback,
        }
    contract = state.get("execution_contract", {}) or {}
    strategy = state.get("selected_strategy", {}) or {}
    required_deps = contract.get("required_dependencies", []) or []
    backend_selection = _resolve_ml_backend_selection(state if isinstance(state, dict) else {})
    dep_backend_profile = backend_selection.get("backend_profile", "e2b")
    dep_result = check_dependency_precheck(code, required_deps, backend_profile=dep_backend_profile)
    if dep_result.get("banned") or dep_result.get("blocked"):
        blocked = dep_result.get("blocked", [])
        banned = dep_result.get("banned", [])
        suggestions = dep_result.get("suggestions", {})
        parts = []
        if banned:
            parts.append(f"banned={', '.join(banned)}")
        if blocked:
            parts.append(f"blocked={', '.join(blocked)}")
        hint_parts = []
        for key in banned + blocked:
            hint = suggestions.get(key)
            if hint:
                hint_parts.append(f"{key}: {hint}")
        hint_text = f" Suggestions: {' | '.join(hint_parts)}" if hint_parts else ""
        feedback = (
            f"DEPENDENCY_BLOCKED[{dep_backend_profile}]: {'; '.join(parts)}."
            f"{hint_text}"
        )
        history = list(state.get("feedback_history", []))
        history.append(feedback)
        gate_context = {
            "source": "ml_preflight",
            "status": "REJECTED",
            "feedback": feedback,
            "failed_gates": ["DEPENDENCY_BLOCKED"],
            "required_fixes": ["DEPENDENCY_BLOCKED"],
        }
        return {
            "ml_preflight_failed": True,
            "feedback_history": history,
            "last_gate_context": gate_context,
            "review_verdict": "REJECTED",
            "review_feedback": feedback,
        }

    flags = _resolve_eval_flags(evaluation_spec)
    allowed_columns = _resolve_allowed_columns_for_gate(state, contract, evaluation_spec)
    allowed_patterns = _resolve_allowed_patterns_for_gate(contract)
    issues = ml_quality_preflight(code, evaluation_spec, allowed_columns, allowed_patterns)
    if isinstance(evaluation_spec, dict):
        obj_type = str(evaluation_spec.get("objective_type") or "").lower()
        validation_policy = evaluation_spec.get("validation_policy") or {}
        require_cv = bool(validation_policy.get("require_cv")) if isinstance(validation_policy, dict) else False
        if (not require_cv or not flags["requires_supervised_split"]) and "CROSS_VALIDATION_REQUIRED" in issues:
            issues = [i for i in issues if i != "CROSS_VALIDATION_REQUIRED"]
        if flags["requires_time_series_split"] and "TIME_SERIES_SPLIT_REQUIRED" not in issues:
            pass
        qa_gates = _extract_qa_gate_names(evaluation_spec.get("qa_gates") or evaluation_spec.get("gates") or [])
        require_variance = "target_variance_guard" in qa_gates or obj_type in {"predictive", "prescriptive"}
        if not require_variance and "TARGET_VARIANCE_GUARD" in issues:
            issues = [i for i in issues if i != "TARGET_VARIANCE_GUARD"]
    if not flags["requires_target"]:
        issues = [
            i
            for i in issues
            if i not in {"TARGET_NOT_IN_X", "TARGET_VARIANCE_GUARD", "CROSS_VALIDATION_REQUIRED", "TIME_SERIES_SPLIT_REQUIRED"}
        ]
    # V4.1 Resolution for key columns
    base_cols = []
    if isinstance(contract, dict):
        base_cols = contract.get("relevant_columns") or []
    if not base_cols:
         base_cols = get_canonical_columns(contract) or []

    constant_cols = _load_constant_columns_from_profile()
    constant_norm = {_norm_name(col) for col in constant_cols if col} if constant_cols else set()
    if constant_norm and base_cols:
        filtered_base = [col for col in base_cols if _norm_name(col) not in constant_norm]
        if filtered_base:
            base_cols = filtered_base
    
    key_columns = list(base_cols)[:30]
    
    # Strategy refinement
    strategy_req = strategy.get("required_columns")
    if isinstance(strategy_req, list) and strategy_req:
        canonical = get_canonical_columns(contract) or []
        intersect = [c for c in strategy_req if c in canonical]
        if constant_norm and intersect:
            intersect_filtered = [c for c in intersect if _norm_name(c) not in constant_norm]
            if intersect_filtered:
                intersect = intersect_filtered
        if intersect:
            key_columns = list(intersect)[:30]
            
    required_columns = key_columns # Map for downstream consistency
    roles = get_column_roles(contract) or {}
    pre_decision_cols = roles.get("pre_decision", []) or []
    decision_vars = roles.get("decision", []) or []
    evaluation_spec = state.get("evaluation_spec") or contract.get("evaluation_spec") or {}
    required_outputs = contract.get("required_outputs", []) or []
    if not flags["requires_row_scoring"]:
        required_outputs = [
            path for path in required_outputs if path != "data/scored_rows.csv"
        ]
    missing_outputs = _missing_required_output_refs(code, required_outputs)
    if missing_outputs:
        issues.append("REQUIRED_OUTPUTS_MISSING")
    read_csv_info = _analyze_read_csv_usage(code)
    has_read_csv = read_csv_info.get("has_read_csv")
    if not has_read_csv:
        issues.append("DATA_LOAD_MISSING")
    else:
        allowed_paths = {"data.csv"}
        ml_data_path = state.get("ml_data_path")
        if isinstance(ml_data_path, str) and ml_data_path.strip():
            allowed_paths.add(ml_data_path.strip())
        de_view = state.get("de_view") or (state.get("contract_views") or {}).get("de_view")
        if isinstance(de_view, dict):
            de_output = de_view.get("output_path")
            if isinstance(de_output, str) and de_output.strip():
                allowed_paths.add(de_output.strip())
        path_hits = [
            p
            for p in read_csv_info.get("paths", [])
            if any(a and a in p for a in allowed_paths)
        ]
        if not path_hits and "data_path" not in (code or "").lower():
            issues.append("DATA_PATH_NOT_USED")
    col_coverage = _required_columns_coverage(code, required_columns)
    if required_columns:
        min_abs = 2 if len(required_columns) >= 4 else 1
        min_ratio = int(len(required_columns) * 0.5 + 0.5)
        min_required = max(min_abs, min_ratio)
        if len(col_coverage.get("hits", [])) < min_required:
            issues.append("REQUIRED_COLUMNS_NOT_USED")
    if "alignment_check.json" in (code or "") and "\"requirements\"" not in (code or "") and "'requirements'" not in (code or ""):
        issues.append("ALIGNMENT_REQUIREMENTS_MISSING")
    segment_features = _extract_named_string_list(code, ["SEGMENT_FEATURES", "segment_features"])
    segmentation_required = False
    if isinstance(evaluation_spec, dict):
        segmentation_required = bool((evaluation_spec.get("segmentation") or {}).get("required"))
    if segmentation_required:
        if not segment_features:
            issues.append("SEGMENT_FEATURES_MISSING")
        else:
            expected_seg = pre_decision_cols or (evaluation_spec.get("segmentation") or {}).get("features") or []
            missing_seg = [col for col in expected_seg if col and col not in segment_features]
            if missing_seg:
                issues.append("SEGMENT_FEATURES_INCOMPLETE")
    model_features = _extract_named_string_list(code, ["MODEL_FEATURES", "model_features"])
    # decision_vars already computed from roles
    model_required = False
    if isinstance(evaluation_spec, dict):
        obj_type = str(evaluation_spec.get("objective_type") or "").lower()
        model_required = obj_type in {"predictive", "prescriptive"}
    if decision_vars and model_required:
        if not model_features:
            issues.append("MODEL_FEATURES_MISSING")
        else:
            if not any(var in model_features for var in decision_vars if var):
                issues.append("MODEL_FEATURES_INCOMPLETE")
    canonical_mismatches: List[Dict[str, str]] = []
    if segment_features:
        canonical_mismatches.extend(_find_canonical_mismatches(segment_features, required_columns))
    if model_features:
        canonical_mismatches.extend(_find_canonical_mismatches(model_features, required_columns + decision_vars))
    if canonical_mismatches:
        issues.append("CANONICAL_MAPPING_REQUIRED")
    derived_targets = _collect_derived_targets(contract)
    if derived_targets:
        code_lower = code.lower()
        has_derived_log = "derived_target:" in code_lower or "derived_target" in code_lower
        has_guard = any(_has_derived_target_guard(code_lower, name) for name in derived_targets)
        has_assignment = any(_code_assigns_df_column(code, name) for name in derived_targets)
        if not (has_derived_log or has_guard or has_assignment):
            issues.append("DERIVED_TARGET_REQUIRED")
    unknown_cols: List[str] = []
    if "UNKNOWN_COLUMNS_REFERENCED" in issues and allowed_columns:
        unknown_cols = _detect_unknown_columns(code, allowed_columns, allowed_patterns)
    forbidden_assignments: List[str] = []
    if "DF_COLUMN_ASSIGNMENT_FORBIDDEN" in issues and allowed_columns:
        forbidden_assignments = _detect_forbidden_df_assignments(code, allowed_columns, allowed_patterns)
    if run_id and issues:
        payload = {"issues": issues}
        if unknown_cols:
            payload["unknown_columns"] = unknown_cols
        if forbidden_assignments:
            payload["forbidden_df_assignments"] = forbidden_assignments
        log_run_event(run_id, "ml_preflight_issues", payload)
    if issues:
        expanded = _expand_required_fixes(issues, issues)
        feedback = f"ML_PREFLIGHT_MISSING: {', '.join(issues)}"
        if missing_outputs:
            feedback += f" | Missing output refs: {missing_outputs}"
        if col_coverage.get("hits") is not None and required_columns:
            feedback += f" | Required columns hits: {col_coverage.get('hits')}"
        if canonical_mismatches:
            feedback += f" | Canonical mismatches: {canonical_mismatches}"
        if unknown_cols:
            preview = unknown_cols[:10]
            feedback += f" | Unknown columns ({len(unknown_cols)}): {preview}"
        if forbidden_assignments:
            preview = forbidden_assignments[:10]
            feedback += f" | Forbidden df column assignments ({len(forbidden_assignments)}): {preview}. SOLUTION: Use df.assign() instead of df['col']=value. Pattern: df = df.assign(new_col=expression). Example: df = df.assign(derived_target=(df['source_col']==condition).astype(int))"
        history = list(state.get("feedback_history", []))
        history.append(feedback)
        gate_context = {
            "source": "ml_preflight",
            "status": "REJECTED",
            "feedback": feedback,
            "failed_gates": issues,
            "required_fixes": expanded,
        }
        fix_block = _build_fix_instructions(expanded)
        if fix_block:
            gate_context["edit_instructions"] = fix_block
        if run_id:
            outputs_state = _collect_outputs_state(_resolve_required_outputs(contract, state))
            reviewer_reasons = _normalize_reason_tags(feedback, issues)
            next_actions = _suggest_next_actions(issues, outputs_state["missing"], reviewer_reasons, [])
            entry = _build_ml_iteration_journal_entry(
                state,
                preflight_issues=issues,
                runtime_error=None,
                outputs_present=outputs_state["present"],
                outputs_missing=outputs_state["missing"],
                reviewer_verdict="REJECTED",
                reviewer_reasons=reviewer_reasons,
                qa_verdict=None,
                qa_reasons=[],
                next_actions=next_actions,
                stage="preflight",
            )
            written_ids = _append_ml_iteration_journal(
                run_id,
                entry,
                state.get("ml_journal_written_ids"),
            )
        else:
            written_ids = state.get("ml_journal_written_ids")
        return {
            "ml_preflight_failed": True,
            "feedback_history": history,
            "last_gate_context": gate_context,
            "review_verdict": "REJECTED",
            "review_feedback": feedback,
            "ml_journal_written_ids": written_ids,
        }
    if manifest_dump_missing_default(code):
        feedback = "ML_JSON_SERIALIZATION_GUARD: json.dump must use default=_json_default to serialize numpy/pandas types."
        history = list(state.get("feedback_history", []))
        history.append(feedback)
        gate_context = {
            "source": "ml_preflight",
            "status": "REJECTED",
            "feedback": feedback,
            "failed_gates": ["JSON_SERIALIZATION_GUARD"],
            "required_fixes": ["Add json.dump(..., default=_json_default) and define _json_default helper."],
        }
        if run_id:
            outputs_state = _collect_outputs_state(_resolve_required_outputs(contract, state))
            reviewer_reasons = _normalize_reason_tags(feedback, ["JSON_SERIALIZATION_GUARD"])
            next_actions = _suggest_next_actions(["JSON_SERIALIZATION_GUARD"], outputs_state["missing"], reviewer_reasons, [])
            entry = _build_ml_iteration_journal_entry(
                state,
                preflight_issues=["JSON_SERIALIZATION_GUARD"],
                runtime_error=None,
                outputs_present=outputs_state["present"],
                outputs_missing=outputs_state["missing"],
                reviewer_verdict="REJECTED",
                reviewer_reasons=reviewer_reasons,
                qa_verdict=None,
                qa_reasons=[],
                next_actions=next_actions,
                stage="preflight",
            )
            written_ids = _append_ml_iteration_journal(
                run_id,
                entry,
                state.get("ml_journal_written_ids"),
            )
        else:
            written_ids = state.get("ml_journal_written_ids")
        return {
            "ml_preflight_failed": True,
            "feedback_history": history,
            "last_gate_context": gate_context,
            "review_verdict": "REJECTED",
            "review_feedback": feedback,
            "ml_journal_written_ids": written_ids,
        }
    return {"ml_preflight_failed": False}

def check_qa_review(state: AgentState):
    if state.get("error_message") or state.get("review_abort_reason"):
        return "failed"
    if state.get('review_verdict') == "REJECTED":
        return "rejected"
    # APPROVED or APPROVE_WITH_WARNINGS -> proceeds
    return "approved"

def check_ml_preflight(state: AgentState):
    if state.get("ml_preflight_failed"):
        return "failed"
    if (
        state.get("review_verdict") == "REJECTED"
        and (state.get("last_gate_context") or {}).get("source") == "ml_preflight"
    ):
        return "failed"
    return "passed"


def check_review(state: AgentState):
    # Fail-Safe Logic
    if state.get("error_message") or state.get("review_abort_reason"):
        return "failed"

    if state['review_verdict'] in ["APPROVED", "APPROVE_WITH_WARNINGS"]:
        return "approved"
    else:
        return "rejected"

def execute_code(state: AgentState) -> AgentState:
    print("--- [5] System: Executing Code ---")
    run_id = state.get("run_id")
    ok, counters, err_msg = _consume_budget(state, "execution_calls", "max_execution_calls", "Execution")
    state["budget_counters"] = counters
    if not ok:
        if run_id:
            log_run_event(run_id, "budget_exceeded", {"label": "execution", "error": err_msg})
        return {"error_message": err_msg, "execution_output": err_msg, "budget_counters": counters}
    if run_id:
        log_run_event(run_id, "execution_start", {})
    exec_start_ts = time.time()
    code = state['generated_code']
    attempt_id = int(state.get("execution_attempt", 0)) + 1
    visuals_missing = False
    contract, contract_min = _resolve_contract_pair_from_state(state if isinstance(state, dict) else {})
    backend_selection = _resolve_ml_backend_selection(state if isinstance(state, dict) else {})
    runtime_mode = str(backend_selection.get("runtime_mode") or _get_execution_runtime_mode())
    heavy_cfg = backend_selection.get("heavy_cfg")
    use_heavy = bool(backend_selection.get("use_heavy"))
    heavy_reason = str(backend_selection.get("reason") or "unknown")
    heavy_imports_in_code = (
        backend_selection.get("heavy_imports_in_code")
        if isinstance(backend_selection.get("heavy_imports_in_code"), list)
        else []
    )
    dependency_backend = "cloudrun"
    ml_plan = backend_selection.get("ml_plan") if isinstance(backend_selection.get("ml_plan"), dict) else {}
    data_profile = (
        backend_selection.get("data_profile")
        if isinstance(backend_selection.get("data_profile"), dict)
        else {}
    )
    if not heavy_cfg or not use_heavy:
        if runtime_mode == "local":
            msg = "LOCAL_RUNNER_REQUIRED: ML execution is configured for local runner, but local runner config is missing/unavailable."
        else:
            msg = (
                "CLOUDRUN_REQUIRED: ML execution is configured for Cloud Run only, "
                "but heavy runner configuration is missing/unavailable."
            )
        if run_id:
            log_run_event(
                run_id,
                "execution_backend_unavailable",
                {
                    "backend": "local_runner" if runtime_mode == "local" else "heavy_runner",
                    "reason": heavy_reason,
                    "runtime_mode": runtime_mode,
                },
            )
        return {"error_message": msg, "execution_output": msg, "budget_counters": counters}

    # Shared prechecks for both backends (Cloud Run + E2B) to keep behavior aligned.
    is_safe, violations = scan_code_safety(code)
    if not is_safe:
        failure_reason = "CRITICAL: Security Violations:\n" + "\n".join(violations)
        print(f"Security Block: {failure_reason}")
        if run_id:
            log_run_event(run_id, "execution_security_blocked", {"violations": violations[:20]})
        return {"error_message": failure_reason, "execution_output": failure_reason, "budget_counters": counters}

    required_deps = contract.get("required_dependencies", []) if isinstance(contract, dict) else []
    dep_result = check_dependency_precheck(code, required_deps or [], backend_profile=dependency_backend)
    blocked = dep_result.get("blocked") or []
    banned = dep_result.get("banned") or []
    if banned or blocked:
        parts: List[str] = []
        if banned:
            parts.append(f"banned imports: {', '.join(banned)}")
        if blocked:
            parts.append(f"imports not in allowlist: {', '.join(blocked)}")
        msg = f"EXECUTION ERROR: DEPENDENCY_BLOCKED[{dependency_backend}] " + "; ".join(parts)
        suggestions = dep_result.get("suggestions", {}) if isinstance(dep_result, dict) else {}
        hints = [f"{name}: {suggestions.get(name)}" for name in (banned + blocked) if suggestions.get(name)]
        if hints:
            msg += " | Suggestions: " + " | ".join(hints)
        fh = list(state.get("feedback_history", []))
        fh.append(msg)
        if run_id:
            log_run_event(
                run_id,
                "execution_dependency_blocked",
                {"banned": banned, "blocked": blocked, "suggestions": suggestions},
            )
        return {"error_message": msg, "execution_output": msg, "feedback_history": fh, "budget_counters": counters}

    # Optional heavy runner path (Cloud Run Job) for large workloads
    if heavy_cfg:
        if run_id:
            hints = state.get("dataset_scale_hints") or {}
            cv_policy = ml_plan.get("cv_policy") if isinstance(ml_plan, dict) else {}
            backend_memory = state.get("backend_memory_estimate") if isinstance(state.get("backend_memory_estimate"), dict) else {}
            log_run_event(
                run_id,
                "execution_backend_selection",
                {
                    "backend": "heavy_runner",
                    "runtime_mode": runtime_mode,
                    "reason": heavy_reason,
                    "dataset_scale": {
                        "scale": hints.get("scale"),
                        "file_mb": hints.get("file_mb"),
                        "est_rows": hints.get("est_rows"),
                        "cols": hints.get("cols") or hints.get("n_cols"),
                    },
                    "cv_folds": cv_policy.get("n_splits") if isinstance(cv_policy, dict) else None,
                    "memory_decision": backend_memory,
                },
            )
        if use_heavy:
            if runtime_mode == "local":
                print(f"    Backend: Local Runner (reason={heavy_reason})")
            else:
                print(f"    Backend: Cloud Run Heavy Runner (reason={heavy_reason})")
            dialect = _resolve_artifact_gate_dialect(state, contract)
            csv_sep = dialect["sep"]
            csv_decimal = dialect["decimal"]
            csv_encoding = dialect["encoding"]
            eval_spec = state.get("evaluation_spec") or (contract.get("evaluation_spec") if isinstance(contract, dict) else {})
            required_outputs = _resolve_ml_heavy_runner_required_outputs(contract, state)
            expected_outputs = _resolve_expected_output_paths(contract, state)
            preserve_paths = []
            ml_candidate_paths = _candidate_ml_input_paths(state if isinstance(state, dict) else {})
            preserve_paths.extend(ml_candidate_paths)
            de_view_paths = state.get("de_view") or (state.get("contract_views") or {}).get("de_view")
            if isinstance(de_view_paths, dict):
                for key in ("output_path", "output_manifest_path", "manifest_path"):
                    value = de_view_paths.get(key)
                    if value:
                        preserve_paths.append(str(value))
            _purge_execution_outputs(required_outputs, expected_outputs, preserve_paths=preserve_paths)
            local_csv = _resolve_ml_input_path(state if isinstance(state, dict) else {}, require_exists=True)
            if not local_csv:
                local_csv_hint = _resolve_ml_input_path(state if isinstance(state, dict) else {}, require_exists=False)
                if not local_csv_hint and ml_candidate_paths:
                    local_csv_hint = str(ml_candidate_paths[0])
                return {
                    "error_message": (
                        "HEAVY_RUNNER: ml_data_path missing from contract-derived context"
                        + (f" (best_candidate={local_csv_hint})" if local_csv_hint else "")
                    ),
                    "execution_output": "HEAVY_RUNNER_ERROR: ml_data_path missing",
                    "ml_data_path": local_csv_hint or "",
                    "budget_counters": counters,
                }
            state["ml_data_path"] = local_csv
            column_inventory = state.get("column_inventory")
            if not isinstance(column_inventory, list) or not column_inventory:
                inv = _load_json_safe("data/column_inventory.json")
                if isinstance(inv, dict):
                    column_inventory = inv.get("columns") or inv.get("column_inventory")
            if not isinstance(column_inventory, list):
                column_inventory = []
            column_sets = state.get("column_sets")
            if not isinstance(column_sets, dict) or not column_sets:
                column_sets = _load_json_safe("data/column_sets.json") or {}
            roles = get_column_roles(contract) if isinstance(contract, dict) else {}
            target_col = _resolve_primary_target_column(eval_spec, contract, state.get("contract_min"))
            if not target_col:
                target_cols = get_outcome_columns(contract) or roles.get("outcome") or []
                if not target_cols and isinstance(ml_plan, dict):
                    train_filter = ml_plan.get("train_filter")
                    if isinstance(train_filter, dict):
                        tf_col = train_filter.get("column")
                        tf_type = str(train_filter.get("type") or "").strip().lower()
                        if isinstance(tf_col, str) and tf_col.strip() and tf_type in {
                            "label_not_null",
                            "label_notna",
                            "label_present",
                        }:
                            target_cols = [tf_col.strip()]
                if not target_cols:
                    role_targets = roles.get("target") or roles.get("label") or []
                    if isinstance(role_targets, str):
                        target_cols = [role_targets]
                    elif isinstance(role_targets, list):
                        target_cols = [str(col) for col in role_targets if str(col).strip()]
                    else:
                        target_cols = []
                if not target_cols:
                    target_cols = list(state.get("target_columns") or [])
                target_col = target_cols[0] if target_cols else None

            header_cols: List[str] = []
            if os.path.exists(local_csv):
                try:
                    header_df = pd.read_csv(
                        local_csv,
                        nrows=0,
                        sep=csv_sep,
                        decimal=csv_decimal,
                        encoding=csv_encoding,
                    )
                    if hasattr(header_df, "columns"):
                        header_cols = [str(col) for col in list(header_df.columns)]
                except Exception:
                    header_cols = []

            if target_col and header_cols and target_col not in header_cols:
                lower_map = {str(col).lower(): col for col in header_cols}
                target_col = lower_map.get(str(target_col).lower(), target_col)

            if not target_col:
                return {"error_message": "HEAVY_RUNNER: target column missing", "execution_output": "HEAVY_RUNNER_ERROR: target column missing", "budget_counters": counters}
            if header_cols and target_col not in header_cols:
                return {
                    "error_message": f"HEAVY_RUNNER: target column '{target_col}' not present in cleaned_data header",
                    "execution_output": "HEAVY_RUNNER_ERROR: target column missing",
                    "budget_counters": counters,
                }

            feature_cols = _resolve_heavy_feature_columns(column_inventory, column_sets, roles, target_col)
            problem_type = _infer_problem_type_for_heavy(contract, eval_spec or {}, data_profile or {}, target_col)
            dataset_scale = state.get("dataset_scale_hints") or {}
            float32_default = (dataset_scale.get("scale") in {"medium", "large"})
            safe_mode_default = (dataset_scale.get("scale") in {"medium", "large"})
            float32 = _env_flag("HEAVY_RUNNER_FLOAT32", default=float32_default)
            safe_mode = _env_flag("HEAVY_RUNNER_SAFE_MODE", default=safe_mode_default)

            model_type_env = os.getenv("HEAVY_RUNNER_MODEL_TYPE")
            model_type = model_type_env or ("random_forest_classifier" if problem_type == "classification" else "random_forest_regressor")
            model_params = {}
            params_env = os.getenv("HEAVY_RUNNER_MODEL_PARAMS")
            if params_env:
                try:
                    model_params = json.loads(params_env)
                except Exception:
                    model_params = {}

            cv_policy = ml_plan.get("cv_policy") if isinstance(ml_plan, dict) else {}
            cv_folds = None
            if isinstance(cv_policy, dict):
                cv_folds = cv_policy.get("n_splits")
            if cv_folds is None:
                validation = contract.get("validation_requirements") if isinstance(contract, dict) else {}
                if isinstance(validation, dict):
                    params = validation.get("params") or {}
                    if isinstance(params, dict):
                        cv_folds = params.get("k")
            cv_cfg = {}
            if cv_folds:
                cv_cfg = {
                    "folds": cv_folds,
                    "shuffle": True,
                    "random_state": 42,
                }

            decisioning_names = _extract_decisioning_required_names(contract)

            required_artifacts = list(required_outputs)
            optional_download_artifacts = _resolve_optional_runtime_downloads(contract)
            optional_download_artifacts = [
                str(path).strip().lstrip("/").replace("\\", "/")
                for path in optional_download_artifacts
                if path
            ]
            optional_download_artifacts = [
                path for path in optional_download_artifacts if path not in required_artifacts
            ]
            timeout_decision = _estimate_heavy_script_timeout(
                stage="ml_engineer",
                code=code,
                state=state,
                ml_plan=ml_plan if isinstance(ml_plan, dict) else None,
                configured_timeout_seconds=heavy_cfg.get("script_timeout_seconds"),
            )

            runtime_required_deps: List[str] = []
            for dep in list(required_deps or []) + list(heavy_imports_in_code or []):
                dep_name = str(dep or "").strip()
                if dep_name and dep_name not in runtime_required_deps:
                    runtime_required_deps.append(dep_name)

            request = {
                "run_id": run_id,
                "dataset_uri": None,
                "output_uri": None,
                "read": {"sep": csv_sep, "decimal": csv_decimal, "encoding": csv_encoding},
                "target_col": target_col,
                "feature_cols": feature_cols or None,
                "problem_type": problem_type,
                "float32": float32,
                "safe_mode": safe_mode,
                "model": {"type": model_type, "params": model_params},
                "cv": cv_cfg,
                "decisioning_required_names": decisioning_names,
                "required_outputs": required_artifacts,
                "required_dependencies": runtime_required_deps,
                "script_timeout_seconds": int(timeout_decision["timeout_seconds"]),
            }

            if not os.path.exists(local_csv):
                return {
                    "error_message": f"HEAVY_RUNNER: ml_data_path missing on disk ({local_csv})",
                    "execution_output": "HEAVY_RUNNER_ERROR: ml_data_path missing",
                    "ml_data_path": local_csv,
                    "budget_counters": counters,
                }

            # Download map: GCS filename -> local path.
            # Contract-required artifacts are downloaded with 1:1 local paths.
            download_map = {
                "error.json": os.path.join("artifacts", "heavy_error.json"),
                "status.json": os.path.join("artifacts", "heavy_status.json"),
                "artifacts/execution_log.txt": os.path.join("artifacts", "heavy_execution_log.txt"),
            }
            for rel_path in required_artifacts:
                download_map.setdefault(rel_path, rel_path)
            for rel_path in optional_download_artifacts:
                download_map.setdefault(rel_path, rel_path)
            support_files = []
            for rel_path in [
                "data/cleaning_manifest.json",
                "data/column_sets.json",
                "data/column_inventory.json",
                "data/execution_contract.json",
                "data/ml_plan.json",
                "data/evaluation_spec.json",
            ]:
                if os.path.exists(rel_path):
                    support_files.append({"local_path": rel_path, "path": rel_path})
            if run_id:
                log_run_event(
                    run_id,
                    "heavy_runner_request",
                    {
                        "mode": "execute_code",
                        "runtime_mode": runtime_mode,
                        "gcloud_bin": (os.getenv("HEAVY_RUNNER_GCLOUD_BIN") or "PATH") if runtime_mode != "local" else "local",
                        "gsutil_bin": (os.getenv("HEAVY_RUNNER_GSUTIL_BIN") or "PATH") if runtime_mode != "local" else "local",
                        "target_col": target_col,
                        "feature_count": len(feature_cols or []),
                        "problem_type": problem_type,
                        "cv_folds": cv_folds,
                        "float32": float32,
                        "safe_mode": safe_mode,
                        "model_type": model_type,
                        "model_params_keys": list(model_params.keys()) if isinstance(model_params, dict) else [],
                        "download_keys": list(download_map.keys()),
                        "required_artifacts": required_artifacts,
                        "optional_download_artifacts": optional_download_artifacts,
                        "support_files": [item.get("path") for item in support_files],
                        "script_timeout_seconds": request.get("script_timeout_seconds"),
                        "script_timeout_decision": timeout_decision,
                        "attempt_id": attempt_id,
                        "ml_data_path": local_csv,
                    },
                )
            if run_id:
                log_run_event(run_id, "heavy_runner_start", {"reason": heavy_reason})
            launch_fn = launch_local_runner_job if runtime_mode == "local" else launch_heavy_runner_job
            launch_exc = (LocalRunnerLaunchError,) if runtime_mode == "local" else (CloudRunLaunchError,)
            try:
                heavy_result = launch_fn(
                    run_id=run_id or "unknown",
                    request=request,
                    dataset_path=local_csv,
                    bucket=heavy_cfg.get("bucket", "local"),
                    job=heavy_cfg.get("job", "local_runner"),
                    region=heavy_cfg.get("region", "local"),
                    project=heavy_cfg.get("project"),
                    input_prefix=heavy_cfg.get("input_prefix", "inputs"),
                    output_prefix=heavy_cfg.get("output_prefix", "outputs"),
                    dataset_prefix=heavy_cfg.get("dataset_prefix", "datasets"),
                    download_map=download_map,
                    code_text=code,
                    support_files=support_files,
                    data_path=local_csv,
                    required_artifacts=required_artifacts,
                    attempt_id=attempt_id,
                    stage_namespace="ml_engineer",
                )
            except launch_exc as exc:
                if run_id:
                    log_run_event(
                        run_id,
                        "heavy_runner_failed",
                        {"error": str(exc), "runtime_mode": runtime_mode},
                    )
                output = f"{'LOCAL_RUNNER_ERROR' if runtime_mode == 'local' else 'HEAVY_RUNNER_ERROR'}: {exc}"
                return _finalize_heavy_execution(
                    state=state,
                    output=output,
                    exec_start_ts=exec_start_ts,
                    contract=contract,
                    eval_spec=eval_spec or {},
                    csv_sep=csv_sep,
                    csv_decimal=csv_decimal,
                    csv_encoding=csv_encoding,
                    counters=counters,
                    run_id=run_id,
                    attempt_id=attempt_id,
                    visuals_missing=False,
                )

            if run_id:
                log_run_event(
                    run_id,
                    "heavy_runner_complete",
                    {
                        "status": heavy_result.get("status"),
                        "output_uri": heavy_result.get("output_uri"),
                        "dataset_uri": heavy_result.get("dataset_uri"),
                        "downloaded": list((heavy_result.get("downloaded") or {}).keys()),
                        "missing_artifacts": heavy_result.get("missing_artifacts") or [],
                        "gcs_listing": heavy_result.get("gcs_listing") or [],
                        "error_present": bool(heavy_result.get("error")),
                        "error_raw_present": bool(heavy_result.get("error_raw")),
                        "status_ok": bool(heavy_result.get("status_ok")),
                        "status_arbitration": heavy_result.get("status_arbitration"),
                        "job_failed_raw": bool(heavy_result.get("job_failed_raw")),
                        "gcloud_flag": heavy_result.get("gcloud_flag"),
                    },
                )

            heavy_error_kind = None
            heavy_error_context = None
            if heavy_result.get("error"):
                heavy_error_kind = "code"
                heavy_error_context = heavy_result.get("error")
            elif heavy_result.get("job_failed"):
                heavy_error_kind = "infra"
                heavy_error_context = heavy_result.get("job_error")
            state["heavy_runner_error_kind"] = heavy_error_kind
            state["heavy_runner_error_context"] = heavy_error_context

            output = f"HEAVY_RUNNER: status={heavy_result.get('status')} reason={heavy_reason}"
            if heavy_result.get("job_failed"):
                output += f"\nHEAVY_RUNNER_ERROR: Job execution failed"
                job_err = heavy_result.get("job_error")
                if job_err:
                    output += f"\nJOB_ERROR_DETAIL: {str(job_err)[:2000]}"
                output += "\nHEAVY_RUNNER_INFRA_ERROR"
            if heavy_result.get("error"):
                err_payload = heavy_result.get("error")
                err_text = ""
                if isinstance(err_payload, dict):
                    err_summary = err_payload.get("error") or ""
                    err_stack = err_payload.get("stacktrace") or ""
                    err_text = "\n".join([item for item in [err_summary, err_stack] if item])
                else:
                    err_text = str(err_payload)
                if err_text:
                    output += f"\nHEAVY_RUNNER_ERROR: {err_text[:4000]}"
                output += "\nHEAVY_RUNNER_CODE_ERROR"

            visual_reqs = contract.get("artifact_requirements") if isinstance(contract.get("artifact_requirements"), dict) else {}
            visual_cfg = visual_reqs.get("visual_requirements") if isinstance(visual_reqs.get("visual_requirements"), dict) else {}
            visual_items = visual_cfg.get("items") if isinstance(visual_cfg.get("items"), list) else []
            visual_required = bool(visual_cfg.get("required")) and bool(visual_items)
            visuals_missing = bool(visual_required)
            state["ml_skipped_reason"] = "HEAVY_RUNNER"

            return _finalize_heavy_execution(
                state=state,
                output=output,
                exec_start_ts=exec_start_ts,
                contract=contract,
                eval_spec=eval_spec or {},
                csv_sep=csv_sep,
                csv_decimal=csv_decimal,
                csv_encoding=csv_encoding,
                counters=counters,
                run_id=run_id,
                attempt_id=attempt_id,
                visuals_missing=visuals_missing,
            )

    # E2B Sandbox execution path
    print("    Backend: E2B Sandbox")

    # Prevent stale metrics from previous iterations
    try:
        if os.path.exists("data/metrics.json"):
            os.remove("data/metrics.json")
    except Exception:
        pass

    artifact_reqs = contract.get("artifact_requirements") if isinstance(contract.get("artifact_requirements"), dict) else {}
    visual_reqs = artifact_reqs.get("visual_requirements") if isinstance(artifact_reqs.get("visual_requirements"), dict) else {}
    visual_outputs_dir = str(visual_reqs.get("outputs_dir") or "static/plots")
    visual_items = visual_reqs.get("items") if isinstance(visual_reqs.get("items"), list) else []
    visual_required = bool(visual_reqs.get("required")) and bool(visual_items)

    required_outputs = _resolve_required_outputs(contract, state)
    expected_outputs = _resolve_expected_output_paths(contract, state)
    preserve_paths = []
    ml_candidate_paths = _candidate_ml_input_paths(state if isinstance(state, dict) else {})
    preserve_paths.extend(ml_candidate_paths)
    de_view_paths = state.get("de_view") or (state.get("contract_views") or {}).get("de_view")
    if isinstance(de_view_paths, dict):
        for key in ("output_path", "output_manifest_path", "manifest_path"):
            value = de_view_paths.get(key)
            if value:
                preserve_paths.append(str(value))
    _purge_execution_outputs(required_outputs, expected_outputs, preserve_paths=preserve_paths)

    eval_spec = state.get("evaluation_spec") or (contract.get("evaluation_spec") if isinstance(contract, dict) else {})
    allowed_columns = _resolve_allowed_columns_for_gate(state, contract, eval_spec)
    allowed_patterns = _resolve_allowed_patterns_for_gate(contract)
    preflight_issues = ml_quality_preflight(code, eval_spec, allowed_columns, allowed_patterns)
    unknown_cols: List[str] = []
    if "UNKNOWN_COLUMNS_REFERENCED" in preflight_issues and allowed_columns:
        unknown_cols = _detect_unknown_columns(code, allowed_columns, allowed_patterns)
    forbidden_assignments: List[str] = []
    if "DF_COLUMN_ASSIGNMENT_FORBIDDEN" in preflight_issues and allowed_columns:
        forbidden_assignments = _detect_forbidden_df_assignments(code, allowed_columns, allowed_patterns)
    preexec_warnings: List[str] = []
    preexec_payload: Dict[str, Any] = {}
    if preflight_issues:
        msg = f"ML_PREEXEC_WARNINGS: {', '.join(preflight_issues)}"
        if unknown_cols:
            preview = unknown_cols[:10]
            msg += f" | Unknown columns ({len(unknown_cols)}): {preview}"
        if forbidden_assignments:
            preview = forbidden_assignments[:10]
            msg += (
                f" | Forbidden df column assignments ({len(forbidden_assignments)}): {preview}. "
                "SOLUTION: Use df.assign() instead of df['col']=value. Pattern: df = df.assign(new_col=expression). "
                "Example: df = df.assign(derived_target=(df['source_col']==condition).astype(int))"
            )
        snippet_tokens = [f"'{col}'" for col in (unknown_cols + forbidden_assignments)[:10]]
        snippets: List[str] = _collect_violation_snippets(code, snippet_tokens) if snippet_tokens else []
        if snippets:
            msg += f" | Code refs: {snippets[:5]}"
        preexec_warnings.append(msg)
        preexec_payload["issues"] = preflight_issues
        if unknown_cols:
            preexec_payload["unknown_columns"] = unknown_cols
        if forbidden_assignments:
            preexec_payload["forbidden_df_assignments"] = forbidden_assignments
        if snippets:
            preexec_payload["snippets"] = snippets

    # 0b. Undefined name preflight (warn only; allow sandbox execution)
    undefined = detect_undefined_names(code)
    if undefined:
        msg = f"ML_PREEXEC_WARNINGS: Undefined names detected preflight: {', '.join(undefined)}"
        preexec_warnings.append(msg)
        preexec_payload["undefined_names"] = undefined

    if preexec_warnings:
        fh = list(state.get("feedback_history", []))
        fh.extend(preexec_warnings)
        state["feedback_history"] = fh
        for msg in preexec_warnings:
            try:
                print(msg)
            except Exception:
                pass
        if run_id:
            log_run_event(run_id, "ml_preexec_warnings", preexec_payload)

    # Secure execution using E2B
    try:
        # load_dotenv() removed (module level)
        api_key = os.getenv("E2B_API_KEY")
        if not api_key:
            msg = "CRITICAL: E2B_API_KEY missing in .env file."
            return {"error_message": msg, "execution_output": msg, "budget_counters": counters}
        os.environ["E2B_API_KEY"] = api_key

        # Determine ML timeout based on dataset scale (P2.2)
        dataset_scale = state.get("dataset_scale") or (state.get("dataset_scale_hints") or {}).get("scale")
        if dataset_scale == "small":
            ml_timeout = ML_TIMEOUT_SMALL_S
        elif dataset_scale == "large":
            ml_timeout = ML_TIMEOUT_LARGE_S
        else:
            ml_timeout = ML_TIMEOUT_MEDIUM_S  # Default to medium

        step_name = "ml_engineer"
        for sb_attempt in range(2):
          try:
            with create_sandbox_with_retry(Sandbox, max_attempts=2, run_id=run_id, step="ml_engineer") as sandbox:
                if not hasattr(sandbox, "commands"):
                    raise RuntimeError(
                        "E2B Sandbox missing commands runner. Ensure sandbox supports commands.run."
                    )
                run_root = f"/home/user/run/{run_id}/{step_name}/attempt_{attempt_id}"
                print("Installing dependencies in Sandbox...")
                pkg_sets = get_sandbox_install_packages(required_deps, backend_profile="e2b")
                base_cmd = "pip install -q " + " ".join(pkg_sets["base"])
                run_cmd_with_retry(sandbox, base_cmd, retries=2)
                if pkg_sets["extra"]:
                    extra_cmd = "pip install -q " + " ".join(pkg_sets["extra"])
                    run_cmd_with_retry(sandbox, extra_cmd, retries=2)
                run_cmd_with_retry(sandbox, f"rm -rf {run_root}", retries=2)
                run_cmd_with_retry(sandbox, f"mkdir -p {run_root}/static/plots", retries=2)
                run_cmd_with_retry(sandbox, f"mkdir -p {run_root}/data", retries=2)

                # P2.1: Use canonical cleaned path + aliases (P2.2: run_cmd_with_retry)
                local_csv = _resolve_ml_input_path(state if isinstance(state, dict) else {}, require_exists=True)
                if not local_csv:
                    local_csv_hint = _resolve_ml_input_path(state if isinstance(state, dict) else {}, require_exists=False)
                    if not local_csv_hint and ml_candidate_paths:
                        local_csv_hint = str(ml_candidate_paths[0])
                    return {
                        "error_message": (
                            "ML_EXECUTION_ABORTED: ml_data_path missing from contract-derived context"
                            + (f" (best_candidate={local_csv_hint})" if local_csv_hint else "")
                        ),
                        "execution_output": "ML_EXECUTION_ERROR: ml_data_path missing",
                        "ml_data_path": local_csv_hint or "",
                        "budget_counters": counters,
                    }
                if not os.path.exists(local_csv):
                    return {
                        "error_message": f"ML_EXECUTION_ABORTED: ml_data_path not found ({local_csv})",
                        "execution_output": "ML_EXECUTION_ERROR: ml_data_path missing",
                        "ml_data_path": local_csv,
                        "budget_counters": counters,
                    }
                state["ml_data_path"] = local_csv

                # Upload cleaned data (P2.1: Canonical path)
                remote_clean_abs = canonical_abs(run_root, CANONICAL_CLEANED_REL)

                if os.path.exists(local_csv):
                    with open(local_csv, "rb") as f:
                        sandbox.files.write(remote_clean_abs, f)
                    print(f"Data uploaded to {CANONICAL_CLEANED_REL}")

                # P2.1: Create aliases for cleaned data (run_cmd_with_retry for resilience)
                cleaned_alias_commands = build_symlink_or_copy_commands(
                    run_root,
                    canonical_rel=CANONICAL_CLEANED_REL,
                    aliases=COMMON_CLEANED_ALIASES
                )
                if cleaned_alias_commands:
                    print(f"Creating {len(cleaned_alias_commands)} cleaned data aliases...")
                    full_cmd = " && ".join(cleaned_alias_commands)
                    run_cmd_with_retry(sandbox, f"sh -c 'cd {run_root} && {full_cmd}'")
                    print(f"SANDBOX_INPUT_CANONICAL: {CANONICAL_CLEANED_REL}")
                    print(f"SANDBOX_INPUT_ALIASES: {COMMON_CLEANED_ALIASES}")

                # P2.1: Upload manifest to canonical path and root
                local_manifest = "data/cleaning_manifest.json"
                remote_manifest_abs = canonical_abs(run_root, CANONICAL_MANIFEST_REL)
                remote_manifest_root_abs = os.path.join(run_root, "cleaning_manifest.json").replace("\\", "/")

                if os.path.exists(local_manifest):
                    with open(local_manifest, "rb") as f:
                        manifest_content = f.read()
                        sandbox.files.write(remote_manifest_abs, manifest_content)
                        sandbox.files.write(remote_manifest_root_abs, manifest_content)
                    print(f"Manifest uploaded to {CANONICAL_MANIFEST_REL} and root")

                # P2.1: Patch code with placeholders and explicit absolute entries
                code = patch_placeholders(code, data_rel=CANONICAL_CLEANED_REL, manifest_rel=CANONICAL_MANIFEST_REL)

                # Explicit substitutions to ensure absolute paths and avoid .//
                if local_csv:
                     # Replace generic data paths with remote_clean_abs
                     # Use pattern matching or strict order to avoid double replacement
                     code = code.replace("./data/cleaned_data.csv", remote_clean_abs)
                     code = code.replace("'data/cleaned_data.csv'", f"'{remote_clean_abs}'")
                     code = code.replace('"data/cleaned_data.csv"', f'"{remote_clean_abs}"')

                     # Only if local_csv is something else like 'data/input.csv'
                     if local_csv not in ["data/cleaned_data.csv", "./data/cleaned_data.csv"]:
                         code = code.replace(local_csv, remote_clean_abs)
                         if not local_csv.startswith("./"):
                             code = code.replace(f"./{local_csv}", remote_clean_abs)

                # Manifest patching -> Point to ROOT manifest as requested
                code = code.replace("./data/cleaning_manifest.json", remote_manifest_root_abs)
                code = code.replace("'data/cleaning_manifest.json'", f"'{remote_manifest_root_abs}'")
                code = code.replace('"data/cleaning_manifest.json"', f'"{remote_manifest_root_abs}"')

                # Inject robust prelude
                working_dir_injection = (
                    "import os\n"
                    f"os.makedirs(r\"{run_root}\", exist_ok=True)\n"
                    f"os.chdir(r\"{run_root}\")\n"
                    f"MANIFEST_PATH = r\"{remote_manifest_root_abs}\"\n"
                    f"CLEANED_CSV_PATH = r\"{remote_clean_abs}\"\n"
                )
                code = working_dir_injection + code

                # Persist executed ML script for traceability
                try:
                    os.makedirs("artifacts", exist_ok=True)
                    with open(os.path.join("artifacts", "ml_engineer_last.py"), "w", encoding="utf-8") as f_art:
                        f_art.write(code)
                except Exception as artifact_err:
                    print(f"Warning: failed to persist ml_engineer_last.py: {artifact_err}")
                if run_id:
                    run_dir = get_run_dir(run_id)
                    if run_dir:
                        try:
                            base = os.path.join(run_dir, "agents", "ml_engineer", f"iteration_{attempt_id}")
                            os.makedirs(base, exist_ok=True)
                            with open(os.path.join(base, "script_executed.py"), "w", encoding="utf-8") as f_exec:
                                f_exec.write(code)
                        except Exception:
                            pass

                print("Running code in Sandbox...")
                script_path = f"{run_root}/ml_engineer.py"
                sandbox.files.write(script_path, code)
                execution = run_python_file_with_optional_timeout(
                    sandbox,
                    script_path,
                    timeout_s=ml_timeout,
                    workdir=run_root,
                )

                stdout_text = "\n".join(execution.logs.stdout or [])
                stderr_text = "\n".join(execution.logs.stderr or [])
                output = ""
                if stdout_text:
                    output += "\nSTDOUT:\n" + stdout_text
                if stderr_text:
                    output += "\nSTDERR:\n" + stderr_text

                if execution.error:
                    output += f"\n\nEXECUTION ERROR:\n{execution.error.name}: {execution.error.value}\n{execution.error.traceback}"
                    error_payload = {
                        "stage": "execution_error",
                        "exception_type": execution.error.name,
                        "exception_msg": execution.error.value,
                        "traceback": execution.error.traceback,
                        "attempt": attempt_id,
                    }
                    try:
                        os.makedirs("artifacts", exist_ok=True)
                        with open(
                            os.path.join("artifacts", "ml_engineer_sandbox_last_error.json"),
                            "w",
                            encoding="utf-8",
                        ) as f_err:
                            json.dump(error_payload, f_err, indent=2, ensure_ascii=True)
                    except Exception as err:
                        print(f"Warning: failed to persist ml_engineer_sandbox_last_error.json: {err}")

                try:
                    os.makedirs("artifacts", exist_ok=True)
                    with open(
                        os.path.join("artifacts", "ml_engineer_sandbox_last.log"),
                        "w",
                        encoding="utf-8",
                    ) as f_log:
                        f_log.write(output)
                except Exception as log_err:
                    print(f"Warning: failed to persist ml_engineer_sandbox_last.log: {log_err}")

                downloaded_paths = []
                visuals_missing = False
                visual_downloaded = []

                # Robust Artifact Download (P0 Fix) using centralized helper
                # Use shell command that always succeeds even if no files found
                remote_viz_dir = visual_outputs_dir.replace("\\", "/").strip("/")
                if not remote_viz_dir:
                    remote_viz_dir = "static/plots"
                ls_proc = run_cmd_with_retry(
                    sandbox,
                    f"sh -c 'ls -1 {run_root}/{remote_viz_dir}/*.png 2>/dev/null || true'",
                    retries=2,
                )

                if ls_proc.exit_code == 0:
                    os.makedirs(visual_outputs_dir, exist_ok=True)
                    # Filter empty strings from split
                    plot_files = [p for p in ls_proc.stdout.strip().split('\n') if p]

                    if not plot_files:
                        print("Info: No plots generated by the script.")
                    else:
                        for remote_plot in plot_files:
                            if remote_plot.endswith('.png'):
                                # Use centralized download helper for binary files
                                content = safe_download_bytes(sandbox, remote_plot)
                                if content and len(content) > 0:
                                    local_name = os.path.basename(remote_plot)
                                    local_path = os.path.join(visual_outputs_dir, local_name)
                                    with open(local_path, "wb") as f_local:
                                        f_local.write(content)
                                    downloaded_paths.append(local_path)
                                    visual_downloaded.append(local_name)
                                    print(f"Downloaded plot: {local_name}")
                                else:
                                    print(f"Warning: Failed to download {remote_plot}")
                else:
                    print(f"Warning: Plot listing failed (Exit Code {ls_proc.exit_code})")
                if run_id:
                    log_run_event(
                        run_id,
                        "plots_downloaded",
                        {
                            "count": len(visual_downloaded),
                            "filenames": visual_downloaded,
                        },
                    )
                visuals_missing = visual_required and not bool(visual_downloaded)
                if visuals_missing:
                    history = list(state.get("feedback_history", []))
                    history.append("VISUALS_MISSING: Required plot outputs were not produced.")
                    state["feedback_history"] = history
                    if run_id:
                        log_run_event(
                            run_id,
                            "visual_requirements_missing",
                            {
                                "expected_items": len(visual_items),
                                "downloaded": len(visual_downloaded),
                            },
                        )

                # Download required outputs per contract (beyond plots) using centralized helper
                req_outputs = required_outputs or state.get("execution_contract", {}).get("required_outputs", []) or []
                for pattern in req_outputs:
                    if not pattern:
                        continue
                    if pattern.startswith("/"):
                        remote_pattern = pattern
                    else:
                        remote_pattern = f"{run_root}/{pattern}"
                    list_cmd = f"sh -c 'ls -1 {remote_pattern} 2>/dev/null || true'"
                    lst = sandbox.commands.run(list_cmd)
                    if lst.exit_code != 0:
                        continue
                    files = [p for p in lst.stdout.strip().split("\n") if p]
                    for remote_path in files:
                        if not remote_path:
                            continue
                        content = safe_download_bytes(sandbox, remote_path)
                        if content is not None:
                            if remote_path.startswith(run_root):
                                local_path = remote_path[len(run_root):].lstrip("/")
                            elif remote_path.startswith("/home/user/"):
                                local_path = remote_path[len("/home/user/"):].lstrip("/")
                            else:
                                local_path = remote_path.lstrip("/")
                            os.makedirs(os.path.dirname(local_path) or ".", exist_ok=True)
                            with open(local_path, "wb") as f_local:
                                f_local.write(content)
                            downloaded_paths.append(local_path)
                            print(f"Downloaded required output: {local_path}")
                        else:
                            print(f"Warning: failed to download required output {remote_path}")

                # Download optional plot insights if present using centralized helper
                for rel_path in ["data/plot_insights.json"]:
                    if rel_path.startswith("/"):
                        remote_path = rel_path
                    else:
                        remote_path = f"{run_root}/{rel_path}"
                    list_cmd = f"sh -c 'ls -1 {remote_path} 2>/dev/null || true'"
                    lst = sandbox.commands.run(list_cmd)
                    if lst.exit_code != 0:
                        continue
                    files = [p for p in lst.stdout.strip().split("\n") if p]
                    for remote_opt in files:
                        if not remote_opt:
                            continue
                        content = safe_download_bytes(sandbox, remote_opt)
                        if content is not None:
                            if remote_opt.startswith(run_root):
                                local_path = remote_opt[len(run_root):].lstrip("/")
                            elif remote_opt.startswith("/home/user/"):
                                local_path = remote_opt[len("/home/user/"):].lstrip("/")
                            else:
                                local_path = remote_opt.lstrip("/")
                            os.makedirs(os.path.dirname(local_path) or ".", exist_ok=True)
                            with open(local_path, "wb") as f_local:
                                f_local.write(content)
                            downloaded_paths.append(local_path)
                            print(f"Downloaded optional output: {local_path}")
                        else:
                            print(f"Warning: failed to download optional output {remote_opt}")

                # Defense-in-depth: download canonical outputs if they exist in sandbox
                for rel_path in ["data/scored_rows.csv", "data/alignment_check.json"]:
                    if os.path.exists(rel_path):
                        continue
                    remote_path = f"{run_root}/{rel_path}"
                    list_cmd = f"sh -c 'ls -1 {remote_path} 2>/dev/null || true'"
                    lst = sandbox.commands.run(list_cmd)
                    if lst.exit_code != 0:
                        continue
                    files = [p for p in lst.stdout.strip().split("\n") if p]
                    for remote_extra in files:
                        if not remote_extra:
                            continue
                        content = safe_download_bytes(sandbox, remote_extra)
                        if content is None:
                            print(f"Warning: failed to download optional canonical output {remote_extra}")
                            continue
                        if remote_extra.startswith(run_root):
                            local_path = remote_extra[len(run_root):].lstrip("/")
                        elif remote_extra.startswith("/home/user/"):
                            local_path = remote_extra[len("/home/user/"):].lstrip("/")
                        else:
                            local_path = remote_extra.lstrip("/")
                        os.makedirs(os.path.dirname(local_path) or ".", exist_ok=True)
                        with open(local_path, "wb") as f_local:
                            f_local.write(content)
                        downloaded_paths.append(local_path)
                        print(f"Downloaded canonical output: {local_path}")
                list_cmd = f"sh -c 'cd {run_root} && find . -maxdepth 5 -type f -printf \"%p\\t%s\\n\" 2>/dev/null'"
                outputs_listing = []
                try:
                    listing_proc = sandbox.commands.run(list_cmd)
                    if listing_proc.exit_code == 0:
                        outputs_listing = [line for line in listing_proc.stdout.splitlines() if line.strip()]
                except Exception:
                    outputs_listing = []
                attempt_success = execution.error is None
                attempt_stage = "completed" if attempt_success else "execution_error"
                if run_id:
                    log_sandbox_attempt(
                        run_id,
                        step_name,
                        attempt_id,
                        code=code,
                        stdout=stdout_text,
                        stderr=stderr_text,
                        outputs_listing=outputs_listing,
                        downloaded_paths=downloaded_paths,
                        exit_code=getattr(execution, "exit_code", None),
                        error_tail=(execution.error.traceback if execution.error else None),
                        success=attempt_success,
                        stage=attempt_stage,
                        exception_type=(execution.error.name if execution.error else None),
                        exception_msg=(str(execution.error.value) if execution.error else None),
                    )

            break  # Sandbox execution successful, exit retry loop
          except Exception as e:
            error_payload = {
                "stage": "exception",
                "exception_type": type(e).__name__,
                "exception_msg": str(e),
                "traceback": traceback.format_exc(),
                "attempt": attempt_id,
            }
            try:
                os.makedirs("artifacts", exist_ok=True)
                with open(
                    os.path.join("artifacts", "ml_engineer_sandbox_last.log"),
                    "w",
                    encoding="utf-8",
                ) as f_log:
                    f_log.write(str(e))
            except Exception as log_err:
                print(f"Warning: failed to persist ml_engineer_sandbox_last.log: {log_err}")
            try:
                os.makedirs("artifacts", exist_ok=True)
                with open(
                    os.path.join("artifacts", "ml_engineer_sandbox_last_error.json"),
                    "w",
                    encoding="utf-8",
                ) as f_err:
                    json.dump(error_payload, f_err, indent=2, ensure_ascii=True)
            except Exception as err:
                print(f"Warning: failed to persist ml_engineer_sandbox_last_error.json: {err}")
            if run_id:
                log_sandbox_attempt(
                    run_id,
                    step_name,
                    attempt_id,
                    code=code,
                    stdout="",
                    stderr="",
                    outputs_listing=[],
                    downloaded_paths=[],
                    exit_code=None,
                    error_tail=str(e),
                    success=False,
                    stage="exception",
                    exception_type=type(e).__name__,
                    exception_msg=str(e),
                )
            if sb_attempt == 0 and is_transient_sandbox_error(e):
                print(f"SANDBOX_RETRY step=ml_engineer attempt={sb_attempt+1} err={e}")
                continue
            raise

    except Exception as e:
        output = f"Sandbox Execution Failed: {e}"
        print(output)

    # Calculate Visuals State locally
    import glob
    plots_local = glob.glob("static/plots/*.png")

    fallback_plots_local = []
    # Fallback plots removed per user request (User prefers no plots over generic ones)

    has_partial_visuals = len(plots_local) > 0

    print(f"Execution finished. Plots generated: {len(plots_local)}")

    eval_spec = state.get("evaluation_spec") or (contract.get("evaluation_spec") if isinstance(contract, dict) else {})

    # CRITICAL: Use runtime dialect from state first (cleaning_manifest), fallback to contract
    dialect = _resolve_artifact_gate_dialect(state, contract)
    csv_sep = dialect["sep"]
    csv_decimal = dialect["decimal"]
    csv_encoding = dialect["encoding"]
    cleaned_path = str(state.get("ml_data_path") or "").strip()
    if not cleaned_path:
        cleaned_path, _, _ = _resolve_de_output_artifacts(state)

    artifact_issues = _artifact_alignment_gate(
        cleaned_path=cleaned_path,
        scored_path="data/scored_rows.csv",
        contract=contract,
        evaluation_spec=eval_spec,
        csv_sep=csv_sep,
        csv_decimal=csv_decimal,
        csv_encoding=csv_encoding,
    )

    # ← NEW: UNIVERSAL soft-warn logic for artifact alignment issues
    # Works for ANY artifact type (scored_rows, metrics, alignment_check, etc.)
    # No hardcoding of specific issues or objectives
    if artifact_issues:
        # Track issue history across iterations to enable learning
        issue_history = state.get("artifact_alignment_issue_history", [])

        # Count occurrences of each specific issue across all previous iterations
        issue_occurrence_counts = {}
        for past_issues in issue_history:
            for issue in past_issues:
                issue_occurrence_counts[issue] = issue_occurrence_counts.get(issue, 0) + 1

        # Determine max occurrence count for current issues (to decide soft vs hard block)
        max_occurrence = 0
        for issue in artifact_issues:
            count = issue_occurrence_counts.get(issue, 0)
            if count > max_occurrence:
                max_occurrence = count

        # UNIVERSAL POLICY: Soft warn for first 2 occurrences, hard block on 3rd+
        # This gives ML Engineer 2 chances to learn and fix before failing
        SOFT_WARN_THRESHOLD = 2  # Can be made configurable per strategy if needed

        if max_occurrence < SOFT_WARN_THRESHOLD:
            # Soft warning: Add to feedback but DON'T block execution
            issue_text = "; ".join(artifact_issues)
            iteration_num = max_occurrence + 1
            warning_msg = (
                f"⚠️ ARTIFACT_ALIGNMENT_WARNING (iteration {iteration_num}/{SOFT_WARN_THRESHOLD + 1}): {issue_text}\n"
                f"   Note: These artifacts will be required for final validation. "
                f"Please generate them in the next iteration."
            )

            # Add to feedback history so ML Engineer receives this in next prompt
            if "feedback_history" not in state:
                state["feedback_history"] = []
            state["feedback_history"].append(warning_msg)

            # Print to logs for visibility
            print(warning_msg)

        else:
            # Hard block: This is the 3rd+ occurrence, fail the execution
            issue_text = "; ".join(artifact_issues)
            output = f"{output}\nVALIDATION_WARNING: ARTIFACT_ALIGNMENT_GUARD: {issue_text}"

        # Track current issues for next iteration (universal tracking)
        if "artifact_alignment_issue_history" not in state:
            state["artifact_alignment_issue_history"] = []
        state["artifact_alignment_issue_history"].append(artifact_issues)

    stale_outputs = _find_stale_outputs(required_outputs, exec_start_ts)
    if stale_outputs:
        output = f"{output}\nVALIDATION_WARNING: STALE_OUTPUTS: {stale_outputs}"

    content_issues, content_diagnostics = _validate_artifact_content(state)
    if content_issues:
        issue_text = ", ".join(content_issues)
        output = f"{output}\nVALIDATION_WARNING: ARTIFACT_CONTENT_INVALID: {issue_text}"

    # Check for Runtime Errors in Output (Traceback)
    sandbox_failed = (
        "Sandbox Execution Failed" in output
        or "peer closed connection" in output
        or "incomplete chunked read" in output
        or "Response 404" in output
    )
    error_in_output = (
        "Traceback (most recent call last)" in output
        or "EXECUTION ERROR" in output
        or sandbox_failed
    )

    outputs_valid = not bool(artifact_issues or stale_outputs or content_issues or error_in_output)
    if not outputs_valid:
        # Preserve produced outputs for auditing and contract validation.
        # Outputs are purged at the start of the next execution attempt (and at run start) to prevent contamination.
        has_partial_visuals = False
    if run_id:
        update_sandbox_attempt(
            run_id,
            "ml_engineer",
            attempt_id,
            artifacts_valid=outputs_valid,
            artifact_issues=artifact_issues,
            stale_outputs=stale_outputs,
            content_issues=content_issues,
        )

    runtime_tail = None
    ml_skipped_reason = state.get("ml_skipped_reason", None)
    memory_pressure_detected = False
    if error_in_output:
        print("runtime error detected in output.")
        tail = output[-4000:] if isinstance(output, str) else str(output)[-4000:]
        print("----- SANDBOX EXECUTION_OUTPUT TAIL (last 4000 chars) -----")
        print(tail)
        print("-----------------------------------------------------------")
        runtime_tail = tail
        memory_pressure_detected = _is_memory_pressure_error(tail)
        if memory_pressure_detected:
            note = (
                "E2B_MEMORY_PRESSURE_DETECTED: promoting next execution to CloudRun to avoid 8GB limit breaches."
            )
            history = list(state.get("feedback_history", []))
            history.append(note)
            state["feedback_history"] = history
            if run_id:
                log_run_event(
                    run_id,
                    "e2b_memory_pressure_detected",
                    {"attempt_id": attempt_id, "tail_excerpt": tail[-800:]},
                )
        if "DETERMINISTIC_TARGET_RELATION" in tail:
            ml_skipped_reason = "DETERMINISTIC_TARGET_RELATION"

    # Suppress fallback plots in successful executions (avoid reporting placeholders)
    if not error_in_output and not sandbox_failed and plots_local:
        plots_local = [
            plot for plot in plots_local
            if not os.path.basename(plot).startswith("fallback_")
        ]
        fallback_plots_local = [
            plot for plot in fallback_plots_local
            if not os.path.basename(plot).startswith("fallback_")
        ]
    # Only flag partial visuals when there was an execution error or sandbox failure
    if not error_in_output and not sandbox_failed:
        has_partial_visuals = False
    else:
        has_partial_visuals = len(plots_local) > 0

    # Validate required outputs early
    contract = state.get("execution_contract", {}) or {}
    deliverables = _resolve_contract_deliverables(contract)
    output_contract = deliverables if isinstance(deliverables, list) and deliverables else contract.get("required_outputs", [])
    oc_report = check_required_outputs(output_contract)
    try:
        os.makedirs("data", exist_ok=True)
        dump_json("data/output_contract_report.json", oc_report)
    except Exception as oc_err:
        print(f"Warning: failed to persist output_contract_report.json: {oc_err}")

    if run_id:
        log_run_event(
            run_id,
            "execution_complete",
            {
                "plots": len(plots_local),
                "has_error": bool(error_in_output),
                "output_missing": len(oc_report.get("missing", [])) if isinstance(oc_report, dict) else None,
            },
        )
    artifact_paths = []
    if isinstance(oc_report, dict):
        artifact_paths.extend(oc_report.get("present", []))
    if plots_local:
        artifact_paths.extend(plots_local)
    for extra_path in [
        "data/strategy_spec.json",
        "data/plan.json",
        "data/evaluation_spec.json",
        "data/plot_insights.json",
    ]:
        if os.path.exists(extra_path):
            artifact_paths.append(extra_path)
    # De-duplicate while preserving order
    deduped = []
    seen = set()
    for item in artifact_paths:
        if item not in seen:
            seen.add(item)
            deduped.append(item)
    artifact_paths = deduped
    deliverables = _resolve_contract_deliverables(contract)
    artifact_index = _build_artifact_index(artifact_paths, deliverables if isinstance(deliverables, list) else None)
    try:
        os.makedirs("data", exist_ok=True)
        dump_json("data/produced_artifact_index.json", artifact_index)
    except Exception as idx_err:
        print(f"Warning: failed to persist produced_artifact_index.json: {idx_err}")

    attempt_score = _score_attempt(outputs_valid, oc_report, content_issues, artifact_paths)
    attempt_valid = bool(outputs_valid and not oc_report.get("missing") and not content_issues)

    result = {
        "execution_output": output,
        "plots_local": plots_local,
        "fallback_plots": fallback_plots_local,
        "has_partial_visuals": has_partial_visuals,
        "execution_error": error_in_output,
        "execution_attempt": state.get('execution_attempt', 0) + 1,
        "last_runtime_error_tail": runtime_tail,
        "ml_skipped_reason": ml_skipped_reason,
        "output_contract_report": oc_report,
        "artifact_index": artifact_index,
        "produced_artifact_index": artifact_index,
        "artifact_paths": artifact_paths,
        "artifact_content_issues": content_issues,
        "artifact_content_diagnostics": content_diagnostics,
        "visuals_missing": visuals_missing,
        "last_attempt_score": attempt_score,
        "last_attempt_valid": attempt_valid,
        "sandbox_failed": sandbox_failed,
        "e2b_memory_failure_detected": bool(memory_pressure_detected),
        "sandbox_retry_count": 0 if not sandbox_failed else state.get("sandbox_retry_count", 0),
        "ml_call_refund_pending": False,
        "execution_call_refund_pending": False,
        "budget_counters": counters,
    }
    if not error_in_output:
        result["runtime_fix_count"] = 0
        result["last_successful_execution_output"] = output
        result["last_successful_plots"] = plots_local
        result["last_successful_output_contract_report"] = oc_report
    best_score = state.get("best_attempt_score")
    if attempt_valid and (best_score is None or attempt_score > float(best_score)):
        dest = _snapshot_best_attempt(
            attempt_id=attempt_id,
            artifact_paths=artifact_paths,
            output_contract_report=oc_report,
            artifact_index=artifact_index,
            execution_output=output,
            plots_local=plots_local,
            diagnostics=content_diagnostics,
        )
        result["best_attempt_score"] = attempt_score
        result["best_attempt_id"] = attempt_id
        result["best_attempt_dir"] = dest
        result["best_attempt_artifact_index"] = artifact_index
        result["best_attempt_output_contract_report"] = oc_report
        result["best_attempt_execution_output"] = output
        result["best_attempt_plots"] = plots_local
    return result

def retry_handler(state: AgentState) -> AgentState:
    print("--- [!] Iteration Retry Triggered ---")

    # Fix: Ensure feedback_history is a list
    current_history = list(state.get('feedback_history', []))

    # Append execution summary
    last_output = state.get('execution_output', '')
    if last_output and ("Traceback" in last_output or "EXECUTION ERROR" in last_output or "VALIDATION_WARNING" in last_output):
        summary = f"EXECUTION OUTPUT (last run): {last_output[-3000:]}" # Truncate to save context
        current_history.append(summary)

    # Cap history size
    if len(current_history) > 20:
        current_history = current_history[-20:]

    result: Dict[str, Any] = {
        "feedback_history": current_history,
        "strategy_reselected": False,
    }
    route_reason = "policy_not_evaluated"

    try:
        state_dict = state if isinstance(state, dict) else {}
        strategies_wrapper = state_dict.get("strategies") if isinstance(state_dict.get("strategies"), dict) else {}
        strategies_list = strategies_wrapper.get("strategies") if isinstance(strategies_wrapper, dict) else []
        selected = state_dict.get("selected_strategy") if isinstance(state_dict.get("selected_strategy"), dict) else None
        can_reselect, reselect_reason = should_reselect_strategy_on_retry(
            state_dict,
            strategies_list if isinstance(strategies_list, list) else [],
            selected if isinstance(selected, dict) else None,
        )
        route_reason = reselect_reason or "policy_default_engineer"

        if can_reselect and isinstance(strategies_list, list) and len(strategies_list) > 1:
            selected = selected if isinstance(selected, dict) else {}
            selected_title = str(selected.get("title") or "").strip().lower()
            selected_index = None
            for idx, strat in enumerate(strategies_list):
                if not isinstance(strat, dict):
                    continue
                if selected and strat is selected:
                    selected_index = idx
                    break
                if selected_title and str(strat.get("title") or "").strip().lower() == selected_title:
                    selected_index = idx
                    break
            if selected_index is None:
                selected_index = 0

            strategy_spec = state.get("strategy_spec") if isinstance(state.get("strategy_spec"), dict) else {}
            column_validation = state.get("column_validation") if isinstance(state.get("column_validation"), dict) else {}
            compute_constraints = _collect_domain_expert_compute_constraints(state if isinstance(state, dict) else {})

            invalid_details_map: Dict[int, Dict[str, Any]] = {}
            for item in (column_validation.get("invalid_details") or []):
                if not isinstance(item, dict):
                    continue
                try:
                    idx = int(item.get("strategy_index"))
                except Exception:
                    continue
                invalid_details_map[idx] = item
            over_budget_map: Dict[int, Dict[str, Any]] = {}
            for item in (column_validation.get("over_budget_details") or []):
                if not isinstance(item, dict):
                    continue
                try:
                    idx = int(item.get("strategy_index"))
                except Exception:
                    continue
                over_budget_map[idx] = item

            alternatives: List[Dict[str, Any]] = []
            for idx, strat in enumerate(strategies_list):
                if idx == selected_index or not isinstance(strat, dict):
                    continue
                enriched = dict(strat)
                enriched["_strategy_index"] = idx
                enriched["_title"] = str(strat.get("title") or f"strategy_{idx}")
                enriched["_meta"] = {
                    "column_validation": {
                        "invalid_count": len((invalid_details_map.get(idx) or {}).get("invalid_columns", [])),
                        "invalid_columns": (invalid_details_map.get(idx) or {}).get("invalid_columns", []),
                        "over_budget": idx in over_budget_map,
                        "max_required_columns": (over_budget_map.get(idx) or {}).get("max_required_columns"),
                        "required_count": (over_budget_map.get(idx) or {}).get("required_count")
                        or (invalid_details_map.get(idx) or {}).get("required_count"),
                    },
                    "strategy_spec": strategy_spec,
                    "compute_constraints": compute_constraints,
                }
                alternatives.append(enriched)

            if alternatives:
                data_summary = _build_senior_summary_context(state if isinstance(state, dict) else {})
                business_objective = str(state.get("business_objective") or "")
                failure_tail = str(state.get("execution_output") or "")[-2500:]
                dataset_memory_context = str(state.get("dataset_memory_context") or "")
                dataset_memory_context = (
                    f"{dataset_memory_context}\n\nRESELECTION_RUNTIME_CONTEXT:\n{failure_tail}"
                    if failure_tail
                    else dataset_memory_context
                )
                reselection_eval = domain_expert.evaluate_strategies(
                    data_summary,
                    business_objective,
                    alternatives,
                    compute_constraints=compute_constraints,
                    dataset_memory_context=dataset_memory_context,
                )
                reselection_reviews = reselection_eval.get("reviews") if isinstance(reselection_eval, dict) else []
                reselection_reviews = reselection_reviews if isinstance(reselection_reviews, list) else []

                best_alt = None
                best_alt_score = -1.0
                best_alt_review = None
                for alt in alternatives:
                    alt_idx = int(alt.get("_strategy_index") or -1)
                    review = None
                    for rev in reselection_reviews:
                        if not isinstance(rev, dict):
                            continue
                        try:
                            if int(rev.get("strategy_index")) == alt_idx:
                                review = rev
                                break
                        except Exception:
                            continue
                    score = _safe_float(review.get("score"), 0.0) if isinstance(review, dict) else 0.0
                    selectable = bool(review.get("selectable", score >= 3.0)) if isinstance(review, dict) else False
                    exec_check = _validate_selected_strategy_executability(
                        alt,
                        review=review if isinstance(review, dict) else None,
                        compute_constraints=compute_constraints,
                    )
                    if selectable and bool(exec_check.get("ok")) and score > best_alt_score:
                        best_alt = alt
                        best_alt_score = score
                        best_alt_review = review

                if isinstance(best_alt, dict):
                    clean_alt = {k: v for k, v in best_alt.items() if not str(k).startswith("_")}
                    alt_title = str(clean_alt.get("title") or "alternative_strategy")
                    reselection_reason = str(best_alt_review.get("reasoning") or "") if isinstance(best_alt_review, dict) else ""
                    current_history.append(
                        f"DOMAIN_EXPERT_RESELECTION: switched to '{alt_title}' after blocking failure."
                    )
                    result.update(
                        {
                            "feedback_history": current_history[-20:],
                            "selected_strategy": clean_alt,
                            "selection_reason": (
                                f"Reselected after blocking retry failure. {reselection_reason}".strip()
                                if reselection_reason
                                else "Reselected after blocking retry failure."
                            ),
                            "strategy_reselected": True,
                            "domain_expert_reselection": {
                                "status": "reselected",
                                "previous_strategy_index": selected_index,
                                "new_strategy_title": alt_title,
                                "score": best_alt_score,
                                "reviews_count": len([r for r in reselection_reviews if isinstance(r, dict)]),
                            },
                            "domain_expert_reviews": [r for r in reselection_reviews if isinstance(r, dict)],
                        }
                    )
                    route_reason = f"{route_reason}|domain_expert_reselected"
                else:
                    current_history.append("DOMAIN_EXPERT_RESELECTION: no viable alternative selected; keeping current strategy.")
                    route_reason = f"{route_reason}|no_viable_alternative"
            else:
                route_reason = f"{route_reason}|no_alternative_strategies"
        elif can_reselect:
            route_reason = f"{route_reason}|insufficient_strategy_options"
    except Exception as reselection_err:
        current_history.append(f"DOMAIN_EXPERT_RESELECTION_WARNING: {reselection_err}")
        route_reason = f"reselection_exception:{type(reselection_err).__name__}"

    route = "replan" if bool(result.get("strategy_reselected")) else "engineer"
    current_history.append(f"RETRY_ROUTE_DECISION: {route} (reason={route_reason})")
    if len(current_history) > 20:
        current_history = current_history[-20:]
    result["feedback_history"] = current_history

    return result


def check_retry_handler_route(state: AgentState):
    if bool(state.get("strategy_reselected")):
        return "replan"
    return "engineer"

def retry_sandbox_execution(state: AgentState) -> AgentState:
    retry_count = int(state.get("sandbox_retry_count", 0)) + 1
    max_retries = int(state.get("max_sandbox_retries", 2))
    print(f"--- [!] Sandbox failure detected. Retrying execution ({retry_count}/{max_retries}) ---")
    history = list(state.get("feedback_history", []))
    last_output = state.get("execution_output", "")
    if last_output:
        history.append(f"SANDBOX_RETRY {retry_count}: {last_output[-500:]}")
    return {
        "sandbox_retry_count": retry_count,
        "feedback_history": history,
    }

# Decisioning output validator
def _check_decisioning_columns(decisioning: Dict[str, Any], max_rows: int = 500) -> Dict[str, Any]:
    result = {"missing_columns": [], "constraint_violations": []}
    if not isinstance(decisioning, dict):
        return result
    output = decisioning.get("output") if isinstance(decisioning.get("output"), dict) else {}
    required_columns = output.get("required_columns") or []
    file_path = output.get("file") or "data/scored_rows.csv"
    if not required_columns:
        return result
    if not os.path.exists(file_path):
        result["missing_file"] = file_path
        return result
    def _coerce_range_value(value: Any, default: float) -> float:
        if value is None:
            return default
        try:
            return float(value)
        except (TypeError, ValueError):
            return default
    with open(file_path, newline="", encoding="utf-8") as csvfile:
        reader = csv.DictReader(csvfile)
        fieldnames = reader.fieldnames or []
        missing_cols = [col for col in required_columns if isinstance(col, dict) and col.get("name") not in fieldnames]
        if missing_cols:
            result["missing_columns"] = [col.get("name") for col in missing_cols if isinstance(col, dict)]
            return result
        counters: Dict[str, int] = {}
        non_null: Dict[str, int] = {}
        numeric_ranges: Dict[str, Dict[str, float]] = {}
        allowed_values: Dict[str, set] = {}
        for entry in required_columns:
            if not isinstance(entry, dict):
                continue
            name = entry.get("name")
            if not name:
                continue
            constraints = entry.get("constraints") or {}
            if isinstance(constraints.get("range"), dict):
                range_spec = constraints.get("range") or {}
                numeric_ranges[name] = {
                    "min": _coerce_range_value(range_spec.get("min", float("-inf")), float("-inf")),
                    "max": _coerce_range_value(range_spec.get("max", float("inf")), float("inf")),
                }
            if entry.get("allowed_values"):
                allowed_values[name] = set(str(val) for val in entry["allowed_values"])
            counters[name] = 0
            non_null[name] = 0
        rows = 0
        for row in reader:
            rows += 1
            for name in counters:
                counters[name] += 1
                val = row.get(name)
                if val not in (None, "", "null"):
                    non_null[name] += 1
                    if name in allowed_values and val not in allowed_values[name]:
                        result["constraint_violations"].append(
                            {"column": name, "issue": f"value '{val}' not in allowed values"}
                        )
                    if name in numeric_ranges:
                        try:
                            num = float(val)
                            rng = numeric_ranges[name]
                            if num < rng["min"] or num > rng["max"]:
                                result["constraint_violations"].append(
                                    {"column": name, "issue": f"value {num} outside range {rng}"}
                                )
                        except Exception:
                            result["constraint_violations"].append(
                                {"column": name, "issue": f"cannot convert '{val}' to float for range check"}
                            )
            if rows >= max_rows:
                break
        for name, total in counters.items():
            if total:
                rate = non_null.get(name, 0) / total
                constraint = next(
                    (
                        entry.get("constraints", {}).get("non_null_rate_min")
                        for entry in required_columns
                        if isinstance(entry, dict) and entry.get("name") == name
                    ),
                    None,
                )
                if constraint and rate < float(constraint):
                    result["constraint_violations"].append(
                        {
                            "column": name,
                            "issue": f"non-null rate {rate:.2f} below {constraint}",
                        }
                    )
    return result

def run_result_evaluator(state: AgentState) -> AgentState:
    print("--- [5.5] Reviewer: Evaluating Results ---")
    abort_state = _abort_if_requested(state, "result_evaluator")
    if abort_state:
        return abort_state
    run_id = state.get("run_id")
    if run_id:
        log_run_event(run_id, "result_evaluator_start", {})
    contract, contract_min = _resolve_contract_pair_from_state(state if isinstance(state, dict) else {})
    metric_improvement_round_active = bool(state.get("ml_improvement_round_active"))
    metric_round_review_mode = _resolve_metric_round_review_mode(contract if isinstance(contract, dict) else {})
    metric_round_review_guarded = metric_improvement_round_active and metric_round_review_mode in {
        "hybrid_guarded",
        "advisor_only",
    }
    metric_round_advisor_only = metric_improvement_round_active and metric_round_review_mode == "advisor_only"
    if metric_improvement_round_active:
        print(
            "METRIC_IMPROVEMENT_REVIEW: active=true "
            + "mode="
            + metric_round_review_mode
            + " reviewer_policy="
            + ("skip_llm" if metric_round_advisor_only else ("non_blocking" if metric_round_review_guarded else "full"))
        )
        if run_id:
            try:
                log_run_event(
                    run_id,
                    "metric_improvement_round_review_mode",
                    {
                        "mode": metric_round_review_mode,
                        "reviewer_policy": "skip_llm"
                        if metric_round_advisor_only
                        else ("non_blocking" if metric_round_review_guarded else "full"),
                    },
                )
            except Exception:
                pass
    artifact_reqs = contract.get("artifact_requirements") if isinstance(contract.get("artifact_requirements"), dict) else {}
    visual_reqs = artifact_reqs.get("visual_requirements") if isinstance(artifact_reqs.get("visual_requirements"), dict) else {}
    visuals_missing = bool(state.get("visuals_missing"))
    if visual_reqs.get("required") and visuals_missing:
        feedback_history = state.get("feedback_history", []) or []
        message = (
            "Reviewer: Required visual artifacts are missing from the run. "
            "Please regenerate the plots defined in visual_requirements."
        )
        gate_context = {
            "source": "result_evaluator",
            "status": "NEEDS_IMPROVEMENT",
            "feedback": message,
            "failed_gates": ["visual_requirements_missing"],
            "required_fixes": ["Generate visual artifacts required by contract.visual_requirements."],
        }
        iteration_handoff = _build_iteration_handoff(
            state=state if isinstance(state, dict) else {},
            status="NEEDS_IMPROVEMENT",
            gate_context=gate_context,
            oc_report={},
            review_result={"feedback": message},
            qa_result={},
            evaluation_spec=(state.get("evaluation_spec") or (contract or {}).get("evaluation_spec") or {}),
        )
        if run_id:
            log_run_event(run_id, "visual_requirements_review", {"missing": len(visual_reqs.get("items", []))})
        return {
            "review_verdict": "NEEDS_IMPROVEMENT",
            "review_feedback": message,
            "failed_gates": ["visual_requirements_missing"],
            "last_gate_context": gate_context,
            "iteration_handoff": iteration_handoff,
            "iteration_count": int(state.get("iteration_count", 0) or 0) + 1,
            "feedback_history": feedback_history,
        }

    decisioning_reqs = (
        contract.get("decisioning_requirements") if isinstance(contract.get("decisioning_requirements"), dict) else {}
    )
    decisioning_enabled = bool(decisioning_reqs.get("enabled"))
    decisioning_required = bool(decisioning_reqs.get("required")) and decisioning_enabled
    decisioning_warning = None
    if decisioning_enabled:
        decisioning_result = _check_decisioning_columns(decisioning_reqs)
        missing_file = decisioning_result.get("missing_file")
        missing_columns = decisioning_result.get("missing_columns") or []
        constraint_violations = decisioning_result.get("constraint_violations") or []
        if decisioning_required and (missing_file or missing_columns or constraint_violations):
            message = (
                "Decisioning requirements missing: "
                f"file={missing_file if missing_file else 'data/scored_rows.csv'}, "
                f"columns={missing_columns}, constraints={constraint_violations}"
            )
            history = list(state.get("feedback_history", []))
            history.append(message)
            if run_id:
                log_run_event(
                    run_id,
                    "decisioning_requirements_review",
                    {"missing_columns": missing_columns, "violations": constraint_violations, "file": missing_file},
                )
            decisioning_warning = message
            state["feedback_history"] = history
        if not decisioning_required and (missing_columns or constraint_violations):
            history = list(state.get("feedback_history", []))
            history.append(
                f"Decisioning warning: columns={missing_columns} violations={constraint_violations}"
            )
            decisioning_warning = history[-1]
            state["feedback_history"] = history

    execution_output = state.get('execution_output', '')
    runtime_failure_detected = _has_runtime_failure_marker(execution_output) or bool(state.get("sandbox_failed"))
    runtime_terminal = bool(state.get("runtime_fix_terminal"))

    strategy = state.get('selected_strategy', {}) or {}
    strategy_context = f"Strategy: {strategy.get('title')}\nType: {strategy.get('analysis_type')}\nRules: {strategy.get('reasoning')}"
    business_objective = state.get('business_objective', '')
    evaluation_spec = state.get("evaluation_spec") or (contract or {}).get("evaluation_spec")
    governance_context = {}
    if decisioning_warning:
        governance_context["decisioning_warning"] = decisioning_warning
    evaluation_spec_for_review = dict(evaluation_spec or {})
    if governance_context:
        evaluation_spec_for_review = dict(evaluation_spec_for_review)
        evaluation_spec_for_review["governance_context"] = governance_context

    metrics_report = _resolve_metrics_report_for_facts(state if isinstance(state, dict) else {})
    oc_report_for_eval = _resolve_output_contract_report_for_facts(state if isinstance(state, dict) else {})
    reviewer_evidence = _build_reviewer_evidence_packet(
        state if isinstance(state, dict) else {},
        metrics_report,
        oc_report_for_eval,
    )
    execution_output_for_review = execution_output
    if not runtime_failure_detected and reviewer_evidence.get("summary_text"):
        execution_output_for_review = f"{execution_output}\n\n{reviewer_evidence['summary_text']}"

    if runtime_failure_detected:
        print("Reviewer: Runtime failure markers detected. Applying deterministic failure packet.")
        tail = execution_output[-1200:] if execution_output else "No execution output captured."
        eval_result = {
            "status": "NEEDS_IMPROVEMENT",
            "feedback": f"Runtime failure detected in execution output.\nError Snippet: {tail}",
            "failed_gates": ["runtime_failure"],
            "required_fixes": ["Fix runtime failure and regenerate required artifacts."],
            "retry_worth_it": not runtime_terminal,
            "hard_failures": ["runtime_failure"],
            "evidence": [{"claim": "Runtime failure marker detected in execution output.", "source": "execution_output_tail"}],
        }
    else:
        eval_result = reviewer.evaluate_results(
            execution_output_for_review, business_objective, strategy_context, evaluation_spec_for_review
        )
        if (
            reviewer_evidence.get("has_structured_evidence")
            and _feedback_claims_missing_evidence(eval_result.get("feedback"), reviewer_evidence)
        ):
            metrics_preview = reviewer_evidence.get("metrics_preview") or []
            metrics_text = ", ".join([str(item) for item in metrics_preview if item])
            normalized_feedback = (
                "Structured evidence is available and confirms required artifacts + metrics. "
                "Treating missing-evidence warning as non-blocking context mismatch."
            )
            if metrics_text:
                normalized_feedback = f"{normalized_feedback} EVIDENCE: {metrics_text}"
            eval_result = dict(eval_result or {})
            eval_result["feedback"] = normalized_feedback
            prev_status = str(eval_result.get("status") or "").upper()
            if prev_status == "NEEDS_IMPROVEMENT":
                eval_result["status"] = "APPROVE_WITH_WARNINGS"
                eval_result["retry_worth_it"] = False
            if run_id:
                log_run_event(
                    run_id,
                    "result_evaluator_evidence_override",
                    {"reason": "llm_missing_evidence_false_positive"},
                )
        if not isinstance(eval_result.get("evidence"), list):
            eval_result = dict(eval_result or {})
            eval_result["evidence"] = []

    status = eval_result.get('status', 'APPROVED')
    feedback = eval_result.get('feedback', '')
    retry_worth_it = eval_result.get("retry_worth_it") if isinstance(eval_result, dict) else None
    eval_improvement_suggestions = eval_result.get("improvement_suggestions") if isinstance(eval_result, dict) else None

    new_history = list(state.get('feedback_history', []))
    has_deterministic_error = runtime_failure_detected
    downgraded = False
    if status == "NEEDS_IMPROVEMENT":
        if has_deterministic_error:
            new_history.append(f"RESULT EVALUATION FEEDBACK: {feedback}")
        else:
            # Only downgrade to APPROVE_WITH_WARNINGS if retry is explicitly NOT worth it.
            # Note: Metric iteration is DISABLED. Metric-only issues are downgraded later via _classify_iteration_type.
            warning = f"REVIEWER_LLM_NONBLOCKING_WARNING: {feedback}"
            new_history.append(warning)
            feedback = warning
            if retry_worth_it is False:
                status = "APPROVE_WITH_WARNINGS"
                downgraded = True
            # else: keep NEEDS_IMPROVEMENT - will be classified as compliance or downgraded if metric-only
    print(f"ITER_EVAL status={status} retry_worth_it={retry_worth_it} downgraded={downgraded} reason={'no_traceback_retry_not_worth' if downgraded else 'none'}")

    # Case alignment QA gate (optional if required by contract/spec)
    skip_reason = _case_alignment_skip_reason(contract, evaluation_spec)
    case_alignment_required = _should_run_case_alignment(contract, evaluation_spec)
    case_report: Dict[str, Any] = {
        "status": "SKIP",
        "failures": [],
        "metrics": {},
        "reason": "case alignment not required",
    }
    case_history = list(state.get("case_alignment_history", []) or [])
    if skip_reason:
        case_alignment_required = False
        case_report = {
            "status": "SKIPPED",
            "mode": "case_level",
            "metrics": {"case_count": None},
            "thresholds": {},
            "failures": [],
            "explanation": f"Case alignment skipped: {skip_reason}.",
            "skip_reason": skip_reason,
        }
    elif case_alignment_required:
        data_paths = []
        ml_data_path = state.get("ml_data_path")
        if isinstance(ml_data_path, str) and ml_data_path and os.path.exists(ml_data_path):
            data_paths.append(ml_data_path)
        if os.path.exists("data/cleaned_full.csv"):
            data_paths.append("data/cleaned_full.csv")
        if os.path.exists("data/cleaned_data.csv"):
            data_paths.append("data/cleaned_data.csv")
        if os.path.exists("data/scored_rows.csv"):
            data_paths.append("data/scored_rows.csv")
        case_report = build_case_alignment_report(
            contract=contract,
            case_summary_path="data/case_summary.csv",
            weights_path="data/weights.json",
            data_paths=data_paths,
            scored_rows_path="data/scored_rows.csv",
        )
        try:
            metrics = case_report.get("metrics", {}) if isinstance(case_report, dict) else {}
            violations = metrics.get("adjacent_refscore_violations")
            if violations is not None:
                case_history.append(float(violations))
        except Exception:
            pass
    try:
        os.makedirs("data", exist_ok=True)
        dump_json("data/case_alignment_report.json", case_report)
    except Exception as err:
        print(f"Warning: failed to persist case_alignment_report.json: {err}")

    # Detect stale metrics file across iterations (diagnostic for ML)
    metrics_report = metrics_report if isinstance(metrics_report, dict) else {}
    weights_report = _load_json_safe("data/weights.json")
    metrics_signature = _hash_json(metrics_report)
    weights_signature = _hash_json(weights_report)
    prev_metrics_signature = state.get("metrics_signature")
    prev_weights_signature = state.get("weights_signature")
    metrics_stale = False
    if metrics_signature and metrics_signature == prev_metrics_signature:
        if weights_signature and weights_signature != prev_weights_signature:
            metrics_stale = True
            new_history.append(
                "METRICS_STALE: data/metrics.json unchanged while weights changed; recompute metrics from current outputs."
            )
        else:
            new_history.append(
                "METRICS_UNCHANGED: data/metrics.json is identical to the prior iteration; ensure metrics are recomputed and saved per run."
            )
    if not metrics_report:
        new_history.append(
            "METRICS_MISSING: data/metrics.json not found or empty; downstream evaluation may be using stale metrics."
        )
    if not metrics_report or metrics_stale:
        synthesized = _normalize_metrics_from_weights(weights_report)
        if not synthesized:
            synthesized = _compute_metrics_from_scored_rows(
                scored_rows_path="data/scored_rows.csv",
                case_summary_path="data/case_summary.csv",
                weights_obj=weights_report,
            )
        if synthesized:
            metrics_report = dict(synthesized)
            metrics_report["source"] = "computed_fallback"
            metrics_signature = _hash_json(metrics_report)
            new_history.append(
                "METRICS_FALLBACK: metrics synthesized from weights/scored_rows due to missing or stale metrics.json."
            )
            try:
                os.makedirs("data", exist_ok=True)
                dump_json("data/metrics.json", metrics_report)
            except Exception as metrics_err:
                print(f"Warning: failed to persist fallback metrics.json: {metrics_err}")

    # 5.5.1) Metrics schema consistency (mean inside CI)
    if metrics_report:
        ci_issues = validate_metrics_ci_consistency(metrics_report)
        if ci_issues:
            status = "NEEDS_IMPROVEMENT"
            issue_text = ", ".join(ci_issues)
            msg = f"METRICS_SCHEMA_INCONSISTENT: {issue_text}"
            new_history.append(msg)
            feedback = f"{feedback}\n{msg}" if feedback else msg

    # 5.6) Model Metrics Consistency Validation (Informative helper)
    if metrics_report:
        try:
            consistency_result = validate_model_metrics_consistency(metrics_report)
            if not consistency_result["passed"]:
                consistency_msg = f"METRIC_CONSISTENCY_WARNING: {consistency_result['error_message']}"
                print(f"Advice: {consistency_msg}")
                new_history.append(consistency_msg)
                if not feedback:
                    feedback = consistency_msg
                else:
                    feedback = f"{feedback}\n{consistency_msg}"
        except Exception as consistency_err:
            print(f"Warning: model metrics consistency validation failed: {consistency_err}")
    iter_id = int(state.get("iteration_count", 0)) + 1
    saved_iter_artifacts = _persist_iteration_artifacts(iter_id)

    if case_alignment_required and case_report.get("status") == "FAIL":
        feedback = f"CASE_ALIGNMENT_GATE_FAILED: {case_report.get('explanation')}"
        status = "NEEDS_IMPROVEMENT"
        new_history.append(f"CASE_ALIGNMENT_GATE_FAILED: {case_report.get('failures')}")

    # Output contract validation (schema-aware)
    oc_report = _persist_output_contract_report(state, reason="result_evaluator")
    oc_overall_status = str(oc_report.get("overall_status") or "").lower() if isinstance(oc_report, dict) else ""
    contract_output_failed_gates: List[str] = []
    contract_output_required_fixes: List[str] = []
    if oc_overall_status == "error" or (isinstance(oc_report, dict) and oc_report.get("missing")):
        status = "NEEDS_IMPROVEMENT"
        miss_text = json.dumps(oc_report, indent=2)
        feedback_missing = f"Output contract compliance error: {miss_text}"
        feedback = f"{feedback}\n{feedback_missing}" if feedback else feedback_missing
        new_history.append(f"OUTPUT_CONTRACT_ERROR: {miss_text}")
        contract_issues = _extract_contract_artifact_issues(oc_report)
        missing_paths = contract_issues.get("missing_paths", [])
        schema_issues = contract_issues.get("schema_issues", [])
        if missing_paths:
            if "contract_required_artifacts_missing" not in contract_output_failed_gates:
                contract_output_failed_gates.append("contract_required_artifacts_missing")
            for path in missing_paths:
                contract_output_required_fixes.append(f"Generate required artifact at path: {path}")
        if schema_issues:
            if "contract_artifact_schema_mismatch" not in contract_output_failed_gates:
                contract_output_failed_gates.append("contract_artifact_schema_mismatch")
            for issue in schema_issues:
                contract_output_required_fixes.append(f"Fix artifact schema issue: {issue}")
        if not contract_output_required_fixes:
            contract_output_required_fixes.append(
                "Regenerate all contract-required artifacts and ensure output contract compliance."
            )
        retry_worth_it = True

    alignment_failed_gates: List[str] = []
    alignment_check = _load_json_safe("data/alignment_check.json")
    alignment_requirements = []
    if isinstance(evaluation_spec, dict):
        alignment_requirements = evaluation_spec.get("alignment_requirements") or []
    if not alignment_requirements and isinstance(contract, dict):
        alignment_requirements = contract.get("alignment_requirements", []) or []
    alignment_requirements = _coerce_alignment_requirements(alignment_requirements)
    if isinstance(alignment_requirements, list) and alignment_requirements:
        if not alignment_check:
            status = "NEEDS_IMPROVEMENT"
            alignment_failed_gates.append("alignment_check_missing")
            msg = "ALIGNMENT_CHECK_MISSING: data/alignment_check.json not found."
            feedback = f"{feedback}\n{msg}" if feedback else msg
            new_history.append(msg)
        else:
            normalized_alignment, alignment_issues = _normalize_alignment_check(
                alignment_check, alignment_requirements
            )
            if normalized_alignment != alignment_check:
                alignment_check = normalized_alignment
                try:
                    dump_json("data/alignment_check.json", alignment_check)
                except Exception:
                    pass
            raw_status = str(alignment_check.get("status", "")).upper()
            failure_mode = str(alignment_check.get("failure_mode", "")).lower()
            summary = alignment_check.get("summary") or alignment_check.get("notes") or ""
            if alignment_issues and raw_status == "PASS":
                raw_status = "WARN"
                summary = f"{summary} Alignment evidence missing." if summary else "Alignment evidence missing."
                failure_mode = failure_mode or "format"
                alignment_check["status"] = raw_status
                alignment_check["summary"] = summary
                alignment_check["failure_mode"] = failure_mode
            alignment_check, forbidden_violations = _apply_forbidden_feature_gate(
                alignment_check,
                contract,
                {},
                state.get("generated_code") or state.get("last_generated_code") or "",
            )
            if forbidden_violations:
                alignment_failed_gates.append("forbidden_features_used")
                msg = f"FORBIDDEN_FEATURES_USED: {forbidden_violations}"
                if status != "NEEDS_IMPROVEMENT":
                    status = "NEEDS_IMPROVEMENT"
                new_history.append(msg)
                feedback = f"{feedback}\n{msg}" if feedback else msg
                try:
                    dump_json("data/alignment_check.json", alignment_check)
                except Exception:
                    pass
            data_modes = {"data_limited", "data", "insufficient_data", "data_limitations"}
            method_modes = {"method_choice", "method", "strategy", "approach"}
            msg = f"ALIGNMENT_CHECK_{raw_status}: failure_mode={failure_mode}; summary={summary}"
            if raw_status in {"WARN", "FAIL"}:
                if failure_mode in data_modes:
                    if status != "NEEDS_IMPROVEMENT":
                        status = "APPROVE_WITH_WARNINGS"
                    new_history.append(msg)
                    feedback = f"{feedback}\n{msg}" if feedback else msg
                elif failure_mode in method_modes:
                    if status != "NEEDS_IMPROVEMENT":
                        status = "APPROVE_WITH_WARNINGS"
                    new_history.append(msg)
                    feedback = f"{feedback}\n{msg}" if feedback else msg
                elif raw_status == "FAIL":
                    status = "NEEDS_IMPROVEMENT"
                    alignment_failed_gates.append("alignment_unknown")
                    new_history.append(msg)
                    feedback = f"{feedback}\n{msg}" if feedback else msg
                else:
                    if status != "NEEDS_IMPROVEMENT":
                        status = "APPROVE_WITH_WARNINGS"
                    new_history.append(msg)
                    feedback = f"{feedback}\n{msg}" if feedback else msg

    data_adequacy_report = {}
    adequacy_status = None
    adequacy_threshold = int(state.get("data_adequacy_threshold", 3) or 3)
    adequacy_consecutive = int(state.get("data_adequacy_consecutive", 0) or 0)
    try:
        data_adequacy_report = build_data_adequacy_report(state)
        adequacy_status = data_adequacy_report.get("status")
        if adequacy_status == "data_limited":
            adequacy_consecutive += 1
        else:
            adequacy_consecutive = 0
        data_adequacy_report["consecutive_data_limited"] = adequacy_consecutive
        data_adequacy_report["data_limited_threshold"] = adequacy_threshold
        data_adequacy_report["threshold_reached"] = adequacy_consecutive >= adequacy_threshold
        try:
            os.makedirs("data", exist_ok=True)
            dump_json("data/data_adequacy_report.json", data_adequacy_report)
        except Exception as adequacy_err:
            print(f"Warning: failed to persist data_adequacy_report.json: {adequacy_err}")
    except Exception as adequacy_err:
        print(f"Warning: data adequacy evaluation failed: {adequacy_err}")

    objective_type = None
    if isinstance(evaluation_spec, dict):
        objective_type = evaluation_spec.get("objective_type")
    if not objective_type and isinstance(contract, dict):
        eval_spec_contract = contract.get("evaluation_spec")
        if isinstance(eval_spec_contract, dict):
            objective_type = eval_spec_contract.get("objective_type")
    if not objective_type:
        objective_type = strategy.get("analysis_type")

    primary_metric_snapshot = _extract_primary_metric_snapshot(
        metrics_report=metrics_report,
        weights_report=weights_report,
        objective_type=objective_type,
        evaluation_spec=evaluation_spec if isinstance(evaluation_spec, dict) else None,
        contract=contract if isinstance(contract, dict) else None,
    )
    metric_history = list(state.get("metric_history", []) or [])
    if primary_metric_snapshot:
        primary_metric_snapshot = dict(primary_metric_snapshot)
        primary_metric_snapshot["iteration_id"] = int(state.get("iteration_count", 0)) + 1
        metric_history.append(primary_metric_snapshot)
        metric_history = metric_history[-20:]

    baseline_check = {}
    try:
        baseline_check = _evaluate_baseline_sanity_check(
            state=state if isinstance(state, dict) else {},
            evaluation_spec=evaluation_spec if isinstance(evaluation_spec, dict) else None,
            contract=contract if isinstance(contract, dict) else None,
            contract_min=contract_min if isinstance(contract_min, dict) else None,
            primary_metric_snapshot=primary_metric_snapshot if isinstance(primary_metric_snapshot, dict) else None,
        )
    except Exception as baseline_err:
        print(f"Warning: baseline sanity check failed: {baseline_err}")
        baseline_check = {}
    if baseline_check and baseline_check.get("failed"):
        baseline_allowed = False
        for source in (
            evaluation_spec if isinstance(evaluation_spec, dict) else None,
            contract if isinstance(contract, dict) else None,
            contract_min if isinstance(contract_min, dict) else None,
        ):
            if isinstance(source, dict) and source.get("baseline_allowed") is True:
                baseline_allowed = True
                break
        reporting_policy = contract.get("reporting_policy") if isinstance(contract, dict) else {}
        if isinstance(reporting_policy, dict) and reporting_policy.get("baseline_allowed") is True:
            baseline_allowed = True
        metric_name = baseline_check.get("metric_name")
        metric_value = baseline_check.get("metric_value")
        baseline_value = baseline_check.get("baseline_value")
        margin = baseline_check.get("margin")
        comparator = baseline_check.get("comparator")
        threshold = baseline_check.get("threshold")
        target_col = baseline_check.get("target_col")
        rows_used = baseline_check.get("rows_used")
        rows_note = f", rows={rows_used}" if rows_used is not None else ""
        msg = (
            "BASELINE_CHECK_FAILED: "
            f"primary_metric={metric_name} value={metric_value:.4f} "
            f"{comparator} baseline_threshold={threshold:.4f} "
            f"(baseline={baseline_value:.4f}, margin={margin:.4f}, target={target_col}{rows_note})"
        )
        if baseline_allowed:
            msg = f"{msg} (baseline_allowed)"
            if status != "NEEDS_IMPROVEMENT":
                status = "APPROVE_WITH_WARNINGS"
        else:
            status = "NEEDS_IMPROVEMENT"
        new_history.append(msg)
        feedback = f"{feedback}\n{msg}" if feedback else msg

    if _detect_refscore_alias(execution_output, contract):
        status = "NEEDS_IMPROVEMENT"
        alias_msg = (
            "TARGET_MAPPING_ERROR: RefScore is derived per contract but was mapped to Score. "
            "Derive RefScore from case taxonomy instead of aliasing Score."
        )
        feedback = f"{feedback}\n{alias_msg}" if feedback else alias_msg
        new_history.append(alias_msg)

    # Post-exec code audit (advisory; deterministic blockers remain canonical)
    code = state.get("generated_code") or state.get("last_generated_code") or ""
    artifact_index_for_review = state.get("artifact_index")
    if not isinstance(artifact_index_for_review, list):
        artifact_index_for_review = _load_json_any("data/produced_artifact_index.json")
    if not isinstance(artifact_index_for_review, list):
        artifact_index_for_review = []
    review_diagnostics = _build_code_review_diagnostics(
        runtime_failure_detected=runtime_failure_detected,
        runtime_terminal=runtime_terminal,
        execution_output=execution_output,
        output_contract_report=oc_report,
        artifact_index=artifact_index_for_review,
    )
    counters = dict(state.get("budget_counters") or {})
    review_counters = counters
    audit_rejected = False
    hard_qa_gate_reject = False
    qa_rejected = False
    qa_failed_gates: List[str] = []
    qa_required_fixes: List[str] = []
    qa_hard_failures: List[str] = []
    qa_notes: List[str] = []
    qa_notes_appended = False
    qa_view = state.get("qa_view") or (state.get("contract_views") or {}).get("qa_view")
    if isinstance(qa_view, dict) and qa_view:
        qa_context = dict(qa_view)
        qa_context["_contract_source"] = "qa_view"
    elif isinstance(contract, dict) and contract:
        qa_context = dict(contract)
        qa_context["_contract_source"] = "execution_contract"
    else:
        qa_context = {"_contract_source": "fallback"}
    ml_data_path = _resolve_ml_input_path(state if isinstance(state, dict) else {}, require_exists=False)
    if ml_data_path:
        qa_context["ml_data_path"] = ml_data_path
    if state.get("ml_training_policy_warnings"):
        qa_context["ml_training_policy_warnings"] = state.get("ml_training_policy_warnings")
    iteration_handoff_ctx = state.get("iteration_handoff")
    if isinstance(iteration_handoff_ctx, dict) and iteration_handoff_ctx:
        qa_context["iteration_handoff"] = iteration_handoff_ctx
    hypothesis_packet_ctx = state.get("ml_improvement_hypothesis_packet")
    if isinstance(hypothesis_packet_ctx, dict) and hypothesis_packet_ctx:
        qa_context["ml_improvement_hypothesis_packet"] = hypothesis_packet_ctx
    metric_round_active_ctx = bool(state.get("ml_improvement_round_active"))
    qa_context["metric_improvement_round_active"] = metric_round_active_ctx
    qa_context["augmentation_requested"] = bool(
        metric_round_active_ctx
        and _resolve_metric_round_augmentation_requested(
            state if isinstance(state, dict) else {},
            contract if isinstance(contract, dict) else {},
        )
    )
    qa_context["execution_diagnostics"] = review_diagnostics
    qa_context_prompt = compress_long_lists(qa_context)[0] if isinstance(qa_context, dict) else qa_context

    qa_gate_specs = _merge_qa_gate_specs(
        (evaluation_spec or {}).get("qa_gates") if isinstance(evaluation_spec, dict) else None,
        (evaluation_spec or {}).get("gates") if isinstance(evaluation_spec, dict) else None,
        get_qa_gates(contract) if isinstance(contract, dict) else None,
        qa_context.get("qa_gates") if isinstance(qa_context, dict) else None,
    )
    qa_active_gate_names = _extract_gate_names(
        get_qa_gates(contract) if isinstance(contract, dict) else []
    )
    reviewer_active_gate_names = _extract_gate_names(
        get_reviewer_gates(contract) if isinstance(contract, dict) else []
    )
    hard_qa_gates: set[str] = {
        str(gate.get("name")).lower()
        for gate in qa_gate_specs
        if isinstance(gate, dict) and str(gate.get("severity") or "HARD").upper() == "HARD"
    }

    column_gate_eval = _evaluate_column_presence_gates(qa_gate_specs)
    if column_gate_eval:
        qa_notes.extend(column_gate_eval.get("messages", []))
        qa_failed_gates.extend(column_gate_eval.get("failed_gates", []))
        qa_required_fixes.extend(column_gate_eval.get("required_fixes", []))
        qa_hard_failures.extend(column_gate_eval.get("hard_failures", []))

    review_warnings: List[str] = []
    review_result: Dict[str, Any] = {}
    qa_result: Dict[str, Any] = {}
    budget_counter_state: Dict[str, Any] = {
        "run_budget": state.get("run_budget"),
        "budget_counters": review_counters,
    }
    if code:
        analysis_type = strategy.get("analysis_type", "predictive")
        evaluation_spec_code_audit = dict(evaluation_spec_for_review or {})
        evaluation_spec_code_audit["execution_diagnostics"] = review_diagnostics
        if metric_round_advisor_only:
            review_result = {
                "status": "APPROVE_WITH_WARNINGS",
                "feedback": "METRIC_IMPROVEMENT_REVIEW_MODE: reviewer LLM skipped (advisor_only).",
                "failed_gates": [],
                "required_fixes": [],
                "hard_failures": [],
            }
            review_warnings.append(str(review_result.get("feedback")))
        else:
            try:
                ok, counters, err_msg = _consume_budget(
                    budget_counter_state,
                    "reviewer_calls",
                    "max_reviewer_calls",
                    "Reviewer",
                )
                review_counters = counters
                budget_counter_state["budget_counters"] = review_counters
                if ok:
                    reviewer_view = state.get("reviewer_view") or (state.get("contract_views") or {}).get("reviewer_view")
                    if not isinstance(reviewer_view, dict) or not reviewer_view:
                        projected_views = build_contract_views_projection(
                            contract,
                            state.get("artifact_index") or [],
                        )
                        reviewer_view = projected_views.get("reviewer_view") or {}
                    reviewer_view, evaluation_spec_code_audit = _apply_ml_reviewer_output_scope(
                        contract if isinstance(contract, dict) else {},
                        state if isinstance(state, dict) else {},
                        reviewer_view if isinstance(reviewer_view, dict) else {},
                        evaluation_spec_code_audit if isinstance(evaluation_spec_code_audit, dict) else None,
                    )
                    if isinstance(reviewer_view, dict):
                        reviewer_view = dict(reviewer_view)
                        reviewer_view["execution_diagnostics"] = review_diagnostics
                        ml_data_path_for_review = _resolve_ml_input_path(state if isinstance(state, dict) else {}, require_exists=False)
                        if ml_data_path_for_review:
                            reviewer_view["ml_data_path"] = ml_data_path_for_review
                        reviewer_view = compress_long_lists(reviewer_view)[0]
                    review_result = reviewer.review_code(
                        code,
                        analysis_type,
                        "",
                        reviewer_view.get("strategy_summary") if isinstance(reviewer_view, dict) else "",
                        evaluation_spec_code_audit,
                        reviewer_view=reviewer_view,
                    )
                    review_result = _apply_review_consistency_guard(
                        review_result,
                        review_diagnostics,
                        actor="reviewer",
                    )
                    review_result = apply_contract_first_gate_policy(
                        review_result,
                        reviewer_active_gate_names,
                        actor="reviewer",
                    )
                    if metric_round_review_guarded:
                        review_result = _coerce_review_packet_to_nonblocking(review_result, "reviewer")
                    if run_id:
                        log_agent_snapshot(
                            run_id,
                            "reviewer",
                            prompt=getattr(reviewer, "last_prompt", None),
                            response=getattr(reviewer, "last_response", None) or review_result,
                            context={
                                "analysis_type": analysis_type,
                                "evaluation_spec": evaluation_spec_code_audit,
                                "reviewer_view": reviewer_view,
                                "execution_diagnostics": review_diagnostics,
                                "metric_round_review_mode": metric_round_review_mode if metric_improvement_round_active else None,
                            },
                            verdicts=review_result,
                            attempt=iter_id,
                        )
                    if review_result and review_result.get("status") != "APPROVED":
                        review_warnings.append(
                            f"REVIEWER_CODE_AUDIT[{review_result.get('status')}]: {review_result.get('feedback')}"
                        )
                else:
                    review_warnings.append(f"REVIEWER_CODE_AUDIT_SKIPPED: {err_msg}")
            except Exception as review_err:
                review_warnings.append(f"REVIEWER_CODE_AUDIT_ERROR: {review_err}")
        if metric_round_advisor_only:
            qa_result = {
                "status": "APPROVE_WITH_WARNINGS",
                "feedback": "METRIC_IMPROVEMENT_REVIEW_MODE: qa_reviewer LLM skipped (advisor_only).",
                "failed_gates": [],
                "required_fixes": [],
                "hard_failures": [],
            }
            review_warnings.append(str(qa_result.get("feedback")))
        else:
            try:
                ok, counters, err_msg = _consume_budget(
                    budget_counter_state,
                    "qa_calls",
                    "max_qa_calls",
                    "QA Reviewer",
                )
                review_counters = counters
                budget_counter_state["budget_counters"] = review_counters
                if ok:
                    qa_context_for_call = qa_context_prompt
                    if isinstance(qa_context_prompt, dict):
                        qa_context_for_call = dict(qa_context_prompt)
                        provisional_gate_context = {
                            "source": "result_evaluator_pre_qa",
                            "status": str((review_result or {}).get("status") or (eval_result or {}).get("status") or ""),
                            "feedback": str((review_result or {}).get("feedback") or (eval_result or {}).get("feedback") or ""),
                            "failed_gates": _normalize_handoff_items(
                                (review_result or {}).get("failed_gates") if isinstance(review_result, dict) else [],
                                max_items=12,
                                max_len=180,
                            ),
                            "required_fixes": _normalize_handoff_items(
                                (review_result or {}).get("required_fixes") if isinstance(review_result, dict) else [],
                                max_items=12,
                                max_len=220,
                            ),
                        }
                        qa_context_for_call["iteration_handoff"] = _build_iteration_handoff(
                            state=state if isinstance(state, dict) else {},
                            status=str(provisional_gate_context.get("status") or ""),
                            gate_context=provisional_gate_context,
                            oc_report=oc_report if isinstance(oc_report, dict) else {},
                            review_result=review_result if isinstance(review_result, dict) else {},
                            qa_result={},
                            eval_result=eval_result if isinstance(eval_result, dict) else {},
                            evaluation_spec=evaluation_spec_for_review if isinstance(evaluation_spec_for_review, dict) else {},
                        )
                        qa_context_for_call = compress_long_lists(qa_context_for_call)[0]
                    qa_result = qa_reviewer.review_code(code, strategy, business_objective, qa_context_for_call)
                    qa_result = _apply_review_consistency_guard(
                        qa_result,
                        review_diagnostics,
                        actor="qa_reviewer",
                    )
                    qa_result = apply_contract_first_gate_policy(
                        qa_result,
                        qa_active_gate_names,
                        actor="qa_reviewer",
                    )
                    if metric_round_review_guarded:
                        qa_result = _coerce_review_packet_to_nonblocking(qa_result, "qa_reviewer")
                    if run_id:
                        log_agent_snapshot(
                            run_id,
                            "qa_reviewer",
                            prompt=getattr(qa_reviewer, "last_prompt", None),
                            response=getattr(qa_reviewer, "last_response", None) or qa_result,
                            context=qa_context_for_call if isinstance(qa_context_for_call, dict) else {"qa_context": qa_context_for_call},
                            verdicts=qa_result,
                            attempt=iter_id,
                        )
                    if qa_result and qa_result.get("status") != "APPROVED":
                        review_warnings.append(
                            f"QA_CODE_AUDIT[{qa_result.get('status')}]: {qa_result.get('feedback')}"
                        )
                    if qa_result:
                        qa_status = qa_result.get("status")
                        if qa_status == "REJECTED":
                            qa_rejected = True
                            audit_rejected = True
                        qa_result_failed = qa_result.get("failed_gates", []) or []
                        qa_result_required = qa_result.get("required_fixes", []) or []
                        qa_result_hard = qa_result.get("hard_failures") or []
                        qa_result_hard = [str(g) for g in qa_result_hard if g]
                        for gate_name in qa_result_failed:
                            if str(gate_name).lower() in hard_qa_gates and gate_name not in qa_result_hard:
                                qa_result_hard.append(gate_name)
                        if qa_result_hard:
                            if any(str(g).lower() in hard_qa_gates for g in qa_result_hard):
                                hard_qa_gate_reject = True
                        qa_failed_gates.extend(qa_result_failed)
                        qa_required_fixes.extend(qa_result_required)
                        qa_hard_failures.extend(qa_result_hard)
                else:
                    review_warnings.append(f"QA_CODE_AUDIT_SKIPPED: {err_msg}")
                    state["qa_budget_exceeded"] = True
            except Exception as qa_err:
                review_warnings.append(f"QA_CODE_AUDIT_ERROR: {qa_err}")
        if qa_notes:
            review_warnings.extend(qa_notes)
            qa_notes_appended = True
        if state.get("qa_budget_exceeded"):
            warn_text = "QA_INCOMPLETE: QA budget exceeded; QA audit skipped."
            feedback = f"{feedback}\n{warn_text}" if feedback else warn_text
            new_history.append(warn_text)

    if qa_notes and not qa_notes_appended:
        review_warnings.extend(qa_notes)

    post_audit_context = {}
    if review_warnings:
        post_audit_context["code_audit_warnings"] = list(review_warnings)
    if qa_notes:
        post_audit_context["deterministic_gate_notes"] = list(qa_notes)
    if qa_failed_gates or qa_required_fixes or qa_hard_failures or qa_rejected:
        post_audit_context["qa_code_audit"] = {
            "status": "REJECTED" if (qa_rejected or qa_hard_failures) else "APPROVE_WITH_WARNINGS",
            "failed_gates": qa_failed_gates,
            "required_fixes": qa_required_fixes,
            "hard_failures": qa_hard_failures,
        }
    if state.get("ml_training_policy_warnings"):
        post_audit_context["ml_training_policy_warnings"] = state.get("ml_training_policy_warnings")
    post_audit_summary = None
    if review_warnings or qa_notes:
        post_audit_summary = "\n".join([*review_warnings, *qa_notes]) if (review_warnings or qa_notes) else None

    post_audit_appended = False
    if post_audit_context and not metric_round_review_guarded:
        governance_context.update(post_audit_context)
        evaluation_spec_final = dict(evaluation_spec_for_review)
        evaluation_spec_final["governance_context"] = governance_context
        if evaluation_spec_final != evaluation_spec_for_review:
            re_eval = reviewer.evaluate_results(
                execution_output_for_review, business_objective, strategy_context, evaluation_spec_final
            )
            if isinstance(re_eval, dict) and re_eval.get("status"):
                eval_result = dict(re_eval)
                status = eval_result.get("status", status)
                feedback = eval_result.get("feedback", feedback)
                retry_worth_it = eval_result.get("retry_worth_it", retry_worth_it)
                new_history.append("REVIEWER_REEVAL: Final verdict computed with governance context.")
                if post_audit_summary:
                    feedback = f"{feedback}\n{post_audit_summary}" if feedback else post_audit_summary
                    new_history.append(post_audit_summary)
                    post_audit_appended = True
    elif post_audit_context and metric_round_review_guarded:
        new_history.append(
            "METRIC_IMPROVEMENT_REVIEW_MODE: reviewer/qa code-audit findings kept as advisory context only."
        )

    if post_audit_summary and not post_audit_appended:
        feedback = f"{feedback}\n{post_audit_summary}" if feedback else post_audit_summary
        new_history.append(post_audit_summary)

    if qa_rejected and not qa_hard_failures:
        qa_hard_failures.append("qa_rejected")

    if audit_rejected:
        note = "CODE_AUDIT_FINDINGS: reviewer/QA raised issues; see governance_context for details."
        feedback = f"{feedback}\n{note}" if feedback else note
        new_history.append(note)

    hard_qa_retry_count = int(state.get("hard_qa_retry_count", 0))
    if hard_qa_gate_reject:
        hard_note = "HARD_QA_GATE_NOTE: QA reported hard-failure signals (advisory)."
        new_history.append(hard_note)
        feedback = f"{feedback}\n{hard_note}" if feedback else hard_note

    failed_gates = (
        case_report.get("failures", [])
        if case_alignment_required and case_report.get("status") == "FAIL"
        else []
    )
    qa_failed_gates = list(dict.fromkeys([str(g) for g in qa_failed_gates if g]))
    qa_required_fixes = list(dict.fromkeys([str(f) for f in qa_required_fixes if f]))
    qa_hard_failures = list(dict.fromkeys([str(h) for h in qa_hard_failures if h]))
    if qa_rejected and not qa_failed_gates:
        qa_failed_gates.append("QA_CODE_AUDIT")
    if qa_failed_gates:
        for gate in qa_failed_gates:
            if gate not in failed_gates:
                failed_gates.append(gate)
    if contract_output_failed_gates:
        for gate in contract_output_failed_gates:
            if gate not in failed_gates:
                failed_gates.append(gate)
    required_fixes = _expand_required_fixes(failed_gates, failed_gates)
    if qa_required_fixes:
        for fix in qa_required_fixes:
            if fix not in required_fixes:
                required_fixes.append(fix)
    if contract_output_required_fixes:
        for fix in contract_output_required_fixes:
            if fix not in required_fixes:
                required_fixes.append(fix)
    if alignment_failed_gates:
        for item in alignment_failed_gates:
            if item not in failed_gates:
                failed_gates.append(item)
                required_fixes.append(item)
    required_fixes = _expand_required_fixes(required_fixes, failed_gates)
    if case_report.get("status") == "FAIL":
        gate_source = "case_alignment_gate"
    elif contract_output_failed_gates:
        gate_source = "output_contract"
    elif alignment_failed_gates:
        gate_source = "alignment_check"
    else:
        gate_source = "result_evaluator"
    gate_evidence: List[Dict[str, str]] = []
    for source in (
        eval_result.get("evidence") if isinstance(eval_result, dict) else None,
        review_result.get("evidence") if isinstance(review_result, dict) else None,
        qa_result.get("evidence") if isinstance(qa_result, dict) else None,
    ):
        for item in _normalize_handoff_evidence(source, max_items=12):
            if item not in gate_evidence:
                gate_evidence.append(item)
    runtime_tail_for_hints = str(state.get("last_runtime_error_tail") or state.get("execution_output") or "")[-1800:]
    evidence_blob = ""
    if gate_evidence:
        try:
            evidence_blob = json.dumps(gate_evidence[:12], ensure_ascii=True)
        except Exception:
            evidence_blob = str(gate_evidence[:12])
    feedback, repair_hints = append_repair_hints(
        feedback=str(feedback or ""),
        error_text=str(feedback or "") + "\n" + runtime_tail_for_hints + "\n" + evidence_blob,
    )
    gate_context = {
        "source": gate_source,
        "status": status,
        "feedback": feedback,
        "failed_gates": failed_gates,
        "required_fixes": required_fixes,
    }
    if repair_hints:
        gate_context["repair_hints"] = repair_hints
    if gate_evidence:
        gate_context["evidence"] = gate_evidence[:12]
    ml_feedback_record = _set_latest_feedback_record(
        state,
        agent="ml_engineer",
        source=gate_source,
        status=status,
        iteration=int(iter_id),
        feedback=str(feedback or ""),
        failed_gates=failed_gates,
        required_fixes=required_fixes,
        hard_failures=[],
        runtime_error_tail=str(state.get("last_runtime_error_tail") or state.get("execution_output") or "")[-1200:],
        evidence=gate_evidence[:12],
    )
    if repair_hints and isinstance(ml_feedback_record, dict):
        ml_feedback_record["repair_hints"] = repair_hints[:2]
    if ml_feedback_record:
        gate_context["feedback_record"] = ml_feedback_record
    existing_hard_failures = [str(h) for h in (state.get("hard_failures") or []) if h]
    merged_hard_failures = list(dict.fromkeys(existing_hard_failures + qa_hard_failures))
    if merged_hard_failures:
        gate_context["hard_failures"] = merged_hard_failures
        if isinstance(gate_context.get("feedback_record"), dict):
            gate_context["feedback_record"]["hard_failures"] = list(merged_hard_failures[:15])
    feedback_json_payload = _build_ml_feedback_json(
        source=gate_source,
        status=status,
        feedback=str(feedback or ""),
        failed_gates=failed_gates,
        required_fixes=required_fixes,
        hard_failures=merged_hard_failures,
        review_result=review_result if isinstance(review_result, dict) else {},
        qa_result=qa_result if isinstance(qa_result, dict) else {},
        evidence=gate_evidence[:12],
        repair_hints=repair_hints,
    )
    gate_context["feedback_json"] = feedback_json_payload
    if isinstance(gate_context.get("feedback_record"), dict):
        gate_context["feedback_record"]["feedback_json"] = feedback_json_payload
    fix_block = _build_fix_instructions(required_fixes)
    if fix_block:
        gate_context["edit_instructions"] = fix_block

    iteration_handoff = _build_iteration_handoff(
        state=state if isinstance(state, dict) else {},
        status=status,
        gate_context=gate_context,
        oc_report=oc_report,
        review_result=review_result,
        qa_result=qa_result,
        eval_result=eval_result,
        evaluation_spec=evaluation_spec_for_review if isinstance(evaluation_spec_for_review, dict) else {},
    )

    print(f"Reviewer Verdict: {status}")
    if status == "NEEDS_IMPROVEMENT":
        print(f"Advice: {feedback}")

    iteration_type = _classify_iteration_type(status, audit_rejected, oc_report, feedback)
    if runtime_failure_detected and status == "NEEDS_IMPROVEMENT":
        iteration_type = "compliance"

    if iteration_type:
        gate_context["iteration_type"] = iteration_type
    compliance_iterations = int(state.get("compliance_iterations", 0))
    metric_iterations = int(state.get("metric_iterations", 0))
    compliance_passed = bool(state.get("compliance_passed", False))
    if status == "NEEDS_IMPROVEMENT":
        if iteration_type == "compliance":
            compliance_iterations += 1
            compliance_passed = False
        # metric iteration accounting/routing is handled downstream by check_evaluation

    review_feedback = feedback or state.get("review_feedback", "")
    qa_packet_for_state = _normalize_review_packet_for_state(
        qa_result if isinstance(qa_result, dict) else {},
        default_status="UNKNOWN",
    )
    reviewer_packet_for_state = _normalize_review_packet_for_state(
        review_result if isinstance(review_result, dict) else {},
        default_status="UNKNOWN",
    )
    qa_has_packet = isinstance(qa_result, dict) and bool(qa_result)
    reviewer_has_packet = isinstance(review_result, dict) and bool(review_result)
    reviewer_failed_from_result = _normalize_handoff_items(
        (review_result or {}).get("failed_gates") if isinstance(review_result, dict) else [],
        max_items=20,
        max_len=180,
    )
    reviewer_required_from_result = _normalize_handoff_items(
        (review_result or {}).get("required_fixes") if isinstance(review_result, dict) else [],
        max_items=20,
        max_len=220,
    )
    reviewer_hard_from_result = _normalize_handoff_items(
        (review_result or {}).get("hard_failures") if isinstance(review_result, dict) else [],
        max_items=15,
        max_len=180,
    )
    reviewer_rejected = str((review_result or {}).get("status") or "").strip().upper() == "REJECTED"
    qa_packet_for_state["failed_gates"] = list(
        dict.fromkeys(
            _normalize_handoff_items(qa_packet_for_state.get("failed_gates"), max_items=20, max_len=180)
            + _normalize_handoff_items(qa_failed_gates, max_items=20, max_len=180)
        )
    )[:20]
    qa_packet_for_state["required_fixes"] = list(
        dict.fromkeys(
            _normalize_handoff_items(qa_packet_for_state.get("required_fixes"), max_items=20, max_len=220)
            + _normalize_handoff_items(qa_required_fixes, max_items=20, max_len=220)
        )
    )[:20]
    qa_packet_for_state["hard_failures"] = list(
        dict.fromkeys(
            _normalize_handoff_items(qa_packet_for_state.get("hard_failures"), max_items=15, max_len=180)
            + _normalize_handoff_items(qa_hard_failures, max_items=15, max_len=180)
        )
    )[:15]
    if qa_rejected or qa_packet_for_state.get("hard_failures"):
        qa_packet_for_state["status"] = "REJECTED"
    elif qa_has_packet and str(qa_packet_for_state.get("status") or "").upper() == "UNKNOWN":
        qa_packet_for_state["status"] = "APPROVE_WITH_WARNINGS"
    elif not qa_packet_for_state.get("status"):
        qa_packet_for_state["status"] = "UNKNOWN"

    reviewer_packet_for_state["failed_gates"] = list(
        dict.fromkeys(
            _normalize_handoff_items(reviewer_packet_for_state.get("failed_gates"), max_items=20, max_len=180)
            + reviewer_failed_from_result
        )
    )[:20]
    reviewer_packet_for_state["required_fixes"] = list(
        dict.fromkeys(
            _normalize_handoff_items(reviewer_packet_for_state.get("required_fixes"), max_items=20, max_len=220)
            + reviewer_required_from_result
        )
    )[:20]
    reviewer_packet_for_state["hard_failures"] = list(
        dict.fromkeys(
            _normalize_handoff_items(reviewer_packet_for_state.get("hard_failures"), max_items=15, max_len=180)
            + reviewer_hard_from_result
        )
    )[:15]
    if reviewer_rejected or reviewer_packet_for_state.get("hard_failures"):
        reviewer_packet_for_state["status"] = "REJECTED"
    elif reviewer_has_packet and str(reviewer_packet_for_state.get("status") or "").upper() == "UNKNOWN":
        reviewer_packet_for_state["status"] = "APPROVE_WITH_WARNINGS"
    elif not reviewer_packet_for_state.get("status"):
        reviewer_packet_for_state["status"] = "UNKNOWN"
    result_state = {
        "review_verdict": status,
        "review_feedback": review_feedback,
        "execution_feedback": feedback,
        "feedback_history": new_history,
        "output_contract_report": oc_report,
        "case_alignment_report": case_report,
        "case_alignment_history": case_history,
        "metrics_signature": metrics_signature,
        "weights_signature": weights_signature,
        "last_gate_context": gate_context,
        "compliance_iterations": compliance_iterations,
        "metric_iterations": metric_iterations,
        "compliance_passed": compliance_passed,
        "last_iteration_type": iteration_type,
        "data_adequacy_consecutive": adequacy_consecutive,
        "data_adequacy_threshold": adequacy_threshold,
        "data_adequacy_status": adequacy_status,
        "data_adequacy_report": data_adequacy_report,
        "primary_metric_snapshot": primary_metric_snapshot,
        "metric_history": metric_history,
        "hard_qa_gate_reject": hard_qa_gate_reject,
        "hard_qa_retry_count": hard_qa_retry_count,
        "iteration_handoff": iteration_handoff,
    }
    if metric_improvement_round_active:
        result_state["ml_improvement_review_mode"] = metric_round_review_mode
    if isinstance(gate_context.get("feedback_record"), dict):
        result_state["ml_feedback_record"] = gate_context.get("feedback_record")
    if merged_hard_failures:
        result_state["hard_failures"] = merged_hard_failures
    if code or qa_packet_for_state:
        result_state["qa_last_result"] = qa_packet_for_state
    if code or reviewer_packet_for_state:
        result_state["reviewer_last_result"] = reviewer_packet_for_state
    if retry_worth_it is not None:
        result_state["review_retry_worth_it"] = bool(retry_worth_it)
    if state.get("qa_budget_exceeded"):
        result_state["qa_budget_exceeded"] = True
    if status in ["APPROVED", "APPROVE_WITH_WARNINGS"]:
        result_state["last_successful_review_verdict"] = status
        result_state["last_successful_gate_context"] = gate_context
    if review_counters:
        result_state["budget_counters"] = review_counters
    # Preserve improvement suggestions from evaluator for the improvement loop
    if isinstance(eval_improvement_suggestions, dict):
        result_state["eval_improvement_suggestions"] = eval_improvement_suggestions

    # NOTE: results_advisor.generate_ml_advice block removed in favor of
    # actor-critic metric improvement orchestration (bootstrap/finalize nodes).

    results_insights: Dict[str, Any] = {}
    try:
        execution_profile = state.get("ml_execution_profile")
        if not isinstance(execution_profile, dict) or not execution_profile:
            execution_profile = _build_ml_execution_profile_for_prompt(
                state if isinstance(state, dict) else {},
                code=str(state.get("generated_code") or ""),
                ml_plan=state.get("ml_plan") if isinstance(state.get("ml_plan"), dict) else None,
            )
        strategy_spec = state.get("strategy_spec") or _load_json_safe("data/strategy_spec.json")
        objective_type = objective_type or (strategy_spec or {}).get("objective_type")
        if not objective_type:
            plan = state.get("execution_plan") or _load_json_safe("data/plan.json")
            if isinstance(plan, dict):
                objective_type = plan.get("objective_type")
        if not objective_type:
            evaluation_spec = state.get("evaluation_spec") or (state.get("execution_contract", {}) or {}).get("evaluation_spec")
            if isinstance(evaluation_spec, dict):
                objective_type = evaluation_spec.get("objective_type")
        normalized_review_status = _normalize_review_status(status)
        normalized_review_feedback = _normalize_review_feedback(feedback, normalized_review_status)
        insights_context = {
            "objective_type": objective_type,
            "artifact_index": state.get("artifact_index") or _load_json_any("data/produced_artifact_index.json"),
            "output_contract_report": oc_report,
            "review_feedback": normalized_review_feedback,
            "review_verdict": normalized_review_status,
            "metrics": metrics_report,
            "metric_history": metric_history,
            "primary_metric_snapshot": primary_metric_snapshot,
            "evaluation_spec": evaluation_spec if isinstance(evaluation_spec, dict) else None,
            "execution_contract": contract if isinstance(contract, dict) else None,
            "data_adequacy_report": data_adequacy_report,
            "iteration_policy": (contract or {}).get("iteration_policy", {}) if isinstance(contract, dict) else {},
            "strategy_spec": strategy_spec,
            "reporting_policy": contract.get("reporting_policy", {}) if isinstance(contract, dict) else {},
            "execution_profile": execution_profile,
        }
        insights = results_advisor.generate_insights(insights_context)
        if insights:
            if isinstance(insights, dict):
                results_insights = dict(insights)
            run_id = state.get("run_id")
            if run_id:
                log_agent_snapshot(
                    run_id,
                    "results_advisor",
                    prompt=getattr(results_advisor, "last_prompt", None),
                    response=getattr(results_advisor, "last_response", None) or insights,
                    context=insights_context,
                )
            try:
                os.makedirs("data", exist_ok=True)
                dump_json("data/insights.json", insights)
                existing_index = _load_json_any("data/produced_artifact_index.json")
                normalized_existing = existing_index if isinstance(existing_index, list) else []
                additions = _build_artifact_index(["data/insights.json"], None)
                merged_index = _merge_artifact_index_entries(normalized_existing, additions)
                dump_json("data/produced_artifact_index.json", merged_index)
                result_state["artifact_index"] = merged_index
                result_state["produced_artifact_index"] = merged_index
            except Exception as ins_err:
                print(f"Warning: failed to persist insights.json: {ins_err}")
    except Exception as ins_err:
        print(f"Warning: results advisor insights failed: {ins_err}")

    runtime_packet = {
        "status": "FAILED_RUNTIME" if runtime_failure_detected else "OK",
        "runtime_fix_terminal": runtime_terminal,
        "runtime_fix_count": int(state.get("runtime_fix_count", 0) or 0),
        "sandbox_failed": bool(state.get("sandbox_failed")),
        "execution_profile": state.get("ml_execution_profile")
        if isinstance(state.get("ml_execution_profile"), dict)
        else _build_ml_execution_profile_for_prompt(
            state if isinstance(state, dict) else {},
            code=str(state.get("generated_code") or ""),
            ml_plan=state.get("ml_plan") if isinstance(state.get("ml_plan"), dict) else None,
        ),
    }
    raw_eval_status = str(eval_result.get("status") or "").upper()
    eval_packet = {
        "status": status,
        "raw_status": raw_eval_status or status,
        "status_origin": "result_evaluator.final",
        "feedback": str(eval_result.get("feedback") or ""),
        "failed_gates": [str(g) for g in (eval_result.get("failed_gates") or []) if g],
        "required_fixes": [str(fx) for fx in (eval_result.get("required_fixes") or []) if fx],
        "retry_worth_it": bool(retry_worth_it) if retry_worth_it is not None else None,
        "evidence": _normalize_handoff_evidence(eval_result.get("evidence"), max_items=8),
    }
    reviewer_packet = _normalize_review_packet_for_state(
        review_result if isinstance(review_result, dict) else {},
        default_status="SKIPPED",
    )
    reviewer_packet["evidence"] = _normalize_handoff_evidence(
        (review_result or {}).get("evidence") if isinstance(review_result, dict) else [],
        max_items=8,
    )
    qa_packet = _normalize_review_packet_for_state(
        qa_result if isinstance(qa_result, dict) else {},
        default_status="SKIPPED",
    )
    qa_packet["evidence"] = _normalize_handoff_evidence(
        (qa_result or {}).get("evidence") if isinstance(qa_result, dict) else [],
        max_items=8,
    )
    if isinstance(qa_packet, dict) and not isinstance(qa_packet.get("evidence"), list):
        qa_packet = dict(qa_packet)
        qa_packet["evidence"] = _normalize_handoff_evidence(qa_result.get("evidence"), max_items=8)
    reviewer_packet, qa_packet, cross_review_notes = _harmonize_review_packets_with_final_eval(
        reviewer_packet,
        qa_packet,
        eval_raw_status=raw_eval_status or status,
        eval_feedback=str(eval_packet.get("feedback") or ""),
        eval_failed_gates=eval_packet.get("failed_gates") if isinstance(eval_packet.get("failed_gates"), list) else [],
        eval_required_fixes=eval_packet.get("required_fixes") if isinstance(eval_packet.get("required_fixes"), list) else [],
    )
    if cross_review_notes:
        try:
            new_history.extend([f"CROSS_REVIEW_ALIGNMENT: {note}" for note in cross_review_notes])
        except Exception:
            pass
    results_packet: Dict[str, Any] = {
        "status": "APPROVED" if status == "APPROVED" else "APPROVE_WITH_WARNINGS",
        "insights_available": bool(results_insights),
        "summary_lines": results_insights.get("summary_lines", []) if isinstance(results_insights, dict) else [],
        "risks": results_insights.get("risks", []) if isinstance(results_insights, dict) else [],
        "recommendations": results_insights.get("recommendations", []) if isinstance(results_insights, dict) else [],
        "iteration_recommendation": {},
    }
    if status == "NEEDS_IMPROVEMENT":
        results_packet["status"] = "NEEDS_IMPROVEMENT"
    elif status == "APPROVE_WITH_WARNINGS":
        results_packet["status"] = "APPROVE_WITH_WARNINGS"
    result_state["results_last_result"] = {
        "status": results_packet.get("status"),
        "iteration_recommendation": (
            results_packet.get("iteration_recommendation")
            if isinstance(results_packet.get("iteration_recommendation"), dict)
            else {}
        ),
        "failed_gates": [],
        "required_fixes": [],
        "hard_failures": [],
    }
    facts_state = dict(state or {})
    facts_state.update(result_state)
    review_board_facts = _build_review_board_facts(facts_state)
    review_stack = {
        "runtime": runtime_packet,
        "result_evaluator": eval_packet,
        "reviewer": reviewer_packet,
        "qa_reviewer": qa_packet,
        "results_advisor": results_packet,
        "metric_improvement_context": {
            "active": bool(metric_improvement_round_active),
            "review_mode": metric_round_review_mode if metric_improvement_round_active else None,
        },
        "iteration_handoff": iteration_handoff,
        "deterministic_facts": review_board_facts,
        "cross_review_alignment": {"notes": cross_review_notes},
        "final_pre_board": {
            "status": status,
            "feedback": feedback,
            "failed_gates": failed_gates,
            "required_fixes": required_fixes,
            "hard_failures": merged_hard_failures,
        },
    }
    try:
        os.makedirs("data", exist_ok=True)
        dump_json("data/ml_review_stack.json", review_stack)
        dump_json("data/iteration_handoff.json", iteration_handoff)
        existing_index = _load_json_any("data/produced_artifact_index.json")
        normalized_existing = existing_index if isinstance(existing_index, list) else []
        additions = _build_artifact_index(["data/ml_review_stack.json", "data/iteration_handoff.json"], None)
        merged_index = _merge_artifact_index_entries(normalized_existing, additions)
        dump_json("data/produced_artifact_index.json", merged_index)
        result_state["artifact_index"] = merged_index
        result_state["produced_artifact_index"] = merged_index
    except Exception as stack_err:
        print(f"Warning: failed to persist ml_review_stack.json: {stack_err}")
    result_state["ml_review_stack"] = review_stack
    result_state["review_board_facts"] = review_board_facts

    # Iteration memory (delta + objective + weights) for patch-mode guidance
    iteration_memory = list(state.get("ml_iteration_memory", []) or [])
    prev_summary = iteration_memory[-1] if iteration_memory else None
    diagnostics = _collect_iteration_diagnostics(state)
    summary = _build_iteration_memory(
        iter_id=iter_id,
        metrics_report=metrics_report,
        case_report=case_report,
        weights_report=_load_json_safe("data/weights.json"),
        code=code,
        prev_summary=prev_summary,
        advisor_note=result_state.get("ml_results_advice"),
        diagnostics=diagnostics,
    )
    if summary:
        iteration_memory.append(summary)
        iteration_memory = iteration_memory[-3:]
        try:
            os.makedirs(os.path.join("artifacts", "iterations"), exist_ok=True)
            summary_path = os.path.join("artifacts", "iterations", f"ml_iteration_summary_iter_{iter_id}.json")
            with open(summary_path, "w", encoding="utf-8") as f_sum:
                json.dump(summary, f_sum, indent=2, ensure_ascii=False)
        except Exception as mem_err:
            print(f"Warning: failed to persist ml_iteration_summary_iter_{iter_id}.json: {mem_err}")
    edit_block = _build_edit_instructions(summary)
    if edit_block:
        gate_context["edit_instructions"] = edit_block
    result_state["ml_iteration_memory"] = iteration_memory
    result_state["ml_iteration_memory_block"] = edit_block

    if run_id:
        outputs_state = _collect_outputs_state(_resolve_required_outputs(contract, state))
        reviewer_reasons = _normalize_reason_tags(review_feedback, failed_gates)
        qa_feedback_for_journal = str(qa_packet_for_state.get("feedback") or "")
        qa_failed_for_journal = [
            str(item)
            for item in (
                qa_packet_for_state.get("failed_gates")
                if isinstance(qa_packet_for_state.get("failed_gates"), list)
                else []
            )
            if str(item).strip()
        ]
        qa_reasons = _normalize_reason_tags(qa_feedback_for_journal, qa_failed_for_journal)
        next_actions = _suggest_next_actions([], outputs_state["missing"], reviewer_reasons, qa_reasons)
        entry = _build_ml_iteration_journal_entry(
            state,
            preflight_issues=[],
            runtime_error=None,
            outputs_present=outputs_state["present"],
            outputs_missing=outputs_state["missing"],
            reviewer_verdict=status,
            reviewer_reasons=reviewer_reasons,
            qa_verdict=str(qa_packet_for_state.get("status") or "UNKNOWN"),
            qa_reasons=qa_reasons,
            next_actions=next_actions,
            stage="review_complete",
            reviewer_packet=reviewer_packet_for_state,
            qa_packet=qa_packet_for_state,
            iteration_handoff=iteration_handoff,
        )
        written_ids = _append_ml_iteration_journal(
            run_id,
            entry,
            state.get("ml_journal_written_ids"),
        )
        result_state["ml_journal_written_ids"] = written_ids
        try:
            if status in {"APPROVED", "APPROVE_WITH_WARNINGS"}:
                memory_event = "attempt_success"
            elif qa_rejected or qa_failed_gates:
                memory_event = "qa_reject"
            else:
                memory_event = "attempt_reject"
            error_signature = ""
            if status == "NEEDS_IMPROVEMENT":
                if failed_gates:
                    error_signature = str(failed_gates[0])
                elif review_feedback:
                    error_signature = str(review_feedback).strip().splitlines()[0]
            phase = _classify_ml_memory_phase(failed_gates, review_feedback)
            changes_summary = str(gate_context.get("edit_instructions") or "")
            if not changes_summary:
                changes_summary = "; ".join([str(item) for item in (required_fixes or []) if str(item).strip()][:3])
            if not changes_summary:
                changes_summary = str(review_feedback or "")[:320]
            append_memory(
                run_id,
                {
                    "iter": int(iter_id),
                    "attempt": int(state.get("execution_attempt", 0) or 0),
                    "event": memory_event,
                    "error_signature": error_signature[:220],
                    "phase": phase,
                    "changes_summary": changes_summary[:400],
                    "metrics": primary_metric_snapshot if isinstance(primary_metric_snapshot, dict) else {},
                    "artifacts_present": outputs_state["present"][:30],
                },
            )
        except Exception:
            pass

    if status == "NEEDS_IMPROVEMENT":
        result_state["iteration_count"] = state.get("iteration_count", 0) + 1
    if run_id:
        log_run_event(run_id, "result_evaluator_complete", {"status": status})
    return result_state


def _packet_has_explicit_findings(packet: Any) -> bool | None:
    """
    Return:
    - True if packet explicitly indicates findings/failures
    - False if packet explicitly indicates no findings
    - None if packet is unavailable
    """
    if not isinstance(packet, dict):
        return None
    status = str(packet.get("status") or "").strip().upper()
    failed = [str(x) for x in (packet.get("failed_gates") or []) if x]
    hard = [str(x) for x in (packet.get("hard_failures") or []) if x]
    if failed or hard:
        return True
    if status in {"REJECTED", "NEEDS_IMPROVEMENT", "FAIL", "FAILED", "ERROR", "CRASH"}:
        return True
    return False


def _sanitize_board_failed_areas(
    failed_areas: List[str],
    board_context: Dict[str, Any],
) -> tuple[List[str], List[str]]:
    """
    Remove broad failed-area labels when reviewer packets do not support them.
    This keeps failed_areas aligned with deterministic packet evidence.
    """
    if not failed_areas:
        return [], []
    qa_findings = _packet_has_explicit_findings(board_context.get("qa_reviewer"))
    reviewer_findings = _packet_has_explicit_findings(board_context.get("reviewer"))
    results_findings = _packet_has_explicit_findings(board_context.get("results_advisor"))

    qa_aliases = {"qa_gates", "qa", "qa_reviewer"}
    reviewer_aliases = {"reviewer_alignment", "reviewer_gates", "reviewer", "code_alignment"}
    results_aliases = {"results_quality", "results_advisor"}

    kept: List[str] = []
    dropped: List[str] = []
    for area in [str(x) for x in failed_areas if x]:
        key = area.strip().lower()
        if key in qa_aliases and qa_findings is False:
            dropped.append(area)
            continue
        if key in reviewer_aliases and reviewer_findings is False:
            dropped.append(area)
            continue
        if key in results_aliases and results_findings is False:
            dropped.append(area)
            continue
        if area not in kept:
            kept.append(area)
    return kept, dropped


def _collect_board_deterministic_blockers(board_context: Dict[str, Any]) -> List[str]:
    blockers: List[str] = []
    if not isinstance(board_context, dict):
        return blockers

    def _add(value: Any) -> None:
        token = str(value or "").strip()
        if token and token not in blockers:
            blockers.append(token)

    runtime = board_context.get("runtime") if isinstance(board_context.get("runtime"), dict) else {}
    runtime_fix_terminal = bool(runtime.get("runtime_fix_terminal"))
    if str(runtime.get("status") or "").strip().upper() == "FAILED_RUNTIME" and not runtime_fix_terminal:
        _add("runtime_failed")
    if bool(runtime.get("sandbox_failed")) and not runtime_fix_terminal:
        _add("sandbox_failed")
    deterministic_facts = (
        board_context.get("deterministic_facts")
        if isinstance(board_context.get("deterministic_facts"), dict)
        else {}
    )
    output_contract = (
        deterministic_facts.get("output_contract")
        if isinstance(deterministic_facts.get("output_contract"), dict)
        else {}
    )
    if str(output_contract.get("overall_status") or "").strip().lower() == "error":
        _add("output_contract_error")
    for path in output_contract.get("missing_required_artifacts") or []:
        _add(f"missing_required_artifact:{path}")
    for issue in output_contract.get("schema_issues") or []:
        _add(f"output_schema_issue:{issue}")

    for key in ("result_evaluator", "reviewer", "qa_reviewer"):
        packet = board_context.get(key) if isinstance(board_context.get(key), dict) else {}
        status = str(packet.get("status") or "").strip().upper()
        status_blockers = {"REJECTED", "FAIL", "FAILED", "ERROR", "CRASH"}
        if key != "result_evaluator":
            status_blockers.add("NEEDS_IMPROVEMENT")
        if status in status_blockers:
            _add(f"{key}_status:{status}")
        for hard in packet.get("hard_failures") or []:
            _add(f"{key}_hard_failure:{hard}")
        for gate in packet.get("failed_gates") or []:
            if _looks_blocking_retry_signal(gate):
                _add(f"{key}_failed_gate:{gate}")
    return blockers


def run_review_board(state: AgentState) -> AgentState:
    print("--- [5.6] Review Board: Consolidating reviewer outputs ---")
    abort_state = _abort_if_requested(state, "review_board")
    if abort_state:
        return abort_state
    run_id = state.get("run_id")
    if run_id:
        log_run_event(run_id, "review_board_start", {})

    review_stack = state.get("ml_review_stack")
    if not isinstance(review_stack, dict) or not review_stack:
        review_stack = _load_json_safe("data/ml_review_stack.json") or {}
    if not isinstance(review_stack, dict):
        review_stack = {}
    if not review_stack:
        review_stack = {
            "runtime": {
                "status": "FAILED_RUNTIME" if _has_runtime_failure_marker(state.get("execution_output")) else "OK",
                "runtime_fix_terminal": bool(state.get("runtime_fix_terminal")),
                "runtime_fix_count": int(state.get("runtime_fix_count", 0) or 0),
            },
            "result_evaluator": {
                "status": state.get("review_verdict"),
                "feedback": state.get("review_feedback"),
                "failed_gates": (state.get("last_gate_context") or {}).get("failed_gates", []),
                "required_fixes": (state.get("last_gate_context") or {}).get("required_fixes", []),
            },
            "reviewer": state.get("reviewer_last_result") or {},
            "qa_reviewer": state.get("qa_last_result") or {},
            "results_advisor": {
                "status": "APPROVE_WITH_WARNINGS",
                "insights_available": bool(_load_json_safe("data/insights.json")),
            },
        }

    board_context = dict(review_stack)
    board_context["runtime"] = board_context.get("runtime") if isinstance(board_context.get("runtime"), dict) else {}
    runtime_block = dict(board_context.get("runtime") or {})
    runtime_block.setdefault("runtime_fix_terminal", bool(state.get("runtime_fix_terminal")))
    runtime_block.setdefault("runtime_fix_count", int(state.get("runtime_fix_count", 0) or 0))
    board_context["runtime"] = runtime_block
    deterministic_facts = board_context.get("deterministic_facts")
    if not isinstance(deterministic_facts, dict) or not deterministic_facts:
        deterministic_facts = _build_review_board_facts(state if isinstance(state, dict) else {})
    board_context["deterministic_facts"] = deterministic_facts
    board_context["progress_tracker"] = _build_review_progress_tracker(state if isinstance(state, dict) else {})
    board_context["review_verdict_before_board"] = state.get("review_verdict")
    board_context["review_feedback_before_board"] = state.get("review_feedback")

    # Add iteration_history for trend/plateau detection by the Review Board
    metric_history = state.get("metric_history") if isinstance(state.get("metric_history"), list) else []
    if metric_history:
        board_context["iteration_history"] = [
            {
                "iteration": int(h.get("iteration", i)),
                "primary_metric": h.get("primary_metric_value"),
                "metric_name": str(h.get("primary_metric_name") or ""),
                "status": str(h.get("status") or ""),
            }
            for i, h in enumerate(metric_history)
            if isinstance(h, dict)
        ][-10:]  # Keep last 10 iterations max

    verdict = review_board.adjudicate(board_context)
    if not isinstance(verdict, dict):
        verdict = {}
    board_status = _normalize_board_status(verdict.get("status"))
    final_status = _board_status_to_pipeline(board_status)
    board_summary = str(verdict.get("summary") or "").strip()
    failed_areas = [str(x) for x in (verdict.get("failed_areas") or []) if x]
    failed_areas, dropped_failed_areas = _sanitize_board_failed_areas(failed_areas, board_context)
    required_actions = [str(x) for x in (verdict.get("required_actions") or []) if x]
    evidence = verdict.get("evidence") if isinstance(verdict.get("evidence"), list) else []
    confidence = str(verdict.get("confidence") or "medium").lower()
    deterministic_blockers = _collect_board_deterministic_blockers(board_context)
    critical_failed_areas = [area for area in failed_areas if _looks_blocking_retry_signal(area)]
    runtime_terminal = bool(runtime_block.get("runtime_fix_terminal"))
    if runtime_terminal and critical_failed_areas:
        runtime_tokens = ("runtime", "traceback", "exception", "crash", "sandbox")
        critical_failed_areas = [
            area
            for area in critical_failed_areas
            if not any(token in str(area).strip().lower() for token in runtime_tokens)
        ]
    if critical_failed_areas and final_status in {"APPROVED", "APPROVE_WITH_WARNINGS"}:
        final_status = "NEEDS_IMPROVEMENT"
        board_note = (
            "Critical contract/business requirements are unresolved and require another iteration."
        )
        board_summary = f"{board_summary} {board_note}".strip() if board_summary else board_note
        critical_action = (
            "Resolve critical failed areas before approval: "
            + ", ".join(critical_failed_areas[:6])
        )
        if critical_action not in required_actions:
            required_actions.append(critical_action)
    if deterministic_blockers and final_status in {"APPROVED", "APPROVE_WITH_WARNINGS"}:
        final_status = "NEEDS_IMPROVEMENT"
        if "deterministic_blockers" not in failed_areas:
            failed_areas.append("deterministic_blockers")
        for blocker in deterministic_blockers[:10]:
            action = f"Resolve deterministic blocker before approval: {blocker}"
            if action not in required_actions:
                required_actions.append(action)
        board_note = (
            "Board verdict adjusted by deterministic evidence: unresolved runtime/QA/output blockers remain."
        )
        board_summary = f"{board_summary} {board_note}".strip() if board_summary else board_note
    current_feedback = str(state.get("review_feedback") or "")
    if board_summary:
        if current_feedback:
            current_feedback = f"{current_feedback}\nREVIEW_BOARD: {board_summary}"
        else:
            current_feedback = f"REVIEW_BOARD: {board_summary}"

    history = list(state.get("feedback_history", []) or [])
    if dropped_failed_areas:
        history.append(
            "REVIEW_BOARD_AREA_SANITIZE: dropped unsupported failed_areas="
            + ", ".join(dropped_failed_areas[:6])
        )
    if board_summary:
        history.append(f"REVIEW_BOARD[{board_status}]: {board_summary}")
    elif required_actions:
        history.append(f"REVIEW_BOARD[{board_status}]: required_actions={required_actions}")
    if critical_failed_areas and final_status == "NEEDS_IMPROVEMENT":
        history.append(
            "REVIEW_BOARD_POLICY: escalated to NEEDS_IMPROVEMENT due to critical failed_areas="
            + ", ".join(critical_failed_areas[:6])
        )
    if deterministic_blockers and final_status == "NEEDS_IMPROVEMENT":
        history.append(
            "REVIEW_BOARD_POLICY: escalated to NEEDS_IMPROVEMENT due to deterministic_blockers="
            + ", ".join(deterministic_blockers[:6])
        )
    gate_context = dict(state.get("last_gate_context") or {})
    current_failed = [str(g) for g in (gate_context.get("failed_gates") or []) if g]
    current_required = [str(g) for g in (gate_context.get("required_fixes") or []) if g]
    for area in failed_areas:
        if area not in current_failed:
            current_failed.append(area)
    for action in required_actions:
        if action not in current_required:
            current_required.append(action)
    if current_failed:
        gate_context["failed_gates"] = current_failed
    if current_required:
        gate_context["required_fixes"] = current_required
    gate_context["review_board"] = {
        "status": board_status,
        "summary": board_summary,
        "failed_areas": failed_areas,
        "required_actions": required_actions,
        "confidence": confidence,
    }
    board_feedback_record = _set_latest_feedback_record(
        state,
        agent="ml_engineer",
        source="review_board",
        status=final_status,
        iteration=int(state.get("iteration_count", 0) or 0),
        feedback=str(board_summary or ""),
        failed_gates=[str(x) for x in failed_areas if x],
        required_fixes=[str(x) for x in required_actions if x],
        hard_failures=[str(x) for x in (gate_context.get("hard_failures") or []) if x],
        runtime_error_tail=str((board_context.get("runtime") or {}).get("status") or ""),
        evidence=_normalize_handoff_evidence(evidence, max_items=8),
    )
    if board_feedback_record:
        gate_context["feedback_record"] = board_feedback_record
    if deterministic_blockers:
        board_hard_failures = [str(x) for x in (gate_context.get("hard_failures") or []) if x]
        for blocker in deterministic_blockers:
            if blocker not in board_hard_failures:
                board_hard_failures.append(blocker)
        gate_context["hard_failures"] = board_hard_failures[:20]
    if final_status == "NEEDS_IMPROVEMENT":
        blocking_retry = _is_blocking_retry_reason(
            state if isinstance(state, dict) else {},
            gate_context=gate_context,
            board_failed_areas=failed_areas,
            board_required_actions=required_actions,
        )
        if not blocking_retry:
            final_status = "APPROVE_WITH_WARNINGS"
            board_note = (
                "Review board marked NEEDS_IMPROVEMENT for non-blocking advisory issues "
                "(metrics/optimization). Retry skipped by policy."
            )
            board_summary = f"{board_summary} {board_note}".strip() if board_summary else board_note
            history.append("REVIEW_BOARD_POLICY: Non-blocking issues downgraded to APPROVE_WITH_WARNINGS.")
            current_feedback = (
                f"{current_feedback}\nREVIEW_BOARD_POLICY: advisory-only, no retry triggered."
                if current_feedback
                else "REVIEW_BOARD_POLICY: advisory-only, no retry triggered."
            )
            gate_context["iteration_type"] = "metric"
        else:
            gate_context["iteration_type"] = "compliance"

    iteration_handoff = state.get("iteration_handoff")
    if not isinstance(iteration_handoff, dict):
        iteration_handoff = {}
    handoff_quality = (
        dict(iteration_handoff.get("quality_focus"))
        if isinstance(iteration_handoff.get("quality_focus"), dict)
        else {}
    )
    handoff_quality["status"] = final_status
    if failed_areas:
        merged_failed = _normalize_handoff_items(handoff_quality.get("failed_gates"), max_items=15)
        for area in _normalize_handoff_items(failed_areas, max_items=10):
            if area not in merged_failed:
                merged_failed.append(area)
        handoff_quality["failed_gates"] = merged_failed[:15]
    handoff_quality["required_fixes"] = _normalize_handoff_items(current_required, max_items=15, max_len=500)
    handoff_quality["hard_failures"] = _normalize_handoff_items(
        gate_context.get("hard_failures") or handoff_quality.get("hard_failures"),
        max_items=10,
        max_len=200,
    )
    handoff_quality["evidence"] = _normalize_handoff_evidence(
        evidence or handoff_quality.get("evidence"),
        max_items=10,
    )
    patch_objectives = _normalize_handoff_items(iteration_handoff.get("patch_objectives"), max_items=8, max_len=420)
    for action in _normalize_handoff_items(required_actions, max_items=8, max_len=500):
        if action not in patch_objectives:
            patch_objectives.append(action)
        if len(patch_objectives) >= 8:
            break
    if final_status == "NEEDS_IMPROVEMENT" and not patch_objectives:
        patch_objectives = ["Apply review_board required actions with minimal edits to the previous script."]
    iteration_handoff["source"] = "review_board"
    iteration_handoff["board_focus"] = {
        "status": board_status,
        "summary": board_summary,
        "failed_areas": _normalize_handoff_items(failed_areas, max_items=12, max_len=200),
        "required_actions": _normalize_handoff_items(required_actions, max_items=12, max_len=500),
        "confidence": confidence,
        "evidence": _normalize_handoff_evidence(evidence, max_items=8),
    }
    iteration_handoff["quality_focus"] = handoff_quality
    iteration_handoff["patch_objectives"] = patch_objectives

    board_payload = {
        "status": board_status,
        "final_review_verdict": final_status,
        "summary": board_summary,
        "failed_areas": failed_areas,
        "deterministic_blockers": deterministic_blockers,
        "required_actions": required_actions,
        "confidence": confidence,
        "evidence": evidence,
        "deterministic_facts": deterministic_facts,
        "runtime_fix_terminal": bool(state.get("runtime_fix_terminal")),
        "review_verdict_before_board": state.get("review_verdict"),
    }
    merged_index = None
    try:
        os.makedirs("data", exist_ok=True)
        dump_json("data/review_board_verdict.json", board_payload)
        existing_index = _load_json_any("data/produced_artifact_index.json")
        normalized_existing = existing_index if isinstance(existing_index, list) else []
        additions = _build_artifact_index(["data/review_board_verdict.json"], None)
        merged_index = _merge_artifact_index_entries(normalized_existing, additions)
        dump_json("data/produced_artifact_index.json", merged_index)
    except Exception as board_err:
        print(f"Warning: failed to persist review_board_verdict.json: {board_err}")

    if run_id:
        try:
            log_agent_snapshot(
                run_id,
                "review_board",
                prompt=getattr(review_board, "last_prompt", None),
                response=getattr(review_board, "last_response", None) or verdict,
                context=board_context,
                verdicts=board_payload,
            )
        except Exception:
            pass
        log_run_event(
            run_id,
            "review_board_complete",
            {"status": board_status, "final_review_verdict": final_status},
        )

    result = {
        "review_board_verdict": board_payload,
        "review_board_facts": deterministic_facts,
        "review_verdict": final_status,
        "review_feedback": current_feedback,
        "feedback_history": history,
        "last_gate_context": gate_context,
        "iteration_handoff": iteration_handoff,
    }
    if board_feedback_record:
        result["ml_feedback_record"] = board_feedback_record
    # Iteration counter guard:
    # - run_result_evaluator already increments iteration_count when it returns NEEDS_IMPROVEMENT.
    # - if review_board escalates a non-NEEDS_IMPROVEMENT status to NEEDS_IMPROVEMENT,
    #   increment here to avoid retry loops on "Iteration 1".
    prev_status = str(state.get("review_verdict") or "").strip().upper()
    if final_status == "NEEDS_IMPROVEMENT" and prev_status != "NEEDS_IMPROVEMENT":
        result["iteration_count"] = int(state.get("iteration_count", 0) or 0) + 1
    if final_status in {"APPROVED", "APPROVE_WITH_WARNINGS"}:
        result["last_successful_review_verdict"] = final_status
        result["last_successful_gate_context"] = gate_context
    if merged_index:
        result["artifact_index"] = merged_index
        result["produced_artifact_index"] = merged_index

    # Consolidate improvement suggestions from reviewer and evaluator packets
    # and set reviewer_no_improvement_room flag for the improvement loop.
    _reviewer_packet = board_context.get("reviewer") if isinstance(board_context.get("reviewer"), dict) else {}
    _eval_packet = board_context.get("result_evaluator") if isinstance(board_context.get("result_evaluator"), dict) else {}
    _reviewer_imp = _reviewer_packet.get("improvement_suggestions") if isinstance(_reviewer_packet.get("improvement_suggestions"), dict) else {}
    _eval_imp = state.get("eval_improvement_suggestions") if isinstance(state.get("eval_improvement_suggestions"), dict) else {}
    # Merge techniques from both sources (deduplicated)
    _all_techniques: List[str] = []
    for src_imp in (_reviewer_imp, _eval_imp):
        for tech in (src_imp.get("techniques") if isinstance(src_imp.get("techniques"), list) else []):
            tech_str = str(tech).strip()
            if tech_str and tech_str not in _all_techniques:
                _all_techniques.append(tech_str)
    # Determine if there's room for improvement
    _reviewer_no_room = bool(_reviewer_imp.get("no_further_improvement"))
    _eval_no_room = bool(_eval_imp.get("no_further_improvement"))
    _no_improvement_room = _reviewer_no_room and _eval_no_room
    # Only set no_room if BOTH agree AND there are no techniques suggested
    if _all_techniques:
        _no_improvement_room = False
    result["reviewer_no_improvement_room"] = _no_improvement_room
    result["consolidated_improvement_suggestions"] = {
        "techniques": _all_techniques[:8],
        "no_further_improvement": _no_improvement_room,
        "from_reviewer": bool(_reviewer_imp),
        "from_evaluator": bool(_eval_imp),
    }
    if _all_techniques:
        print(f"IMPROVEMENT_SUGGESTIONS: {len(_all_techniques)} techniques consolidated from reviewer/evaluator")
    if _no_improvement_room:
        print("IMPROVEMENT_SUGGESTIONS: Both reviewer and evaluator agree no further improvement possible")

    return result


def _detect_target_nan_error(output: str) -> bool:
    if not output:
        return False
    lower = str(output).lower()
    if "input y contains nan" in lower or "y contains nan" in lower:
        return True
    if re.search(r"valueerror.*y.*nan", lower):
        return True
    return False


def check_execution_status(state: AgentState):
    # Check for critical failures first
    if state.get("error_message") and "Security Block" in state["error_message"]:
        return "failed"

    output = state.get("execution_output", "")
    attempt = state.get("execution_attempt", 1)
    runtime_fix_count = int(state.get("runtime_fix_count", 0))
    skipped_reason = state.get("ml_skipped_reason")

    # Traceback check (Runtime Error)
    has_error = (
        "Traceback (most recent call last)" in output
        or "HEAVY_RUNNER_ERROR" in output
        or "Sandbox Execution Failed" in output
        or "peer closed connection" in output
        or "incomplete chunked read" in output
        or "Response 404" in output
        or state.get("sandbox_failed")
    )
    determinism_error = "DETERMINISTIC_TARGET_RELATION" in output
    undefined_precheck = "STATIC_PRECHECK_UNDEFINED" in output
    sandbox_error = (
        state.get("sandbox_failed")
        or "Sandbox Execution Failed" in output
        or "peer closed connection" in output
        or "incomplete chunked read" in output
        or "Response 404" in output
    )

    if determinism_error or skipped_reason == "DETERMINISTIC_TARGET_RELATION":
        return "evaluate"

    if undefined_precheck:
        return "retry_fix"

    if sandbox_error:
        retry_count = int(state.get("sandbox_retry_count", 0))
        max_retries = int(state.get("max_sandbox_retries", 2))
        if retry_count < max_retries:
            return "retry_sandbox"
        print(
            f"Sandbox failure detected. Max retries reached ({retry_count}/{max_retries}). "
            "Escalating to evaluator for reviewer/QA-guided retry."
        )
        return "evaluate"

    if has_error:
        max_runtime_fixes = int(state.get("max_runtime_fix_attempts", 3))
        next_attempt = runtime_fix_count + 1
        if runtime_fix_count < max_runtime_fixes:
            print(f"Runtime Error detected (Attempt {next_attempt}/{max_runtime_fixes}). Preparing runtime fix.")
            return "retry_fix"
        print(f"Runtime Error detected (Attempt {runtime_fix_count}/{max_runtime_fixes}). Max runtime fixes reached.")
        return "failed_runtime"

    return "evaluate"

def prepare_runtime_fix(state: AgentState) -> AgentState:
    print("--- [!] Preparing Runtime Fix Context ---")
    output = state.get("execution_output", "")
    base_fix_count = int(state.get("runtime_fix_count", 0))
    terminal_fix = bool(state.get("runtime_fix_terminal"))
    fix_attempt = base_fix_count if terminal_fix else base_fix_count + 1
    max_runtime_fixes = int(state.get("max_runtime_fix_attempts", 3))

    error_context = {
        "source": "Execution Runtime",
        "status": "REJECTED",
        "feedback": f"RUNTIME ERROR trace:\n{output[-2000:]}\n\nFIX THIS CRASH.",
        "failed_gates": ["Runtime Stability"],
        "required_fixes": ["Fix the exception."]
    }

    ml_override = state.get("ml_engineer_audit_override", "")
    feedback_history = list(state.get("feedback_history", []))
    if _detect_target_nan_error(output):
        target_nan_feedback = (
            "TARGET_NAN_DETECTED: Target contains NaN in part of the dataset. "
            "Use dataset_semantics.json to identify labeled rows (target not null) "
            "for training, and score the remaining rows."
        )
        ml_override = _merge_de_audit_override(ml_override, target_nan_feedback)
        error_context["required_fixes"].append(
            "Handle partial labels: train on rows where target is not null; score all rows."
        )
        feedback_history.append(target_nan_feedback)
    try:
        error_details = state.get("last_runtime_error_tail") or output
        code = state.get("generated_code") or state.get("last_generated_code") or ""
        expl_ctx = state.get("ml_context_snapshot") or {}
        expl_text = failure_explainer.explain_ml_failure(
            code=code,
            error_details=str(error_details),
            context=expl_ctx,
        )
        if expl_text:
            payload = "ML_FAILURE_EXPLANATION:\n" + expl_text.strip()
            payload += "\nRUNTIME_ERROR_TAIL:\n" + str(error_details)[-2000:]
            ml_override = _merge_de_audit_override(ml_override, payload)
            expl_lines = [line.strip() for line in expl_text.splitlines() if line.strip()]
            if expl_lines:
                fix_summary = "ML_FAILURE_EXPLANATION: " + " | ".join(expl_lines)
                error_context["required_fixes"].append(fix_summary)
            try:
                os.makedirs("artifacts", exist_ok=True)
                with open(os.path.join("artifacts", "ml_engineer_failure_explainer.txt"), "w", encoding="utf-8") as f_exp:
                    f_exp.write(expl_text.strip())
            except Exception as exp_err:
                print(f"Warning: failed to persist ml_engineer_failure_explainer.txt: {exp_err}")
    except Exception as expl_err:
        print(f"Warning: ML failure explainer failed during runtime fix: {expl_err}")

    runtime_tail_for_hints = str(state.get("last_runtime_error_tail") or output or "")
    runtime_feedback = str(error_context.get("feedback") or "")
    enriched_feedback, repair_hints = append_repair_hints(
        feedback=runtime_feedback,
        error_text=runtime_tail_for_hints + "\n" + runtime_feedback,
    )
    error_context["feedback"] = enriched_feedback
    if repair_hints:
        error_context["repair_hints"] = repair_hints

    run_id = state.get("run_id")
    if run_id:
        contract = state.get("execution_contract", {}) or {}
        outputs_state = _collect_outputs_state(_resolve_required_outputs(contract, state))
        reviewer_feedback = state.get("review_feedback") or ""
        reviewer_reasons = _normalize_reason_tags(reviewer_feedback, [])
        next_actions = _suggest_next_actions([], outputs_state["missing"], reviewer_reasons, [])
        runtime_summary = _summarize_runtime_error(output)
        entry = _build_ml_iteration_journal_entry(
            state,
            preflight_issues=[],
            runtime_error=runtime_summary,
            outputs_present=outputs_state["present"],
            outputs_missing=outputs_state["missing"],
            reviewer_verdict=state.get("review_verdict"),
            reviewer_reasons=reviewer_reasons,
            qa_verdict=None,
            qa_reasons=[],
            next_actions=next_actions,
            stage="runtime_fix",
        )
        written_ids = _append_ml_iteration_journal(
            run_id,
            entry,
            state.get("ml_journal_written_ids"),
        )
        try:
            phase = _classify_ml_memory_phase(["runtime_failure"], output)
            error_signature = ""
            if isinstance(runtime_summary, dict):
                error_signature = str(runtime_summary.get("message") or runtime_summary.get("type") or "")
            if not error_signature:
                error_signature = str(output or "").strip().splitlines()[-1] if str(output or "").strip() else "runtime_failure"
            append_memory(
                run_id,
                {
                    "iter": int(state.get("iteration_count", 0) or 0) + 1,
                    "attempt": int(state.get("execution_attempt", 0) or 0) + 1,
                    "event": "runtime_error",
                    "error_signature": error_signature[:220],
                    "phase": phase,
                    "changes_summary": "Runtime crash detected; apply minimal targeted fix.",
                    "metrics": state.get("primary_metric_snapshot") if isinstance(state.get("primary_metric_snapshot"), dict) else {},
                    "artifacts_present": outputs_state["present"][:20],
                },
            )
        except Exception:
            pass
    else:
        written_ids = state.get("ml_journal_written_ids")

    return {
        "last_gate_context": error_context,
         # We add error to history so it persists
        "feedback_history": feedback_history + [f"RUNTIME ERROR (Attempt {fix_attempt}/{max_runtime_fixes}):\n{output[-500:]}"],
        "ml_engineer_audit_override": ml_override,
        "runtime_fix_count": base_fix_count if terminal_fix else fix_attempt,
        "ml_journal_written_ids": written_ids,
    }

def finalize_runtime_failure(state: AgentState) -> AgentState:
    print("--- [!] Final runtime failure: capturing failure explanation ---")
    state_with_terminal = dict(state)
    state_with_terminal["runtime_fix_terminal"] = True
    result = prepare_runtime_fix(state_with_terminal)
    result["runtime_fix_terminal"] = True
    return result


def _metric_improvement_policy(contract: Dict[str, Any] | None) -> Tuple[int, float, int]:
    policy = contract.get("iteration_policy") if isinstance(contract, dict) else {}
    if not isinstance(policy, dict):
        policy = {}
    rounds_raw = policy.get("metric_improvement_rounds", os.getenv("METRIC_IMPROVEMENT_MAX_ROUNDS", 4))
    min_delta_raw = policy.get("metric_min_delta", 0.0005)
    patience_raw = policy.get("metric_improvement_patience", os.getenv("METRIC_IMPROVEMENT_PATIENCE", 2))
    try:
        rounds = int(rounds_raw)
    except Exception:
        rounds = 4
    try:
        min_delta = float(min_delta_raw)
    except Exception:
        min_delta = 0.0005
    try:
        patience = int(patience_raw)
    except Exception:
        patience = 2
    if rounds < 0:
        rounds = 0
    if rounds > 12:
        rounds = 12
    if min_delta < 0:
        min_delta = 0.0
    if patience < 1:
        patience = 1
    if rounds > 0:
        patience = min(max(1, patience), rounds)
    return rounds, min_delta, patience


def _normalize_metric_round_review_mode(raw: Any) -> str:
    token = str(raw or "").strip().lower()
    if token in {"full", "hybrid_guarded", "advisor_only"}:
        return token
    return "hybrid_guarded"


def _resolve_metric_round_review_mode(contract: Dict[str, Any] | None) -> str:
    policy = contract.get("iteration_policy") if isinstance(contract, dict) else {}
    if not isinstance(policy, dict):
        policy = {}
    contract_mode = policy.get("metric_round_review_mode")
    if contract_mode is not None and str(contract_mode).strip():
        return _normalize_metric_round_review_mode(contract_mode)
    return _normalize_metric_round_review_mode(os.getenv("METRIC_ROUND_REVIEW_MODE", "hybrid_guarded"))


def _is_approved_review_status(value: Any) -> bool:
    normalized = _normalize_review_status(str(value or ""))
    return normalized in {"APPROVED", "APPROVE_WITH_WARNINGS"}


def _extract_review_status_from_packet(packet: Any) -> str | None:
    if not isinstance(packet, dict):
        return None
    raw = packet.get("status")
    if raw is None:
        return None
    normalized = _normalize_review_status(str(raw or ""))
    if normalized == "UNKNOWN":
        return None
    return normalized


def _resolve_baseline_reviewer_status_pair(state: Dict[str, Any]) -> Tuple[str | None, str | None, str]:
    if not isinstance(state, dict):
        return None, None, "unavailable"
    sources: List[Tuple[str, Any, Any]] = [
        (
            "state.last_results",
            state.get("reviewer_last_result"),
            state.get("qa_last_result"),
        ),
    ]
    review_stack = state.get("ml_review_stack")
    if isinstance(review_stack, dict):
        sources.append(
            (
                "state.ml_review_stack",
                review_stack.get("reviewer"),
                review_stack.get("qa_reviewer"),
            )
        )
    for source, reviewer_packet, qa_packet in sources:
        reviewer_status = _extract_review_status_from_packet(reviewer_packet)
        qa_status = _extract_review_status_from_packet(qa_packet)
        if reviewer_status and qa_status:
            return reviewer_status, qa_status, source
    return None, None, "unavailable"


def _is_augmentation_technique_name(value: Any) -> bool:
    token = re.sub(r"[^a-z0-9]+", "_", str(value or "").strip().lower()).strip("_")
    if not token:
        return False
    direct = {
        "data_augmentation",
        "augmentation",
        "oversampling",
        "undersampling",
        "resampling",
        "bootstrap_augmentation",
        "class_balancing",
        "synthetic_minority_oversampling",
    }
    if token in direct:
        return True
    fuzzy = ["augment", "oversampl", "undersampl", "resampl", "synthetic", "bootstrap", "class_balanc"]
    return any(item in token for item in fuzzy)


def _extract_hypothesis_technique(packet: Any) -> str:
    if not isinstance(packet, dict):
        return ""
    hypothesis = packet.get("hypothesis")
    if isinstance(hypothesis, dict):
        technique = hypothesis.get("technique")
        if isinstance(technique, str) and technique.strip():
            return technique.strip()
    direct = packet.get("technique")
    if isinstance(direct, str) and direct.strip():
        return direct.strip()
    return ""


def _resolve_metric_round_hypothesis_packet(
    state: Dict[str, Any],
    iteration_handoff: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    if not isinstance(state, dict):
        return {}
    handoff = iteration_handoff if isinstance(iteration_handoff, dict) else (
        state.get("iteration_handoff") if isinstance(state.get("iteration_handoff"), dict) else {}
    )
    packet_candidates: List[Any] = [
        state.get("ml_improvement_hypothesis_packet"),
        handoff.get("hypothesis_packet") if isinstance(handoff, dict) else None,
        handoff.get("iteration_hypothesis_packet") if isinstance(handoff, dict) else None,
        state.get("last_gate_context", {}).get("iteration_hypothesis_packet")
        if isinstance(state.get("last_gate_context"), dict)
        else None,
    ]
    for packet in packet_candidates:
        if isinstance(packet, dict) and packet:
            return packet
    return {}


def _resolve_metric_round_augmentation_requested(
    state: Dict[str, Any],
    contract: Dict[str, Any] | None = None,
) -> bool:
    if not isinstance(state, dict):
        return False
    hypothesis_packet = _resolve_metric_round_hypothesis_packet(state)
    if _is_augmentation_technique_name(_extract_hypothesis_technique(hypothesis_packet)):
        return True

    source_contract = contract if isinstance(contract, dict) else (
        state.get("execution_contract") if isinstance(state.get("execution_contract"), dict) else {}
    )
    fe_plan = source_contract.get("feature_engineering_plan") if isinstance(source_contract, dict) else {}
    if isinstance(fe_plan, dict):
        techniques = fe_plan.get("techniques")
        if isinstance(techniques, list):
            for item in techniques:
                if isinstance(item, dict):
                    technique = item.get("technique") or item.get("name")
                else:
                    technique = item
                if _is_augmentation_technique_name(technique):
                    return True
    return False


def _has_real_baseline_reviewer_approval(state: Dict[str, Any]) -> bool:
    if not isinstance(state, dict):
        return False
    reviewer_status, qa_status, _source = _resolve_baseline_reviewer_status_pair(state)
    if not reviewer_status or not qa_status:
        return False
    return _is_approved_review_status(reviewer_status) and _is_approved_review_status(qa_status)


def _metric_improvement_skip_reason(state: Dict[str, Any], contract: Dict[str, Any]) -> str | None:
    if not isinstance(state, dict) or not isinstance(contract, dict):
        return "invalid_state_or_contract"
    if not _is_approved_review_status(state.get("review_verdict")):
        return "review_verdict_not_approved"
    if not _has_real_baseline_reviewer_approval(state):
        return "baseline_reviewer_pair_not_approved"
    if bool(state.get("execution_error")):
        return "execution_error_present"
    if bool(state.get("sandbox_failed")):
        return "sandbox_failed_present"
    if bool(state.get("ml_improvement_loop_complete")):
        return "loop_already_complete"
    if bool(state.get("ml_improvement_attempted")):
        return "improvement_already_attempted"
    if bool(state.get("ml_improvement_round_active")):
        return "improvement_round_already_active"
    if _is_data_limited_mode_active(state, contract):
        return "data_limited_mode_active"
    rounds, _, _ = _metric_improvement_policy(contract)
    if rounds <= 0:
        return "metric_rounds_disabled"
    done = int(state.get("ml_improvement_round_count", 0) or 0)
    if done >= rounds:
        return "metric_round_budget_exhausted"
    return None


def _build_steward_feedback_for_improvement(state: Dict[str, Any]) -> str:
    if not isinstance(state, dict):
        return ""
    quality = state.get("steward_context_quality") if isinstance(state.get("steward_context_quality"), dict) else {}
    ready = bool(state.get("steward_context_ready"))
    reasons = quality.get("reasons") if isinstance(quality.get("reasons"), list) else []
    warnings = quality.get("warnings") if isinstance(quality.get("warnings"), list) else []
    semantic_summary = _truncate_handoff_text(
        str(state.get("dataset_semantics_summary") or ""),
        max_len=260,
    )
    summary = _truncate_handoff_text(str(state.get("data_summary") or ""), max_len=260)
    parts: List[str] = []
    if ready:
        parts.append("steward_context_ready=true")
    else:
        parts.append("steward_context_ready=false")
    if reasons:
        parts.append("reasons=" + ", ".join([str(item) for item in reasons[:3]]))
    if warnings:
        parts.append("warnings=" + ", ".join([str(item) for item in warnings[:2]]))
    if semantic_summary:
        parts.append("dataset_semantics=" + semantic_summary)
    elif summary:
        parts.append("summary=" + summary)
    return " | ".join([str(item) for item in parts if str(item).strip()])


def _build_results_advisor_feedback_for_improvement(
    state: Dict[str, Any],
    critique_packet: Dict[str, Any] | None = None,
) -> str:
    if not isinstance(state, dict):
        return ""
    review_stack = state.get("ml_review_stack") if isinstance(state.get("ml_review_stack"), dict) else {}
    advisor_packet = review_stack.get("results_advisor") if isinstance(review_stack.get("results_advisor"), dict) else {}
    summary_lines = advisor_packet.get("summary_lines") if isinstance(advisor_packet.get("summary_lines"), list) else []
    recommendations = advisor_packet.get("recommendations") if isinstance(advisor_packet.get("recommendations"), list) else []
    risks = advisor_packet.get("risks") if isinstance(advisor_packet.get("risks"), list) else []
    review_feedback = _truncate_handoff_text(str(state.get("review_feedback") or ""), max_len=220)
    critique_summary = ""
    if isinstance(critique_packet, dict):
        critique_summary = _truncate_handoff_text(str(critique_packet.get("analysis_summary") or ""), max_len=220)

    lines: List[str] = []
    for item in summary_lines[:2]:
        token = str(item or "").strip()
        if token:
            lines.append(token)
    if critique_summary:
        lines.append("critique=" + critique_summary)
    if recommendations:
        lines.append("recommendation=" + str(recommendations[0]))
    if risks:
        lines.append("risk=" + str(risks[0]))
    if not lines and review_feedback:
        lines.append(review_feedback)
    return " | ".join(lines[:3])


def _coerce_review_packet_to_nonblocking(packet: Dict[str, Any], actor: str) -> Dict[str, Any]:
    patched = dict(packet) if isinstance(packet, dict) else {}
    original_status = str(patched.get("status") or "").strip().upper()
    if original_status not in {"APPROVED", "APPROVE_WITH_WARNINGS"}:
        patched["status"] = "APPROVE_WITH_WARNINGS"
    elif not original_status:
        patched["status"] = "APPROVE_WITH_WARNINGS"
    patched["failed_gates"] = []
    patched["required_fixes"] = []
    patched["hard_failures"] = []
    feedback = str(patched.get("feedback") or "").strip()
    note = (
        "METRIC_IMPROVEMENT_REVIEW_MODE: "
        + str(actor or "reviewer")
        + " findings are advisory-only in this round."
    )
    patched["feedback"] = f"{feedback}\n{note}".strip() if feedback else note
    return patched


def _collect_active_gate_names(contract: Dict[str, Any]) -> List[str]:
    active: List[str] = []
    for gate in (get_qa_gates(contract) or []):
        if isinstance(gate, dict) and gate.get("name"):
            active.append(str(gate.get("name")))
    for gate in (get_reviewer_gates(contract) or []):
        if isinstance(gate, dict) and gate.get("name"):
            active.append(str(gate.get("name")))
    return list(dict.fromkeys(active))


def _is_metric_round_advisory_review_mode(state: Dict[str, Any], contract: Dict[str, Any] | None = None) -> bool:
    if not isinstance(state, dict):
        return False
    mode = str(
        state.get("ml_improvement_review_mode")
        or _resolve_metric_round_review_mode(contract if isinstance(contract, dict) else {})
    ).strip().lower()
    return mode in {"hybrid_guarded", "advisor_only"}


def _metric_round_has_deterministic_blockers(
    state: Dict[str, Any],
    gate_context: Dict[str, Any] | None = None,
    *,
    include_review_signals: bool = True,
) -> bool:
    if not isinstance(state, dict):
        return True
    if bool(state.get("runtime_fix_terminal")) or bool(state.get("sandbox_failed")):
        return True
    if _has_runtime_failure_marker(state.get("execution_output")):
        return True

    oc_report = state.get("output_contract_report")
    if isinstance(oc_report, dict):
        if str(oc_report.get("overall_status") or "").strip().lower() == "error":
            return True
        if isinstance(oc_report.get("missing"), list) and any(str(x).strip() for x in oc_report.get("missing", [])):
            return True
        artifact_report = oc_report.get("artifact_requirements_report")
        if isinstance(artifact_report, dict):
            if str(artifact_report.get("status") or "").strip().lower() == "error":
                return True

    board_payload = state.get("review_board_verdict")
    if isinstance(board_payload, dict):
        blockers = [str(x) for x in (board_payload.get("deterministic_blockers") or []) if x]
        if blockers:
            return True

    if include_review_signals:
        current_gate = gate_context if isinstance(gate_context, dict) else (
            state.get("last_gate_context") if isinstance(state.get("last_gate_context"), dict) else {}
        )
        hard_failures = [str(x) for x in (current_gate.get("hard_failures") or []) if x]
        if hard_failures:
            return True
        for gate in [str(x) for x in (current_gate.get("failed_gates") or []) if x]:
            if _looks_blocking_retry_signal(gate):
                return True
    return False


def _is_data_limited_mode_active(state: Dict[str, Any], contract: Dict[str, Any]) -> bool:
    data_limited = contract.get("data_limited_mode") if isinstance(contract, dict) else {}
    if isinstance(data_limited, bool):
        return bool(data_limited)
    if isinstance(data_limited, dict):
        if bool(data_limited.get("is_active")):
            return True
        status = str(data_limited.get("status") or "").strip().lower()
        if status in {"data_limited", "insufficient_signal"}:
            return True
    report = state.get("data_adequacy_report")
    if isinstance(report, dict):
        status = str(report.get("status") or "").strip().lower()
        if status in {"data_limited", "insufficient_signal"}:
            return True
    return False


def _should_run_metric_improvement_round(state: Dict[str, Any], contract: Dict[str, Any]) -> bool:
    return _metric_improvement_skip_reason(state, contract) is None


def _flatten_numeric_metrics_for_improvement(payload: Any, prefix: str = "") -> List[Tuple[str, float]]:
    items: List[Tuple[str, float]] = []
    if isinstance(payload, dict):
        for key, value in payload.items():
            next_key = f"{prefix}.{key}" if prefix else str(key)
            if isinstance(value, (int, float)):
                items.append((next_key, float(value)))
            elif isinstance(value, dict):
                items.extend(_flatten_numeric_metrics_for_improvement(value, next_key))
    return items


def _extract_primary_metric(metrics_json: Dict[str, Any], metric_name: str) -> Optional[float]:
    if not isinstance(metrics_json, dict):
        return None
    metric = str(metric_name or "").strip()
    preferred_keys: List[str] = []
    if metric:
        preferred_keys.extend(
            [
                metric,
                f"cv_{metric}",
                f"{metric}_mean",
                f"mean_{metric}",
                f"primary_{metric}",
            ]
        )
    preferred_keys.extend(["primary_metric_value", "metric_value", "score", "value", "cv_mean"])

    flat = _flatten_numeric_metrics_for_improvement(metrics_json)

    def _norm(text: str) -> str:
        return re.sub(r"[^0-9a-zA-Z]+", "", str(text or "").lower())

    preferred_norm = [_norm(key) for key in preferred_keys if key]
    for key, value in flat:
        key_norm = _norm(key)
        if any(token and token == key_norm for token in preferred_norm):
            return float(value)
    for key, value in flat:
        key_norm = _norm(key)
        if any(token and token in key_norm for token in preferred_norm):
            return float(value)
    return None


def _is_improvement(
    baseline_val: Optional[float],
    improved_val: Optional[float],
    higher_is_better: bool,
    min_delta: float,
    stability_ok: bool = True,
) -> bool:
    if baseline_val is None or improved_val is None:
        return False
    delta = float(improved_val) - float(baseline_val)
    if not higher_is_better:
        delta = -delta
    return bool(delta >= float(min_delta)) and bool(stability_ok)


def _extract_metric_round_tradeoff(
    metric_value: Optional[float],
    critique_packet: Dict[str, Any] | None,
) -> Dict[str, Any]:
    critique_packet = critique_packet if isinstance(critique_packet, dict) else {}
    validation = critique_packet.get("validation_signals")
    validation = validation if isinstance(validation, dict) else {}
    cv_block = validation.get("cv") if isinstance(validation.get("cv"), dict) else {}
    cv_std = _coerce_float(cv_block.get("cv_std"))
    if cv_std is None:
        cv_std = _coerce_float(validation.get("cv_std"))
    gen_gap = _coerce_float(validation.get("generalization_gap"))
    return {
        "metric_value": metric_value,
        "cv_std": cv_std,
        "generalization_gap_abs": abs(float(gen_gap)) if gen_gap is not None else None,
    }


def _pareto_dominates_metric_round(
    left: Dict[str, Any],
    right: Dict[str, Any],
    *,
    higher_is_better: bool,
) -> bool:
    left_metric = _coerce_float(left.get("metric_value"))
    right_metric = _coerce_float(right.get("metric_value"))
    left_cv_std = _coerce_float(left.get("cv_std"))
    right_cv_std = _coerce_float(right.get("cv_std"))
    left_gap = _coerce_float(left.get("generalization_gap_abs"))
    right_gap = _coerce_float(right.get("generalization_gap_abs"))

    comparisons: List[tuple[Optional[float], Optional[float], bool]] = [
        (left_metric, right_metric, bool(higher_is_better)),
        (left_cv_std, right_cv_std, False),
        (left_gap, right_gap, False),
    ]
    any_strict_better = False
    for left_value, right_value, maximize in comparisons:
        if left_value is None or right_value is None:
            continue
        if maximize:
            if left_value < right_value:
                return False
            if left_value > right_value:
                any_strict_better = True
        else:
            if left_value > right_value:
                return False
            if left_value < right_value:
                any_strict_better = True
    return any_strict_better


def _update_metric_round_pareto_frontier(
    frontier: List[Dict[str, Any]] | None,
    candidate: Dict[str, Any],
    *,
    higher_is_better: bool,
) -> tuple[List[Dict[str, Any]], bool]:
    frontier = [item for item in (frontier or []) if isinstance(item, dict)]
    candidate = candidate if isinstance(candidate, dict) else {}
    for incumbent in frontier:
        if _pareto_dominates_metric_round(incumbent, candidate, higher_is_better=bool(higher_is_better)):
            return frontier, False

    filtered: List[Dict[str, Any]] = []
    for incumbent in frontier:
        if _pareto_dominates_metric_round(candidate, incumbent, higher_is_better=bool(higher_is_better)):
            continue
        filtered.append(incumbent)
    filtered.append(candidate)
    return filtered[-24:], True


def _metric_round_stability_ok(
    critique_packet: Dict[str, Any] | None,
    *,
    max_cv_std: Optional[float] = None,
    max_generalization_gap: Optional[float] = 0.02,
    disallow_high_variance: bool = True,
) -> bool:
    if not isinstance(critique_packet, dict):
        return True
    error_modes = critique_packet.get("error_modes") if isinstance(critique_packet.get("error_modes"), list) else []
    error_mode_ids = {
        str(item.get("id") or "").strip().lower()
        for item in error_modes
        if isinstance(item, dict) and str(item.get("id") or "").strip()
    }
    if "fold_instability" in error_mode_ids or "generalization_gap_high" in error_mode_ids:
        return False

    validation = (
        critique_packet.get("validation_signals")
        if isinstance(critique_packet.get("validation_signals"), dict)
        else {}
    )
    cv_block = validation.get("cv") if isinstance(validation.get("cv"), dict) else {}
    variance_level = str(cv_block.get("variance_level") or "").strip().lower()
    if disallow_high_variance and variance_level == "high":
        return False

    cv_std = _coerce_float(cv_block.get("cv_std"))
    if max_cv_std is not None and cv_std is not None and cv_std > float(max_cv_std):
        return False

    gap = _coerce_float(validation.get("generalization_gap"))
    if max_generalization_gap is not None and gap is not None:
        if abs(float(gap)) > float(max_generalization_gap):
            return False
    return True


def _resolve_ml_outputs_for_metric_round(contract: Dict[str, Any], state: Dict[str, Any]) -> List[str]:
    if not isinstance(contract, dict):
        return []
    outputs = _resolve_ml_heavy_runner_required_outputs(contract, state)
    if not outputs:
        try:
            outputs = _normalize_output_path_list(get_required_outputs(contract))
        except Exception:
            outputs = []
        excluded = _resolve_ml_de_input_exclusions(state)
        outputs = [path for path in outputs if str(path or "").lower() not in excluded]

    extras = ["data/metrics.json", "data/submission.csv", "data/scored_rows.csv"]
    seen = {str(path).lower() for path in outputs}
    for path in extras:
        if path.lower() in seen:
            continue
        if os.path.exists(path):
            outputs.append(path)
            seen.add(path.lower())
    return _normalize_output_path_list(outputs)


def _snapshot_ml_outputs(output_paths: List[str], snapshot_dir: Path) -> None:
    snapshot_root = Path(snapshot_dir)
    snapshot_root.mkdir(parents=True, exist_ok=True)
    manifest: Dict[str, Any] = {"paths": []}
    for rel_path in _normalize_output_path_list(output_paths):
        src = Path(rel_path)
        exists = src.exists() and src.is_file()
        manifest["paths"].append({"path": rel_path, "exists": bool(exists)})
        if not exists:
            continue
        dst = snapshot_root / rel_path
        dst.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(src, dst)
    try:
        with open(snapshot_root / "_snapshot_manifest.json", "w", encoding="utf-8") as f:
            json.dump(manifest, f, ensure_ascii=True, indent=2)
    except Exception:
        pass


def _restore_ml_outputs(snapshot_dir: Path, output_paths: List[str]) -> None:
    snapshot_root = Path(snapshot_dir)
    manifest_paths: List[str] = []
    manifest_file = snapshot_root / "_snapshot_manifest.json"
    if manifest_file.exists():
        try:
            with open(manifest_file, "r", encoding="utf-8") as f:
                payload = json.load(f)
            entries = payload.get("paths") if isinstance(payload, dict) else []
            if isinstance(entries, list):
                for entry in entries:
                    if not isinstance(entry, dict):
                        continue
                    path = entry.get("path")
                    if isinstance(path, str) and path.strip():
                        manifest_paths.append(path.strip())
        except Exception:
            manifest_paths = []
    candidates = _normalize_output_path_list((manifest_paths or []) + (output_paths or []))
    for rel_path in candidates:
        src = snapshot_root / rel_path
        dst = Path(rel_path)
        if src.exists() and src.is_file():
            dst.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(src, dst)
        else:
            if dst.exists() and dst.is_file():
                try:
                    dst.unlink()
                except Exception:
                    pass


def _build_metric_improvement_feedback_block(
    *,
    feature_engineering_plan: Dict[str, Any],
    critique_packet: Dict[str, Any],
    hypothesis_packet: Dict[str, Any],
    steward_feedback: str = "",
    advisor_feedback: str = "",
) -> str:
    plan_compact = compress_long_lists(feature_engineering_plan or {})[0]
    plan_text = json.dumps(plan_compact, ensure_ascii=True)
    critique_text = json.dumps(compress_long_lists(critique_packet or {})[0], ensure_ascii=True)
    hypothesis_text = json.dumps(compress_long_lists(hypothesis_packet or {})[0], ensure_ascii=True)
    steward_text = _truncate_handoff_text(str(steward_feedback or ""), max_len=420)
    advisor_text = _truncate_handoff_text(str(advisor_feedback or ""), max_len=420)
    return (
        "\n\n# IMPROVEMENT_ROUND\n"
        + ("STEWARD_FEEDBACK: " + steward_text + "\n" if steward_text else "")
        + ("RESULTS_ADVISOR_FEEDBACK: " + advisor_text + "\n" if advisor_text else "")
        + "FEATURE_ENGINEERING_PLAN: "
        + plan_text
        + "\nADVISOR_CRITIQUE_PACKET: "
        + critique_text
        + "\nITERATION_HYPOTHESIS_PACKET: "
        + hypothesis_text
    )


def _build_metric_improvement_patch_objectives(hypothesis_packet: Dict[str, Any]) -> List[str]:
    hypothesis_packet = hypothesis_packet if isinstance(hypothesis_packet, dict) else {}
    hypothesis = hypothesis_packet.get("hypothesis") if isinstance(hypothesis_packet.get("hypothesis"), dict) else {}
    technique = str(hypothesis.get("technique") or "NO_OP")
    target_columns = hypothesis.get("target_columns") if isinstance(hypothesis.get("target_columns"), list) else []
    targets_text = ", ".join([str(item) for item in target_columns[:6]]) if target_columns else "ALL_NUMERIC"
    action = str(hypothesis_packet.get("action") or "NO_OP").upper()

    objectives: List[str] = []
    if action == "APPLY" and technique and technique != "NO_OP":
        objectives.append(
            "Apply hypothesis technique '" + technique + "' on target columns: " + targets_text + "."
        )
        objectives.append(
            "NO_OP is forbidden in this round. Implement the hypothesis with material feature engineering edits."
        )
        objectives.append(
            "Keep baseline model family and CV/data-split protocol stable while injecting the hypothesis end-to-end."
        )
    else:
        objectives.append("No-op hypothesis selected; preserve baseline logic and keep outputs contract-compliant.")
    objectives.append("Preserve CV/data-split protocol and all contract output paths.")
    return objectives[:8]


def _normalize_code_for_apply_guard(code: Any) -> str:
    if not isinstance(code, str) or not code.strip():
        return ""
    lines: List[str] = []
    for raw in code.splitlines():
        line = str(raw).strip()
        if not line or line.startswith("#"):
            continue
        lines.append(re.sub(r"\s+", " ", line))
    return "\n".join(lines)


def _count_code_line_changes(previous_code: str, candidate_code: str) -> int:
    if not previous_code and not candidate_code:
        return 0
    prev_lines = previous_code.splitlines()
    cand_lines = candidate_code.splitlines()
    changes = 0
    for opcode, i1, i2, j1, j2 in difflib.SequenceMatcher(None, prev_lines, cand_lines).get_opcodes():
        if opcode == "equal":
            continue
        changes += max(i2 - i1, j2 - j1)
    return int(changes)


def _evaluate_metric_round_hypothesis_application(
    state: Dict[str, Any],
    previous_code: Any,
    candidate_code: Any,
    iteration_handoff: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    report: Dict[str, Any] = {
        "enforced": False,
        "applied": True,
        "reason": "not_metric_round",
        "action": "NO_OP",
        "technique": "",
        "similarity": None,
        "changed_lines": 0,
        "char_delta": 0,
    }
    if not isinstance(state, dict) or not bool(state.get("ml_improvement_round_active")):
        return report

    packet = _resolve_metric_round_hypothesis_packet(state, iteration_handoff=iteration_handoff)
    action = str(packet.get("action") or "NO_OP").strip().upper()
    technique = str(_extract_hypothesis_technique(packet) or "").strip()
    report["action"] = action
    report["technique"] = technique

    enforce_apply = bool(action == "APPLY" and technique and technique.upper() != "NO_OP")
    report["enforced"] = enforce_apply
    if not enforce_apply:
        report["reason"] = "no_apply_hypothesis"
        return report

    if not isinstance(previous_code, str) or not previous_code.strip():
        report["reason"] = "missing_previous_code"
        return report
    if not isinstance(candidate_code, str) or not candidate_code.strip():
        report["applied"] = False
        report["reason"] = "empty_candidate_code"
        return report

    prev_norm = _normalize_code_for_apply_guard(previous_code)
    cand_norm = _normalize_code_for_apply_guard(candidate_code)
    if not prev_norm or not cand_norm:
        report["reason"] = "insufficient_code_for_comparison"
        return report

    if prev_norm == cand_norm:
        report["applied"] = False
        report["reason"] = "no_code_change"
        report["similarity"] = 1.0
        return report

    similarity = float(difflib.SequenceMatcher(None, prev_norm, cand_norm).ratio())
    changed_lines = _count_code_line_changes(prev_norm, cand_norm)
    char_delta = abs(len(cand_norm) - len(prev_norm))
    report["similarity"] = round(similarity, 6)
    report["changed_lines"] = int(changed_lines)
    report["char_delta"] = int(char_delta)

    technique_tokens = [
        token
        for token in re.split(r"[^a-z0-9]+", technique.lower())
        if token and len(token) >= 4 and token not in {"feature", "engineering", "technique"}
    ]
    prev_lower = prev_norm.lower()
    cand_lower = cand_norm.lower()
    token_added = any(token in cand_lower and token not in prev_lower for token in technique_tokens[:4])

    if token_added:
        report["reason"] = "technique_token_added"
        return report
    if changed_lines >= 8 or char_delta >= 180:
        report["reason"] = "material_diff_detected"
        return report
    if similarity <= 0.985 and changed_lines >= 4:
        report["reason"] = "moderate_diff_detected"
        return report

    report["applied"] = False
    report["reason"] = "no_material_hypothesis_edit"
    return report


def _bootstrap_metric_improvement_round(state: Dict[str, Any], contract: Dict[str, Any]) -> bool:
    skip_reason = _metric_improvement_skip_reason(state, contract)
    if skip_reason:
        run_id = str(state.get("run_id") or "")
        reviewer_status, qa_status, status_source = _resolve_baseline_reviewer_status_pair(state)
        if run_id:
            try:
                log_run_event(
                    run_id,
                    "metric_improvement_round_skipped",
                    {
                        "reason": skip_reason,
                        "review_verdict": str(state.get("review_verdict") or ""),
                        "reviewer_status": reviewer_status,
                        "qa_status": qa_status,
                        "status_source": status_source,
                        "execution_error": bool(state.get("execution_error")),
                        "sandbox_failed": bool(state.get("sandbox_failed")),
                        "loop_complete": bool(state.get("ml_improvement_loop_complete")),
                        "attempted": bool(state.get("ml_improvement_attempted")),
                        "round_active": bool(state.get("ml_improvement_round_active")),
                        "round_count": int(state.get("ml_improvement_round_count", 0) or 0),
                    },
                )
            except Exception:
                pass
        return False

    run_id = str(state.get("run_id") or "")
    metric_target = _resolve_contract_metric_target(state, contract)
    metric_name = str(metric_target.get("name") or "roc_auc").strip() or "roc_auc"
    metric_higher_is_better = metric_target.get("higher_is_better")
    if not isinstance(metric_higher_is_better, bool):
        metric_higher_is_better = bool(_metric_higher_is_better(metric_name))
    baseline_metrics = _load_json_safe("data/metrics.json")
    if not isinstance(baseline_metrics, dict):
        baseline_metrics = {}

    baseline_value = _extract_primary_metric(baseline_metrics, metric_name)
    if baseline_value is None:
        snapshot = state.get("primary_metric_snapshot")
        if isinstance(snapshot, dict):
            baseline_value = _coerce_float(snapshot.get("primary_metric_value"))
            snap_name = snapshot.get("primary_metric_name")
            if isinstance(snap_name, str) and snap_name.strip():
                metric_name = snap_name.strip()
                metric_higher_is_better = bool(_metric_higher_is_better(metric_name))
                metric_target = {
                    "name": metric_name,
                    "higher_is_better": metric_higher_is_better,
                    "source": "primary_metric_snapshot",
                }
    if baseline_value is None:
        if run_id:
            try:
                log_run_event(
                    run_id,
                    "metric_improvement_round_skipped",
                    {
                        "reason": "baseline_metric_unavailable",
                        "primary_metric_name": metric_name,
                        "metric_target_source": metric_target.get("source"),
                    },
                )
            except Exception:
                pass
        return False

    rounds, min_delta, patience = _metric_improvement_policy(contract)
    if rounds <= 0:
        if run_id:
            try:
                log_run_event(
                    run_id,
                    "metric_improvement_round_skipped",
                    {
                        "reason": "metric_rounds_disabled",
                        "rounds": int(rounds),
                    },
                )
            except Exception:
                pass
        return False
    round_index_before = int(state.get("ml_improvement_round_count", 0) or 0)
    round_id = round_index_before + 1
    no_improve_streak = int(state.get("ml_improvement_no_improve_streak", 0) or 0)
    round_history = state.get("ml_improvement_round_history")
    if not isinstance(round_history, list):
        round_history = []
    best_metric_so_far = _coerce_float(state.get("ml_improvement_best_metric"))
    if best_metric_so_far is None:
        best_metric_so_far = _coerce_float(baseline_value)

    output_paths = _resolve_ml_outputs_for_metric_round(contract, state)
    snapshot_dir = Path("work") / f"ml_incumbent_snapshot_r{round_id}"
    _snapshot_ml_outputs(output_paths, snapshot_dir)
    if run_id:
        try:
            log_run_event(
                run_id,
                "metric_improvement_round_start",
                {
                    "iteration": int(state.get("iteration_count", 0) or 0) + 1,
                    "round_id": int(round_id),
                    "round_count_current": int(round_index_before),
                    "rounds_allowed": int(rounds),
                    "patience": int(patience),
                    "no_improve_streak": int(no_improve_streak),
                    "primary_metric_name": metric_name,
                    "baseline_metric": float(baseline_value),
                    "best_metric_so_far": best_metric_so_far,
                    "min_delta": float(min_delta),
                    "output_paths": output_paths[:12],
                },
            )
        except Exception:
            pass

    feature_engineering_plan = contract.get("feature_engineering_plan")
    if not isinstance(feature_engineering_plan, dict):
        feature_engineering_plan = {"techniques": [], "derived_columns": [], "notes": ""}

    baseline_code = str(state.get("generated_code") or state.get("last_generated_code") or "")
    advisor_context = {
        "baseline_metrics": baseline_metrics,
        "primary_metric_name": metric_name,
        "feature_engineering_plan": feature_engineering_plan,
        "baseline_ml_script_snippet": baseline_code[:4000],
        "dataset_profile": state.get("data_profile") if isinstance(state.get("data_profile"), dict) else {},
        "column_roles": contract.get("column_roles") if isinstance(contract.get("column_roles"), dict) else {},
    }
    advisor_context["run_id"] = str(state.get("run_id") or "")
    advisor_context["iteration"] = int(state.get("iteration_count", 0) or 0)
    advisor_context["higher_is_better"] = bool(metric_higher_is_better)
    advisor_context["min_delta"] = float(min_delta)
    advisor_context["phase"] = "baseline_review"
    advisor_context["candidate_metrics"] = baseline_metrics
    advisor_context["active_gates_context"] = _collect_active_gate_names(contract)

    critique_packet = results_advisor.generate_critique_packet(advisor_context)
    critique_meta = (
        results_advisor.last_critique_meta
        if isinstance(getattr(results_advisor, "last_critique_meta", None), dict)
        else {}
    )
    if critique_meta:
        critique_line = (
            "RESULTS_ADVISOR_CRITIQUE: "
            + f"mode={critique_meta.get('mode')} "
            + f"source={critique_meta.get('source')} "
            + f"provider={critique_meta.get('provider')} "
            + f"model={critique_meta.get('model')}"
        )
        llm_error = critique_meta.get("llm_error") if isinstance(critique_meta.get("llm_error"), dict) else {}
        if llm_error:
            critique_line += (
                " "
                + f"error_stage={llm_error.get('stage')} "
                + f"error_detail={llm_error.get('detail')}"
            )
        validation_errors = critique_meta.get("validation_errors")
        if isinstance(validation_errors, list) and validation_errors:
            critique_line += " validation_errors=" + str(validation_errors[:3])
        print(critique_line)

    tracker_entries = load_recent_experiment_entries(run_id, k=20) if run_id else []
    strategist_context = {
        "run_id": run_id,
        "iteration": int(state.get("iteration_count", 0) or 0) + 1,
        "round_id": int(round_id),
        "rounds_allowed": int(rounds),
        "patience": int(patience),
        "no_improve_streak": int(no_improve_streak),
        "primary_metric_name": metric_name,
        "min_delta": float(min_delta),
        "feature_engineering_plan": feature_engineering_plan,
        "critique_packet": critique_packet,
        "experiment_tracker": tracker_entries,
        "round_history": round_history[-8:],
        "dataset_profile": state.get("data_profile") if isinstance(state.get("data_profile"), dict) else {},
        "column_roles": contract.get("column_roles") if isinstance(contract.get("column_roles"), dict) else {},
    }
    hypothesis_packet = strategist.generate_iteration_hypothesis(strategist_context)
    hypothesis_meta = (
        strategist.last_iteration_meta
        if isinstance(getattr(strategist, "last_iteration_meta", None), dict)
        else {}
    )
    if hypothesis_meta:
        print(
            "STRATEGIST_ITERATION_HYPOTHESIS: "
            + f"mode={hypothesis_meta.get('mode')} "
            + f"source={hypothesis_meta.get('source')} "
            + f"model={hypothesis_meta.get('model')}"
        )

    patch_objectives = _build_metric_improvement_patch_objectives(hypothesis_packet)
    steward_feedback = _build_steward_feedback_for_improvement(state)
    advisor_feedback = _build_results_advisor_feedback_for_improvement(state, critique_packet)
    feedback_block = _build_metric_improvement_feedback_block(
        feature_engineering_plan=feature_engineering_plan,
        critique_packet=critique_packet,
        hypothesis_packet=hypothesis_packet,
        steward_feedback=steward_feedback,
        advisor_feedback=advisor_feedback,
    )
    hypothesis_action = str(hypothesis_packet.get("action") or "NO_OP").strip().upper()
    hypothesis_technique = str(_extract_hypothesis_technique(hypothesis_packet) or "").strip()
    enforce_apply_hypothesis = bool(
        hypothesis_action == "APPLY"
        and hypothesis_technique
        and hypothesis_technique.upper() != "NO_OP"
    )

    history = list(state.get("feedback_history", []) or [])
    history.append(feedback_block)
    state["feedback_history"] = history[-25:]

    existing_gate = state.get("last_gate_context") if isinstance(state.get("last_gate_context"), dict) else {}
    # Optimization rounds should not inherit baseline rejection framing.
    # Keep a clean optimization context for editor mode.
    merged_feedback = feedback_block.strip()
    state["last_gate_context"] = {
        **existing_gate,
        "source": "metric_improvement_optimizer",
        "status": "OPTIMIZATION_REQUIRED",
        "failed_gates": [],
        "hard_failures": [],
        "required_fixes": patch_objectives,
        "feedback": merged_feedback,
        "feature_engineering_plan": feature_engineering_plan,
        "advisor_critique_packet": critique_packet,
        "iteration_hypothesis_packet": hypothesis_packet,
        "metric_round_enforcement": {
            "must_apply_hypothesis": bool(enforce_apply_hypothesis),
            "forbid_noop": bool(enforce_apply_hypothesis),
            "patch_intensity": "aggressive" if enforce_apply_hypothesis else "incremental",
        },
    }

    state["iteration_handoff"] = {
        "handoff_version": "v1",
        "mode": "optimize",
        "source": "actor_critic_metric_improvement",
        "from_iteration": int(state.get("iteration_count", 0) or 0),
        "next_iteration": int(state.get("iteration_count", 0) or 0) + 1,
        "contract_focus": {
            "required_outputs": output_paths[:12],
            "present_outputs": [],
            "missing_outputs": [],
        },
        "quality_focus": {
            "status": "OPTIMIZATION_REQUIRED",
            "failed_gates": [],
            "required_fixes": patch_objectives,
            "hard_failures": [],
            "evidence": [],
        },
        "optimization_focus": {
            "round_id": int(round_id),
            "rounds_allowed": int(rounds),
            "primary_metric_name": metric_name,
            "baseline_metric": float(baseline_value),
            "min_delta": float(min_delta),
            "higher_is_better": bool(metric_higher_is_better),
            "feature_engineering_plan": feature_engineering_plan,
        },
        "feedback": {
            "reviewer": feedback_block.strip(),
            "qa": "",
            "runtime_error_tail": "",
            "evidence": [],
            "steward": steward_feedback,
            "results_advisor": advisor_feedback,
        },
        "must_preserve": [
            "data_split_logic",
            "cv_protocol",
            "output_paths_contract",
        ],
        "editor_constraints": {
            "must_apply_hypothesis": bool(enforce_apply_hypothesis),
            "forbid_noop": bool(enforce_apply_hypothesis),
            "patch_intensity": "aggressive" if enforce_apply_hypothesis else "incremental",
            "strategy_lock": True,
        },
        "must_apply_hypothesis": bool(enforce_apply_hypothesis),
        "forbid_noop": bool(enforce_apply_hypothesis),
        "patch_intensity": "aggressive" if enforce_apply_hypothesis else "incremental",
        "patch_objectives": patch_objectives,
        "critic_packet": critique_packet,
        "hypothesis_packet": hypothesis_packet,
    }

    state["ml_improvement_critique_packet"] = critique_packet
    state["ml_improvement_hypothesis_packet"] = hypothesis_packet
    state["ml_improvement_apply_guard_report"] = {}
    state["ml_improvement_round_active"] = True
    state["ml_improvement_round_count"] = int(round_id)
    state["ml_improvement_attempted"] = False
    state["ml_improvement_continue"] = False
    state["ml_improvement_loop_complete"] = False
    state["ml_improvement_kept"] = "pending"
    state["ml_improvement_review_mode"] = _resolve_metric_round_review_mode(contract)
    state["ml_improvement_snapshot_dir"] = str(snapshot_dir)
    state["ml_improvement_output_paths"] = output_paths
    state["ml_improvement_current_round_id"] = int(round_id)
    state["ml_improvement_round_baseline_metric"] = float(baseline_value)
    state["ml_improvement_round_baseline_metrics"] = baseline_metrics
    state["ml_improvement_round_baseline_reviewer_packet"] = (
        dict(state.get("reviewer_last_result"))
        if isinstance(state.get("reviewer_last_result"), dict)
        else {}
    )
    state["ml_improvement_round_baseline_qa_packet"] = (
        dict(state.get("qa_last_result"))
        if isinstance(state.get("qa_last_result"), dict)
        else {}
    )
    state["ml_improvement_incumbent_metric"] = float(baseline_value)
    state["ml_improvement_primary_metric_name"] = metric_name
    state["ml_improvement_primary_metric_source"] = metric_target.get("source")
    state["ml_improvement_baseline_metric"] = float(best_metric_so_far if best_metric_so_far is not None else baseline_value)
    state["ml_improvement_baseline_metrics"] = baseline_metrics
    state["ml_improvement_baseline_review_verdict"] = normalize_review_status(state.get("review_verdict"))
    state["ml_improvement_higher_is_better"] = bool(metric_higher_is_better)
    state["ml_improvement_min_delta"] = float(min_delta)
    state["ml_improvement_rounds_allowed"] = int(rounds)
    state["ml_improvement_patience"] = int(patience)
    state["ml_improvement_no_improve_streak"] = int(no_improve_streak)
    state["ml_improvement_best_metric"] = (
        float(best_metric_so_far)
        if best_metric_so_far is not None
        else float(baseline_value)
    )
    state["ml_improvement_best_round"] = int(state.get("ml_improvement_best_round", 0) or 0)
    if not isinstance(state.get("ml_improvement_round_history"), list):
        state["ml_improvement_round_history"] = round_history
    state["last_iteration_type"] = "metric"
    state["improvement_attempt_count"] = 0
    if run_id:
        hypothesis = hypothesis_packet.get("hypothesis") if isinstance(hypothesis_packet.get("hypothesis"), dict) else {}
        tracker_context = hypothesis_packet.get("tracker_context") if isinstance(hypothesis_packet.get("tracker_context"), dict) else {}
        try:
            log_run_event(
                run_id,
                "metric_improvement_round_activated",
                {
                    "iteration": int(state.get("iteration_count", 0) or 0) + 1,
                    "round_id": int(round_id),
                    "round_count": int(state.get("ml_improvement_round_count", 0) or 0),
                    "rounds_allowed": int(rounds),
                    "patience": int(patience),
                    "no_improve_streak": int(no_improve_streak),
                    "primary_metric_name": metric_name,
                    "baseline_metric": float(baseline_value),
                    "min_delta": float(min_delta),
                    "action": hypothesis_packet.get("action"),
                    "technique": hypothesis.get("technique"),
                    "signature": tracker_context.get("signature"),
                    "editor_mode_forced": True,
                },
            )
        except Exception:
            pass
    if run_id:
        tracker_context = hypothesis_packet.get("tracker_context") if isinstance(hypothesis_packet.get("tracker_context"), dict) else {}
        append_experiment_entry(
            run_id,
            {
                "iter": int(state.get("iteration_count", 0) or 0),
                "event": "hypothesis_proposed",
                "phase": "metric_improvement_round",
                "action": hypothesis_packet.get("action"),
                "signature": tracker_context.get("signature"),
                "duplicate_of": tracker_context.get("duplicate_of"),
                "technique": (
                    hypothesis_packet.get("hypothesis", {}).get("technique")
                    if isinstance(hypothesis_packet.get("hypothesis"), dict)
                    else None
                ),
                "primary_metric_name": metric_name,
                "baseline_metric": float(baseline_value),
            },
        )
    return True


def _finalize_metric_improvement_round(state: Dict[str, Any], contract: Dict[str, Any]) -> str:
    metric_target = _resolve_contract_metric_target(state, contract if isinstance(contract, dict) else {})
    metric_name = str(
        state.get("ml_improvement_primary_metric_name")
        or metric_target.get("name")
        or _resolve_contract_primary_metric_name(state, contract)
        or "roc_auc"
    ).strip()
    round_baseline_value = _coerce_float(
        state.get("ml_improvement_round_baseline_metric")
    )
    if round_baseline_value is None:
        round_baseline_value = _coerce_float(state.get("ml_improvement_incumbent_metric"))
    best_metric_value = _coerce_float(state.get("ml_improvement_best_metric"))
    if best_metric_value is None:
        best_metric_value = _coerce_float(state.get("ml_improvement_baseline_metric"))
    baseline_value = (
        round_baseline_value
        if round_baseline_value is not None
        else best_metric_value
    )
    min_delta = float(state.get("ml_improvement_min_delta", 0.0005) or 0.0005)
    rounds_allowed = int(state.get("ml_improvement_rounds_allowed", 1) or 1)
    patience = int(state.get("ml_improvement_patience", 2) or 2)
    round_id = int(state.get("ml_improvement_current_round_id", state.get("ml_improvement_round_count", 0) or 0) or 0)
    no_improve_streak = int(state.get("ml_improvement_no_improve_streak", 0) or 0)
    round_history = state.get("ml_improvement_round_history")
    if not isinstance(round_history, list):
        round_history = []
    higher_is_better_state = state.get("ml_improvement_higher_is_better")
    if isinstance(higher_is_better_state, bool):
        higher_is_better = higher_is_better_state
    else:
        resolved_hib = metric_target.get("higher_is_better")
        higher_is_better = (
            bool(resolved_hib)
            if isinstance(resolved_hib, bool)
            else bool(_metric_higher_is_better(metric_name))
        )
    output_paths = state.get("ml_improvement_output_paths") if isinstance(state.get("ml_improvement_output_paths"), list) else []
    snapshot_dir = Path(str(state.get("ml_improvement_snapshot_dir") or Path("work") / "ml_baseline_snapshot"))
    baseline_verdict = normalize_review_status(state.get("ml_improvement_baseline_review_verdict") or "APPROVED")
    force_finalize_reason = str(state.get("ml_improvement_force_finalize_reason") or "").strip().lower()
    force_finalize = bool(force_finalize_reason)
    current_metrics = _load_json_safe("data/metrics.json")
    if not isinstance(current_metrics, dict):
        current_metrics = {}
    improved_value = _extract_primary_metric(current_metrics, metric_name)
    if improved_value is None:
        snapshot = state.get("primary_metric_snapshot")
        if isinstance(snapshot, dict):
            improved_value = _coerce_float(snapshot.get("primary_metric_value"))

    active_gates_context = _collect_active_gate_names(contract if isinstance(contract, dict) else {})
    baseline_metrics_payload = (
        state.get("ml_improvement_round_baseline_metrics")
        if isinstance(state.get("ml_improvement_round_baseline_metrics"), dict)
        else {}
    )
    if not baseline_metrics_payload:
        baseline_metrics_payload = (
            state.get("ml_improvement_baseline_metrics")
            if isinstance(state.get("ml_improvement_baseline_metrics"), dict)
            else {}
        )
    if not baseline_metrics_payload and baseline_value is not None:
        baseline_metrics_payload = {
            metric_name: float(baseline_value),
            "primary_metric_value": float(baseline_value),
        }
    critique_context = {
        "run_id": str(state.get("run_id") or "unknown_run"),
        "iteration": int(state.get("iteration_count", 0) or 0),
        "phase": "candidate_review",
        "primary_metric_name": metric_name,
        "higher_is_better": bool(higher_is_better),
        "min_delta": float(min_delta),
        "baseline_metrics": baseline_metrics_payload,
        "candidate_metrics": current_metrics,
        "active_gates_context": active_gates_context,
        "dataset_profile": state.get("data_profile") if isinstance(state.get("data_profile"), dict) else {},
        "column_roles": contract.get("column_roles") if isinstance(contract.get("column_roles"), dict) else {},
    }
    critique_packet: Dict[str, Any] = {}
    critique_meta: Dict[str, Any] = {}
    try:
        critique_packet = results_advisor.generate_critique_packet(critique_context)
        if not isinstance(critique_packet, dict):
            critique_packet = {}
    except Exception:
        critique_packet = {}
    meta_obj = getattr(results_advisor, "last_critique_meta", None)
    if isinstance(meta_obj, dict):
        critique_meta = dict(meta_obj)
    if critique_meta:
        critique_line = (
            "RESULTS_ADVISOR_CANDIDATE_CRITIQUE: "
            + f"mode={critique_meta.get('mode')} "
            + f"source={critique_meta.get('source')} "
            + f"provider={critique_meta.get('provider')} "
            + f"model={critique_meta.get('model')}"
        )
        llm_error = critique_meta.get("llm_error") if isinstance(critique_meta.get("llm_error"), dict) else {}
        if llm_error:
            critique_line += (
                " "
                + f"error_stage={llm_error.get('stage')} "
                + f"error_detail={llm_error.get('detail')}"
            )
        validation_errors = critique_meta.get("validation_errors")
        if isinstance(validation_errors, list) and validation_errors:
            critique_line += " validation_errors=" + str(validation_errors[:3])
        print(critique_line)

    metric_comparison = critique_packet.get("metric_comparison") if isinstance(critique_packet, dict) else {}
    if isinstance(metric_comparison, dict):
        baseline_from_packet = _coerce_float(metric_comparison.get("baseline_value"))
        candidate_from_packet = _coerce_float(metric_comparison.get("candidate_value"))
        if baseline_value is None and baseline_from_packet is not None:
            baseline_value = baseline_from_packet
        if improved_value is None and candidate_from_packet is not None:
            improved_value = candidate_from_packet
    meets_min_delta_packet = (
        metric_comparison.get("meets_min_delta")
        if isinstance(metric_comparison, dict) and isinstance(metric_comparison.get("meets_min_delta"), bool)
        else None
    )

    policy = contract.get("iteration_policy") if isinstance(contract, dict) else {}
    if not isinstance(policy, dict):
        policy = {}
    max_cv_std = _coerce_float(policy.get("metric_max_cv_std"))
    if max_cv_std is not None and max_cv_std < 0:
        max_cv_std = None
    max_generalization_gap = _coerce_float(policy.get("metric_max_generalization_gap"))
    if max_generalization_gap is None:
        max_generalization_gap = 0.02
    if max_generalization_gap < 0:
        max_generalization_gap = abs(max_generalization_gap)
    disallow_high_variance = _coerce_optional_bool(policy.get("metric_disallow_high_variance"))
    if disallow_high_variance is None:
        disallow_high_variance = True

    verdict = normalize_review_status(state.get("review_verdict"))
    advisory_review_mode = _is_metric_round_advisory_review_mode(
        state if isinstance(state, dict) else {},
        contract if isinstance(contract, dict) else {},
    )
    deterministic_blockers = _metric_round_has_deterministic_blockers(
        state,
        include_review_signals=not advisory_review_mode,
    )
    approved = (
        (not deterministic_blockers)
        if advisory_review_mode
        else (_is_approved_review_status(verdict) and (not deterministic_blockers))
    )
    if advisory_review_mode and not _is_approved_review_status(verdict):
        _append_feedback_history(
            state,
            "METRIC_IMPROVEMENT_REVIEW_OVERRIDE: reviewer status treated as advisory in guarded mode.",
        )
    improved_by_metric = (
        bool(meets_min_delta_packet)
        if isinstance(meets_min_delta_packet, bool)
        else _is_improvement(baseline_value, improved_value, higher_is_better, min_delta)
    )
    stability_ok = _metric_round_stability_ok(
        critique_packet,
        max_cv_std=max_cv_std,
        max_generalization_gap=max_generalization_gap,
        disallow_high_variance=bool(disallow_high_variance),
    )
    if force_finalize:
        improved_by_metric = False
        stability_ok = False
    improved = approved and improved_by_metric and stability_ok
    if not improved:
        _restore_ml_outputs(snapshot_dir, output_paths)
        state["ml_improvement_kept"] = "baseline"
        state["review_verdict"] = baseline_verdict
        state["stop_reason"] = "IMPROVEMENT_ROUND_RESTORE_INCUMBENT"
        baseline_reviewer_packet = (
            state.get("ml_improvement_round_baseline_reviewer_packet")
            if isinstance(state.get("ml_improvement_round_baseline_reviewer_packet"), dict)
            else {}
        )
        baseline_qa_packet = (
            state.get("ml_improvement_round_baseline_qa_packet")
            if isinstance(state.get("ml_improvement_round_baseline_qa_packet"), dict)
            else {}
        )
        if baseline_reviewer_packet:
            state["reviewer_last_result"] = dict(baseline_reviewer_packet)
        if baseline_qa_packet:
            state["qa_last_result"] = dict(baseline_qa_packet)
        if baseline_value is not None:
            state["ml_improvement_incumbent_metric"] = float(baseline_value)
        no_improve_streak = int(no_improve_streak) + 1
    else:
        state["ml_improvement_kept"] = "improved"
        state["stop_reason"] = "IMPROVEMENT_ROUND_KEPT_IMPROVED"
        no_improve_streak = 0
        state["ml_improvement_incumbent_metric"] = float(improved_value) if improved_value is not None else baseline_value

    def _metric_better(candidate: Optional[float], incumbent: Optional[float], hib: bool) -> bool:
        if candidate is None:
            return False
        if incumbent is None:
            return True
        if hib:
            return float(candidate) > float(incumbent)
        return float(candidate) < float(incumbent)

    if _metric_better(improved_value if improved else baseline_value, best_metric_value, bool(higher_is_better)):
        best_metric_value = improved_value if improved else baseline_value
        if best_metric_value is not None:
            state["ml_improvement_best_metric"] = float(best_metric_value)
            state["ml_improvement_best_round"] = int(round_id or 0)

    round_record = {
        "round_id": int(round_id or 0),
        "metric_name": metric_name,
        "baseline_metric": baseline_value,
        "candidate_metric": improved_value,
        "delta": None
        if baseline_value is None or improved_value is None
        else float(improved_value - baseline_value),
        "approved": bool(approved),
        "improved_by_metric": bool(improved_by_metric),
        "stability_ok": bool(stability_ok),
        "deterministic_blockers": bool(deterministic_blockers),
        "advisory_review_mode": bool(advisory_review_mode),
        "forced_finalize": bool(force_finalize),
        "forced_finalize_reason": force_finalize_reason if force_finalize else "",
        "kept": state.get("ml_improvement_kept"),
        "no_improve_streak": int(no_improve_streak),
        "rounds_allowed": int(rounds_allowed),
        "patience": int(patience),
    }
    apply_guard_report = (
        state.get("ml_improvement_apply_guard_report")
        if isinstance(state.get("ml_improvement_apply_guard_report"), dict)
        else {}
    )
    if apply_guard_report:
        round_record["apply_guard"] = {
            "enforced": bool(apply_guard_report.get("enforced")),
            "applied": bool(apply_guard_report.get("applied")),
            "reason": str(apply_guard_report.get("reason") or ""),
            "changed_lines": int(apply_guard_report.get("changed_lines", 0) or 0),
            "repair_attempted": bool(apply_guard_report.get("repair_attempted")),
        }
    round_record.update(_extract_metric_round_tradeoff(improved_value, critique_packet))
    frontier = state.get("ml_improvement_pareto_frontier")
    if not isinstance(frontier, list):
        frontier = []
    updated_frontier, frontier_improved = _update_metric_round_pareto_frontier(
        frontier,
        {
            "round_id": int(round_id or 0),
            "metric_value": round_record.get("metric_value"),
            "cv_std": round_record.get("cv_std"),
            "generalization_gap_abs": round_record.get("generalization_gap_abs"),
            "kept": round_record.get("kept"),
        },
        higher_is_better=bool(higher_is_better),
    )
    round_record["pareto_frontier_improved"] = bool(frontier_improved)
    state["ml_improvement_pareto_frontier"] = updated_frontier
    round_history.append(round_record)
    state["ml_improvement_round_history"] = round_history[-24:]
    state["ml_improvement_no_improve_streak"] = int(no_improve_streak)

    rounds_done = int(state.get("ml_improvement_round_count", 0) or 0)
    has_budget = rounds_done < int(max(0, rounds_allowed))
    under_patience = int(no_improve_streak) < int(max(1, patience))
    continue_round = bool(has_budget and under_patience and (not force_finalize))
    state["ml_improvement_continue"] = bool(continue_round)

    decision_note = (
        f"METRIC_IMPROVEMENT_ROUND: round={round_id}/{rounds_allowed} metric={metric_name} baseline={baseline_value} "
        f"improved={improved_value} min_delta={min_delta} "
        f"meets_min_delta={improved_by_metric} stability_ok={stability_ok} "
        f"deterministic_blockers={deterministic_blockers} "
        f"advisory_review_mode={advisory_review_mode} "
        f"forced_finalize={force_finalize} "
        f"kept={state.get('ml_improvement_kept')} "
        f"pareto_frontier_improved={round_record.get('pareto_frontier_improved')} "
        f"no_improve_streak={no_improve_streak} "
        f"patience={patience} continue_round={continue_round}"
    )
    _append_feedback_history(state, decision_note)
    if isinstance(critique_packet, dict) and critique_packet:
        state["ml_improvement_candidate_critique_packet"] = critique_packet
        critique_summary = str(critique_packet.get("analysis_summary") or "").strip()
        if critique_summary:
            _append_feedback_history(state, "RESULTS_ADVISOR_CANDIDATE_REVIEW: " + critique_summary)

    run_id = str(state.get("run_id") or "")
    if run_id:
        hypothesis_packet = state.get("ml_improvement_hypothesis_packet")
        hypothesis_packet = hypothesis_packet if isinstance(hypothesis_packet, dict) else {}
        tracker_context = hypothesis_packet.get("tracker_context") if isinstance(hypothesis_packet.get("tracker_context"), dict) else {}
        append_experiment_entry(
            run_id,
            {
                "iter": int(state.get("iteration_count", 0) or 0),
                "event": "candidate_evaluated",
                "phase": "metric_improvement_round",
                "round_id": int(round_id or 0),
                "kept": state.get("ml_improvement_kept"),
                "approved": approved,
                "primary_metric_name": metric_name,
                "baseline_metric": baseline_value,
                "candidate_metric": improved_value,
                "delta": None
                if baseline_value is None or improved_value is None
                else float(improved_value - baseline_value),
                "signature": tracker_context.get("signature"),
                "action": hypothesis_packet.get("action"),
                "deterministic_blockers": bool(deterministic_blockers),
                "advisor_meets_min_delta": bool(improved_by_metric),
                "stability_ok": bool(stability_ok),
                "pareto_frontier_improved": bool(round_record.get("pareto_frontier_improved")),
                "no_improve_streak": int(no_improve_streak),
                "continue_round": bool(continue_round),
                "apply_guard_reason": (
                    round_record.get("apply_guard", {}).get("reason")
                    if isinstance(round_record.get("apply_guard"), dict)
                    else None
                ),
            },
        )
        try:
            delta_value: Optional[float] = None
            if baseline_value is not None and improved_value is not None:
                delta_value = float(improved_value - baseline_value)
            if critique_packet:
                log_run_event(
                    run_id,
                    "metric_improvement_candidate_critique",
                    {
                        "iteration": int(state.get("iteration_count", 0) or 0),
                        "mode": critique_meta.get("mode"),
                        "source": critique_meta.get("source"),
                        "provider": critique_meta.get("provider"),
                        "model": critique_meta.get("model"),
                        "analysis_summary": str(critique_packet.get("analysis_summary") or "")[:280],
                        "meets_min_delta": bool(improved_by_metric),
                    },
                )
            log_run_event(
                run_id,
                "metric_improvement_round_complete",
                {
                        "iteration": int(state.get("iteration_count", 0) or 0),
                        "round_id": int(round_id or 0),
                        "rounds_allowed": int(rounds_allowed),
                        "primary_metric_name": metric_name,
                        "baseline_metric": baseline_value,
                        "candidate_metric": improved_value,
                        "delta": delta_value,
                        "min_delta": float(min_delta),
                    "higher_is_better": bool(higher_is_better),
                    "approved": bool(approved),
                    "improved": bool(improved),
                        "improved_by_metric": bool(improved_by_metric),
                        "stability_ok": bool(stability_ok),
                        "pareto_frontier_improved": bool(round_record.get("pareto_frontier_improved")),
                        "deterministic_blockers": bool(deterministic_blockers),
                        "advisory_review_mode": bool(advisory_review_mode),
                        "forced_finalize": bool(force_finalize),
                        "forced_finalize_reason": force_finalize_reason if force_finalize else "",
                        "kept": state.get("ml_improvement_kept"),
                        "no_improve_streak": int(no_improve_streak),
                        "patience": int(patience),
                        "continue_round": bool(continue_round),
                        "review_verdict": verdict,
                    "metric_source": metric_target.get("source"),
                    "apply_guard": round_record.get("apply_guard"),
                },
            )
            if continue_round:
                log_run_event(
                    run_id,
                    "metric_improvement_round_continue",
                    {
                        "round_id": int(round_id or 0),
                        "rounds_allowed": int(rounds_allowed),
                        "no_improve_streak": int(no_improve_streak),
                        "patience": int(patience),
                        "pareto_frontier_size": len(state.get("ml_improvement_pareto_frontier") or []),
                    },
                )
        except Exception:
            pass

    if continue_round:
        state["stop_reason"] = "IMPROVEMENT_ROUND_CONTINUE"
        state["ml_improvement_attempted"] = False
        state["ml_improvement_loop_complete"] = False
    else:
        state["ml_improvement_attempted"] = True
        state["ml_improvement_loop_complete"] = True
        if force_finalize:
            state["stop_reason"] = f"IMPROVEMENT_ROUND_{force_finalize_reason.upper()}"
    state["ml_improvement_round_active"] = False
    state["ml_improvement_force_finalize_reason"] = ""
    state["last_iteration_type"] = None
    return "approved"


def _collect_state_updates(before: Dict[str, Any], after: Dict[str, Any]) -> Dict[str, Any]:
    updates: Dict[str, Any] = {}
    before = before if isinstance(before, dict) else {}
    after = after if isinstance(after, dict) else {}
    for key, value in after.items():
        try:
            changed = key not in before or before.get(key) != value
        except Exception:
            changed = True
        if changed:
            updates[key] = value
    return updates


def run_metric_improvement_bootstrap(state: AgentState) -> AgentState:
    working_state = dict(state if isinstance(state, dict) else {})
    before = dict(working_state)
    contract = (
        working_state.get("execution_contract")
        if isinstance(working_state.get("execution_contract"), dict)
        else {}
    )
    activated = _bootstrap_metric_improvement_round(working_state, contract)
    updates = _collect_state_updates(before, working_state)
    updates["metric_improvement_nodes_managed"] = True
    updates["metric_improvement_bootstrapped"] = bool(activated)
    updates["metric_improvement_finalized"] = False
    return updates


def run_metric_improvement_finalize(state: AgentState) -> AgentState:
    working_state = dict(state if isinstance(state, dict) else {})
    before = dict(working_state)
    contract = (
        working_state.get("execution_contract")
        if isinstance(working_state.get("execution_contract"), dict)
        else {}
    )
    finalized = False
    if bool(working_state.get("ml_improvement_round_active")):
        _finalize_metric_improvement_round(working_state, contract)
        finalized = True
    continue_round = bool(working_state.get("ml_improvement_continue"))
    updates = _collect_state_updates(before, working_state)
    updates["metric_improvement_nodes_managed"] = False if continue_round else True
    updates["metric_improvement_bootstrapped"] = False
    updates["metric_improvement_finalized"] = bool(finalized)
    return updates


def check_review_board_metric_improvement_route(state: AgentState) -> str:
    if bool(state.get("ml_improvement_round_active")):
        return "finalize_improvement_round"
    return "bootstrap_improvement_round"


def check_metric_improvement_bootstrap_route(state: AgentState) -> str:
    if bool(state.get("metric_improvement_bootstrapped")):
        snapshot = state.get("primary_metric_snapshot") if isinstance(state.get("primary_metric_snapshot"), dict) else {}
        metric_name = snapshot.get("primary_metric_name", "unknown")
        metric_value = snapshot.get("primary_metric_value", "N/A")
        best_value = snapshot.get("baseline_value", "N/A")
        rounds_allowed = int(state.get("ml_improvement_rounds_allowed", 1) or 1)
        round_count = int(state.get("ml_improvement_round_count", 0) or 0)
        budget_left = max(0, rounds_allowed - round_count)
        print(
            f"ITER_DECISION type=metric action=retry reason=METRIC_IMPROVEMENT_ROUND "
            f"metric={metric_name}:{metric_value} best={best_value} budget_left={budget_left}"
        )
        return "retry"
    return check_evaluation(state)


def check_evaluation(state: AgentState):
    # Helper to get metric info for logging
    def _get_metric_info():
        snapshot = state.get("primary_metric_snapshot") or {}
        metric_name = snapshot.get("primary_metric_name", "unknown")
        metric_value = snapshot.get("primary_metric_value", "N/A")
        best_value = snapshot.get("baseline_value", "N/A")
        return metric_name, metric_value, best_value

    if state.get("runtime_fix_terminal"):
        metric_name, metric_value, best_value = _get_metric_info()
        print(
            f"ITER_DECISION type=runtime action=stop reason=TERMINAL_RUNTIME_FAILURE "
            f"metric={metric_name}:{metric_value} best={best_value} budget_left=0"
        )
        state["stop_reason"] = "TERMINAL_RUNTIME_FAILURE"
        return "approved"

    contract = state.get("execution_contract") if isinstance(state.get("execution_contract"), dict) else {}
    metric_nodes_managed = bool(state.get("metric_improvement_nodes_managed"))
    if not metric_nodes_managed and state.get("ml_improvement_round_active"):
        return _finalize_metric_improvement_round(state, contract)

    policy = _get_iteration_policy(state)
    last_iter_type = state.get("last_iteration_type")
    metric_iters = state.get("metric_iterations", 0)
    metric_max = policy.get("metric_improvement_max") if policy else None
    budget_left = (metric_max - metric_iters) if metric_max else "unlimited"
    metric_name, metric_value, best_value = _get_metric_info()

    if policy:
        compliance_max = policy.get("compliance_bootstrap_max")
        if last_iter_type == "compliance" and compliance_max:
            if state.get("compliance_iterations", 0) >= compliance_max:
                print("WARNING: Compliance bootstrap limit reached. Proceeding with current results.")
                print(f"ITER_DECISION type=compliance action=stop reason=BUDGET metric={metric_name}:{metric_value} best={best_value} budget_left=0")
                return "approved"
        if last_iter_type != "compliance" and metric_max:
            if metric_iters >= metric_max:
                print("WARNING: Metric-iteration limit reached. Proceeding with current results.")
                print(f"ITER_DECISION type=metric action=stop reason=BUDGET metric={metric_name}:{metric_value} best={best_value} budget_left=0")
                return "approved"
    else:
        if state.get('iteration_count', 0) >= 6:
            print("WARNING: Max iterations reached. Proceeding with current results.")
            print(f"ITER_DECISION type=metric action=stop reason=BUDGET metric={metric_name}:{metric_value} best={best_value} budget_left=0")
            return "approved"

    # Adaptive stop: if case alignment degrades or stagnates, stop early.
    if last_iter_type == "compliance":
        if state.get('review_verdict') == "NEEDS_IMPROVEMENT":
            print(f"ITER_DECISION type=compliance action=retry reason=COMPLIANCE_FIX metric={metric_name}:{metric_value} best={best_value} budget_left={budget_left}")
            return "retry"
        print(f"ITER_DECISION type=compliance action=stop reason=SUCCESS metric={metric_name}:{metric_value} best={best_value} budget_left={budget_left}")
        return "approved"

    if last_iter_type == "metric":
        data_report = state.get("data_adequacy_report") or _load_json_safe("data/data_adequacy_report.json") or {}
        reasons = data_report.get("reasons", []) if isinstance(data_report, dict) else []
        threshold_reached = bool(data_report.get("threshold_reached")) if isinstance(data_report, dict) else False
        if threshold_reached or "signal_ceiling_reached" in reasons:
            msg = "DATA_LIMITED_STOP: data adequacy indicates signal ceiling reached; stopping metric iterations."
            print(f"WARNING: {msg}")
            _append_feedback_history(state, msg)
            state["stop_reason"] = "CEILING"
            print(f"ITER_DECISION type=metric action=stop reason=CEILING metric={metric_name}:{metric_value} best={best_value} budget_left={budget_left}")
            return "approved"
        plateau_window = 2
        plateau_epsilon = 0.01
        if policy:
            plateau_window = int(policy.get("plateau_window", plateau_window) or plateau_window)
            plateau_epsilon = float(policy.get("plateau_epsilon", plateau_epsilon) or plateau_epsilon)
        plateau, reason = _detect_metric_plateau(state.get("metric_history"), plateau_window, plateau_epsilon)
        if plateau:
            msg = f"PLATEAU_STOP: {reason or 'metric plateau detected'}"
            print(f"WARNING: {msg}")
            _append_feedback_history(state, msg)
            state["stop_reason"] = "PLATEAU"
            print(f"ITER_DECISION type=metric action=stop reason=PLATEAU metric={metric_name}:{metric_value} best={best_value} budget_left={budget_left}")
            return "approved"

    case_report = state.get("case_alignment_report", {}) or {}
    metrics = case_report.get("metrics", {}) if isinstance(case_report, dict) else {}
    try:
        curr_violation_rate = float(metrics.get("adjacent_refscore_violations", metrics.get("case_order_violations", 1.0)))
    except Exception:
        curr_violation_rate = None
    prev_rates = state.get("case_alignment_history", []) or []
    if curr_violation_rate is not None:
        new_history = prev_rates + [curr_violation_rate]
        # stop if last two iterations didn't improve by at least 5%
        if len(new_history) >= 3:
            last = new_history[-1]
            prev = new_history[-2]
            prev2 = new_history[-3]
            if last >= prev * 0.95 and prev >= prev2 * 0.95:
                print("WARNING: Case alignment not improving across iterations. Stopping early.")
                state["stop_reason"] = "CASE_ALIGNMENT_STAGNANT"
                print(f"ITER_DECISION type=metric action=stop reason=CASE_ALIGNMENT_STAGNANT metric={metric_name}:{metric_value} best={best_value} budget_left={budget_left}")
                return "approved"
        # stop if regression >10% vs best so far
        best = min(new_history) if new_history else curr_violation_rate
        if curr_violation_rate > best * 1.10:
            print("WARNING: Case alignment regressed vs best. Stopping early.")
            state["stop_reason"] = "CASE_ALIGNMENT_REGRESSED"
            print(f"ITER_DECISION type=metric action=stop reason=CASE_ALIGNMENT_REGRESSED metric={metric_name}:{metric_value} best={best_value} budget_left={budget_left}")
            return "approved"

    if state.get('review_verdict') == "NEEDS_IMPROVEMENT":
        if _is_blocking_retry_reason(state if isinstance(state, dict) else {}):
            print(f"ITER_DECISION type=other action=retry reason=COMPLIANCE_OR_RUNTIME metric={metric_name}:{metric_value} best={best_value} budget_left={budget_left}")
            return "retry"
        print(f"ITER_DECISION type=other action=stop reason=ADVISORY_ONLY metric={metric_name}:{metric_value} best={best_value} budget_left={budget_left}")
        state["stop_reason"] = "ADVISORY_ONLY"
        return "approved"

    if not metric_nodes_managed and _bootstrap_metric_improvement_round(state, contract):
        rounds_allowed = int(state.get("ml_improvement_rounds_allowed", 1) or 1)
        round_count = int(state.get("ml_improvement_round_count", 0) or 0)
        budget_left = max(0, rounds_allowed - round_count)
        print(
            f"ITER_DECISION type=metric action=retry reason=METRIC_IMPROVEMENT_ROUND "
            f"metric={metric_name}:{metric_value} best={best_value} budget_left={budget_left}"
        )
        return "retry"

    print(f"ITER_DECISION type=other action=stop reason=SUCCESS metric={metric_name}:{metric_value} best={best_value} budget_left={budget_left}")
    return "approved"

def run_translator(state: AgentState) -> AgentState:
    print("--- [6] Translator: Generating Report ---")
    abort_state = _abort_if_requested(state, "translator")
    if abort_state:
        return abort_state
    state = sanitize_text_payload(state if isinstance(state, dict) else {})
    run_id = state.get("run_id")
    if run_id:
        log_run_event(run_id, "translator_start", {})

    best_score = state.get("best_attempt_score")
    last_score = state.get("last_attempt_score")
    promote_best = False
    if best_score is not None and state.get("best_attempt_dir"):
        if state.get("execution_error") or state.get("sandbox_failed"):
            promote_best = True
        if state.get("artifact_content_issues"):
            promote_best = True
        missing_outputs = (state.get("output_contract_report") or {}).get("missing") if isinstance(state.get("output_contract_report"), dict) else []
        if missing_outputs:
            promote_best = True
        try:
            if last_score is not None and float(best_score) > float(last_score):
                promote_best = True
        except Exception:
            pass
    if promote_best:
        updates = _promote_best_attempt(state)
        if updates:
            state = {**state, **updates}

    error_msg = state.get("error_message")

    # Extract visuals context
    has_partial_visuals = state.get("has_partial_visuals", False)
    plots_local = state.get("plots_local", [])
    fallback_plots = state.get("fallback_plots", [])

    report_state = dict(state)
    summary = None
    try:
        if not os.path.exists("data/output_contract_report.json"):
            reason = state.get("pipeline_aborted_reason") or "pipeline_aborted"
            _persist_output_contract_report(state, reason=reason)
        summary = build_run_summary(state)
        os.makedirs("data", exist_ok=True)
        dump_json("data/run_summary.json", summary)
    except Exception:
        summary = None
    report_error = error_msg
    if error_msg and "BUDGET_EXCEEDED" in str(error_msg) and state.get("last_successful_execution_output"):
        report_state["execution_output"] = state.get("last_successful_execution_output")
        if state.get("last_successful_plots"):
            report_state["plots_local"] = state.get("last_successful_plots")
            report_state["has_partial_visuals"] = True
        report_error = None
    report_state.setdefault("execution_error", state.get("execution_error", False))
    report_state.setdefault("sandbox_failed", state.get("sandbox_failed", False))
    translator_view = state.get("translator_view") or (state.get("contract_views") or {}).get("translator_view")
    if not isinstance(translator_view, dict) or not translator_view:
        projected_views = build_contract_views_projection(
            report_state.get("execution_contract", {}) or {},
            report_state.get("artifact_index") or _load_json_any("data/produced_artifact_index.json") or [],
        )
        translator_view = projected_views.get("translator_view") or {}
    if isinstance(translator_view, dict):
        translator_view = compress_long_lists(translator_view)[0]
    report_state["translator_view"] = translator_view
    normalized_review_status = _normalize_review_status(report_state.get("review_verdict"))
    normalized_review_feedback = _normalize_review_feedback(report_state.get("review_feedback"), normalized_review_status)
    review_verdict_normalized = normalize_review_status(normalized_review_status)
    report_state["review_verdict"] = normalized_review_status
    report_state["review_feedback"] = normalized_review_feedback
    report_state["review_verdict_normalized"] = review_verdict_normalized
    report_state["review_feedback_normalized"] = normalized_review_feedback
    state["review_verdict_normalized"] = review_verdict_normalized
    state["review_feedback_normalized"] = normalized_review_feedback
    try:
        translator_view_len = len(json.dumps(translator_view, ensure_ascii=True))
        print(f"Using TRANSLATOR_VIEW_CONTEXT length={translator_view_len}")
        if run_id:
            log_run_event(run_id, "translator_view_context", {"length": translator_view_len})
    except Exception:
        pass
    contract = report_state.get("execution_contract", {}) or {}
    deliverables = _resolve_contract_deliverables(contract)
    has_preview_deliverable = False
    if isinstance(deliverables, list):
        for item in deliverables:
            if isinstance(item, dict) and item.get("path") == "reports/recommendations_preview.json":
                has_preview_deliverable = True
                break
            if isinstance(item, str) and item == "reports/recommendations_preview.json":
                has_preview_deliverable = True
                break
    reporting_policy = contract.get("reporting_policy") if isinstance(contract, dict) else {}
    preview_enabled = True
    if isinstance(reporting_policy, dict) and reporting_policy.get("demonstrative_examples_enabled") is False:
        preview_enabled = False
    if has_preview_deliverable and preview_enabled:
        output_text = report_state.get("execution_output", "") or ""
        artifact_guard = "ARTIFACT_ALIGNMENT_GUARD" in output_text
        stale_guard = "STALE_OUTPUTS" in output_text
        artifacts_valid = not (
            report_state.get("execution_error")
            or report_state.get("sandbox_failed")
            or artifact_guard
            or stale_guard
        )
        cleaned_path = str(report_state.get("ml_data_path") or state.get("ml_data_path") or "").strip()
        if not cleaned_path or not os.path.exists(cleaned_path):
            de_cleaned_path, _, _ = _resolve_de_output_artifacts(report_state if isinstance(report_state, dict) else {})
            if de_cleaned_path and os.path.exists(de_cleaned_path):
                cleaned_path = de_cleaned_path
        if not cleaned_path:
            cleaned_path = "data/cleaned_full.csv" if os.path.exists("data/cleaned_full.csv") else "data/cleaned_data.csv"
        preview_root = None
        run_dir = get_run_dir(run_id) if run_id else None
        if run_id and not run_dir:
            run_dir = os.path.join("runs", run_id)
        if run_dir:
            preview_root = os.path.join(run_dir, "artifacts")
            try:
                work_dir_abs = _resolve_work_dir_abs(report_state if isinstance(report_state, dict) else None)
                copy_run_artifacts(
                    run_id,
                    [
                        _abs_in_work(work_dir_abs, "data"),
                        _abs_in_work(work_dir_abs, "reports"),
                        _abs_in_work(work_dir_abs, "static"),
                    ],
                    since_epoch=state.get("run_start_epoch"),
                )
            except Exception:
                pass
        produced_index = (
            state.get("produced_artifact_index")
            or state.get("artifact_index")
            or _load_json_any("data/produced_artifact_index.json")
        )
        preview_cleaned_path = None
        if preview_root:
            candidate = os.path.join(preview_root, "data", "cleaned_data.csv")
            if os.path.exists(candidate):
                preview_cleaned_path = candidate
        if not preview_cleaned_path and cleaned_path and os.path.exists(cleaned_path):
            preview_cleaned_path = cleaned_path
        preview_payload = build_recommendations_preview(
            contract=contract,
            governance_summary=summary or {},
            artifacts_dir=preview_root or ".",
            cleaned_data_path=preview_cleaned_path,
            produced_artifact_index=produced_index,
            run_scoped_root=run_dir,
        )
        chosen_source = preview_payload.get("chosen_source") if isinstance(preview_payload, dict) else {}
        if not artifacts_valid:
            if isinstance(chosen_source, dict) and chosen_source.get("kind") == "sandbox_attempt":
                preview_payload["status"] = "illustrative_only"
                preview_payload["risk_level"] = "high"
                preview_payload.setdefault("caveats", []).append(
                    "Artifacts were invalid or blocked; illustrative examples sourced from sandbox attempt outputs."
                )
            else:
                preview_payload["items"] = []
                preview_payload["reason"] = preview_payload.get("reason") or "artifacts_invalid"
                preview_payload["status"] = "illustrative_only"
                preview_payload["risk_level"] = "high"
                preview_payload.setdefault("caveats", []).append(
                    "Artifacts were invalid or blocked; examples withheld."
                )
        try:
            os.makedirs("reports", exist_ok=True)
            with open("reports/recommendations_preview.json", "w", encoding="utf-8") as f_prev:
                json.dump(preview_payload, f_prev, indent=2, ensure_ascii=False)
            existing_index = _load_json_any("data/produced_artifact_index.json")
            normalized_existing = existing_index if isinstance(existing_index, list) else []
            additions = _build_artifact_index(["reports/recommendations_preview.json"], deliverables)
            merged_index = _merge_artifact_index_entries(normalized_existing, additions)
            dump_json("data/produced_artifact_index.json", merged_index)
            report_state["artifact_index"] = merged_index
            report_state["produced_artifact_index"] = merged_index
        except Exception as prev_err:
            print(f"Warning: failed to persist recommendations_preview.json: {prev_err}")

        if isinstance(chosen_source, dict) and chosen_source.get("kind") == "sandbox_attempt":
            label_col_hint = None
            if isinstance(contract, dict):
                label_col_hint = contract.get("segment_label_column")
            staged = _stage_illustrative_assets(
                chosen_source.get("root"),
                report_root="report",
                label_col_hint=label_col_hint,
                contract=contract,
            )
            if staged.get("plots") and not report_state.get("plots_local"):
                report_state["plots_local"] = staged.get("plots")
            report_state["illustrative_assets"] = staged
    report_plots = report_state.get("plots_local", plots_local)
    artifact_entries = report_state.get("artifact_index") or []
    report_artifacts = [
        item.get("path") if isinstance(item, dict) else item
        for item in artifact_entries
        if item
    ]
    error_flag = bool(report_error) or report_state.get("execution_error") or report_state.get("sandbox_failed")
    if not error_flag:
        if fallback_plots:
            report_plots = [plot for plot in report_plots if plot not in fallback_plots]
            report_state["plots_local"] = report_plots
            if artifact_entries:
                filtered_entries = []
                for entry in artifact_entries:
                    path = entry.get("path") if isinstance(entry, dict) else entry
                    if path in fallback_plots:
                        continue
                    filtered_entries.append(entry)
                report_state["artifact_index"] = filtered_entries
                report_state["produced_artifact_index"] = filtered_entries
    report_state["has_partial_visuals"] = bool(report_plots) and error_flag
    report_has_partial = report_state["has_partial_visuals"]
    try:
        report = translator.generate_report(
            report_state,
            error_message=report_error,
            has_partial_visuals=report_has_partial,
            plots=report_plots,
            translator_view=translator_view,
        )
    except Exception as e:
        print(f"CRITICAL: Translator crashed in host: {e}")
        # Fallback Report
        report = f"""
        # System Recovery Report

        **CRITICAL FAILURE IN REPORT GENERATION**

        The system encountered an internal error while synthesizing the final report.

        ### Error Details:
        {str(e)}

        ### Original Error (if any):
        {error_msg if error_msg else "None"}

        ### Partial Results:
        - Visuals Generated: {has_partial_visuals}
        - Plots Available: {len(plots_local)}

        Please check the logs for more details.
        """
    report = sanitize_text(report or "")
    report_state["final_report"] = report
    if run_id:
            log_agent_snapshot(
                run_id,
                "translator",
                prompt=getattr(translator, "last_prompt", None),
                response=getattr(translator, "last_response", None) or report,
                context={
                    "error_message": report_error,
                    "has_partial_visuals": report_has_partial,
                    "plot_count": len(report_plots) if isinstance(report_plots, list) else 0,
                },
            )

    try:
        os.makedirs("data", exist_ok=True)
        with open("data/executive_summary.md", "w", encoding="utf-8") as f_exec:
            f_exec.write(report or "")
        existing_index = _load_json_any("data/produced_artifact_index.json")
        normalized_existing = existing_index if isinstance(existing_index, list) else []
        report_artifacts = ["data/executive_summary.md"]
        if os.path.exists("data/report_artifact_manifest.json"):
            report_artifacts.append("data/report_artifact_manifest.json")
        if os.path.exists("data/report_visual_tables.json"):
            report_artifacts.append("data/report_visual_tables.json")
        additions = _build_artifact_index(report_artifacts, None)
        merged_index = _merge_artifact_index_entries(normalized_existing, additions)
        dump_json("data/produced_artifact_index.json", merged_index)
        report_state["artifact_index"] = merged_index
        report_state["produced_artifact_index"] = merged_index
    except Exception as exec_err:
        print(f"Warning: failed to persist executive_summary.md: {exec_err}")

    try:
        encoding_audit = _persist_encoding_audit(state, report_text=report)
        existing_index = _load_json_any("data/produced_artifact_index.json")
        normalized_existing = existing_index if isinstance(existing_index, list) else []
        additions = _build_artifact_index(["data/encoding_audit.json"], None)
        merged_index = _merge_artifact_index_entries(normalized_existing, additions)
        dump_json("data/produced_artifact_index.json", merged_index)
        report_state["artifact_index"] = merged_index
        report_state["produced_artifact_index"] = merged_index
        state["encoding_audit"] = encoding_audit
        if run_id:
            log_run_event(
                run_id,
                "encoding_guard",
                {
                    "mojibake_detected": bool(encoding_audit.get("mojibake_detected")),
                    "flagged_files": encoding_audit.get("flagged_files", []),
                    "report_repaired": bool(encoding_audit.get("report_repaired")),
                    "objective_repaired": bool(encoding_audit.get("objective_repaired")),
                },
            )
    except Exception as enc_err:
        print(f"Warning: encoding audit failed: {enc_err}")

    try:
        pdf_payload = generate_pdf_artifact({**report_state, "final_report": report})
        pdf_path = pdf_payload.get("pdf_path") if isinstance(pdf_payload, dict) else None
        if pdf_path:
            report_state["pdf_path"] = pdf_path
    except Exception as pdf_err:
        print(f"Warning: PDF generation failed in translator: {pdf_err}")

    try:
        write_data_adequacy_report(state)
        write_governance_report(state)
        summary = summary or build_run_summary(state)
        try:
            os.makedirs("data", exist_ok=True)
            dump_json("data/run_summary.json", summary)
        except Exception:
            pass
        fingerprint = state.get("dataset_fingerprint")
        if fingerprint:
            record_dataset_memory(
                {
                    "fingerprint": fingerprint,
                    "run_id": state.get("run_id"),
                    "status": summary.get("status"),
                    "failed_gates": summary.get("failed_gates", []),
                }
            )
        if run_id:
            finalize_run_log(run_id, summary)
            log_run_event(run_id, "translator_complete", {"report_len": len(report or "")})
            work_dir_abs = _resolve_work_dir_abs(state if isinstance(state, dict) else None)
            copy_run_contracts(
                run_id,
                [
                    _abs_in_work(work_dir_abs, "data/execution_contract.json"),
                    _abs_in_work(work_dir_abs, "data/execution_contract_diagnostics.json"),
                    _abs_in_work(work_dir_abs, "data/evaluation_spec.json"),
                    _abs_in_work(work_dir_abs, "data/produced_artifact_index.json"),
                ],
            )
            _verify_run_bundle_contracts(run_id, state.get("execution_contract") or {}, work_dir_abs)
            since_epoch = state.get("run_start_epoch")
            copy_run_artifacts(
                run_id,
                [
                    _abs_in_work(work_dir_abs, "data"),
                    _abs_in_work(work_dir_abs, "analysis"),
                    _abs_in_work(work_dir_abs, "models"),
                    _abs_in_work(work_dir_abs, "plots"),
                    _abs_in_work(work_dir_abs, os.path.join("static", "plots")),
                ],
                since_epoch=since_epoch,
            )
            report_sources = [
                _abs_in_work(work_dir_abs, "report"),
                _abs_in_work(work_dir_abs, "reports"),
            ]
            pdf_path = report_state.get("pdf_path") or state.get("pdf_path")
            if pdf_path:
                report_sources.append(
                    pdf_path if os.path.isabs(pdf_path) else _abs_in_work(work_dir_abs, pdf_path)
                )
            copy_run_reports(run_id, report_sources, since_epoch=since_epoch)
            if pdf_path and state.get("run_bundle_dir"):
                try:
                    dest_path = os.path.join(state.get("run_bundle_dir"), "report", "final_report.pdf")
                    os.makedirs(os.path.dirname(dest_path), exist_ok=True)
                    shutil.copy2(pdf_path, dest_path)
                except Exception:
                    pass
            status_final = normalize_status(summary.get("status") if isinstance(summary, dict) else None)
        finalize_run(run_id, status_final=status_final, state=state)
    except Exception:
        pass
    finally:
        # P0 FIX: Always restore cwd on exit
        exit_run_workspace(state)
    return {"final_report": report, "pdf_path": report_state.get("pdf_path")}
# Generate Unique PDF Path to avoid file locks
import uuid

def generate_pdf_artifact(state: AgentState) -> AgentState:
    try:
        print("--- [7] System: Generating PDF Report ---")
        import glob

        work_dir = state.get("work_dir") if isinstance(state, dict) else None
        if not work_dir:
            work_dir = "."
        work_dir = os.path.abspath(work_dir)

        def _copy_pdf_artifact(pdf_path: str) -> None:
            run_id = state.get("run_id")
            if run_id:
                copy_run_reports(run_id, [pdf_path], since_epoch=None)
                try:
                    dest_root = os.path.join("runs", run_id, "report")
                    os.makedirs(dest_root, exist_ok=True)
                    shutil.copy2(pdf_path, os.path.join(dest_root, "final_report.pdf"))
                except Exception:
                    pass
            run_bundle_dir = state.get("run_bundle_dir")
            if run_bundle_dir:
                try:
                    dest_path = os.path.join(run_bundle_dir, "report", "final_report.pdf")
                    os.makedirs(os.path.dirname(dest_path), exist_ok=True)
                    shutil.copy2(pdf_path, dest_path)
                except Exception:
                    pass

        report = state.get("final_report")
        existing_pdf = state.get("pdf_path")
        if existing_pdf:
            candidate = existing_pdf
            if not os.path.isabs(candidate):
                candidate = os.path.join(work_dir, candidate)
            if os.path.exists(candidate):
                _copy_pdf_artifact(candidate)
                return {"final_report": report, "pdf_path": os.path.abspath(candidate)}
        if not report:
            try:
                summary_path = os.path.join(work_dir, "data", "executive_summary.md")
                with open(summary_path, "r", encoding="utf-8") as f_exec:
                    report = f_exec.read()
            except Exception:
                report = ""
        report = str(report or "")
        if not report.strip():
            print("PDF Generation Skipped: no report content available.")
            return {"final_report": state.get("final_report"), "pdf_path": None}

        # Check for visualizations
        if "static/plots" not in report:
            plots = state.get("plots_local", []) or []
            fallback_plots = state.get("fallback_plots", []) or []
            has_exec_error = bool(state.get("execution_error") or state.get("sandbox_failed"))
            if not has_exec_error and fallback_plots:
                plots = [plot for plot in plots if plot not in fallback_plots]
            if not plots:
                report_plots_dir = os.path.join(work_dir, "report", "static", "plots")
                if os.path.isdir(report_plots_dir):
                    plots = glob.glob(os.path.join(report_plots_dir, "*.png"))
            if plots:
                report += "\n\n## Visualizations\n"
                for plot in plots:
                    if os.path.isabs(plot) and plot.startswith(work_dir):
                        rel_plot = os.path.relpath(plot, work_dir)
                    else:
                        rel_plot = plot
                    plot_ref = _normalize_path_posix(rel_plot)
                    report += f"![{os.path.basename(plot)}]({plot_ref})\n"

        # Generate unique filename
        unique_id = uuid.uuid4().hex[:8]
        pdf_filename = os.path.join(work_dir, f"final_report_{unique_id}.pdf")

        # Absolute path for clarity
        abs_pdf_path = os.path.abspath(pdf_filename)

        # Convert without relying on cwd
        success = convert_report_to_pdf(report, abs_pdf_path, base_dir=work_dir)

        if success:
            print(f"PDF generated at: {abs_pdf_path}")
            run_id = state.get("run_id")
            since_epoch = state.get("run_start_epoch")

            latest_pdf = pdf_filename
            try:
                candidates = []
                for path in glob.glob(os.path.join(work_dir, "final_report*.pdf")):
                    try:
                        mtime = os.path.getmtime(path)
                    except Exception:
                        continue
                    if since_epoch is None or mtime >= float(since_epoch) - 1.0:
                        candidates.append((mtime, path))
                if candidates:
                    candidates.sort(reverse=True)
                    latest_pdf = candidates[0][1]
            except Exception:
                latest_pdf = pdf_filename

            latest_abs = os.path.abspath(latest_pdf)
            _copy_pdf_artifact(latest_abs)
            return {"final_report": report, "pdf_path": latest_abs}
        else:
            print("PDF Generation Failed")
            return {"final_report": report, "pdf_path": None}

    finally:
        exit_run_workspace(state)
